INSERT INTO public.restaurants (name, address, phone, category, youtube_link, lat, lng, region, tzuyang_review) VALUES
('Midyeci Ahmet', 'Yıldız, Çırağan Cd. No:22, 34349 Beşiktaş/İstanbul, Turkey', '+904444176', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=V__oVpfMi8I', 41.0426331, 29.0100516, '튀르키예', '쯔양은 이스탄불의 ''미디예 아흐멧''에서 홍합에 양념된 밥을 채워 찐 요리인 ''미디예 돌마'' 먹방을 진행했습니다. 전날 맛본 후 계속 생각나서 다시 방문했다고 밝혔습니다. 오리지널, 소스, 칠리 세 가지 맛이 있으며, 오리지널은 굴 소스 해물 볶음밥과 비슷한 감칠맛이 특징이라고 설명했습니다. 소스 맛은 더 크리미해서 마음에 들어 했고, 칠리 맛은 매우면서도 맛있다고 평가했습니다. 여성 기록인 160개를 시작으로 최종적으로 300개를 먹으며 가게의 신기록을 세웠습니다. 먹어도 질리지 않는 맛과 친절한 현지인들의 응원 덕분에 즐겁게 식사했으며, 터키 음식이 입맛에 아주 잘 맞는다고 극찬했습니다. 시간이 늦어 300개에서 멈췄지만, 500개도 먹을 수 있을 것 같다며 아쉬움을 표현했습니다.'),
('Şehzade Cağ Kebap', 'Hocapaşa Sokak No:4, Istanbul 34200 Türkiye', '+90 212 520 33 61', ARRAY['고기'], 'https://www.youtube.com/watch?v=FPg95PvRbew', 41.0143, 28.9754583, '튀르키예', '쯔양은 이 집의 대표 메뉴인 ''자으 케밥''을 총 40꼬치 먹었습니다. 양고기 특유의 잡내가 전혀 없고 완벽한 양고기 향만 남아있다고 평가했습니다. 겉은 바삭하고 속은 부드러우면서 쫄깃한 식감이 예술이라고 극찬했습니다. 특히 레어로 익힌 고기는 매우 부드럽고 육즙이 풍부해 입에서 녹는다고 했습니다. 얇은 토르티야에 고기와 토마토, 양파를 함께 싸 먹는 조합이 최고라고 말했으며, 고기에 뿌려진 소금도 맛있다고 언급했습니다. 함께 먹은 렌틸 수프는 고소한 콩 맛이 나고 맛있다고 평가했습니다. 전체적으로 ''역대급 맛집''을 찾았다며, 양고기는 예술의 경지였다고 리뷰를 마무리했습니다.'),
('Nusr-Et Steakhouse Etiler', 'Etiler, Nispetiye Cd. No:87, 34337 Beşiktaş/İstanbul, Türkiye', '+90 530 919 09 94', ARRAY['고기'], 'https://www.youtube.com/watch?v=JgmopiEN8dU', 41.0804494, 29.0334964, '튀르키예', '쯔양은 이 레스토랑이 매우 고급스럽지만, 음식의 질과 퍼포먼스를 고려할 때 가격이 합리적이라고 평가했습니다. 골든 스테이크는 부드럽고 풍미가 깊으며, 양고기는 잡내가 적어 누구나 즐길 수 있다고 언급했습니다. 특히 코베 스테이크는 입에서 녹는 듯한 식감과 기름진 풍미가 일품이라며 강력 추천했습니다. 또한, 등심(tenderloin)은 버터를 머금은 듯한 맛이 특징이라고 설명했습니다. 사이드 메뉴인 감자튀김과 아스파라거스도 훌륭했으며, 디저트로 먹은 바클라바는 매우 달콤하다고 평가했습니다. 전반적으로 모든 고기 메뉴의 양이 푸짐하고, 직원들의 친절함과 화려한 분위기 덕분에 특별한 날 방문하기 좋은 곳이라고 요약했습니다.'),
('새집한정식', '전북 순창군 순창읍 순창6길 5-1', '063-653-2271', ARRAY['한식'], 'https://www.youtube.com/watch?v=DJrOIqKlnDo', 35.3731837, 127.142902, '전라북도', '쯔양은 65년 전통의 순창 최고(最古) 한정식집 ''새집''을 방문했습니다. 할머니 댁에 온 것 같은 한옥 분위기와 상을 통째로 들여오는 방식이 인상적이라고 평했습니다. 27가지의 다채로운 반찬과 함께 나온 연탄 소불고기와 돼지불고기가 메인 메뉴였습니다. 특히 돼지불고기는 달콤한 맛과 불향이 뛰어나고, 전라도식 김치와 갓김치는 감칠맛이 폭발한다고 극찬했습니다. 멸치볶음은 과자처럼 바삭했고, 조기구이도 숯불에 구워 껍질이 쫄깃하다며 맛있게 먹었습니다. 된장찌개는 구수하고 진한 맛이 일품이라고 평가했습니다. 쯔양은 음식 맛과 고즈넉한 분위기 모두 완벽하다며, 밥 네 공기를 비우며 만족스러운 식사였다고 총평했습니다.'),
('평화족발', '전북 군산시 신금길 18 군산공설시장 1074호', '063-446-2804', ARRAY['족발·보쌈'], 'https://www.youtube.com/watch?v=9dmuQzjhYFI', 36.01873945, 126.7365042866, '전라북도', '쯔양은 매운잡채, 미니족발, 김밥, 잡탕, 열무김치국수를 주문했습니다. 김밥은 오이가 없어 평범해 보이지만 맛있다고 평가했습니다. 대표 메뉴인 매운잡채는 떡볶이보다는 전골에 가까운 느낌이며, 잡탕보다 조금 더 맛있다고 언급했습니다. 족발은 잡채와 함께 먹는 것을 추천받았으며, 초장에 찍어 먹는 조합이 색다르고 좋다고 평가했습니다. 특히 껍데기를 좋아한다면 미니족발이 최고라고 했고, 식어도 맛있을 정도로 간이 완벽하다고 칭찬했습니다. 잡탕은 라면, 만두, 떡, 당면 등 다양한 재료가 들어간 종합적인 맛이라고 설명했습니다. 전반적으로 군산의 모든 음식이 맛있었다며, 특히 족발이 인상적이었다고 만족감을 표현했습니다.'),
('산북동 달구지', '전라북도 군산시 칠성6길 144', '063-468-3534', ARRAY['고기'], 'https://www.youtube.com/watch?v=QuwlZxZHHq0', 35.9684433, 126.678563, '전라북도', '쯔양은 이곳이 지금껏 먹어본 소곱창 중 곱이 가장 확실하게 꽉 차 있는 ''역대급'' 맛집이라고 극찬했다. 당일 도축한 신선한 소의 100% 천연 곱만을 사용하여 쓴맛이 전혀 없고, 곱이 매우 고소하고 풍미가 깊다고 평가했다. 특히, 비밀 가루를 뿌려 튀기듯이 구워낸 소곱창의 겉은 바삭하고 속은 쫄깃한 식감이 일품이라고 언급했다. 간장 베이스 양념의 대창은 일본식 곱창덮밥 같은 풍미가, 바삭하게 구운 막창은 ''베이징덕''에 비유할 정도로 독특한 식감이 특징이라고 설명했다. 촉촉한 계란찜과 곱창과 잘 어울리는 파김치 등 밑반찬도 훌륭하다고 덧붙였다. 신선함, 식감, 맛 모든 면에서 만족스러운 곳이라고 종합적으로 평가했다.'),
('빈해원', '전북 군산시 동령길 57', '063-445-2429', ARRAY['중식'], 'https://www.youtube.com/watch?v=r23NV582e8Q', 35.9888393, 126.7139649, '전라북도', '짬뽕, 탕수육, 짜장면을 주문. 짬뽕은 산처럼 쌓여 나오며 해장되는 느낌이라고 평가했고, 국물은 맑지만 깊은 감칠맛이 나는 깔끔하게 매운맛이라고 함. 탕수육은 찹쌀이 없는 옛날 스타일로 과자처럼 바삭하며 소스에 담가 먹는 것을 추천. 짜장면은 소스가 진하고 풍부하며 은은한 불향이 특징으로 누구나 좋아할 맛이라고 함. 전체적으로 전통 방식이면서도 현대화된 맛으로, ''짬뽕의 정석'' 같은 맛이라고 최종 평가함.'),
('복성루', '전북 군산시 월명로 382', '063-445-8412', ARRAY['중식'], 'https://www.youtube.com/watch?v=r23NV582e8Q', 35.9782367, 126.715749, '전라북도', '짬뽕과 잡채밥을 주문. 짬뽕은 그릇이 매우 크고 면이 얇은 우동면처럼 두꺼운 것이 특징이며, 국물은 돼지고기가 듬뿍 들어간 묵직하고 진한 고기 육수 베이스라고 함. 잡채밥은 양이 매우 많고 볶음밥 자체가 기름에 잘 코팅되어 맛있으며, 짜장 소스는 개성이 강한 맛이라고 평가. 잡채 면은 불어서 쫄깃한 중국 정통 스타일이라고 함. 전반적으로 간이 완벽하고 감칠맛이 풍부하다고 칭찬함.'),
('지린성', '전북 군산시 미원로 87', '063-467-2905', ARRAY['중식'], 'https://www.youtube.com/watch?v=r23NV582e8Q', 35.9796712, 126.7139533, '전라북도', '고추짜장면과 고추짬뽕밥을 주문. 음식에서 짜장이나 짬뽕 향보다 고추 향이 압도적으로 강하게 느껴진다고 함. 고추짜장은 불맛이 강렬하고 건더기가 큼직하며, 청양고추의 매운맛이 목을 조이는 듯 강렬해 개인적으로는 감당하기 힘들었다고 평가. 반면 고추짬뽕은 짜장보다 덜 맵지만 여전히 매우며, 국물이 정말 맛있어서 맵지만 멈출 수 없는 맛이라고 함. 스트레스를 풀어주는 기분 좋게 매운맛이라고 최종적으로 평가함.'),
('솥뚜껑 충주본점', '충북 충주시 성서7길 6-1', '043-843-8161', ARRAY['고기'], 'https://www.youtube.com/watch?v=3651eb7XF98', 36.9698577, 127.9318371, '충청북도', '쯔양은 이 식당의 대표 메뉴인 ''닭사리''와 ''삼겹살''을 모두 극찬했습니다. ''닭사리''에 대해서는 어디서도 맛본 적 없는 독특한 맛이라고 표현했으며, 국물은 맑은 부대찌개처럼 깔끔하면서도 깊고 시원한 맛이 난다고 평가했습니다. 24시간 숙성시킨 닭고기는 수비드한 것처럼 매우 부드럽고, 오래 끓여도 불지 않는 국수 면발이 인상적이라고 언급했습니다. 40년 넘은 솥뚜껑에 구워 먹는 ''삼겹살''은 비계 부분은 쫄깃하고 살코기 부분은 육즙이 가득하며 고소한 맛이 일품이라고 칭찬했습니다. 특히 고기 자체의 맛이 뛰어나 다른 것과 곁들이기보다 고기만 먹는 것이 더 맛있다고 강조했습니다. 함께 나온 김치와 감자 또한 매우 맛있다고 여러 차례 언급하며 전반적으로 식사에 크게 만족하는 모습을 보였습니다.'),
('행복짬뽕', '충북 충주시 행정7길 30', '043-856-8060', ARRAY['중식'], 'https://www.youtube.com/watch?v=M3K6xj5yyg4', 37.0131601, 127.9175236, '충청북도', '쯔양은 총 3단계의 짬뽕을 맛보았습니다. 1단계 육지짬뽕은 맑고 시원하며 개운한 국물 맛이 일품이라고 평가했으며, 고기가 듬뿍 들어있다고 언급했습니다. 2단계 문어짬뽕은 1단계보다 훨씬 맵지만, 혀가 아닌 속이 뜨거워지는 매운맛이라고 설명했습니다. 특히 문어가 질기지 않고 부드러우면서도 쫄깃한 식감이 완벽하다고 칭찬했습니다. 마지막 도전 메뉴였던 3단계 매운짬뽕은 캐롤라이나 리퍼 고추를 사용해 ''지옥에서 올라오는 냄새''라고 표현할 정도로 극강의 매운맛이었지만, 인공적인 캡사이신 맛이 아닌 깔끔한 매운맛이라 즐겁게 먹었다고 합니다. 매운맛이 순간적으로 강하게 왔다가 빠르게 사라지는 점을 높이 평가하며, 매운 음식점들 중에서도 맛 자체가 훌륭한 최고의 맛집이었다고 극찬했습니다. 탕수육과 볶음밥 등 다른 메뉴도 맛있었다고 덧붙였습니다.'),
('연흥식당', '강원 원주시 평원로 1-1', '033-742-9993', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=ccABGZjVvgU', 37.3472836, 127.9537339, '강원특별자치도', '쯔양은 ''연흥식당''의 소머리 수육을 맛본 후, ''인생 최고의 수육''이라고 극찬했습니다. 특히 평소 잘 먹지 못하는 우설(소 혀) 부위조차 잡내 없이 눈꽃처럼 부드럽다고 감탄했으며, 머릿고기 껍데기 부분은 족발보다 더 쫀득하고 입에 착 달라붙는 식감이라고 평가했습니다. 함께 나온 곰탕 국물은 잡내 없이 깔끔하고 진한 맛이 일품이며, 김치와 부추 등 밑반찬도 훌륭하다고 언급했습니다. 하루에 5~6개만 한정 판매하는 수육의 희소성과 품질에 놀라워했고, 식당 내부에 고기 냄새가 전혀 나지 않는 점을 통해 사장님의 관리 실력을 엿볼 수 있다고 말했습니다. 재방문 의사를 강력하게 밝히며 ''원주 최고의 맛집''으로 꼽았습니다.'),
('똘이떡볶이', '강원특별자치도 원주시 중앙시장길 11 자유시장 지층 9블럭 2호', '033-731-8082', ARRAY['분식'], 'https://www.youtube.com/watch?v=_g7lXJtbueg', 37.3507475, 127.9487543, '강원특별자치도', '떡볶이 소스는 집에서 만든 것 같은 맛이며 약간 오징어볶음 맛이 난다고 평가함 . 떡은 밀떡으로, 빨리 팔려서 불지 않고 쫄깃한 식감을 유지한다고 언급함 . 김밥은 참기름 맛이 고소하여 그냥 먹는 것이 더 맛있다고 함 . 김말이 튀김은 소스에 찍어 먹는 것을 추천했으며, 전체적으로 독특하면서 먹을수록 중독되는 맛이라고 요약함 {ts:326-377, 1210}.'),
('해달스낵', '강원도 원주시 중앙시장길 11 자유시장 지하1층 8블럭 5,6호', '033-745-8103', ARRAY['분식'], 'https://www.youtube.com/watch?v=_g7lXJtbueg', 37.3507475, 127.9487543, NULL, '김밥 위에 참기름을 많이 뿌려줘서 매우 고소하고 밥알이 부서지는 식감이 특징이라고 함 . 떡볶이 소스는 닭볶음탕처럼 매우 걸쭉하고 크리미하며, 양배추 물을 사용해 맵지 않고 채소의 깊은 단맛이 난다고 평가함 . 어묵 국물이 오랫동안 끓여내 매우 진하고 최고라고 칭찬함 . 전체적으로 진하고 부드러운 맛이라고 요약함 .'),
('충남집', '강원특별자치도 원주시 중앙시장길 11 지층 9블럭5호 (중앙동, 자유시장)', '010-7922-7628', ARRAY['분식'], 'https://www.youtube.com/watch?v=_g7lXJtbueg', 37.3507475, 127.9487543, '강원특별자치도', '떡볶이가 윤기가 흐르며, 맛은 차돌박이 해장국, 매콤한 낙지볶음 등에 비유함 . 소스는 너무 걸쭉하지 않으면서도 응축된 느낌이며, 달콤하면서 감칠맛이 난다고 설명함 . 튀김 범벅도 맛있다고 언급함 . 아이들이 더 좋아할 만한 달콤한 맛이라고 최종적으로 평함 .'),
('우정집', '강원특별자치도 원주시 중앙시장길 11 자유시장 지층 9블럭 8호', '033-743-5822', ARRAY['분식'], 'https://www.youtube.com/watch?v=_g7lXJtbueg', 37.3507475, 127.9487543, '강원특별자치도', '떡볶이 소스 색이 유독 새빨갛다고 언급함 . 맛은 집에서 만든 소스에 현대적인 맛이 섞인 느낌으로, 후추 맛이 나는 매콤한 라면스프의 감칠맛과 비슷하다고 설명함 . 갓 튀긴 튀김이 하이라이트이며 소스에 찍어 먹는 것이 탕수육 부먹을 연상시킨다고 함 . 어묵 국물은 따뜻한 집 국물 맛이라고 평가함 . 현대적인 맛이 가미된 맛으로 정리함 .'),
('멕시칼리', '서울 광진구 능동로36길 181 1층', '0507-1360-1707', ARRAY['양식'], 'https://www.youtube.com/watch?v=NNcvNxD4vVg', 37.5527337, 127.0883657, '서울특별시', '쯔양은 이곳을 ''서울 3대 타코'' 맛집 중 하나로 소개하며, 푸드트럭으로 시작해 3층 건물로 확장할 정도로 인기가 많다고 언급했습니다. 주말에는 오픈 1시간 반 전부터 대기 줄이 생길 정도라고 합니다. 쯔양은 메뉴판의 모든 메뉴를 주문했으며, 전반적으로 재료가 매우 신선하고 소스가 풍부하여 맛있다고 평가했습니다. 특히 토르티야가 얇고 쫄깃해서 인상적이라고 말했습니다. 쯔양이 꼽은 메뉴 순위 1위는 ''피쉬 타코''로, 겉은 바삭하고 속은 녹는 듯한 생선살이 일품이라고 극찬하며 압도적인 1위로 선정했습니다. 2위는 육즙이 풍부하고 부드러운 ''소고기 타코''였고, 4위는 ''돼지고기 타코''였습니다. ''시금치&버섯 샐러드''에 대해서는 평소 채소를 즐기지 않음에도 불구하고 ''인생 최고의 샐러드''라고 평가할 만큼 소스가 훌륭하다고 감탄했습니다. 이 외에도 ''파파스'', ''몰카헤테 믹스토'' 등 다양한 메뉴를 맛보며, 모든 음식이 대중적으로 즐길 수 있는 맛이라고 총평했습니다.'),
('현고대닭발 본점', '서울 동대문구 제기로2가길 3', '02-928-9995', ARRAY['야식'], 'https://www.youtube.com/watch?v=xoxVobpBW_E', 37.5853583, 127.0346268, '서울특별시', '쯔양은 평소 뼈를 발라 먹기 번거로워 닭발을 즐겨 먹지 않는다고 밝혔지만, PD의 추천으로 방문한 ''현고대닭발''의 모든 메뉴를 맛본 후 극찬했습니다. 닭발은 흐물거리지 않고 콜라겐처럼 쫀득한 식감이 일품이라고 평가했으며, 캡사이신 없이 고춧가루로만 맛을 낸 매운 양념은 ''맛있게 매운맛''이라 중독성이 강하다고 했습니다. 특히 ''닭똥집''은 부드러우면서도 서걱거리는 식감이 살아있어 안 먹으면 바보라고 할 정도로 강력 추천했으며, 달콤하고 풍부한 맛의 ''돼지갈비''는 인생 갈비를 찾았다며 닭발 소스와의 조합을 극찬했습니다. 전체적으로 모든 메뉴가 맛있다고 여러 번 언급하며, 50년 전통의 맛에 크게 만족하는 모습을 보였습니다.'),
('제천원조빨간오뎅보금자리', '충북 제천시 의림대로 158', '043-642-7737', ARRAY['분식'], 'https://www.youtube.com/watch?v=Dhc9X5vqwNs', 37.1414242, 128.2125952, '충청북도', '단맛과 매운맛이 적절히 조화된 맛이 특징입니다. 처음에는 맵지 않다고 느꼈지만 먹다 보면 혀끝에 매운맛이 올라옵니다. 특히 물어묵이 쫄깃해서 맛있었다고 합니다. 실내 공간이 넓어 쾌적하게 식사할 수 있는 장점이 있고, 슬러시, 라면, 우동 등 다양한 메뉴를 판매합니다.'),
('제천명물빨간오뎅', '충북 제천시 의병대로18길 1-2', '043-644-8997', ARRAY['분식'], 'https://www.youtube.com/watch?v=Dhc9X5vqwNs', 37.1352839, 128.2123427, '충청북도', '4년 3개월 만에 재방문했는데, 예전과 맛이 정확히 똑같다고 평가했습니다. 빨간오뎅의 식감이 쫄깃쫄깃해서 맛있었다고 합니다. 쯔양이 과거에 빨간오뎅 76개, 떡 2개, 물어묵 6개, 계란 2개, 슬러시 6개, 콜라 1개를 먹었다고 사장님이 정확히 기억하고 있었습니다.'),
('통큰식당', '충북 제천시 덕산면 약초로 3길 5-1', '043-645-3005', ARRAY['한식'], 'https://www.youtube.com/watch?v=Toi35vekNN8', 36.909274, 128.1661226, '충청북도', '대표 메뉴인 제육칼국수는 국물이 있는 형태로, 육개장과 비슷한 얼큰함과 강한 감칠맛, 진한 제육의 풍미가 특징이라고 평가함. 직접 반죽하여 숙성시킨 면은 부드럽고 밀가루 냄새가 없다고 칭찬함. 함께 맛본 물냉면은 해물 기반의 독특한 육수가 인상적이며, 바지락밥은 조미료 맛이 나지 않는 맑고 시원한 국물이 일품이라고 언급함. 김밥, 들깨칼국수, 비빔냉면 등 모든 메뉴가 인공적이지 않고 정성이 느껴지는 자연스러운 맛이라며 전반적으로 매우 만족스러워함.'),
('수정관', '전북 전주시 완산구 문화광장로 18', '063-287-7268', ARRAY['중식'], 'https://www.youtube.com/watch?v=c2WW0RGNFgY', 35.822384, 127.1461169, '전라북도', '쯔양은 이 식당을 ''옛날 중국집 음식''의 맛을 그대로 간직한 곳이라고 총평했습니다. 대표 메뉴인 ''물짜장''은 짜장 맛이 전혀 나지 않고, 짬뽕과 유산슬을 섞은 듯한 독특한 맛이라고 평가했습니다. ''깐풍육''은 매우 인기 있는 메뉴답게 맛있는 양념치킨 같은 느낌이라고 표현했으며, ''탕수육''은 케첩 베이스의 옛날식 소스가 인상적이라고 했습니다. 특히 ''짜장면''은 처음엔 심심하게 느껴졌지만 먹을수록 감칠맛이 깊어지는, 어릴 때 먹던 맛이라며 칭찬했습니다. 전반적으로 모든 음식의 간이 세지 않고 담백하면서도 깊은 맛이 나서, 다 먹고 나서도 입안이 짜지 않고 편안했다고 만족감을 표현했습니다.'),
('대성식품', '전북 전주시 완산구 팔달로 157-5', '063-284-1486', ARRAY['분식'], 'https://www.youtube.com/watch?v=oRWZAJN4ZFQ', 35.8162906, 127.1471678, '전라북도', '쯔양은 이곳의 음식들이 할머니가 해준 것 같은 깊은 ''손맛''과 감칠맛이 특징이라고 극찬했습니다. 대표 메뉴인 ''울트라 라면''은 만두, 수제비, 떡, 콩나물 등 푸짐한 재료와 완벽하게 익은 면발이 인상적이며, 김치가 들어가 국물이 시원하다고 평가했습니다. 여러 메뉴 중 ''비빔국수''를 가장 맛있는 메뉴로 꼽았는데, 너무 시거나 달지 않은 완벽한 균형감과 따라 할 수 없는 손맛이 느껴진다고 말했습니다. ''짜파구리''는 면 굵기가 다른 두 라면의 익힘 정도를 완벽하게 맞췄다고 칭찬했으며, 국물 없이 볶아낸 ''라볶이''는 고소하고 달콤한 맛이 특징이라고 언급했습니다. 저렴한 가격에도 불구하고 음식을 즐기는 손님을 보며 행복을 느끼는 사장님의 친절함과 따뜻한 분위기 또한 긍정적으로 평가했습니다.'),
('춘선만두', '서울 광진구 군자로 101', '02-466-4398', ARRAY['중식'], 'https://www.youtube.com/watch?v=K1Hc4cZKXt0', 37.5523229, 127.0712754, '서울특별시', '쯔양은 평소 두부를 즐겨 먹지 않지만, 이 식당의 마파두부는 비주얼에 이끌려 처음으로 먹고 싶다는 생각이 들었다고 언급했다. 마파두부는 산초 향이 강하지만 거부감 없이 맛있게 즐길 수 있어 마파두부 입문자에게 완벽하다고 평가했다. 특히 두부가 매우 부드럽고 연해서 마음에 들어 했다. ''류류똴(류러우돤)''은 간장 베이스의 꿔바로우 같은 요리로, 단맛과 신맛 없이 간장의 감칠맛이 특징이며 찹쌀 탕수육처럼 매우 쫀득하고 쫄깃한 식감이 일품이라고 설명했다. 만두는 피를 직접 만들어 쫄깃하고 맛있으며, 그중에서도 부추만두가 가장 맛있었다고 극찬했다. 김치볶음밥은 돌아가신 어머니가 해주신 맛과 똑같아 눈물이 날 것 같다고 말하며 깊은 감동을 표현했다. 전반적으로 호불호가 갈릴 수 있는 독특한 맛집이지만, 좋아하는 사람들은 단골이 될 것이라며 매우 만족스러운 식사였다고 총평했다.'),
('닭동가리 강남역점', '서울 서초구 서초대로77길 37 서초동월드 상가 1층 103호', '010-9906-7680', ARRAY['치킨'], 'https://www.youtube.com/watch?v=KZWOjfpg2iI', 37.5009917, 127.0251242, '서울특별시', '쯔양은 이곳의 대표 메뉴인 ''닭동가리 통닭''을 맛본 후 ''감동의 치킨''이라며, 튀김옷이 매우 바삭하고 속은 육즙이 가득해 물을 머금은 듯 촉촉하다고 극찬했습니다[ts:331, ts:370]. 특히 식어도 맛있다는 점을 강조했습니다. 또한 단맛 없이 후추와 카레 향이 나는 떡볶이와, 불맛이 강하며 전문점 수준의 맛을 내는 ''팔당 오징어''가 맥주와 잘 어울린다고 평가했습니다. 이 외에도 포장마차 스타일의 우동, 오돌갈비, 해물라면 등 다양한 안주를 맛보며 전반적으로 음식 맛에 크게 만족하는 모습을 보였습니다.'),
('하영슈퍼', '서울 종로구 종로36길 8', '02-765-5714', ARRAY['한식'], 'https://www.youtube.com/watch?v=2TYa1R-kcpc', 37.5705587, 127.0038165, '서울특별시', '쯔양은 이곳을 ''갓김치 짜파게티의 달인''이 있는 곳으로 소개하며, 라면 애호가로서 방문했다고 밝혔습니다. 메인 메뉴인 갓김치와 짜파게티의 조합을 극찬했는데, 갓김치는 너무 익지 않고 부드러우면서도 맛있게 시큼한 맛이 짜파게티와 환상적인 궁합을 이룬다고 평가했습니다. 특히 짜파게티는 국물이 너무 많거나 뻑뻑하지 않게 완벽하게 조리되었으며, 고춧가루가 뿌려져 있어 더욱 맛있다고 언급했습니다. 이 조합이 일반 짜장면보다 낫다고 할 정도였습니다. 이 갓김치는 사장님의 어머니가 직접 담그신 것으로, 아쉽게도 따로 판매는 하지 않는다고 합니다. 짜파게티 외에 다른 라면과도 잘 어울리지만, 짜파게티와의 조합이 단연 최고라고 강조했습니다. 추가로 주문한 치즈계란말이는 매우 촉촉하고 부드러워 입에서 녹는 식감이라고 칭찬했으며, 매운 불닭볶음면, 스팸 구이 등 다양한 메뉴를 갓김치와 곁들여 먹으며 만족스러운 ''가맥집'' 경험이었다고 총평했습니다.'),
('한강반점', '대구광역시 중구 달구벌대로387길 42', '053-253-7518', ARRAY['중식'], 'https://www.youtube.com/watch?v=sO8qdAuBAQs', 35.8650228, 128.5752432, '대구광역시', '쯔양은 3,000원짜리 짜장면에 대해, 자극적이거나 너무 달지 않고 깔끔한 옛날 짜장면 맛이라고 평가했습니다. 소스 안에 감자와 고기 건더기가 큼직하게 들어있고 잘 익었으며, 특히 고기가 퍽퍽하지 않고 부드럽다고 언급했습니다. 감자와 고구마가 함께 들어가 자연스러운 맛을 내며, 고구마를 먼저 튀겨 부드럽고 맛있다고 ''명품 짜장면''이라 칭찬했습니다. 6,000원짜리 간짜장은 강한 마늘 향과 스모키한 풍미가 특징이라고 설명했습니다. 탕수육은 옛날 스타일이라고 언급했습니다. 사장님이 봉사하는 마음으로 가격을 올리지 않을 것이라고 말한 것에 감동받았다고 전했습니다.'),
('너구리식당', '대구 남구 성당로34길 5-2', '053-654-9433', ARRAY['고기'], 'https://www.youtube.com/watch?v=JQUWY-z9Q2E', 35.848516, 128.5702752, '대구광역시', '쯔양은 대구의 명물인 뭉티기를 먹기 위해 36년 전통의 ''너구리식당''을 방문했습니다. 대표 메뉴인 뭉티기는 두툼하게 썰어 나와 씹는 맛이 좋고, 질기지도 무르지도 않은 완벽한 식감을 자랑한다고 평가했습니다. 특히 매콤하면서도 고소하고 깊은 맛이 나는 특제 소스가 일품이라고 극찬하며, 뭉티기를 소스에 20~30분간 재워두었다 먹는 방법을 추천했습니다. 뭉티기 외에도 독특한 양념의 육회, 마시멜로처럼 부드럽고 신기한 식감의 등골, 소 한 마리에서 소량만 나오는 귀한 부위인 주먹시(안창살) 등 다양한 메뉴를 맛보았습니다. 주먹시는 살짝만 익혀 먹었을 때 소고기의 풍미가 진하고 매우 부드럽다고 평했습니다. 전체적으로 저렴한 가격에 훌륭한 품질의 고기를 즐길 수 있는 곳이며, 재료가 일찍 소진될 수 있으니 방문 전 전화 예약을 하는 것이 좋다고 조언했습니다.'),
('부산안면옥', '대구광역시 중구 국채보상로125길 4-1', '053-424-9389', ARRAY['한식'], 'https://www.youtube.com/watch?v=x6CqjKYFyiU', 35.8705982, 128.598939, '대구광역시', '쯔양은 이 식당의 여러 메뉴를 맛보고 극찬했습니다. 특히 평양냉면에 대해 입문자도 먹기 좋은 맛으로, 밍밍하지 않고 간이 되어있어 맛있다고 평가했으며, 본인 인생 최고의 평양냉면으로 꼽았습니다. 함흥냉면은 면이 쫄깃하고 양념이 매우 매운 편이며, 회무침이 들어있다고 언급했습니다. 따뜻하게 나온 제육은 잡내 없이 단단하고 쫀득하며, 소고기 수육은 기름기가 빠져 담백하고 깔끔한 맛이라고 했습니다. 갈비탕 역시 고기가 부드럽고 국물이 진하고 고소하다고 칭찬했습니다. 함께 나온 김치도 서울 김치와는 다른 특별한 맛이 있다고 여러 번 언급하며 맛있게 먹었습니다.'),
('수봉반점', '대구광역시 북구 대현남로2길 60', '053-941-1503', ARRAY['중식'], 'https://www.youtube.com/watch?v=6YZCvnlAbTc', 35.8782434, 128.6064043, '대구광역시', '쯔양은 대구 최고의 중화비빔밥 맛집이라는 말을 듣고 오픈 시간에 맞춰 방문했다고 밝혔습니다. 50년 전통의 노포로, 양이 매우 푸짐하다고 언급했습니다. 대표 메뉴인 ''바람돌이 짬뽕''은 국물이 매우 시원하고 칼칼하며, 훈연향과 채소향이 잘 어우러져 깔끔하면서도 깊은 맛이 난다고 평가했습니다. ''볶음밥''은 양이 일반적인 곳의 두 배라며 놀라워했고, 고슬고슬한 식감을 칭찬했습니다. 사장님의 추천대로 짬뽕 국물에 찍어 먹으니 더 맛있다고 했습니다. ''중화비빔면''은 강한 불맛과 함께 채소의 단맛이 조화롭다고 느꼈고, ''중화비빔밥'' 역시 아주 맛있다고 감탄했습니다. 특히 다른 중식당과 달리 먹고 난 후에도 입이 마르거나 짜지 않고 깔끔한 맛이 유지되는 점을 가장 큰 장점으로 꼽았습니다. 정해진 식사 시간 35분을 넘겨 음식을 다 먹지 못하고 포장해 가야 하는 것을 아쉬워했습니다.'),
('영생덕', '대구 중구 종로 39', '053-255-5777', ARRAY['중식'], 'https://www.youtube.com/watch?v=Mm76nsEkOIM', 35.8693928, 128.5913992, '대구광역시', '60년 전통의 중식 만두 전문점으로, 꾼만두, 물만두, 찐교스를 주문함. **꾼만두**는 기름지지 않으면서 겉은 바삭하고 속은 고기 육즙이 풍부하여 최고의 메뉴로 꼽았음. **물만두**는 일반 만두피보다 두꺼워 수제비 같은 식감이 특징이며 육즙이 풍부하다고 평가함. **찐교스**는 은은한 생강 향이 느껴진다고 언급함. 전반적으로 이곳에서만 맛볼 수 있는 특별한 만두라고 평가하며, 특히 만두소와 밀가루 맛이 나지 않는 피를 칭찬함.'),
('삼화만두', '대구 중구 남성로 58-1', '0507-1354-5651', ARRAY['분식'], 'https://www.youtube.com/watch?v=Mm76nsEkOIM', 35.8670763, 128.5930564, '대구광역시', '우리나라 최초로 비빔만두를 개발한 원조집으로, 비빔만두, 찐만두, 쫄면을 주문함. **비빔만두**는 바삭한 만두피와 곱게 다진 부드러운 소가 특징이며, 새콤달콤한 소스와 섞어 먹을 때 훨씬 맛있다고 평가함. 소스는 단맛보다 새콤한 맛이 강해 취향에 맞다고 언급함. **찐만두**는 두부가 많이 들어간 듯 기름기가 거의 없고 아주 부드러우며 담백한 맛이라고 함. 북한식 만두처럼 순한 맛의 만두소가 강한 맛의 비빔 소스와 잘 어울린다고 총평함.'),
('세창만두', '대구 남구 봉덕로12길 6', '053-324-7333', ARRAY['분식'], 'https://www.youtube.com/watch?v=Mm76nsEkOIM', 35.8446455, 128.5969195, '대구광역시', '오래된 동네 맛집 분위기의 분식집으로, 꾼만두, 김치찐만두, 라면을 주문함. **꾼만두**는 튀긴 향이 고소하고, 만두소는 샤오롱바오처럼 촉촉하고 고소함이 강하다고 평가함. 피는 쫄깃하고 바삭하며 할머니가 해주는 손만두 같은 느낌이라고 함. **김치찐만두**는 동그란 모양에 김치 조각이 크게 들어있는 꽉 찬 소가 특징임. 전반적으로 할머니 손맛이 느껴지는 스타일이라 마음에 들었다고 평가함.'),
('전가네김밥천국', '서울특별시 성북구 석관동 261-159', '02-960-0777', ARRAY['분식'], 'https://www.youtube.com/watch?v=1itT_ytJ7Xc', 37.6048917, 127.060218, '서울특별시', '쯔양은 매니저와 매니저의 아버지가 자주 방문하는 단골 맛집이라 기대를 안고 방문했습니다 . 총 10가지 메뉴(주먹밥, 된장찌개, 라볶이, 새우볶음밥, 소고기김밥, 참치김밥, 치즈돈까스, 라면, 치즈제육, 냉면)를 주문했고, 이후 김치볶음밥을 추가했습니다 . 전반적으로 음식의 간이 짜거나 달지 않고 자극적이지 않아서 좋았다고 평가했으며, 어렸을 때 먹던 맛과 비슷하다고 언급했습니다 . 특히 새우볶음밥과 된장찌개를 ''머스트 해브'' 메뉴로 꼽았습니다 . 새우볶음밥은 순한 맛이면서도 후추 향이 나는 중독적인 맛이라고 극찬했고 , 된장찌개는 감자가 잘 익어 아주 맛있다고 했습니다 . 사장님이 추천한 치즈제육은 국물이 많아 두루치기 같은 느낌이며, 짜지 않고 감칠맛이 돌아 밥 없이 먹기에도 좋다고 평했습니다 . 치즈돈까스는 치즈가 풍부하고 소스가 수제 맛이 난다고 했으며 , 라볶이는 양배추에서 단맛이 우러나와 맵고 짠 요즘 떡볶이와 달리 순해서 좋다고 말했습니다 . 소고기김밥에서는 멸치 맛이 나는 독특한 풍미가 느껴져 맛있었다고 합니다 .'),
('스시정', '경기 수원시 팔달구 인계로 126 수원미디어시티 1층', '031-225-5664', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=4vg-3uctgxQ', 37.2671331, 127.0312559, '경기도', '쯔양은 모든 접시가 1,200원이라는 저렴한 가격에 놀라워하며 가성비가 훌륭하다고 평가했습니다. 특히, 저가 초밥집에서는 보기 드물게 기계가 아닌 손으로 직접 쥔 따뜻하고 촉촉한 밥을 사용하는 점을 높이 평가했습니다. 연어 뱃살은 매우 두툼하고 신선하며 입에서 녹는 맛이라고 극찬했고, 가장 기대했던 도미 뱃살은 냄새가 전혀 없고 장어보다 부드럽고 촉촉해 입에서 녹는다고 말했습니다. 또한, 광어 지느러미의 아삭한 식감에 감탄하며 여러 번 추가 주문했습니다. 튀김류는 주문 즉시 튀겨주어 바삭하고 맛있다고 언급했으며, 전반적으로 생선이 신선하고 초밥의 꼬리가 길어 1,200원이라는 가격이 믿기지 않는 퀄리티라고 종합적으로 평가하며 총 101접시를 먹었습니다.'),
('이가바지락손칼국수', '서울특별시 강서구 양천로 460', '02-3661-2077', ARRAY['한식'], 'https://www.youtube.com/watch?v=smlnESe6mGY', 37.5625888, 126.851709, '서울특별시', '쯔양은 이 식당의 대표 메뉴인 4인분 초대왕 바지락 칼국수와 물만두를 먹었습니다. 칼국수에 대해, 국물은 매우 깔끔하면서도 전분 때문에 약간의 점성이 느껴진다고 평가했으며, 후추를 더하면 훨씬 맛있다고 언급했습니다. 자극적이지 않은 옛날 스타일의 칼국수로, 국물이 맛있어서 계속 먹게 된다고 했습니다. 면은 떡처럼 밀도 있고 쫄깃한 식감이며, 두꺼워서 국물이 잘 배지 않으므로 국물과 함께 먹는 것을 추천했습니다. 그릇의 절반을 채울 정도로 많은 양의 바지락은 매우 부드럽고 질기지 않아 맛있다고 칭찬했습니다. 함께 나온 겉절이 김치도 양념이 매우 맛있다고 평가했습니다. 전반적으로 양이 매우 푸짐하고 맛있는 식사였다고 만족감을 표현했습니다.'),
('키이로', '서울 강남구 강남대로 652 신사스퀘어 2층 206호', '0507-1477-1182', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=Op9zNhmj3ok', 37.5196035, 127.0190762, '서울특별시', '쯔양은 1년을 기다려 방문한 곳으로, ''인생 1등 튀김''이라고 극찬했습니다. 튀김 옷을 매번 새로 만들어 매우 얇고 바삭하며, 저온에서 오래 튀겨 속은 부드러운 감자와 고구마에 특히 감탄했습니다. 새우 머리와 뼈 튀김은 과자처럼 맛있었고, 새우, 옥수수, 제철 생선, 연근 등 모든 튀김이 훌륭하다고 평가했습니다. 특히 평소 먹지 않는 채소(당근, 시소)마저 맛있게 먹을 수 있었다고 언급했으며, 이날 먹은 것 중 아스파라거스 튀김이 가장 충격적으로 맛있었다고 말했습니다. 정식 메뉴가 아닌 ''민어 삼계탕''과 새우 머리로 육수를 낸 ''새우 라면''은 각각 진한 국물 맛으로 큰 감동을 주었습니다. 디저트로 나온 1시간 튀긴 고구마와 수제 소금 아이스크림의 조합 역시 전문점보다 맛있다며 전반적으로 모든 요리에 대해 최고의 만족감을 표현했습니다.'),
('모모라면', '인천광역시 미추홀구 석정로150번길 43 새한빌딩', '032-888-7871', ARRAY['분식'], 'https://www.youtube.com/watch?v=SCpmx_9QN0o', 37.4675499, 126.6543713, '인천광역시', '쯔양은 25년 경력의 사장님이 운영하는 인천 제물포의 ''모모라면''을 방문하여 총 10가지의 라면을 맛보았습니다. 모든 라면의 맛이 각기 다르며, 사장님이 직접 개발한 독특한 레시피로 만들어진다는 점에 감탄했습니다. 그중에서도 ''햄피자치즈라면''을 가장 인상 깊은 메뉴로 꼽았는데, 국물 베이스에 모짜렐라 치즈가 들어간 독특한 조합과 고소한 풍미를 극찬했습니다. 또한, 3,500원이라는 저렴한 가격에 계란과 공기밥까지 무료로 제공되는 ''기본라면''의 뛰어난 가성비를 칭찬했으며, ''김치라면''은 해장에 완벽한 맛이라고 평가했습니다. ''얼큰해장라면''은 진한 북엇국 같은 느낌이라고 언급했고, ''매울신신신라면''은 시야가 흔들릴 정도로 매우 강렬한 매운맛이라고 설명했습니다. 쯔양은 저렴한 가격, 푸짐한 양, 그리고 학생들을 위해 가격을 올리지 않는 사장님의 따뜻한 마음에 감동하며 전반적으로 모든 메뉴에 높은 만족감을 표현했습니다.'),
('Pho Toan Thang', '9/95 The Crescent, Homebush West NSW 2140, Australia', '+61 2 9764 3687', ARRAY['아시안'], 'https://www.youtube.com/watch?v=9gVyvPCGQNA', -33.8654786, 151.0710102, '오스트레일리아', '쯔양은 이 식당을 ''30년 단골인 기사님이 추천해준 맛집''으로 소개하며, 호주 총리도 방문한 유명한 곳이라고 언급했습니다. 여러 메뉴를 맛본 후, ''소고기 쌀국수''를 그날의 최고 메뉴로 꼽았습니다. 쌀국수 면이 쉽게 끊어지지 않고 탱탱해서 좋았으며, 국물은 저녁이 될수록 진해지지만 낮에 방문하면 더 깔끔한 맛을 즐길 수 있다고 평가했습니다. 특히, 원래 제공되는 면과 다른, 칼국수처럼 두껍고 부드러운 식감의 면을 맛보고 특별한 경험이었다고 덧붙였습니다. ''크리스피 치킨 볶음밥''은 양이 푸짐하고, 짭짤하면서도 고슬고슬한 밥과 부드러운 닭고기, 바삭한 껍질의 조화가 훌륭하다고 칭찬했습니다. ''시즐링 비프''는 독특한 식감과 한국에서는 맛보기 힘든 향신료가 특징이며, ''소고기 계란면''은 자극적이지 않고 고소해서 중독성이 강하다고 말했습니다. 전반적으로 음식이 짠 편이지만 쉽게 물리지 않으며, 모든 요리가 전문적으로 조리되어 음료까지 맛있었다고 극찬하며 방문을 마무리했습니다.'),
('The Meat & Wine Co Barangaroo', 'Ground level, International Tower One, 100 Barangaroo Avenue, Barangaroo NSW 2000', '+61 2 8629 8888', ARRAY['고기'], 'https://www.youtube.com/watch?v=x8EdsDzKuQk', -33.86549, 151.20147, NULL, '쯔양은 호주에서 먹어본 스테이크 중 최고라고 극찬하며 재방문했습니다. 와규 립아이, 토마호크, 드라이에이징 뉴욕 스테이크 등 총 11가지의 다양한 메뉴를 주문했습니다. 특히 토마호크는 매우 부드럽고 풍미가 진해 가장 맛있다고 평가했습니다. 또한, 냄새가 날 것이라는 편견과 달리 매우 부드럽고 쫄깃한 식감의 캥거루 고기 꼬치에 감탄했습니다. 포크립은 소스가 달지 않고 상큼해서 좋았으며, 비프립은 포크립보다 더 맛있다고 언급했습니다. 연어 꼬치는 입에서 녹는 부드러운 식감을 칭찬했습니다. 전반적으로 고기가 육즙이 많으면서도 느끼하지 않아 부담 없이 즐길 수 있었다고 평가했으며, 디저트도 유명하다고 언급하며 다음 방문을 기약했습니다.'),
('The Boiling Crab Sydney CBD', 'Ground floor/68 Harbour Street, Haymarket, NSW 2000, Australia', '+61 2 9069 5599', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=vZnL1qrf2zs', -33.878308, 151.2034885, '오스트레일리아', '시드니에 방문하면 꼭 가봐야 할 맛집이라는 지인의 추천으로 방문했습니다. 금요일 저녁에는 한 시간 가까이 기다려야 할 정도로 인기가 많은 곳입니다. 쯔양은 뱅인 콤보 2개, 블루 크랩, 브라운 크랩, 스노우 크랩, 크로우피쉬, 랍스터, 보스턴 랍스터, 호주 랍스터 2개, 킹크랩 2개 등 총 10kg에 달하는 엄청난 양의 해산물을 주문했습니다. 다양한 소스 중 클래식한 케이준 소스와 갈릭 소스를 선택했으며, 여러 가지 맵기 단계 중 순한 맛부터 아주 매운맛(XXX)까지 다양하게 맛보았습니다. 새우는 정말 맛있었고, 특히 갈릭 소스에 찍어 먹는 조합을 극찬했습니다. 가장 인상 깊었던 메뉴는 내장이 가득한 ''브라운 크랩''과 살이 매우 부드럽고 달콤했던 ''블루 크랩''을 꼽았습니다. 다만 아주 매운맛은 혀가 아플 정도로 매우니 주의가 필요하다고 언급했습니다. 전반적으로 음식의 비주얼이 화려해 파티나 모임에 잘 어울리며, 보는 즐거움과 먹는 즐거움을 모두 만족시키는 곳이라고 평가했습니다.'),
('George''s Gourmet Pizzeria', '1 Circa Boulevarde, Bella Vista, NSW, 2153, Australia', '+61 2 9836 2711', ARRAY['피자'], 'https://www.youtube.com/watch?v=8Op9zyBztCo', -33.746431, 150.952098, '오스트레일리아', '처음 주문한 거대한 페퍼로니 피자에 대해, 안쪽은 촉촉하고 치즈가 풍부하며 짜지 않고 간이 완벽해 한국인 입맛에 잘 맞는다고 평가했습니다. 두 번째로 먹은 스모크 BBQ 브리스킷 피자는 호주인들이 가장 좋아하는 메뉴 중 하나로, 고기가 듬뿍 올라가 있고 잡내가 전혀 없다고 칭찬했습니다. 다만, 맛이 진하고 무거워 많이 먹기에는 다소 부담스럽다고 덧붙였습니다. 이어서 추천받은 볼로네제 파스타는 면발이 우동처럼 두껍고 쫄깃한 식감이 특징이라고 설명했습니다. 디저트로 주문한 누텔라 피자와 티라미수, 망고 아이스크림도 모두 만족스러워했으며, 특히 망고 아이스크림은 생망고를 그대로 먹는 듯한 맛이라고 극찬했습니다. 전반적으로 챌린지를 위해 방문했지만 음식이 매우 맛있어서 행복하게 식사를 즐겼다고 총평했습니다.'),
('금별맥주 신사역점', '서울 강남구 강남대로152길 20 1층', '0507-1335-5154', ARRAY['야식'], 'https://www.youtube.com/watch?v=Blh_iDc72mI', 37.51739, 127.0211113, '서울특별시', '쯔양은 ''금별맥주''가 자신의 ''최애 맛집'' 중 하나이며 수십 번 방문한 단골이라고 밝혔습니다. 이날 영상은 해당 브랜드의 초대로 6코스 요리를 맛보는 콘텐츠로 제작되었습니다. 쯔양은 이곳의 시그니처인 얼음 생맥주를 특별히 제작된 잔에 마시며 매우 상쾌하고 크리미하다고 칭찬했습니다. 코스 요리로 나온 다양한 메뉴에 대해 상세한 평가를 남겼습니다. 처음 맛본 ''돼지고기 맥앤치즈''는 느끼함을 잡아주는 완벽한 맥주 안주라고 했고, ''트러플 감자전''과 ''보리새우 부추전'' 등 새로운 메뉴도 극찬했습니다. 특히 ''토마토 해장 파스타''는 이곳에 올 때마다 빼놓지 않고 시키는 자신의 최애 메뉴라고 강조하며, 술을 마시면서 동시에 해장되는 느낌이라고 평했습니다. 신메뉴인 ''버터구이 갑오징어''는 최고의 식감을 가졌다고 언급했습니다. 모든 코스 식사를 마친 후, 쯔양은 개인적인 ''TOP 3'' 메뉴로 **''보리새우 부추전'', ''들기름 이나니와 냉우동'', ''빨간 소고기 힘줄 쌀국수''**를 꼽았으며, ''버터구이 갑오징어''를 명예로운 메뉴로 추가 언급했습니다. 전반적으로 메뉴들의 밸런스가 매우 뛰어나고, 술안주로 완벽하다고 총평했습니다.'),
('Elements Smokehouse and Bar', '248 Palmer St, Darlinghurst NSW 2010, Australia', '+61 1300 353 636', ARRAY['고기'], 'https://www.youtube.com/watch?v=mmF70W8acHM', -33.8780186, 151.2167588, '오스트레일리아', '쯔양은 호주 현지에서 처음 맛보는 스테이크로, 전반적으로 건강하고 신선하며 육즙이 풍부한 ''웰니스 스타일''이라고 평가했습니다. 한국에서 먹던 호주산 스테이크보다 신선하고 육즙이 많았으며, 기름기가 적고 담백한 점이 매력적이라고 느꼈습니다. 또한, 친절한 직원들과 활기찬 야외 분위기도 좋았다고 덧붙였습니다. - **주문 메뉴**: 토마호크, 필레미뇽, 포터하우스(티본), 뉴욕 스트립, 립아이, 와규 브리스킷 등 약 4kg에 달하는 스테이크 메뉴 대부분을 주문했습니다. - **맛 평가**: - **뉴욕 스트립**: 가장 맛있었던 부위로 꼽았으며, 부드럽고 고소한 맛이 일품이라고 평가했습니다. 그레인 페드(곡물 사육) 소고기라 더 부드러웠을 것이라고 추측했고, 실제로 맞았습니다. 추가로 한 판을 더 주문할 정도로 만족했습니다. - **립아이**: 매우 부드러워 안심을 먹는 듯한 식감이라고 칭찬했습니다. - **필레미뇽**: 버섯 소스와 함께 먹었을 때, 주스가 넘칠 정도로 붉고 육즙이 풍부했다고 합니다. - **와규 브리스킷**: 양념된 메뉴로, 놀랍게도 한국의 ''국밥 속 고기''와 맛이 똑같다고 표현하며 독특한 감상을 남겼습니다. - **토마호크**: 매우 거대한 크기가 인상적이었으며, 씹는 맛이 좋은 부위라고 설명했습니다. 그래스 페드(목초 사육) 소고기라 근육질의 담백하고 깔끔한 맛이 특징이라고 언급했습니다. - **사이드 및 소스**: 미국에서 먹었던 것만큼 맛있는 감자튀김과 트러플 소스를 특히 선호했으며, 다양한 소스가 제공되어 스테이크와 곁들이기 좋았다고 평가했습니다.'),
('세스크 멘슬', '서울특별시 성동구 성수이로14길 7 1층', '0507-1328-0393', ARRAY['양식'], 'https://www.youtube.com/watch?v=rF2E3zO_LAg', 37.5410636, 127.0564267, '서울특별시', '쯔양은 PD의 강력한 추천으로 ''세스크 멘슬''을 방문했으며, 음식 맛에 크게 감탄했습니다. 특히 PD가 ''인생 최고의 연어''라고 극찬한 통연어에 대해, 짭짤하면서도 고소하고 기름지지만 느끼하지 않으며, 훈연 향과 꾸덕한 식감이 일품이라고 평가했습니다. 다양한 수제 소시지들은 터지는 육즙과 부드러운 식감이 특징이며, 특히 직접 만든 머스타드 소스와의 조화를 칭찬했습니다. 잠봉, 프로슈토 등 여러 종류의 햄 플래터와 함께 버섯 수프, 라구 파스타 등 다른 메뉴들도 맛이 매우 풍부하고 깊다고 언급했습니다. 전반적으로 모든 음식이 와인이나 맥주와 잘 어울리는 맛이며, 분위기 좋은 곳에서 술과 함께 즐기기에 최적화된 장소라고 요약했습니다.'),
('솥뚜껑삼겹살', '인천광역시 서구 서달로137번길 13', '032-582-0647', ARRAY['고기'], 'https://www.youtube.com/watch?v=mn69-hUGKx0', 37.510551, 126.6772911, '인천광역시', '쯔양은 비 오는 날 솥뚜껑 삼겹살이 생각나 맛집을 찾던 중, 한 블로그에서 후식으로 제공되는 ''식혜'' 사진을 보고 이 집을 방문하기로 결심했습니다. 가게에 들어서자마자 사장님의 유쾌한 환대를 받았으며, 곧이어 나온 산더미 같은 김치와 푸짐한 상차림에 감탄했습니다. 특히, 이곳의 ''파김치''는 인생 최고의 맛이라고 극찬하며, 잘 익은 신김치처럼 감칠맛이 폭발한다고 평가했습니다. 총각김치 또한 쓴맛 없이 부드럽고 달콤하며, 사장님이 직접 담근 진한 ''갈치속젓''은 고기의 풍미를 극대화해준다고 말했습니다. 삼겹살은 처음에는 평범하게 느껴졌으나, 잘 구워내니 잡내 없이 쫄깃하고 고소한 맛이 일품이었다고 합니다. 쯔양은 파김치와 총각김치 때문에 인천까지 올 가치가 있다고 말했으며, 식사를 마친 후 ''음식 맛이 정말 경이롭다''며 인천 맛집 리스트에 추가해야 한다고 만족감을 표했습니다.'),
('동춘이만두', '부산 부산진구 당감로25번길 11', '051-896-1869', ARRAY['분식'], 'https://www.youtube.com/watch?v=kgcxjWNkRAU', 35.16405, 129.038944, '부산광역시', '쯔양은 부산 당감동에 위치한 30년 이상 된 로컬 맛집으로, 모든 메뉴가 5,000원이 넘지 않는 가성비가 매우 뛰어난 곳이라고 소개했습니다. 수제비는 국물이 떡국 맛과 비슷하며 완벽하고, 반죽이 쫄깃해서 맛있다고 평가했습니다. 직접 만든 만두는 속이 꽉 차 있고 후추 향과 함께 단맛이 도는 것이 특징이며, 피는 얇은 편이라고 언급했습니다. 비빔 칼국수는 새콤달콤하고 상큼하며, 면이 쫄깃해 쫄면과 비빔냉면을 섞은 듯한 맛이라고 했습니다. 라면은 특별한 비법이 있는 것처럼 맛있다고 감탄했으며, 냉면 역시 국물을 직접 만들어 상쾌하고 달콤한 맛이 난다고 칭찬했습니다. 찐빵은 팥소가 달고 반죽이 쫄깃하다고 평가하며 전반적으로 모든 음식이 맛있고 가격이 저렴해 동네 주민들에게 사랑받을 만한 맛집이라고 총평했습니다.'),
('연지가양곱창', '부산광역시 연제구 반송로 18-6', '051-853-2345', ARRAY['고기'], 'https://www.youtube.com/watch?v=MMnivNofP0M', 35.1867573, 129.0832189, '부산광역시', '쯔양은 이 식당을 ''부산 1등 맛집''이라 극찬하며 인생 최고의 행복한 날 중 하나라고 표현했습니다. 메인 메뉴인 특양 모듬은 잡내가 전혀 없고 질기지 않으며, 부드러우면서도 쫄깃한 식감이 역대 최고라고 평가했습니다. 특히 입안에서 녹아내리는 깨끗하고 고소한 기름 맛에 감탄했습니다. 밑반찬으로 나온 진한 맛의 황태 미역국과 고소한 마 음료, 사장님이 직접 만들어준 비트 소주와 트리플 베리 디저트 등 ''이모카세'' 스타일로 제공되는 모든 음식에 크게 만족했습니다. 또한, 별미인 날치알 김밥은 김이 질기지 않고 밥알이 살아있어 식감이 좋다고 언급했습니다. 전반적으로 음식의 맛, 친절한 분위기, 사장님의 특별한 서비스까지 모든 면에서 완벽에 가깝다고 평가하며, 이 식당 하나만을 위해 부산에 다시 올 의향이 있다고 밝혔습니다.'),
('수변최고돼지국밥 민락본점', '부산 수영구 광안해변로370번길 9-32', '051-754-1115', ARRAY['한식'], 'https://www.youtube.com/watch?v=4Hdavi_3o8I', 35.156747, 129.134285, '부산광역시', '쯔양은 이 식당이 돼지국밥에 익숙하지 않은 초심자나 외국인도 즐길 수 있을 만큼 돼지 특유의 냄새가 거의 없고 국물이 매우 깔끔하면서도 진하다고 평가했습니다. 특히 ''항정국밥''은 국물이 더 진하고 고소하며 고기가 부드러워 개인적으로 가장 마음에 들었다고 언급했습니다. 반면 ''섞어국밥''은 국물이 더 가볍고 깔끔하며, ''순대국밥''의 국물은 약간의 간이 되어있어 그냥 먹어도 좋다고 했습니다. 또한, 수육이 식어도 맛있다고 칭찬하며, 밥을 한 번에 다 넣기보다 조금씩 넣어 먹는 것이 국물 맛을 해치지 않는 팁이라고 전했습니다. 이 식당은 리뷰가 16,000개가 넘고 밤 10시에도 줄을 설 정도로 매우 유명한 곳이라고 소개했습니다.'),
('삼성갈미조개', '부산광역시 강서구 르노삼성대로 602', '051-271-4389', ARRAY['고기'], 'https://www.youtube.com/watch?v=EgQcq1d5Crg', 35.1014925, 128.929203, '부산광역시', '쯔양은 부산 지인에게 ''촬영하지 말고 그냥 가서 먹어보라''는 추천을 받고 이곳을 방문했다. ''갈미조개''라는 이름은 처음 들어봤다고 언급했다. 식당에서는 갈미조개가 낙동강 하구의 기수역에서만 잡히는 자연산이며, 조개가 잡히지 않으면 영업을 하지 않을 정도로 신선함을 강조한다고 설명했다. 주요 메뉴인 ''갈삼구이(갈미조개+삼겹살 구이)''에 대해, 먼저 조개만 먹어본 뒤 ''아삭하고 쫄깃한 식감에 입안에서 육즙이 터진다''며 감탄했다. 삼겹살과 함께 먹으니 훨씬 맛있다고 평가했으며, 특히 조개 자체의 단맛이 매우 뛰어나다고 여러 번 강조했다. 이후 맛본 ''된장찌개''는 일반적인 것과 달리 색이 옅고 조개가 가득 들어있으며, 아주 구수하고 진한 국물 맛이 일품이라고 평했다. 추가로 주문한 ''갈미조개 샤브샤브''는 국물 냄새부터 맛있다고 했으며, 조개의 식감이 ''충격적''일 정도로 훌륭하다고 극찬했다. 다만 오래 익히면 질겨지므로 바로 건져 먹어야 한다고 언급했다. 최종적으로 쯔양은 구이와 샤브샤브 중 하나만 추천하기 어렵다고 했다. ''갈삼구이''는 식감과 조화에 초점을 맞춘 맛이고, ''샤브샤브''는 뜨끈한 국물과 조개 본연의 맛에 집중할 수 있는 메뉴라며 두 가지 모두 각자의 매력이 있어 모두 추천한다고 결론 내렸다.'),
('동삼동불짬뽕', '부산 영도구 동삼남로 21', '051-403-7388', ARRAY['중식'], 'https://www.youtube.com/watch?v=naazmdZLdD4', 35.0778045, 129.0679413, '부산광역시', '쯔양은 1단계부터 4단계까지의 불짬뽕과 탕수육, 군만두를 맛보았습니다. 1단계는 신라면보다 맵고 틈새라면과 비슷한 수준으로, 국물이 깔끔하고 시원해서 맛있다고 평가했습니다. 2단계는 불닭볶음면보다 맵지만 맛있게 매운맛이라고 언급했습니다. 3단계부터는 매운맛이 강해져 국물은 거의 먹지 못했고, 4단계는 입에 넣자마자 고통을 느끼며 눈물을 흘렸지만 면과 해산물은 모두 먹었습니다. 쯔양은 1, 2단계가 가장 맛있었다고 밝혔습니다. 탕수육에 대해서는 독특한 튀김 질감과 소스에 대해 극찬하며 자신의 입맛에 완벽하게 맞는다고 평가했습니다. 군만두는 과자처럼 바삭한 식감이 특징이라고 언급했습니다.'),
('동방밀면', '부산 영도구 꿈나무길 239', '051-416-9592', ARRAY['한식'], 'https://www.youtube.com/watch?v=eCm58sGQM2s', 35.0867092, 129.043431, '부산광역시', '쯔양은 이 식당을 20년 이상 된 영도 주민들의 맛집으로, 누구나 즐길 수 있는 대중적인 맛을 가졌다고 소개했습니다. 특히 양이 매우 많아 ''노가다 밀면''으로 불릴 만큼 가성비가 뛰어나다고 평가했습니다. 물밀면은 한방 향이 거의 없고 면발이 얇아 냉면과 밀면의 중간 느낌이며, 양념 없이 맑은 육수로 먹는 것을 개인적으로 더 선호했는데, 풍부한 육향의 평양냉면에 단맛이 더해진 맛이라고 했습니다. 비빔밀면은 고소한 참기름 향이 나는 맛있는 비빔국수 같다고 표현했습니다. 짜장면은 옛날 짜장의 순한 맛이 특징이며, 밀면과 같은 반죽으로 만든 굵은 면을 사용한다고 언급했습니다. 또한, 여러 잔을 마실 정도로 따뜻한 온육수를 극찬하며, 직접 끓여내어 깊은 맛이 난다고 했습니다.'),
('빨간떡볶이', '부산 해운대구 우동1로20번가길 4', '051-743-2814', ARRAY['분식'], 'https://www.youtube.com/watch?v=9tkT6z80_ro', 35.1652975, 129.1595009, '부산광역시', '어묵 국물에서 무의 시원한 맛이 강하게 느껴져 아주 맛있다고 평가했습니다(2:57). 떡볶이는 새빨간 비주얼과 달리 전혀 맵지 않으며(2:22), 쌀떡임에도 밀떡처럼 부드럽고 쫄깃한 식감이 일품이라고 칭찬했습니다(3:29). 고추장 맛이 진하게 나는 꾸덕하고 진득한 양념이 특징이라고 설명했으며(3:51), 함께 주문한 순대의 간이 신선하고 맛있다고 언급했습니다(4:28).'),
('다리집', '부산 수영구 남천바다로10번길 70', '051-625-0130', ARRAY['분식'], 'https://www.youtube.com/watch?v=9tkT6z80_ro', 35.1468161, 129.1107574, '부산광역시', '떡볶이 국물은 오랫동안 끓여낸 듯한 깊은 맛이 나며, 달콤하면서도 꽤 매운 편이라고 평가했습니다(10:15). 대표 메뉴인 오징어튀김은 튀김옷이 폭신하고 부드러우면서도 바삭한 식감을 가졌고, 안에 들어있는 오징어가 매우 커서 씹는 맛이 좋다고 극찬했습니다(10:44). 함께 먹은 우동은 쫄깃한 면발의 평범한 우동이라고 덧붙였습니다(11:43).'),
('상국이네', '부산 해운대구 구남로41번길 40-1', '0507-1400-9027', ARRAY['분식'], 'https://www.youtube.com/watch?v=9tkT6z80_ro', 35.1619879, 129.1629393, '부산광역시', '떡볶이 소스는 일반적인 떡볶이보다 검붉은 빛을 띠며, 물엿이 들어간 것처럼 걸쭉하고 달콤하면서도 익숙한 맛이라고 평가했습니다(15:27). 이곳의 떡볶이와 김밥의 조합이 매우 훌륭하다고 언급하며, 일부러 라면도 함께 주문했다고 밝혔습니다(17:01). 어묵 국물은 깊은 풍미가 일품이며, 어묵의 크기가 매우 크다고 감탄했습니다(17:27). 마지막으로 세 곳의 떡볶이 맛을 종합하며, 모두 쌀떡을 사용했지만 소스 맛은 각기 다른 개성을 가지고 있으며, 부산 떡볶이는 양념이 진하고 단 것이 특징이라고 총평했습니다(18:47).'),
('털보감자탕', '서울 서초구 나루터로15길 16', '02-515-9535', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=uhPUI60ZnyE', 37.516521, 127.0181832, '서울특별시', '쯔양은 이 식당을 개인적으로 매우 좋아하는 단골 맛집으로 여러 번 방문하고 배달도 시켜 먹었다고 밝혔습니다. 모든 메뉴가 메인 요리 수준으로 맛있다고 평가했으며, 특히 감자탕은 끓일수록 국물 맛이 깊어지고 고기 잡내가 없으며 매우 부드럽다고 극찬했습니다. 보쌈은 겉을 구운 삼겹살처럼 독특한 식감에 고기가 부드러워 입에서 녹는다고 표현했고, 제육볶음은 촉촉하고 부드러운 옛날 맛이 나는 숨겨진 메뉴라고 소개했습니다. 묵은지 김치찜 또한 감자탕과 1, 2위를 다툴 정도로 맛이 뛰어나다고 언급했습니다. 매일 메뉴가 바뀌는 점심 특선 ''불고기 잡채 덮밥''을 먹고는 고정 메뉴가 되었으면 좋겠다고 할 정도로 만족감을 표했습니다. 전반적으로 어린 시절의 추억을 떠올리게 하는 그리운 맛이라고 종합적인 평을 남겼습니다.'),
('야수각', '경기도 수원시 영통구 권선로803번길 6 1층', '0507-1486-9307', ARRAY['중식'], 'https://www.youtube.com/watch?v=820jZBF4eX8', 37.2557493, 127.039206, '경기도', '쯔양은 채소를 잘 먹지 않는 자신과 같은 ''편식러''들을 위한 메뉴인 ''편식 짬뽕''에 큰 호기심을 갖고 식당을 방문했습니다. 건더기 없이 국물과 면만으로 구성된 이 짬뽕에 대해 "딱 내가 좋아하는 스타일"이라며 높은 만족감을 표했습니다. 국물은 시원하고 칼칼하면서도 끝맛은 사골육수처럼 진하고 고소하며, 면발은 매우 쫄깃하다고 평가했습니다. 또한, 6,000원이라는 저렴한 가격과 배달 앱을 통해 차돌박이 같은 원하는 토핑만 골라 추가할 수 있다는 점을 장점으로 꼽았습니다. 함께 주문한 ''야수 간짜장''은 수비드 조리한 고기를 사용한 점이 독특하며, 짬뽕을 먹으러 왔지만 간짜장이 더 맛있다고 극찬했습니다. ''탕수육''은 숙성 반죽을 사용해 바삭하고 쫄깃한 식감이 특징이며, 소스에도 건더기가 없어 주인장의 확고한 요리 철학이 엿보인다고 언급했습니다. 전반적으로 채소를 낭비할 필요 없이 원하는 재료만으로 즐길 수 있는 컨셉이 자신과 같은 사람들에게 완벽한 곳이라고 총평했습니다.'),
('더즌오이스터 한남', '서울 용산구 이태원로54길 63-4', '02-790-0916', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=qh9hJj0hDxg', 37.5355061, 127.0014045, '서울특별시', '쯔양은 여름에도 안전하게 먹을 수 있는 삼배체 굴을 먹기 위해 한남동의 ''더즌오이스터''를 방문했습니다. 생굴은 서해안(태안)과 남해안(강진)에서 온 것으로, 비린내가 전혀 없고 각각 풍부한 감칠맛과 맛있는 맛을 자랑한다고 평가했습니다. 굴의 크기가 주먹만 하고 갤럭시 울트라 핸드폰만큼 크다고 감탄했습니다. 특히 여름 삼배체굴은 살균 처리를 거쳐 겨울 자연산 굴보다 안전할 수 있다고 언급했습니다. 구운 굴, 가리비, 새우 꼬치, 숭어 등이 포함된 플래터와 오징어 먹물 리조또, 감자 100%로 만든 뇨끼 등 다양한 요리를 맛보았습니다. 뇨끼는 밀가루 맛 없이 부드럽게 녹는 식감이라고 극찬했으며, 구운 굴과 뇨끼, 후추 조합을 최고로 꼽았습니다. 전반적으로 내일 또 오고 싶을 만큼 맛있는 곳이라고 평가하며, 시원한 굴과 다양한 요리들에 크게 만족했습니다.'),
('부농정육식당', '서울 송파구 백제고분로28길 29 1층', '02-413-3308', ARRAY['고기'], 'https://www.youtube.com/watch?v=RYLgZz9UKz0', 37.5004, 127.0914076, '서울특별시', '쯔양은 38년 전통의 정육식당으로, 특히 운동선수들에게 인기가 많은 맛집이라고 소개했습니다. 총 3.27kg의 고기를 먹으며 역대 최고 기록을 세웠다고 언급했습니다. - **한우 (Hanwoo/Korean Beef)**: 전반적으로 고기 질이 매우 뛰어나다고 평가했습니다. 육사시미는 부드러우면서도 씹는 맛이 일품이라고 했고, 등심은 육즙과 풍미가 폭발적이라고 극찬했습니다. 특히 차돌박이는 쫄깃한 식감과 고소함이 특징이며, 김치와 함께 구워 먹는 조합을 최고로 꼽았습니다. 다양한 특수부위(치마살, 안창살, 살치살 등) 역시 각각의 독특한 식감과 맛을 즐겼습니다. - **돼지고기 (Pork)**: 목살이 퍽퍽하지 않고 매우 쫄깃하며, 삼겹살과의 조화가 좋다고 평가했습니다. - **사이드 메뉴 (Side Dishes)**: 거의 모든 테이블에서 주문하는 ''소고기 된장라면''은 단백질 섭취 후 즐기는 탄수화물 조합으로 필수 주문 메뉴라고 강조했으며, 매우 쫄깃하고 맛있다고 했습니다. 마지막에는 남은 육회를 이용해 직접 육회비빔밥을 만들어 먹기도 했습니다. 쯔양은 전반적으로 고기 자체의 맛이 매우 뛰어나 소금만 살짝 찍어 먹는 것을 추천했으며, 와사비를 곁들이면 느끼함을 잡아주어 좋다고 덧붙였습니다. 이곳은 저녁 6시부터 대기 줄이 생길 정도로 인기가 많다고 전했습니다.'),
('이조순대국', '서울 용산구 원효로41길 54 1층', '02-717-3387', ARRAY['한식'], 'https://www.youtube.com/watch?v=YvM-mTNwFaQ', 37.5352371, 126.9603065, '서울특별시', '쯔양은 새벽 5시에 방문하여 순대국과 내장탕으로 식사를 시작했습니다. 국물에 대해 잡내가 전혀 없고 아주 진하면서도 깔끔한 맛이라고 극찬했으며, 건더기가 70%를 차지할 정도로 양이 매우 푸짐하다고 감탄했습니다. 특히 이 집의 메인 메뉴로 목살수육을 꼽으며, 족발 같은 비주얼과 달리 살코기는 매우 부드럽고 비계는 쫀득한 식감이 일품이라고 평가했고, 지금까지 먹어본 수육 중 최고라고 말했습니다. 편육은 술안주로 제격이라고 언급했으며, 그 외에 머리고기, 오소리감투, 김치순대국 등 다양한 메뉴를 맛보며 모든 음식이 맛있다고 만족감을 표했습니다. 특히 새벽 2시부터 준비하는 사장님의 정성에 감동하며 음식의 맛을 더욱 높게 평가했습니다.'),
('내고향강원도', '인천광역시 중구 연안부두로75번길 27-2', '032-883-4543', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=gE6KJbIpj2k', 37.4523317, 126.6009554, '인천광역시', '쯔양은 6년 만에 재방문한 식당의 60첩 반상에 대해 전반적으로 매우 만족했습니다. 끝없이 나오는 음식의 양과 다양성에 연신 놀라움을 표하며 ''도전 먹방''이라고 칭했습니다. 특히, 수많은 가짓수에도 불구하고 모든 해산물이 신선하고 품질이 좋다는 점을 높이 평가했습니다. 가장 맛있었던 메뉴로는 꽃게찜을 꼽았고, 살아있는 랍스터와 게를 바로 쪄주는 방식에 감탄하며 가성비가 훌륭하다고 언급했습니다. 그 외에도 전복 내장죽의 고소한 맛, 푸짐한 알밥, 식감이 좋은 각종 활어회(농어, 광어)와 해산물(가리비, 전복, 낙지)에 대해 긍정적으로 평가했습니다. 다만, 해삼은 좋아하지 않는다고 언급했습니다. 쯔양은 이곳이 가족 외식이나 회사 회식, 그리고 다양한 한국 해산물을 경험하고 싶은 관광객에게 완벽한 장소라고 추천하며 영상을 마무리했습니다.'),
('중화요리 정궁', '서울 동대문구 약령시로 116', '02-963-4210', ARRAY['중식'], 'https://www.youtube.com/watch?v=wn-uL7ColtY', 37.5829358, 127.0428817, '서울특별시', '쯔양은 30년 전통의 이 식당을 방문하여 여러 메뉴를 맛보았습니다. 대표적으로 직접 비벼 먹는 독특한 스타일의 ''김치볶음밥''은 진한 불맛과 감칠맛이 폭발적이며, 계란 노른자와 섞으면 맛이 한층 더 풍부해진다고 평가했습니다. ''깐쇼새우''는 주인장이 추천한 메뉴로, 완벽한 양념과 통통한 새우에 감탄하며 그날의 1등 메뉴로 꼽았습니다. 옛날식 ''짜장면''은 감칠맛이 좋고 면발이 쫄깃하며, ''짬뽕''은 해물 기반의 맑고 시원하면서도 칼칼한 국물이 일품이라고 했습니다. 처음 보는 비주얼의 ''냉짬뽕''은 말로 표현하기 힘든 특별한 별미라고 극찬했으며, ''탕수육''은 소스의 균형이 완벽하고 튀김옷이 과자 같아 찍어 먹기 좋다고 평했습니다. 전반적으로 모든 음식의 양이 푸짐하고 맛이 뛰어나 매우 만족스러운 식사였다고 총평했습니다.'),
('돈파치', '3 Chome-17-15 Chiyoda, Naka Ward, Nagoya, Aichi 460-0012, Japan', '+81-52-331-0546', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=mb8OV1knYeo', 35.1547551, 136.913573, '일본', '나고야 현지인이 추천한 47년 전통의 맛집으로, 문 열자마자 만석이 될 정도로 인기가 많다고 합니다. 대표 메뉴인 미소카츠는 한국의 된장과 다른 달콤하고 부드러운 맛의 된장 소스가 특징이며, 처음 맛보는 특별한 맛이라고 극찬했습니다. 특히 두툼한 등심 카츠가 육즙이 많고 부드러워 가장 맛있었다고 평가했습니다. 안심 카츠와 규카츠도 맛있었지만 등심 카츠를 최고로 꼽았습니다. 이 외에도 함박스테이크는 입에서 녹을 정도로 부드럽고, 간장 소스로 구운 등심구이도 맛있게 먹었습니다. 방문한 모든 가게 중 특히 이곳이 가장 마음에 들었다고 언급하며 나고야 방문 시 된장 요리를 꼭 먹어보라고 추천했습니다.'),
('Niisuzume Honten', '2-30-12 Osu, Naka Ward, Nagoya, Aichi Prefecture, Japan', '0522217010', ARRAY['카페·디저트'], 'https://www.youtube.com/watch?v=8YSYlNg1AE4', 35.1586514, 136.9013692, '일본', '미타라시 당고와 키나코 당고를 하나씩 먹었습니다. 미타라시(간장) 맛은 짜면서도 너무 달지 않고 구운 맛이 일품이라고 평가했습니다. 키나코(콩고물) 맛은 아주 달다고 하며, 두 맛의 ''단짠'' 조화가 좋다고 언급했습니다. 이전에 먹었던 다른 당고와는 달리 정말 맛있어서 사람들이 왜 줄을 서는지 알겠다고 극찬했습니다.'),
('Naruto Taiyaki Honpo Osu Niomon-dori store', '3-chōme-21-47 Ōsu, Naka Ward, Nagoya, Aichi 460-0011, Japan', '+81 52-262-0544', ARRAY['카페·디저트'], 'https://www.youtube.com/watch?v=8YSYlNg1AE4', 35.1597781, 136.9044029, '일본', '고구마 타이야끼와 커스터드 타이야끼를 먹었습니다. 빵의 껍질이 아주 얇고, 쫄깃하거나 바삭하기보다는 푹신한 식감이라고 설명했습니다. 커스터드 맛이 더 맛있어 보이고 실제로도 더 맛있다고 평가했습니다.'),
('김복남맥주 구의점', '서울 광진구 자양로18길 49 2층', '0507-1365-0687', ARRAY['야식'], 'https://www.youtube.com/watch?v=UpXae60ZpAE', 37.5381506, 127.0862191, '서울특별시', '쯔양은 ''김복남맥주''가 가성비가 뛰어나고 소셜 미디어에서 유명한 술집이라고 소개했습니다. 10가지 안주 먹기 도전을 진행하며, 모든 메뉴의 양이 매우 푸짐했지만 음식이 다양하고 맛있어 예상보다 수월하게 성공했다고 평가했습니다. 시그니처 메뉴인 ''눈꽃 어니언 치킨''은 옛날에 먹던 부드러운 치킨 맛이라고 칭찬했고, ''우삼겹 떡볶이''는 강한 불향과 매콤한 맛이 인상적이라고 언급했습니다. ''치즈 계란말이''는 매운 떡볶이와 잘 어울리는 조합이라고 평했습니다. 이외에도 ''불왕 돈까스'', 쫄깃한 ''클래식 족발'', 바삭한 ''먹태'' 등 다양한 안주를 맛보며 모두 맥주와 잘 어울린다고 말했습니다. 특히 여름 신메뉴로 나온 ''국물닭발'', ''한치물회'', ''나초치킨플래터''는 시원한 맥주와 완벽한 조합이라고 추천했습니다. 맥주에 대해서는 ''눈꽃 생맥주''가 뼛속까지 시원하게 만들고, ''김복남 수제맥주''는 오렌지향이 나며 목 넘김이 부드럽다고 극찬했습니다.'),
('Yanagiya', '573-27 Suechomashizume, Mizunami, Gifu 509-6361, Japan', '+81-572-65-2102', ARRAY['고기'], 'https://www.youtube.com/watch?v=pUo73nxPUek', 35.3174667, 137.3432468, '일본', '쯔양은 나고야에서 1시간 반 떨어진 기후현 미즈나미의 79년 전통 이로리야키 맛집 ''야나기야''를 방문했습니다. 이곳은 미슐랭 2스타를 받은 유명한 곳으로, 예약을 통해 방문했으며 전체적인 분위기와 경험에 매우 만족했습니다. 그녀는 20만 원 상당의 코스 요리를 맛보았으며, 맛보지 못했던 새로운 맛의 세계를 경험했다고 극찬했습니다. 주요 메뉴와 평가는 다음과 같습니다: - **벌 유충 조림**: 생강을 싫어함에도 불구하고 은은한 생강 향이 나는 달콤한 맛이 좋았다고 평가했습니다. - **멧돼지 고기**: 처음 먹어보았지만 잡내가 전혀 없었다고 합니다. - **아마고(Amago) 구이**: 통째로 먹을 수 있을 만큼 껍질이 부드럽고 아주 맛있다고 감탄했습니다. - **오리 껍질과 파 꼬치**: 파는 달고 오리 껍질은 쫄깃하며, 훈연 향이 더해져 달고 고소한 맛이 일품이었다고 합니다. - **사슴 안심**: 양고기만큼 강하지 않으면서 소고기보다는 진한, 독특하고 맛있는 향이 특징이었고 잡내가 전혀 없었습니다. - **오리 가슴살**: 매우 부드럽고 촉촉하게 요리되어 맛있다고 칭찬했습니다. - **멧돼지 등심**: 일반적인 멧돼지고기와 달리 잡내 없이 매우 부드러웠으며, 특히 비계의 고소한 맛이 행복감을 준다고 했습니다. - **사슴 등심**: 6년 숙성된 고급 와사비와 곁들여 먹었으며, 사슴고기 특유의 향이 좋았다고 합니다. - **이로리 나베(오리 전골)**: 감자로 착각했던 토란이 매우 맛있었고, 새로운 맛의 발견이었다고 즐거워했습니다. 쯔양은 전반적으로 가격이 비싸지만, 맛과 경험 모든 면에서 만족스러운 식사였다고 총평했습니다.'),
('정낙원 (正楽園)', '1-chōme-4-28 Shin Sakae, Naka Ward, Nagoya, Aichi 460-0007, Japan', '+81-52-261-2915', ARRAY['고기'], 'https://www.youtube.com/watch?v=2iLC-idpf28', 35.1694363, 136.9121868, '일본', '나고야 현지 택시 기사가 추천한 44년 전통의 야끼니꾸 맛집으로, 관광객보다는 현지인에게 유명한 곳입니다. 쯔양은 총 21인분의 고기를 주문했으며, 다양한 부위를 맛보았습니다. 특히 우설(소혀)은 잡내가 전혀 없고 식감이 좋아 놀라워했고, 가장 인기가 많다는 우위(미노)는 얇게 썰어 나와 쫄깃하고 오독한 식감이 일품이라고 평가했습니다. 가장 비싼 안심은 입에서 녹는다는 표현을 사용하며 부드러움을 극찬했습니다. 쯔양은 전반적으로 음식이 맛있고 술과 잘 어울린다며, 특히 우설과 안심, 국밥을 인상적인 메뉴로 꼽으며 만족스러운 식사였다고 총평했습니다.'),
('Sushi Honke Kanayama Ten (寿司本家 金山店)', '1-2-18, Kanayama-cho, Atsuta-ku, Nagoya, Aichi 456-0002, Japan', '+81-52-681-0041', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=lZIfcL_pJSU', 35.1415253, 136.9010317, '일본', '쯔양은 70년 전통의 게 전문점 ''카니혼케''가 운영하는 이 회전초밥집에서 총 101접시를 먹으며 만족감을 표했습니다. 주문 즉시 만들어주는 신선한 스시 시스템을 칭찬했으며, 100엔대 저가 스시부터 900엔대 고급 스시까지 다양한 메뉴를 맛봤습니다. 특히 ''게 내장 군함말이''는 비린 맛 없이 매우 고소하고 감칠맛이 뛰어나 그날의 베스트 메뉴로 꼽으며 6접시나 먹었습니다. 또한, 보통 굴의 3배 크기인 ''굴 튀김'', 푸딩처럼 부드러운 ''게살 계란찜'', ''인생 최고의 생선''이라 극찬한 ''줄무늬 전갱이'', 상큼한 유자향이 나는 ''게두부'' 등을 추천했습니다. 이 외에도 ''지방이 많은 참치'', ''오지상(수염대구)'', ''흑돔 아부리'', ''가다랑어'' 등 다양한 스시를 맛보며 각각의 식감과 맛에 대해 긍정적으로 평가했습니다.'),
('すし本家 かなやま', '1 Chome-2-18 Kanayamacho, Atsuta Ward, Nagoya, Aichi 456-0002, Japan', '+81-52-681-0041', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=UeNIHU29oq0', 35.1420428, 136.9016352, '일본', ''),
('원조엄마네', '경기 수원시 팔달구 팔달문로 19 지동시장 지동순대타운', '031-253-5210', ARRAY['한식'], 'https://www.youtube.com/watch?v=nQCE5_KIkIU', 37.2779032, 127.0196088, '경기도', '쯔양은 순대곱창볶음이 볶음보다는 국물이 넉넉한 전골에 가깝다고 평가했습니다. 처음에는 감자탕과 비슷한 순한 국물 맛이 나지만, 끓일수록 진한 곱창전골 맛으로 변한다고 언급했습니다. 특히 돼지 잡내가 전혀 없고 고소하며, 들깨가루와 깻잎의 향이 일품이라고 칭찬했습니다. 순대는 잡내 없이 쫄깃하고, 곱창은 부드러우면서도 쫄깃한 식감이 살아있다고 평가했습니다. 또한, 사장님을 제외한 모든 것이 리필되는 푸짐한 인심과 서비스(음료, 슬러시 무료)에 감탄하며 시장 특유의 정겨운 분위기를 좋게 평가했습니다.'),
('동떡이아주대점', '경기 수원시 영통구 아주로 22', '031-215-0208', ARRAY['분식'], 'https://www.youtube.com/watch?v=rTWmz8FmP-c', 37.2767925, 127.0441253, '경기도', '쯔양은 이곳이 아주대학교 학생들의 추억이 깃든 장소라고 소개하며 부대떡볶이 4인분을 다양한 사리와 함께 주문했습니다. 음식이 나오자 ''도전 먹방'' 수준의 엄청난 양에 놀라워했습니다. 김말이 튀김은 어릴 적 먹던 추억의 맛이라고 했고, 떡은 매우 부드럽고 말랑말랑하다고 평가했습니다. 부대떡볶이의 소시지는 쫄깃하고 맛있으며, 함께 시킨 순대는 위에 뿌려진 들깨가루가 고소한 맛을 더해 잘 어울린다고 칭찬했습니다. 식사 마무리로 먹은 치즈 볶음밥은 떡볶이 국물의 강한 맛 대신 치즈의 영향으로 고소하고 부드러운 맛이 인상적이라고 평했습니다. 쯔양은 오랜만에 학교 앞에서 먹어서 그런지 음식이 특히 더 맛있게 느껴졌다고 총평을 남겼습니다.'),
('풍년식당', '충북 충주시 동량면 조동2길 88', '043-851-7727', ARRAY['중식'], 'https://www.youtube.com/watch?v=NGJEJvELysU', 37.0287456, 127.9690214, '충청북도', '36시간의 공복 후 첫 식사로 짜장면, 짬뽕, 탕수육을 주문했습니다. 쯔양은 짜장면이 옛날 짜장 맛으로 고소하고 맛있다고 평가했습니다. 짬뽕은 일부 후기에서 ''너구리 라면'' 맛과 비슷하다고 묘사되며, 후추 맛이 강하고 배추가 들어가 단맛이 느껴지는 걸쭉한 고기 국물 베이스의 짬뽕입니다. 쯔양은 오랜 공복 상태였기 때문에 모든 음식을 매우 맛있게 먹었습니다.'),
('반월소바', '충남 논산시 해월로 132', '041-733-2210', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=DQWFNnQ5oDA', 36.2029392, 127.0824855, '충청남도', '쯔양은 이 식당이 가성비와 양으로 유명하다고 언급했습니다. 차가운 메밀소바에 대해서는 국물이 약간 달지만 맛있고, 전체적으로 맛의 균형이 잘 잡혀있다고 평가했습니다. 면은 부드럽고 매끈하며, 와사비를 약간 넣었을 때의 절묘한 맛을 칭찬했습니다. 치즈돈까스는 치즈가 풍부하고 소스가 새콤하며, 바삭함과 부드러운 식감이 공존한다고 말했습니다. 매운 돈까스는 매우 맵지만 고기가 부드럽고 맛있다고 평가했으며, 개인적으로는 일반 돈까스를 더 선호한다고 덧붙였습니다. 따뜻한 온면은 차가운 소바와는 다른 매력이 있으며 국물이 짭짤하다고 언급했습니다. 전반적으로 모든 메뉴가 가성비가 좋고 맛있어서 매우 만족스러운 식사였다고 총평했습니다.'),
('은희네순대', '충남 논산시 노성면 노성로 576', '041-734-6009', ARRAY['한식'], 'https://www.youtube.com/watch?v=p7kzlaHAuQA', 36.2762154, 127.1300664, '충청남도', '쯔양은 이전에 논산 딸기 홍보 촬영 후 우연히 방문했다가 음식 맛에 반해 재방문했다고 밝혔습니다({ts:43-ts:56}). 그는 모든 메뉴가 맛있다고 극찬하며, 특히 ''막창구이''를 인생 막창이라고 칭했습니다. 막창은 별다른 소스 없이 쌈장만 찍어 먹어도 될 정도로 매우 고소하다고 평가했습니다({ts:514-ts:520}). ''순대국''은 소 무릎뼈로 우려낸 맑고 깊은 국물이 특징으로, 평양냉면처럼 자극적이지 않고 깔끔한 맛이라고 설명했습니다. 직접 만든다는 ''순대수육''은 잡내가 전혀 없고 식감이 훌륭하며, 족발 또한 직접 삶아 깊은 맛이 난다고 언급했습니다. 전반적으로 ''말이 필요 없는 맛''이라며, 다음에 다시 방문해 막창과 소주를 함께 즐기고 싶다는 의사를 밝혔습니다.'),
('황금곱창 본점', '인천 계양구 아나지로 185', '032-204-7796', ARRAY['고기'], 'https://www.youtube.com/watch?v=HfyEbRuIXBU', 37.5255007, 126.7124272, '인천광역시', '쯔양은 인천 계양구에 위치한 ''황금곱창''을 방문하여 약 33.3인분의 한우 곱창을 먹었습니다. 그녀는 이곳의 곱창이 자르지 않은 통째로 제공되는 점과 높은 평점을 보고 찾아왔다고 밝혔습니다. 곱창에서 독특하게 마늘빵 같은 향이 난다고 평가했으며, 곱이 가득 차 터져 나올 정도라고 감탄했습니다. 질기거나 고무 같지 않고 쫄깃한 식감이 훌륭하며, 특유의 양념 맛이 좋아 소스 없이도 맛있다고 말했습니다. 특히 잡내가 없고, 바삭하게 구워 깻잎과 부추를 곁들여 먹는 조합을 추천했습니다. 식사 후반에는 곱창전골과 볶음밥까지 완벽한 마무리였다고 극찬하며, 활기찬 식당 분위기에도 만족감을 표했습니다.'),
('앤티앤스 롯데아울렛 구리점', '경기도 구리시 동구릉로136번길 47 롯데아울렛 구리점 6층', '031-8034-2617', ARRAY['카페·디저트'], 'https://www.youtube.com/watch?v=6OX0oBeqjJU', 37.6118666, 127.1405479, '경기도', '쯔양은 앤티앤스로부터 2kg짜리 초대왕 프레즐, 핫도그 8개, 다양한 맛의 프레즐 스틱, 5L 레몬에이드 등을 제공받아 먹방을 진행했습니다. 그녀는 갓 나온 프레즐의 쫄깃하고 고소한 맛에 감탄했으며, 특히 ''아몬드 크림치즈 스틱''이 매우 맛있다고 칭찬했습니다. 핫도그는 여러 종류를 맛보았으며, 소시지의 풍부한 육즙과 쫄깃한 빵의 조화가 훌륭하다고 평가했습니다. 영상 내내 음식의 크기와 양에 놀라면서도 모든 메뉴를 맛있게 즐기는 모습을 보였고, 전반적으로 앤티앤스 제품의 맛과 다양성에 대해 큰 만족감을 표현했습니다.'),
('CU 왕산마리나점', '인천 중구 왕산마리나길 143', '1577-8007', ARRAY['분식'], 'https://www.youtube.com/watch?v=G_9WMI0PNas', 37.4577046, 126.357802, '인천광역시', '쯔양은 라면을 매우 좋아하여 인천 왕산마리나에 위치한 ''라면 라이브러리''에 큰 기대를 안고 방문했다. 100가지가 넘는 라면 종류에 감탄하며, 즉석에서 한강 스타일로 라면을 끓여 먹을 수 있는 점을 장점으로 꼽았다. 그녀는 총 10가지 종류의 라면을 시식하고 나머지는 집으로 가져갔다. 각 라면에 대한 평가는 다음과 같다: - **팔도 짜장면**: 모든 짜장 라면 중 가장 좋아하며, 실제 짜장면과 가장 맛이 흡사하다고 평가했다. 두꺼운 면발과 액상 소스가 실제 짜장면의 느낌을 잘 살린다고 말했다. - **신라면 툼바**: 우유를 넣고 끓인 크림 파스타 라면과 맛이 비슷하지만 더 짜고 감칠맛이 강하며, 중독성이 있다고 언급했다. - **감자면**: 오랜만에 먹어보니 정말 맛있다며, 쫄깃한 면을 좋아하는 사람에게 강력 추천했다. - **미고랭 엑스트라 핫 스파이시**: 한국의 매운 라면과는 다른 향의 매운맛으로, 기침이 절로 나오며 기관지가 매운 느낌이라고 표현했다. - **생생우동**: 어릴 때부터 가장 좋아했던 라면으로, 오랜만에 먹어도 여전히 맛있다고 하며 어릴 적 추억의 맛을 높이 평가했다. - **간짬뽕**: 다른 라면에서는 찾아볼 수 없는 독보적인 해물 맛을 가졌다고 설명했다. - **점보 도시락**: 한강 라면처럼 꼬들꼬들한 면발이 특징이며, 국물은 컵라면과 비슷하지만 특유의 향은 덜하다고 느꼈다. - **김치 사발면**: 국물은 김치찌개처럼 새콤하지만, 맛이 면에 잘 배지 않는다고 평했다. - **채식주의 순**: 계란을 넣어 먹었으며, 5분 가까이 끓여도 면이 불지 않는 점을 특징으로 꼽았다. - **불닭 로제**: 먹어보지 않았던 유일한 불닭 시리즈로, 까르보 불닭과 비슷하면서도 다른 맛이라고 간단히 언급했다. 전반적으로 한적한 평일에 방문하여 여유롭게 라면을 즐기고 드라이브하는 코스를 추천하며 만족스러운 식사를 마쳤다.'),
('프랭크버거 인천검단점', '인천광역시 서구 완정로 18', '032-562-1110', ARRAY['패스트푸드'], 'https://www.youtube.com/watch?v=RtD8v_zCjuY', 37.595102, 126.6721924, '인천광역시', '쯔양은 프랭크버거를 ''배달 앱의 왕''이라 부를 정도로 즐겨 먹는다고 밝혔으며, 이날 셰프가 만들어주는 버거에 대한 기대감을 표현했습니다. 총 17개의 버거와 다양한 사이드 메뉴를 먹으며 상세한 리뷰를 남겼습니다. ### 신메뉴 ''쿡락 버거'' 시리즈 리뷰 * **치즈도넛 비프 버거:** 바질 마요와 발사믹 소스 덕분에 마치 카프레제 샐러드를 먹는 것처럼 맛이 풍부하다고 평가했습니다. 특히 느끼하지 않고 깔끔해서 입가심하는 느낌이라며 마지막 버거로 다시 선택했습니다. * **어니언탑 비프 버거:** 강한 후추 향과 딜 허브 소스의 조화가 완벽하다고 극찬하며, 셰프와 함께 ''원픽''으로 꼽았습니다. * **해쉬 비프 버거:** 신선하고 고소하면서도 느끼하지 않아 많이 먹을 수 있을 것 같다고 말했습니다. * **크리스피 카츠 버거:** 육즙이 풍부하게 잡혀있어 매우 촉촉하고, 달콤한 소스와 치즈의 단짠 조합이 일품이라고 평가했습니다. ### 기존 메뉴 및 기타 * **머쉬룸 크림 스테이크 버거:** ''입에 행복을 가져다주는 맛''이라며 감탄했고, 촉촉한 버섯 수프 같은 크림소스를 칭찬하며 추가로 주문하기도 했습니다. * **치킨 버거 & K-불고기 버거:** 크리스피 치킨 버거는 매콤하고 육즙이 많다고 했으며, K-불고기 버거는 달고 짠 소스가 맛있다고 언급했습니다. * **총평:** 프랭크버거의 특징으로 쫄깃한 번을 꼽았으며, 특히 신메뉴 시리즈는 일반적인 패스트푸드를 넘어 ''셰프가 만든 요리'' 같다는 인상을 받았다고 호평했습니다.'),
('88포장마차 옥암점', '전남 목포시 원형로 13', '0507-1419-8251', ARRAY['야식'], 'https://www.youtube.com/watch?v=0ykT2jWpwVk', 34.7978751, 126.4312357, '전라남도', '쯔양은 목포 88포장마차 옥암점에서 생소한 메뉴인 생닭발과 생똥집을 중심으로 다양한 안주를 맛보았습니다. 처음에는 생소함에 걱정했지만, 생똥집은 잡내 없이 고소하며 유쾌, 회, 소 생간을 합친 듯한 식감이라고 극찬했습니다. 특히 김밥에 생똥집을 올려 먹는 조합을 추천받아 맛있게 먹었습니다. 생닭발은 독특한 식감이 있지만, 양념 맛이 회무침과 비슷하고 맛있다고 평가했습니다. 그 외에도 함께 주문한 익힌 닭똥집, 딱돔구이, 김밥, 간재미무침 등 모든 음식이 맛있다고 언급했으며, 포장마차의 활기찬 분위기와 지역 소주인 ''잎새주''와의 궁합을 즐겼습니다. 전반적으로 음식, 분위기, 술 모두에 크게 만족하며, 특히 생똥집과 생닭발이라는 특별한 메뉴에 대한 긍정적인 경험을 상세히 공유했습니다.'),
('성식당', '전남 목포시 수강로4번길 6', '061-244-1401', ARRAY['고기'], 'https://www.youtube.com/watch?v=5-QUaEhtAvA', 34.785635, 126.3865022, '전라남도', '쯔양은 65년 전통의 이 식당에서 떡갈비 3.6kg(8인분)을 주문했습니다. 그는 떡갈비가 다진 고리가 아닌 큼직하게 썬 갈빗살을 뭉쳐 만들어 독특한 식감을 가졌으며, 석쇠에 구워 불향이 살아있다고 평가했습니다. 특히 고기가 두툼하고 육즙이 풍부하며, 일반적인 떡갈비와 달리 갈비 자체의 식감이 살아있어 매우 맛있다고 극찬했습니다. 함께 나오는 곰탕 국물과 다양한 밑반찬과의 조화도 훌륭하다고 언급했습니다.'),
('논산 딸기축제 길거리음식', '충청남도 논산시 시민로 270', '041-746-8386', ARRAY['분식'], 'https://www.youtube.com/watch?v=EqEwDztxHRo', 36.1909538, 127.0951436, '충청남도', '쯔양은 논산 딸기축제에서 다양한 딸기 활용 음식을 맛보았다. ''딸기 초코파이''는 부드러운 빵과 맛있는 크림의 조화를 칭찬했으며, ''딸기 식혜''는 일반 식혜와 다른 새콤한 맛이 특징이지만 맛있다고 평가했다. ''두바이 딸기''는 바삭한 식감과 맛의 조합이 훌륭하다고 언급했다. ''딸기 핫도그''는 반죽에서 나는 딸기 맛이 신기하고 푹신해서 맛있다고 했고, ''딸기 떡볶이''는 은은한 딸기 향이 느껴지는 점을 긍정적으로 평했다. ''딸기 비빔밥''은 딸기 고추장을 사용해 새콤한 맛이 나며 맛있다고 했지만, 밥과 생딸기는 따로 먹는 편이 낫다는 팁을 주었다. 전반적으로 딸기를 이용한 창의적인 길거리 음식들에 대해 신기해하며 대부분 맛있게 즐기는 모습을 보였다.'),
('당진제일꽃게장', '충남 당진시 백암로 246', '041-353-6379', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=iwf7uuKMqYw', 36.8919538, 126.6253115, '충청남도', '쯔양은 이 식당의 음식에 대해 극찬을 아끼지 않았습니다. 특히 ''간장게장''은 전혀 짜지 않고 단맛이 돌며, 살과 내장, 주황빛의 알이 가득 차 있어 역대급이라고 평가했습니다. 비린 맛이 전혀 없고 신선함이 특징이라고 여러 번 강조했으며, 밥 없이도 많이 먹을 수 있을 정도라고 했습니다. ''꽃게탕'' 역시 국물이 매우 진하고 시원하며, 탕에 들어간 게에도 알이 꽉 차 있는 점에 감탄했습니다. 게딱지에 밥과 날달걀 노른자, 김, 참기름 등을 넣어 비벼 먹는 비빔밥은 최고로 맛있는 밥이었다고 말했습니다. 쯔양은 가게의 신기록을 세웠을 정도로 만족스러운 식사를 했으며, 인생 게장, 꽃게탕이라고 평가했습니다.'),
('노가네우동', '서울 영등포구 도신로 223-2', '02-831-0456', ARRAY['분식'], 'https://www.youtube.com/watch?v=YxPnR4idxN0', 37.5121827, 126.9158569, '서울특별시', '쯔양은 길을 지나가다 풍기는 냄새에 이끌려 가게에 방문했다고 밝혔습니다. 이곳은 포장마차로 시작해 자리 잡은 오래된 맛집으로, 저렴한 가격에 엄청난 양의 음식을 제공하는 것이 가장 큰 특징이라고 언급했습니다. 우동은 양이 일반 가게의 두 배에 달하며 면발이 매우 쫄깃하고, 국물은 묽지 않고 진한 편이라고 평가했습니다. 짜장면은 자극적이지 않고 고소한 맛이 특징이며, 김치와 잘 어울린다고 말했습니다. 짬뽕은 해산물이 푸짐하게 들어있고, 뼈 육수가 아닌 맑고 개운한 국물이 해장에 좋을 것 같다고 평가했습니다. 특히 해물 우동은 진한 우동 국물과 해산물의 감칠맛이 어우러져 가장 마음에 들었던 메뉴로 꼽았으며, 여름 메뉴인 비빔밀면 또한 매우 맛있다고 극찬했습니다. 전반적으로 가성비가 매우 훌륭하고 사장님이 친절하며, 다시 방문하고 싶은 맛집이라고 총평했습니다.'),
('쇼미더크랩 압구정점', '서울 강남구 압구정로28길 22-6 1층', '0507-1385-4728', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=6sYv8CqGvFo', 37.5252911, 127.0270477, '서울특별시', '쯔양은 과거 미국에서 맛있게 먹었던 보일링크랩을 잊지 못해 한국에 개점한 이곳을 방문했습니다. ''패밀리 사이즈'' 두 개에 킹크랩, 랍스터, 대게 등을 추가로 주문해 엄청난 양의 해산물 먹방을 선보였습니다. 기본으로 제공되는 샐러드, 마늘 파스타, 계란 볶음밥부터 훌륭한 맛이라고 평가했으며, 메인 메뉴인 해산물찜은 신라면과 불닭볶음면을 섞은 듯한 매콤함의 케이준 소스가 일품이라고 극찬했습니다. 특히 킹크랩 다리, 랍스터 내장, 통통한 새우, 훈제향 소시지에 만족감을 표했습니다. 식당 직원이 직접 손질해주는 킹크랩과 랍스터 살로 만든 초밥을 별미로 꼽았으며, 남은 소스에 밥을 비벼 먹는 것으로 식사를 마무리했습니다. 쯔양은 해산물이 매우 신선하고 소스가 환상적이라 질리지 않고 만족스러운 식사였다고 총평하며 재방문 의사를 밝혔습니다.'),
('오근내닭갈비 본점', '서울 용산구 이촌로29길 15', '02-797-0131', ARRAY['고기'], 'https://www.youtube.com/watch?v=qExwShSLP3Y', 37.5245271, 126.9597327, '서울특별시', '쯔양은 이 집 닭갈비를 ''인생 닭갈비''라고 극찬하며, 카레향이 감도는 독특한 양념이 느끼하지 않고 씹을수록 풍미가 깊어진다고 평가했습니다. 고기는 오래 볶아도 육즙이 풍부하고 부드러웠다고 언급했습니다. 사이드 메뉴인 물막국수는 시판 육수와 다른 깊은 동치미 맛으로 느끼함을 잡아주어 닭갈비와 완벽한 조합이라고 칭찬했습니다. 식사 마무리로 볶음밥을 먹으며, 치즈를 넣지 않아야 닭갈비 본연의 고소한 소스 맛을 제대로 느낄 수 있어 더 맛있다고 개인적인 취향을 밝혔습니다. 맛에 크게 만족하여 재방문 의사를 보이며 포장까지 해갔습니다.'),
('구들짱황소곱창 인덕원점', '경기 안양시 동안구 인덕원로 33', '0507-1379-2779', ARRAY['고기'], 'https://www.youtube.com/watch?v=sD_tYU21KxU', 37.402591, 126.9744739, '경기도', '쯔양은 이 식당의 대창이 매우 신선하고 부드러우면서도 약간의 쫄깃한 식감이 훌륭하다고 평가했습니다. 특히 기름진 맛이 느끼하지 않고 고소해 ''도파민이 터지는 맛''이라고 극찬하며, 40인분을 먹고도 더 먹을 수 있을 정도로 맛있다고 언급했습니다. 시그니처 메뉴인 ''인생대창''에 대해서는 부추향이 더해져 느끼함을 잡아주고 풍미가 매우 독특하고 매력적이라며 ''인생 메뉴''라고 칭했습니다. 또한, 함께 나온 김치, 감자, 계란찜 등의 사이드 메뉴와 마무리로 먹은 볶음밥과 곱창에 대해서도 만족감을 표했습니다.'),
('바다회상 잠실점', '서울특별시 송파구 오금로 62 수협중앙회빌딩 지하1층', '02-2240-3101', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=xz0Tbmu5N2o', 37.5163914, 127.1054982, '서울특별시', '수협 63주년 기념으로 특별히 준비된 20인분이 넘는 엄청난 양의 해물찜을 먹었습니다. 100% 국내산 해산물로 만들어졌으며, 거대한 문어 다리, 대왕 전복, 홍합, 조개, 가리비, 소라 등 다양한 해산물이 들어있었습니다. 홍합과 조개는 크고 쫄깃하며 양념이 맛있다고 평가했습니다. 전복은 매우 크고 신선하며 쫄깃했고, 특히 비린 맛 없는 내장이 고소하고 맛있다고 극찬했습니다. 문어 다리는 일반 문어 한 마리 크기임에도 불구하고 매우 부드럽고 맛있다고 했습니다. 소라는 독성이 있는 침샘을 제거하고 먹어야 한다고 언급하며, 아삭한 식감이 일품이라고 했습니다. 이 외에도 국내산 대게찜, 전복죽, 문어 라면을 먹었는데, 대게는 살이 꽉 차고 달았으며, 전복죽은 신선한 내장 덕분에 비린내 없이 맛있었다고 합니다. 전반적으로 모든 해산물이 신선하고 살이 커서 매우 맛있었다고 총평하며, 수협 쇼핑을 통해 구매하면 어민들에게 도움이 된다고 강조했습니다.'),
('산호', '서울 강남구 논현로175길 111', '02-517-0035', ARRAY['한식'], 'https://www.youtube.com/watch?v=tlhanCh6kKU', 37.5222961, 127.0204182, '서울특별시', '쯔양은 이곳의 안주 구성이 훌륭하다고 평가했습니다. 특히 육회가 정말 맛있다고 칭찬했으며, 한치튀김의 바삭한 식감에 감탄했습니다. 또한, 된장 베이스의 꽃게탕은 밥반찬으로도, 술안주로도 완벽하다고 극찬했습니다. 보쌈 역시 매우 부드럽다고 언급하며 전반적으로 모든 안주가 술과 잘 어울린다고 말했습니다. 이 식당은 브레이크 타임이 없어 낮술을 즐기기에 좋은 장소라는 점도 강조했습니다.'),
('전주백반', '서울특별시 동대문구 고산자로36길 3 신관지하 1층', '02-964-5564', ARRAY['한식'], 'https://www.youtube.com/watch?v=DyIrnuUxRsc', 37.5789581, 127.0388573, '서울특별시', '인도네시아에서 돌아온 후 한국의 집밥 스타일인 백반이 먹고 싶어 새벽 6시에 경동시장을 방문했습니다. 온라인에서 ''백반을 팔아 집 세 채를 샀다''는 소문을 듣고 찾아간 곳입니다. 1인분에 10,000원이 안 되는 저렴한 가격에 엄청나게 푸짐한 양이 나오는 가성비에 놀라워했습니다. 솥밥은 밥이 찰지고 쫀득하며, 식후에 만들어주는 숭늉과 누룽지가 일품이라고 극찬했습니다. 특히 숭늉은 ''약''이라고 표현할 정도로 건강해지는 맛이라고 했습니다. 반찬 중에서는 콩나물이 아삭하고 달콤하며, 무생채는 새콤달콤하다고 평가했습니다. 계란말이는 감칠맛이 있고 촉촉하며, 구운 고등어는 간이 완벽하다고 말했습니다. 여러 반찬 중 멸치볶음을 가장 맛있는 반찬으로 꼽았습니다. 메인 메뉴인 된장찌개는 진하고 깊은 맛이 일품이며, 두부도 부드럽다고 칭찬했습니다. 김치찌개에는 고기가 들어있어 만족감을 표했고, 김치를 잘게 잘라 밥과 함께 먹는 것을 즐겼습니다. 전반적으로 모든 음식의 간이 잘 맞고, 시장의 정겨운 분위기와 난방이 되는 좌석 등 손님을 위한 배려가 돋보이는 공간이라고 평가했습니다.'),
('Seblak prasmanan MURMER', 'Jl. Mawar Legoso, RT.002/RW.07, Pisangan, Ciputat Timur, Kota Tangerang Selatan, Banten 15419, Indonesia', '+628997405798', ARRAY['아시안'], 'https://www.youtube.com/watch?v=OOwbBh44y70', -6.3161251, 106.7646154, '인도네시아', '쯔양은 구독자들의 요청으로 인도네시아 자카르타 찌뿌땃(Ciputat Timur)에 위치한 ''Seblak prasmanan MURMER''를 방문했다. 이곳은 젊은 층에게 인기가 많은 10년 된 맛집으로, 마라탕처럼 원하는 재료를 직접 골라 담는 방식이다. 쯔양은 닭발, 어묵, 소시지, 미트볼(박소) 등 다양한 토핑을 5개 바구니에 가득 담았다[attached_file:1, ts:161-254]. 맵기는 총 5단계로, 1단계는 맵지 않고 꼬리곰탕처럼 진한 맛, 2단계는 신라면과 틈새라면 사이의 맵기, 3단계는 틈새라면보다 맵고 깔끔한 맛이라고 평가했다. 4단계부터는 한국의 매운 음식 챌린지 수준으로 매우 맵지만 맛있게 중독적인 맛이라고 했고, 5단계는 엽기떡볶이 오리지널보다 더 매워 어지러움을 느낄 정도라고 설명했다. 매운맛을 중화시키기 위해 감자튀김과 초콜릿 바나나 치즈 튀김 디저트를 함께 먹었으며, 세블락을 매우 만족스럽게 먹어 다음 인도네시아 방문 시 재방문 의사를 밝혔다.'),
('Warung Isnuri', 'Jl. Raya Sanggingan, Ubud, Gianyar Regency, Bali 80571, Indonesia', '+6281227021502', ARRAY['아시안'], 'https://www.youtube.com/watch?v=acseWyAHPhw', -8.4923652, 115.2533975, '인도네시아', '쯔양은 우붓의 여러 폭립 식당을 다니다가 자신의 입맛에 완벽하게 맞는 이곳을 ''숨은 맛집''으로 발견했다고 밝혔습니다. 대표 메뉴인 폭립과 BBQ 치킨에 대해, 달콤한 바비큐 소스에 매콤한 칠리 소스를 더하면 ''천상의 맛''이라고 극찬했습니다. 고기가 뼈에서 쉽게 분리될 정도로 부드럽고, 누구나 좋아할 만한 맛이라고 평가했습니다. 함께 주문한 나시고랭은 간이 세지 않아 고기와 잘 어울렸고, 추가로 주문한 미고랭(인도미, 미고랭 세답)에 대해서도 계란을 넣어 먹으면 감칠맛이 폭발한다며 만족감을 표했습니다. 특히 현지 식당이라 다른 곳에 비해 폭립 가격이 125,000루피아(약 12,000원)로 매우 저렴하다는 점을 큰 장점으로 꼽았습니다. 몸이 좋지 않은 상태에서 촬영을 시작했지만, 음식을 먹고 병이 나을 정도로 맛있었다고 말하며 전반적으로 매우 높은 만족도를 보였습니다.'),
('Tepi Pantai Bali', 'Jl. Pantai Kedonganan No.24, Kedonganan, Kec. Kuta, Kabupaten Badung, Bali 80361, Indonesia', '+62 852-3872-6667', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=aOtNLZ05ypw', -8.78033, 115.1668, '인도네시아', '쯔양은 끄동아난 수산시장에서 구매한 약 15kg의 해산물을 ''Tepi Pantai Bali'' 식당으로 가져와 조리를 의뢰했습니다. 약 30만 원의 비용으로 모든 재료와 조리 서비스를 이용했으며, 일부 향신료가 강한 요리를 제외하고 약 10kg을 먹었습니다. 무늬오징어 구이는 매콤한 소스와 잘 어울리며, 두툼하고 불향이 좋다고 평가했습니다. 짐바란 소스를 곁들인 조개는 달콤, 매콤, 짭짤한 맛의 조화가 뛰어나 밥을 비벼 먹고 싶을 정도라고 극찬했습니다. 거대한 크레이피쉬와 타이거 새우, 일반 새우보다 훨씬 부드러운 징거미새우(강새우)도 맛있게 먹었습니다. 추천받은 바라문디(baronang) 생선구이는 껍질과 살이 모두 매우 쫄깃하다고 평가했습니다. 버터 스타일로 구운 가리비는 재가열했음에도 매우 부드러웠다고 합니다. 해변에 위치한 식당의 분위기에 대해, 일몰이 아름답고 라이브 음악과 전통 춤 공연이 있어 매우 만족스러웠다고 언급했습니다.'),
('라면타임 본점', '대전광역시 중구 계백로1685번길 45 시티팰리스 1층', '042-533-3048', ARRAY['분식'], 'https://www.youtube.com/watch?v=8LGD2mMQ1RQ', 36.3225885, 127.4051693, '대전광역시', '쯔양은 37년 전통의 라면 전문점인 ''라면타임''을 방문하여 총 10그릇의 라면을 먹었습니다. 특히 이 집의 시그니처 메뉴인 ''우유라면''을 가장 맛있었다고 극찬하며, 부드럽고 고소한 크림 파스타 같은 맛에 라면의 매콤함이 조화롭게 어우러져 독특하고 인상 깊다고 평가했습니다. 또한 ''얼큰장 라면''은 황태 해장국처럼 깊고 시원한 맛이라고 언급했고, ''카레 라면''은 자극적이지 않고 부드러운 카레 요리 같다고 묘사하는 등 다양한 라면 메뉴에 대해 긍정적인 반응을 보였습니다.'),
('Waroeng Suka Bakmie', 'Jl. Kubu Anyar No.25, Kuta, Kec. Kuta, Kabupaten Badung, Bali 80361 Indonesia', '+6281339885119', ARRAY['아시안'], 'https://www.youtube.com/watch?v=ba4weMv0tZo', -8.7301798, 115.1723443, '인도네시아', '쯔양은 발리 쿠타에 위치한 ''Waroeng Suka Bakmie''를 방문하여 매우 저렴한 가격에 깊은 인상을 받았습니다. 가장 저렴한 국수는 1,000원(약 12,000루피아)이었습니다. 그녀는 여러 메뉴를 맛보았습니다. 기본 메뉴인 **미 아얌**은 감칠맛이 돌고 간이 완벽하며, 닭고기 맛이 진해 간장 베이스의 라멘과 비슷하다고 평가했고 튀긴 만두피와 함께 즐겼습니다. 주인의 추천 메뉴인 **미 아얌 자무르**(버섯 닭고기 국수)는 짭짤하고 맛있으며, 국물을 부으면 베트남 쌀국수 같은 독특한 맛이 난다고 했습니다. **치위 미 아얌 뜰루르**는 고소하지만 짠맛이 더 강해 소금 베이스의 라멘 같다고 평가하며, 기본 미 아얌을 더 선호한다고 밝혔습니다. **박소 스페셜**은 특유의 향신료(오렌지 잎, 생강)를 피하기 위해 국물을 미 아얌 육수로 변경하여 주문했습니다. 소고기 미트볼은 맛있고, 닭고기 미트볼은 향신료 맛 없이 단단해서 좋았지만 만두소에서는 약간의 향이 느껴졌다고 합니다. 특히 매운 삼발 소스를 추가했을 때 국물이 훨씬 맛있어졌다고 언급했습니다. 무더운 날씨에도 불구하고 저렴한 가격과 맛있는 음식에 전반적으로 만족스러운 식사였다고 총평했습니다.'),
('권바우부대찌개 춘천본점', '강원 춘천시 솟발1길 4-13', '033-262-0019', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=_-szbqPsPEo', 37.8475929, 127.7320638, '강원특별자치도', '쯔양은 대포(발칸포)로 생햄을 쏴주는 독특한 퍼포먼스에 감탄하며 ''굿''이라고 평가했습니다[att:1]. 익히지 않은 생햄이 뜨거운 육수에서 부드럽게 익어가는 과정을 즐겼으며, 직접 만든 수제 햄의 담백하고 고소한 맛을 높이 평가했습니다. 일반적인 부대찌개의 자극적인 맛과 달리, 이곳의 부대찌개는 깔끔하고 깊은 풍미가 특징이라고 언급하며 매우 만족스러운 식사였음을 표현했습니다.'),
('황금오리', '경기 용인시 기흥구 지삼로250번길 12', '031-8005-9252', ARRAY['고기'], 'https://www.youtube.com/watch?v=wBZqLQ6yO0U', 37.2353082, 127.1361088, '경기도', '쯔양은 초대형 돌판에 직접 구워주는 오리고기와 마지막에 철판 아이스크림처럼 만들어주는 누룽지 볶음밥을 이 가게의 특징으로 꼽았습니다. 오리고기는 부드럽고 잡내가 없으며, 오리 기름에 구워진 감자와 양파 등 채소와의 조화가 훌륭하다고 평가했습니다. 특히, 식사 후 제공되는 누룽지 볶음밥은 바삭하고 고소한 맛이 일품이며, 배가 불러도 꼭 먹어야 할 별미라고 강조했습니다. 양념구이보다는 오리 본연의 고소한 맛을 더 잘 느낄 수 있는 로스구이를 더 추천했습니다.'),
('라면타임 본점', '대전 중구 계백로1685번길 45 시티팰리스 1층', '042-533-3048', ARRAY['분식'], 'https://www.youtube.com/watch?v=swV9d6MDgJk', 36.3225885, 127.4051693, '대전광역시', '쯔양은 대전 오류동에 위치한 37년 전통의 분식집 ''라면타임''을 방문하여 총 10그릇의 라면을 먹었다. 가장 인상 깊었던 메뉴는 ''우유라면''으로, 로제처럼 부드럽고 고소하며 크리미한 맛이 일품이라고 극찬했다. 또한 ''짬뽕라면''은 해산물과 돼지고기가 들어있어 실제 짬뽕과 같은 깊은 맛과 불맛이 난다고 평가하며 우유라면 다음으로 맛있었다고 언급했다. 이외에도 짜장라면, 참치라면, 기본라면, 치즈라면, 해장라면 등 다양한 메뉴를 맛보았으며, 모든 라면이 각각의 특색 있는 맛과 푸짐한 양을 자랑한다고 전반적으로 매우 만족스러운 평가를 내렸다. 특히 모든 라면의 국물이 일반 라면과 달리 깊고 풍부한 맛을 내며, ''라면의 신''이 주방에 있는 것 같다고 감탄했다.'),
('우나다이 서울점', '서울 강남구 테헤란로83길 36 2층', '070-7766-0117', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=CbHQjy6Nq0Y', 37.509789, 127.0569658, '서울특별시', '쯔양은 밥 10인분과 장어 8마리가 들어간 ''대왕 장어덮밥'' 도전에 나섰다. 성공 시 평생 무료 이용권이 걸려 있었다. 그녀는 장어덮밥을 맛있게 먹는 4가지 방법(기본, 야쿠미 첨가, 오차즈케 등)을 선보이며, 불향이 나는 부드러운 장어와 소스 맛을 극찬했다. 결국 도전에 성공하며 음식에 대한 큰 만족감을 표현했다.'),
('천원국수', '충남 천안시 동남구 문암로 66', '041-554-0965', ARRAY['분식'], 'https://www.youtube.com/watch?v=qUljlf9ym0g', 36.8405659, 127.1807782, '충청남도', '쯔양은 국물이 매우 맛있고 중독성이 강하다고 평가했습니다. 또한, 15년 동안 가격이 천 원으로 동일하다는 점을 언급하며 놀라워했습니다.'),
('철수네매운갈비찜', '대전광역시 유성구 대학로 31 한진오피스텔 1층', '042-824-8085', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=rQsuysaJMsg', 36.3566095, 127.3419006, '대전광역시', '쯔양은 음식이 나오자마자 "비주얼 끝장 나는데"라며 감탄했고, 양이 "엄청 크네"라고 언급하며 만족감을 표했습니다. 제공된 영상 정보만으로는 상세한 맛 평가를 추출하기 어려우나, 일반적인 리뷰에 따르면 이곳의 매운갈비찜은 부드러운 등갈비와 중독성 있는 매운 양념이 특징이며, 남은 양념에 치즈 볶음밥을 해 먹는 것이 별미로 꼽힙니다.'),
('김수사', '서울 강남구 도산대로 132', '02-542-5235', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=YXiBcp0Fo4Y', 37.5171894, 127.0232319, '서울특별시', '쯔양은 이 식당을 ''강남구의 터줏대감''이라 부르며 오랜 역사를 강조했습니다. 식당 이전을 앞둔 마지막 영업일에 방문하여 초밥 100개 먹기에 도전하며 감사를 표했고, ''대박'', ''진짜 멋있다'' 등의 감탄사를 통해 긍정적인 반응을 보였습니다. 영상에서는 새우초밥 등을 맛있게 먹는 모습을 보여주었으며, 검색 결과에 따르면 가리비, 삼치, 안키모군함 등 다양한 메뉴를 즐긴 것으로 확인됩니다.'),
('제일분식', '서울 종로구 숭인동 76-1', '02-2234-9440', ARRAY['분식'], 'https://www.youtube.com/watch?v=nAAuuWU4Ql0', 37.5740182, 127.0166727, '서울특별시', '쯔양은 이 식당의 떡볶이에 대해 고추장 맛이 진하게 나면서 매콤달콤하다고 평가했습니다. 특히 방앗간에서 갓 나온 떡처럼 매우 쫀득쫀득한 식감을 칭찬하며, 양념이 잘 졸여져 있어 맛있는 ''맵단''의 조화를 이룬다고 언급했습니다. 떡볶이 안의 어묵도 맛있다고 덧붙였습니다. 튀김의 경우 기름기가 다소 느껴졌지만, 떡볶이 국물에 찍어 먹으니 아주 맛있다고 리뷰했습니다.'),
('명화횟집', '강원도 강릉시 주문진읍 시장1길 4-1', '033-662-4987', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=wDR3Is4aibE', 37.8907918, 128.8279917, NULL, '쯔양은 주문진 수산시장에서 자연산 회 6kg(광어, 참가자미, 범도다리 등)을 주문하여 먹었습니다. 특히 ''도다리 진짜 맛있다''고 감탄했으며, 엄청난 양에 주변 상인들이 놀라워했습니다. 많은 양에도 부족하다고 느낄 정도로 맛있게 먹었으며, 상인들이 회를 추가로 가져다줄 때마다 감사 인사를 하며 맛있게 먹었다고 합니다.'),
('철수네매운갈비찜', '대전 중구 태평로 120', '042-525-2929', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=l8-RIG3yEb8', 36.3271902, 127.3957013, '대전광역시', '쯔양은 ''철수네매운갈비찜''을 처음에는 독특한 맛이라고 느꼈지만, 먹을수록 중독성이 강해져 계속 맛있어지는 곳이라고 평가했습니다. 특히 고기가 매우 부드러워 뼈에서 쉽게 분리되는 점을 칭찬했습니다. 매운맛은 3단계(순한맛, 중간맛, 매운맛)로 나뉘는데, 순한맛도 신라면보다 맵지만 맛있게 매운 정도이며, 중간맛은 불닭볶음면과 비슷한 맵기라고 설명했습니다. 평소 매운맛이 음식 본연의 맛을 해쳐 선호하지 않지만, 이곳의 매운맛은 강렬하면서도 맛있어 3가지 맛 중 가장 맛있었다고 극찬했습니다. 함께 나오는 동치미와 미역국도 매우 맛있다고 언급했으며, 특히 치즈 볶음밥은 갈비찜보다 더 맛있을 정도로 ''전설적인 맛''이라며 방문 시 꼭 먹어야 할 메뉴로 강력 추천했습니다.'),
('김수사', '서울 강남구 도산대로 132 해정빌딩 1층', '02-542-5235', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=sFm9UUP9a5M', 37.5171894, 127.0232319, '서울특별시', '쯔양은 40년 전통의 초밥 맛집 김수사를 ''인생 초밥집''이라 극찬하며, 구관에서의 마지막 식사를 하게 되어 영광이라고 밝혔습니다. 특히 밥이 약간 달고 짜게 간이 완벽하게 되어 있어 모든 초밥이 맛있다고 평가했습니다. 가장 인상 깊었던 메뉴로는 새우 가루가 뿌려진 가리비 초밥, 솜사탕처럼 녹는 참치 뱃살, 비린 맛이 전혀 없는 고등어, 천국 같은 맛의 안키모(아귀간) 군함, 그리고 단맛만 남은 우니(성게알) 군함을 꼽았습니다. 특히 가장 좋아하는 초밥인 장어초밥은 살이 꽉 차고 소스가 일품이라고 칭찬했으며, 게살 초밥의 두툼한 두께에 감탄했습니다. 마지막에 즉석에서 만들어준 5점의 초밥은 ''인생 초밥''이라고 표현할 정도로 최고의 맛이었다고 합니다. 가성비와 맛, 재료의 퀄리티 모두를 만족시키는 곳으로, 잊지 못할 맛이라고 리뷰를 마무리했습니다.'),
('이화루', '강원 삼척시 근덕면 교가길 13-3', '033-573-7749', ARRAY['중식'], 'https://www.youtube.com/watch?v=ZmeGYBhFgko', 37.3804777, 129.2266381, '강원특별자치도', '쯔양은 이 식당의 시그니처 메뉴인 비빔짬뽕과 비빔짬짜면을 맛보았습니다. 비빔짬뽕은 살짝 매콤하고 자극적인 맛이 특징이며, 비빔짬짜면은 그보다 더 부드러운 맛이라고 평가했습니다. 다른 손님들이 놀랄 정도로 맛있게 식사하는 모습을 보였으며, 음식을 남김없이 다 먹고 추천할 만한 맛집이라고 언급하며 만족감을 표현했습니다.'),
('빙그레김밥', '강원특별자치도 강릉시 경강로 2095', '033-645-1358', ARRAY['분식'], 'https://www.youtube.com/watch?v=sTzn9qh6vEY', 37.7547225, 128.8958125, '강원특별자치도', '35년 전통의 노포 분식집으로, 할머니 댁에 온 것처럼 아늑하고 향수를 불러일으키는 분위기를 칭찬했습니다. 야채김밥을 제외한 계란말이김밥, 햄김밥, 소고기김밥, 맛살김밥, 멸치김밥 등 모든 김밥과 라볶이, 떡볶이, 라면, 어묵탕을 주문했습니다. 김밥은 밥이 쫀득하고 고전적인 맛이며, 특히 멸치김밥을 가장 맛있다고 꼽았습니다. 라면은 양배추가 들어가 시원하고 클래식한 분식집 라면 맛이라고 극찬하며 한 그릇을 추가 주문했고, 함께 나온 김치도 맛있다고 언급했습니다. 라볶이는 어릴 때 먹던 추억의 맛으로, 과하지 않은 양념과 쫄깃한 떡이 특징이라고 평했습니다. 특별한 맛은 아니지만, 음식과 분위기 전반에서 느껴지는 향수 때문에 매우 만족스러운 식사였다고 총평했습니다.'),
('속초어장물회', '강원 속초시 엑스포로 31', '033-637-8833', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=ez641ZixE1s', 38.1910403, 128.5876722, '강원특별자치도', '쯔양은 이곳의 전복죽을 ''인생 최고의 전복죽''이라고 극찬하며, 이전 방문 때 먹어보고 반해서 다시 찾아왔다고 밝혔습니다. 전복죽은 내장의 색에 따라 맛이 달라지는데, 황금색 내장은 고소한 맛이 강하고, 짙은 녹색 내장은 바다의 향이 깊게 느껴진다고 평했습니다. 또한, 진한 설렁탕처럼 식으면 젤라틴 막이 생길 정도로 진하다고 감탄했습니다. 비빔물회는 처음 먹어보는데 소스가 달콤하고 맛있으며, 사장님이 직접 뼈를 발라낸 가자미가 들어있어 먹기 편하다고 언급했습니다. 이외에도 계란물을 입혀 부드러운 오징어순대, 신선함이 느껴지는 홍게비빔밥, 해장에 좋을 것 같은 시원한 홍합탕 등 주문한 모든 메뉴에 대해 만족감을 표현하며 40년 경력 사장님의 솜씨를 높이 평가했습니다.'),
('Retro Lángos Budapest', 'Bajcsy-Zsilinszky út 25, Budapest 1065 Hungary', '+36 20 294 6571', ARRAY['패스트푸드'], 'https://www.youtube.com/watch?v=iSb0LHcOMhs', 47.503235, 19.055081, '헝가리', '쯔양은 이곳의 랑고쉬가 다른 곳보다 짜지 않아서 훨씬 맛있다고 평가했습니다. 특히 직원이 가장 맛있다고 추천한 ''케밥 랑고쉬''를 먹어본 후, 자신의 최애 메뉴가 되었다고 극찬했습니다. 음식의 모양은 한국의 호떡과 비슷하며, 맛은 갓 튀긴 꽈배기와 유사하지만 속이 더 쫄깃하다고 설명했습니다. 쯔양은 이 푸드트럭에서 랑고쉬를 총 6판 먹었습니다.'),
('유포리막국수', '강원 춘천시 신북읍 맥국2길 123', '033-242-5168', ARRAY['한식'], 'https://www.youtube.com/watch?v=1SxiNnPoa1o', 37.9460926, 127.7783185, '강원특별자치도', '쯔양은 이곳의 막국수 양이 산처럼 많다고 여러 번 감탄했습니다. 먼저 비빔막국수는 양념이 순하지만 중독성 있는 맛이라고 평가했고, 이후 식초와 설탕을 추가해 더 자극적이고 맛있는 ''쯔양 스타일''로 즐겼습니다. 특히, 따로 제공되는 동치미 국물은 매우 시원하고 상쾌해서 그냥 마셔도 맛있고, 국수와 섞었을 때 더 맛있다고 극찬했습니다. 함께 주문한 편육(수육)은 잡내가 전혀 없고 풍미가 깊으며 동치미와 궁합이 완벽하다고 말했습니다. 감자전은 가장자리가 바삭해서 훌륭하다고 평가했으며, 메밀전병은 만두처럼 쫄깃하고, 녹두부침은 어릴 적 먹던 맛이라고 언급했습니다. 전반적으로 모든 메뉴가 맛있다고 만족감을 표현했습니다.'),
('신매콤터', '서울 강북구 오패산로 412', '02-993-9086', ARRAY['분식'], 'https://www.youtube.com/watch?v=8zsCX3FR90A', 37.637474, 127.0266107, '서울특별시', '쯔양은 10년 만에 방문했음에도 맛이 변하지 않았다며 만족감을 표했습니다. 이곳을 ''엄청난 맛집은 아니지만 기본에 충실해 맛있는 동네 맛집''이라고 표현했습니다. 특히 제육덮밥은 채소 없이 고기가 가득해 과거부터 가장 좋아했던 메뉴로 꼽았으며, 달고 맵지만 끝 맛은 고소하다고 평가했습니다. 떡볶이는 예전 기억보다 훨씬 매웠지만 매우 맛있다고 언급했고, 튀김은 식어도 바삭함이 유지된다고 칭찬했습니다. 라면은 분식집 특유의 맛이 살아있어 집에서 끓인 것보다 맛있다고 했으며, 김치볶음밥은 다른 메뉴에 비해 순한 맛으로 집에서 만든 맛과 비슷하다고 평가했습니다. 전체적으로 가성비가 좋고 양이 푸짐하며, 24시간 운영되는 점을 장점으로 꼽았습니다.'),
('호남식당', '경기 구리시 동구릉로136번길 90 구리농수산물도매시장 수산2동 2층', '031-562-8259', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=S0E0PpIX6v0', 37.6159547, 127.1445826, '경기도', '쯔양은 구리수산시장에서 구매한 킹크랩과 홍게 약 10kg을 먹었습니다. 킹크랩의 엄청난 크기에 감탄하며, 살이 꽉 차 있고 매우 달다고 평가했습니다. 특히 고소하고 진한 맛의 내장에 밥을 비벼 먹는 것을 즐겼습니다. 마지막으로 킹크랩 다리를 넣어 끓인 라면을 먹으며, 국물 맛이 해물탕처럼 깊고 진해져 차원이 다르다고 극찬했습니다. 신선한 해산물을 바로 조리해 먹는 맛에 크게 만족하며 역대급 킹크랩 먹방이라고 언급했습니다.'),
('Pléh Csárda', 'Budapest, Kolozsvár u. 48, 1155 Hungary', '+36 30 335 0300', ARRAY['고기'], 'https://www.youtube.com/watch?v=JDlXwyCrvLE', 47.4843613, 19.1234746, '헝가리', '쯔양은 영상에서 거대한 고기 접시를 보고 놀라며, 양이 정말 많아서 다 먹는 데 시간이 오래 걸릴 것 같다고 말합니다. 맛에 대해서는 ''힘겹게 맛있다''고 표현하며, 양이 적은 사람이라면 하나만 먹어도 배가 부를 것이라고 언급합니다.'),
('McDonald''s Nyugati', 'Budapest, Teréz krt. 55, 1062 Hungary', '+36 1 302 6791', ARRAY['패스트푸드'], 'https://www.youtube.com/watch?v=g-bz7LdNkiU', 47.5102, 19.0581, '헝가리', '쯔양은 이곳을 ''세상에서 가장 아름다운 맥도날드''라고 칭하며, 궁전처럼 웅장하고 멋진 인테리어에 감탄했습니다. 그녀는 일반 맥도날드가 아닌 고급 레스토랑에 온 것 같다고 평가했습니다. 쯔양은 다양한 메뉴를 맛보았는데, 특히 ''마에스트로 풀드 포크'' 버거가 가장 인상적이었다고 합니다. 기존에 가장 좋아하던 더블 불고기 버거를 뛰어넘는 맛이라고 극찬하며, 달고 짠 BBQ 소스와 부드러운 풀드 포크의 조화가 훌륭하다고 평가했습니다. 또한 전반적으로 헝가리 맥도날드의 햄버거 번이 더 쫄깃하고 패티가 부드러워, 아이스크림을 포함한 모든 메뉴가 한국보다 더 맛있게 느껴졌다고 말했습니다. 이러한 특별한 맛은 아름다운 매장 분위기 덕분인 것 같다고 덧붙였습니다.'),
('Fakanal Étterem', 'Budapest, Vámház krt. 1-3, 1093 Hungary', '+36 1 217 7860', ARRAY['양식'], 'https://www.youtube.com/watch?v=wp0vjk3tyZM', 47.48721, 19.06222, '헝가리', '쯔양은 이 식당에서 닭다리와 감자, 과일, 음료를 선택했습니다. 다양한 종류의 음식이 많지는 않아서 아쉬움을 표현했지만, 음식은 맛있다고 말했습니다. 특히 디저트로 먹은 귤이 맛있다고 언급하며 식사를 마무리했습니다.'),
('Pléh Csárda', 'Budapest, Kolozsvár u. 48, 1155 Hungary', '+36 30 311 2712', ARRAY['고기'], 'https://www.youtube.com/watch?v=T84RZWzsiG8', 47.4843613, 19.1234746, '헝가리', '쯔양은 헝가리 부다페스트에 위치한 이 식당에서 3kg에 달하는 거대한 스테이크 먹방을 선보였습니다. 영상에서 쯔양은 뜨거운 돌판 위에 올려진 두툼한 스테이크를 맛있게 먹으며 만족감을 표현했고, 셰프는 그 모습을 놀랍게 지켜봤습니다. 여러 매체에 따르면 쯔양은 이 방문에서 스테이크 외에도 굴라시 수프, 으깬 감자, 스파게티와 같은 사이드 메뉴와 양귀비 씨 롤, 초콜릿 케이크 등 다양한 디저트까지 먹은 것으로 알려졌습니다. 쯔양은 이전 방문 시 먹었던 슈니첼을 한국의 돈까스와 비슷하다고 평가했으며, 식당의 분위기를 ''낭만적인 유럽 감성''이라고 표현하기도 했습니다.'),
('Pléhcsárda', 'Budapest, Kolozsvár u. 48, 1155 Hungary', '+36 30 335 0300', ARRAY['양식'], 'https://www.youtube.com/watch?v=KNrfkcA8vzY', 47.4843613, 19.1234746, '헝가리', '영상에서 쯔양은 슈니첼의 크기에 "우와 진짜 크다", "말도 안 되게 크다"라며 놀라는 반응을 보입니다. 그녀의 방문을 다룬 기사에 따르면, 쯔양은 2kg의 슈니첼, 2kg의 코르동 블루, 그리고 곱창 스튜를 주문했습니다. 그녀는 식당의 분위기를 ''낭만적인 유럽 분위기''라고 표현했으며, 슈니첼의 맛과 모양이 한국의 돈까스와 비슷하다고 평가했습니다. 또한, 라즈베리 시럽 9잔을 마셨고, 이 식당의 30년 역사상 가장 많은 양을 먹은 손님으로 기록되었습니다.'),
('Sir Lancelot Medieval Restaurant', 'Podmaniczky u. 14, Budapest 1065, Hungary', '+3613024456', ARRAY['양식'], 'https://www.youtube.com/watch?v=ezWrb7bK4vU', 47.508183, 19.056732, '헝가리', '쯔양은 중세 유럽 분위기의 독특한 컨셉의 식당에 방문하여 6인분짜리 ''헝가리안 킹 플래터''를 주문했습니다. 그녀는 거대하고 웅장한 식당 내부 인테리어와 크리스마스 장식에 감탄했습니다. 플래터는 매우 무거워서 혼자 들기 어려울 정도였으며, 중세 콘셉트에 따라 포크 없이 손으로 먹는 방식이 독특하다고 언급했습니다. 음식에 대해서는 거위 고기가 겉은 바삭하고 속은 촉촉하며 맛있다고 평가했고, 꼬치에 있는 닭가슴살과 소시지도 한국인 입맛에 잘 맞을 것이라고 말했습니다. 특히 양 다리 고기는 양고기 특유의 향이 진하고 소스와의 조화가 훌륭하다고 칭찬했습니다. 또한, 뼈 없는 생선, 버펄로 윙 맛의 닭 날개, 그리고 다른 곳에서 먹었을 때 비렸던 푸아그라가 여기서는 구워 나와 비린 맛 없이 풍미가 깊고 맛있다고 극찬했습니다. 식사를 하는 동안 펼쳐지는 공연을 즐겼으며, 다른 손님들이 자신의 먹는 모습에 관심을 보이는 것을 보고 행복하고 뿌듯하다고 느꼈습니다. 최종적으로 음식 맛과 분위기, 공연 모두 훌륭하여 방문할 가치가 있는 곳이라고 평가했습니다.'),
('Beef & Bone', 'Belgrád Rakpart 17, Budapest 1056 Hungary', '+36 70 329 7815', ARRAY['고기'], 'https://www.youtube.com/watch?v=r-fV0eHaV_4', 47.4891379, 19.054201, '헝가리', '쯔양은 헝가리 부다페스트에 위치한 스테이크 전문점 ''Beef & Bone''을 방문하여 총 3kg의 스테이크를 먹었습니다. 그녀는 T본(안심, 등심), 립아이, 와규, 오마하 립아이, 브라질리언 안심 등 다양한 부위를 주문했습니다. T본 스테이크의 안심은 입에서 녹을 정도로 부드럽고, 등심은 씹는 맛이 있으면서도 드라이에이징이 잘 되어 매우 부드럽고 풍미가 좋다고 평가했습니다. 와규는 지방이 많아 육즙이 풍부했으며, 오븐에 다시 데워 먹으니 기름진 느낌이 줄어들어 완벽했다고 말했습니다. 셰프가 추천한 브라질리언 안심은 지방이 거의 없고 부드러워 입에서 녹는 맛이라고 극찬하며 추천 메뉴는 꼭 주문해야 한다고 강조했습니다. 사이드 메뉴인 매쉬드 포테이토는 구운 양파가 들어가 있어 양파향이 풍부하며 꼭 먹어야 할 메뉴라고 언급했고, 헝가리 전통 수프인 굴라쉬는 한국의 육개장과 맛이 비슷해 맛있다고 평가했습니다. 또한, 고기만 먹기에는 다소 물려서 주문한 토마토 스파게티는 면발이 쫄깃하고 맛있다고 칭찬했습니다. 디저트로는 헝가리 전통 케이크인 베이글리(Beigli)와 솜로이(Somlói), 그리고 초콜릿 케이크를 먹었는데 모두 매우 맛있었다고 합니다. 전반적으로 식당의 크리스마스 분위기와 맛있는 음식에 매우 만족하며 행복한 식사였다고 총평했습니다.'),
('Pléh Csárda', 'Budapest, Kolozsvár u. 48, 1155 Hungary', '+36 30 311 2712', ARRAY['양식'], 'https://www.youtube.com/watch?v=GBRoyvoSfAY', 47.55176, 19.14369, '헝가리', '쯔양은 30년 전통의 이 식당에서 1.3kg 슈니첼, 1kg 치킨 슈니첼, 1.9kg 코르동 블루를 주문했습니다. 슈니첼은 소스 없는 옛날 경양식 돈까스 맛과 비슷하며, 고기가 부드럽고 쫄깃해서 맛있다고 평가했습니다. 특히 후추를 뿌려 먹으니 훨씬 맛있다고 언급했습니다. 한국에서 가져온 돈까스 소스와 함께 먹었을 때는 한국 돈까스와 맛이 완전히 똑같다고 했습니다. 치킨 슈니첼은 닭가슴살임에도 불구하고 매우 부드럽다고 칭찬했습니다. 함께 주문한 ''PACALPÖRKÖLT''라는 양 내장 스튜는 처음에는 입맛에 맞지 않았지만 먹을수록 중독성이 있는 맛이라고 평가했습니다. 전반적으로 30년 전통의 맛집은 다르다며 헝가리에서의 첫 식사에 매우 만족했습니다.'),
('공아춘수타손짜장', '경북 상주시 경상대로 3197', '054-531-3050', ARRAY['중식'], 'https://www.youtube.com/watch?v=7kSC8-pnAzE', 36.432451, 128.152588, '경상북도', '쯔양은 상주에 위치한 수타면 전문 중식당 ''공아춘수타손짜장''을 방문하여 여러 메뉴를 맛보았습니다. 그 중 ''짬뽕''을 이날의 최고 메뉴로 꼽았는데, 한우 사골 육수 베이스의 진한 국물과 수타면의 쫄깃한 식감이 일품이라고 극찬했습니다. ''돌판 짜장면''은 일반 짜장면보다 맛있었다고 평가했는데, 매콤한 맛과 마지막까지 식지 않는 점을 장점으로 꼽았습니다. 탕수육은 비트를 사용한 붉은 소스가 독특하며 과일처럼 상큼한 신맛이 중독성 있다고 평했습니다. 일반 짜장면은 옛날식의 담백한 맛, 야끼우동은 고추장 맛이 강한 매콤한 볶음면이라고 설명했습니다. 쯔양은 주방장이 끊임없이 면을 직접 뽑는 모습에 감탄하며, 음식에 대한 진심이 맛으로 이어진다고 총평했습니다.'),
('굴이짱', '서울 광진구 긴고랑로 61', '02-458-9995', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=Zj9fS4ZmW_o', 37.562108, 127.0831567, '서울특별시', '쯔양은 겨울 제철 음식인 굴을 먹기 위해 이 식당을 방문했습니다. 11kg에 달하는 굴찜을 주문했으며, 굴의 크기가 매우 크고 맛이 좋다고 감탄했습니다. 굴 자체의 맛이 뛰어나 별다른 소스 없이도 맛있다고 평가했으며, 쪄서 먹으니 매우 촉촉하다고 언급했습니다. 함께 제공된 미역국에 굴을 넣어 ''굴 미역국''을 만들어 먹는 등 다양한 방법으로 굴을 즐겼습니다. 특히, 사이드로 주문한 굴전이 매우 부드럽고 촉촉하며 맛이 뛰어나다고 극찬하며 ''인생 굴전''이자 ''최고의 메뉴''라고 평가했습니다. 전반적으로 식사에 매우 만족하며, 겨울이 가기 전에 신선한 굴찜을 꼭 먹어보길 추천했습니다.'),
('큰집설농탕', '서울특별시 양천구 화곡로4길 9', '02-2605-1999', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=zngViIh42ok', 37.5386214, 126.8276247, '서울특별시', '쯔양은 이곳을 ''인생 설렁탕''이라 극찬하며 떡국 10그릇을 먹었습니다. 특히 국물 맛에 크게 감명받았는데, 추가 간이 필요 없을 정도로 진하고 깔끔하며, 조미료 없이 집에서 끓인 듯한 사골 본연의 맛이라고 평가했습니다. 차갑게 식었을 때 묵처럼 굳는 것을 보여주며 ''진짜 찐 국물''임을 강조했습니다. 기본인 사골과 양지 반반 육수, 사골 육수, 양지 육수를 각각 맛본 후, 우유처럼 뽀얗고 진한 사골 육수를 자신의 ''원픽''으로 꼽았습니다. 떡은 매우 쫄깃하고 부드러우며, 고기만두 또한 감칠맛이 뛰어나다고 언급했습니다. 마지막 그릇에 특별히 넣어주신 도가니는 쫀득함과 부드러움 등 다채로운 식감이 일품이라고 칭찬했습니다. 전반적으로 맛과 사장님의 친절함에 크게 만족하며, 앞으로 집에서 계속 시켜 먹을 단골집으로 정했다고 밝혔습니다.'),
('천원분식', '제주특별자치도 제주시 관덕로8길 22', '064-753-3397', ARRAY['분식'], 'https://www.youtube.com/watch?v=5HvsKPp2HU8', 33.5112686, 126.5231353, '제주특별자치도', '쯔양은 1,000원이라는 가격이 믿기지 않을 정도로 모든 음식이 맛있다고 극찬했습니다. 특히 1,000원 김밥은 내용물이 알차고 밥이 맛있게 양념되어 있으며, 햄 맛이 강하게 느껴져 아주 맛있다고 평가했습니다. 떡볶이는 매일 아침 직접 뽑은 떡을 사용해 치즈처럼 늘어날 정도로 부드럽고 쫄깃하며, 소스는 집에서 해주는 맛있는 맛이라고 언급했습니다. 라볶이, 계란라면, 만두, 참치김밥, 치즈김밥, 쫄면, 비빔밥 등 주문한 모든 메뉴에 대해 칭찬을 아끼지 않았으며, 특히 직접 만든 쫄면 소스와 고소한 참기름 맛을 높이 평가했습니다. 가격뿐만 아니라 음식의 퀄리티 자체가 매우 뛰어나며, 사장님의 요리 솜씨가 대단하다고 여러 차례 감탄했습니다.'),
('금복식당', '제주특별자치도 제주시 동문로 16', '064-757-6055', ARRAY['한식'], 'https://www.youtube.com/watch?v=NYcK7Cg0Ua0', 33.5127895, 126.5283174, '제주특별자치도', ''),
('서울떡볶이', '제주특별자치도 제주시 동문로4길 11', '064-726-9266', ARRAY['분식'], 'https://www.youtube.com/watch?v=NYcK7Cg0Ua0', 33.5122791, 126.5278017, '제주특별자치도', '국물이 많은 떡볶이로, 국물이 맛있다고 평가했습니다. 떡은 방앗간에서 만든 것처럼 쫄깃하며 옛날 학교 앞에서 팔던 맛있는 떡볶이 맛이라고 합니다. 특히 튀긴 고추가 엄청 크고 맛있으며, 튀김옷과 함께 녹는다고 감탄했습니다. 겨울에 딱 맞는 국물이라고 하며 만족스럽게 식사를 마쳤습니다, 0:02:44-0:05:08).'),
('번네식당', '제주특별자치도 서귀포시 안덕면 산방로 16', '064-792-1006', ARRAY['한식'], 'https://www.youtube.com/watch?v=3okMOI9wcfo', 33.2457077, 126.3297016, '제주특별자치도', '쯔양은 이 식당의 대표 메뉴인 뼈 없는 갈치조림을 먹기 매우 편리하다고 극찬했습니다. 갈치 살이 입에서 녹을 정도로 부드럽고, 양념은 너무 맵거나 달거나 짜지 않은 완벽한 밥도둑 맛이라고 평가했습니다. 또한, 조림에 함께 들어있는 감자와 무가 양념에 잘 배어있어 맛있다고 여러 차례 언급했습니다. 1미터에 달하는 통갈치구이는 크기에 감탄하며, 살이 매우 촉촉하고 부드럽다고 칭찬했습니다. 밑반찬과 미역국까지 모두 맛있다고 평가하며, 밥 세 공기를 비울 정도로 만족스러운 식사였다고 요약했습니다. 뼈가 거의 없어 먹기 편하다는 점을 가장 큰 장점으로 꼽았습니다.'),
('몰질식육식당', '제주특별자치도 서귀포시 이어도로 598', '064-739-1542', ARRAY['중식'], 'https://www.youtube.com/watch?v=6YLPoxJwoyU', 33.235363, 126.4802884, '제주특별자치도', '쯔양은 이 식당의 짬뽕이 일반적인 짬뽕과 달리 김치찌개나 고추장찌개 같은 독특한 맛을 낸다고 평가했습니다 . 국물이 너무 짜거나 맵지 않으면서도 매우 진하고 중독성이 강하다고 느꼈으며, 특히 푸짐하게 들어간 고기가 부드럽고 맛있다고 칭찬했습니다 . 짬뽕 외에 주문한 중화풍 우동 역시 국물이 진하고 맛있다고 언급했고, 만두는 껍질이 쫀득하고 속이 담백하여 짬뽕 국물과 잘 어울린다고 말했습니다 . 맛이 자극적이지 않아 물리지 않고 계속 먹을 수 있는 점을 큰 장점으로 꼽으며, 국물까지 남김없이 다 먹을 정도로 만족스러운 식사였다고 총평했습니다 .'),
('동궁찜닭 은평연신내점', '서울특별시 은평구 연서로29길 14-12 2층', '0507-1421-3383', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=SZsHrezUPm4', 37.6193774, 126.9192203, '서울특별시', '쯔양은 동궁찜닭 연신내점에서 여러 메뉴를 맛보며 다채로운 리뷰를 남겼습니다. - **황금찜닭**: 고추장과 안동찜닭의 황금 비율로 만든 시그니처 메뉴로, 소스가 훌륭하고 치즈의 풍미가 좋다고 평가했습니다. 닭고기도 다양한 부위가 섞여 있어 취향에 맞게 즐길 수 있다고 언급했습니다. - **로제찜닭**: 꾸덕하고 진한 로제 소스와 중국 당면의 조합을 칭찬했으며, 함께 제공되는 빵을 소스에 찍어 먹는 것을 추천했습니다. - **고불찜닭**: 처음에는 달콤하게 느껴지지만 먹을수록 후추의 매운맛이 올라오는 메뉴로, 해장에 좋을 것 같다고 말했습니다. 특히 납작만두와 함께 먹는 조합이 맛있다고 강조했습니다. - **안동찜닭**: 간장 베이스의 달콤한 맛으로 아이들이 좋아할 메뉴이며, 소스가 진하고 걸쭉해 재료에 잘 배어있다고 평가했습니다. - **닭도리탕**: 남은 양념에 으깬 감자와 밥을 비벼 먹는 것을 ''쯔양의 꿀팁''으로 소개하며 맛이 완벽하다고 극찬했습니다. - **동궁식혜**: 인공적인 단맛 없이 은은하고 깊은 맛이 나는 수제 식혜라고 여러 번 칭찬하며, 총 7리터를 마셨습니다. 전반적으로 모든 메뉴가 맛있으며, 특히 연말 홈파티 메뉴로 강력 추천했습니다.'),
('말고기연구소', '제주 제주시 북성로 43 1층', '0507-1308-8251', ARRAY['고기'], 'https://www.youtube.com/watch?v=XkjRApcHoJA', 33.5154613, 126.5202417, NULL, '쯔양은 “말도 안 되게 맛있다”고 극찬하며, 말고기에 대한 기존의 편견(잡내, 질긴 식감)을 완전히 깨는 맛이라고 평가했습니다. 고기에서 잡내가 전혀 나지 않고 소고기보다 부드러워 입에서 살살 녹는 식감이 일품이라고 언급했습니다[60, 72]. 특히 5초만 익혀 먹는 ''마샤브(샤브샤브)''의 진한 육수와 부드러운 고기의 조화를 칭찬했으며, 덮밥 메뉴는 크림처럼 부드럽다고 표현했습니다. 얼큰하고 칼칼한 마라맛이 나는 샤브샤브는 술안주로 제격이라고도 덧붙였습니다[59, 65]. 전반적으로 신선한 재료 덕분에 말고기의 참맛을 새롭게 경험하게 해준 곳이라고 종합적으로 평가했습니다.'),
('마라도별장식당', '제주특별자치도 서귀포시 대정읍 마라로101번길 43', '0507-1339-6461', ARRAY['중식'], 'https://www.youtube.com/watch?v=MvbqVkhViFM', 33.1183144, 126.2665506, '제주특별자치도', '쯔양은 이 식당의 짜장면과 탕수육을 리뷰했다. 짜장면은 일반적인 짜장면과 달리 특이하면서 중독성 있는 맛이라고 평가했다. 고기와 양파, 감자가 큼직하게 들어가 있으며, 새우와 톳이 들어있어 바다의 맛이 느껴진다고 언급했다. 특히 춘장 맛이 강하지 않으면서 감칠맛이 돌아 호불호가 갈릴 수 있지만 본인은 ''호''라고 밝혔다. 탕수육에 대해서는 ''인생 탕수육''이라고 극찬하며, 매우 바삭하고 맛있다고 여러 번 강조했다. 주변에서 마라도 짜장면에 대한 기대가 크지 않았으나, 직접 먹어보니 짜장면과 탕수육 모두 매우 만족스럽다고 평가했다. 또한, 식당에서 바라보는 경치가 매우 아름답다고 덧붙였다.'),
('웅담식당', '제주특별자치도 서귀포시 중앙로59번길 5', '064-762-6442', ARRAY['고기'], 'https://www.youtube.com/watch?v=YvwIXlP0z3c', 33.2498541, 126.5610421, '제주특별자치도', '쯔양은 32년간 방송에 한 번도 공개되지 않은 제주도민 추천 맛집이라고 소개하며 방문했습니다. 이 식당의 오겹살을 맛본 후 ''인생 최고의 오겹살''이라고 극찬했으며, 함께 간 제작진 모두가 동의했다고 합니다. 고기의 식감에 대해 너무 단단하지도, 무르지도 않은 완벽한 식감이며 한 입 베어 물면 육즙이 터져 나온다고 평가했습니다. 또한, 소금 없이 그냥 먹어도 맛있다고 감탄했습니다. 직접 담근 김치는 올해 먹어본 김치 중 최고라고 칭찬했고, 쌈장 역시 시판 제품이 아닌 직접 만든 것이라며 훌륭하다고 언급했습니다. 솥뚜껑에 구워 먹는 방식과 신선한 채소, 그리고 구수한 된장찌개 등 모든 요소에 만족감을 표현했습니다. 식사의 마무리로 먹은 볶음밥은 찹쌀밥 같은 식감에 간이 세지 않아 계속 들어가는 맛이라고 평가했습니다. 전반적으로 제주도에 이사 오고 싶을 만큼 만족스러운 식사였다고 총평했습니다.'),
('옛날국수갤러리', '제주특별자치도 제주시 한경면 고산로 73', '064-773-7778', ARRAY['한식'], 'https://www.youtube.com/watch?v=lB0Y9DpZga4', 33.3073333, 126.1780507, '제주특별자치도', '쯔양은 블로그에서 ''쯔양 꼭 와주세요''라는 글을 보고 이 식당을 방문했습니다. 이곳의 대표 메뉴인 초대형 잔치국수는 라면 8개 분량으로, 5년간 단 7명만 성공한 어려운 도전이었습니다. 쯔양은 국물을 맛본 후 멸치 육수임에도 비린 맛 없이 깔끔하고 진하다며 감탄했고, 맛이 너무 좋아 5,000원만 내기 미안할 정도라고 평가했습니다. 함께 나온 김치도 달고 맛있다고 칭찬했습니다. 또한 설탕 대신 효소로 단맛을 낸 비빔국수 양념을 맛보고, 달콤새콤하며 맛있다고 언급했습니다. 쯔양은 이 도전을 ''가장 힘들었던 먹방 도전 중 하나''로 꼽으며, 조미료 없이 정성으로 끓여낸 건강하고 진한 맛이라고 최종 평을 남겼습니다.'),
('마라예찬 화정본점', '경기 고양시 덕양구 화중로152번길 38-15', '0507-1400-0792', ARRAY['중식'], 'https://www.youtube.com/watch?v=MboGWV6Y7Mg', 37.6395234, 126.835007, '경기도', '쯔양은 이 식당의 대표 메뉴인 마라롱샤(마라 가재) 100마리 먹기 도전을 진행했습니다. 마라 소스에 대해 한 달간 숙성시킨 깊은 맛이라고 평하며, 시중에서 파는 소스와는 차원이 다른 예술적인 맛이라고 극찬했습니다. 매운 정도는 불닭볶음면보다 약간 덜하지만 상당히 맵다고 언급했습니다. 가재 살이 매우 통통하고 쫄깃하며, 이전에 먹어본 마라롱샤와는 비교가 안 될 정도로 맛있다고 평가했습니다. 또한, 새우볶음밥에 마라롱샤의 내장과 살, 소스를 비벼 먹는 조합을 ''환상적''이라고 표현했으며, 후식으로 주문한 파인애플 셔벗과 중국식 츄러스(유타오)도 매우 맛있게 먹었습니다. 전반적으로 PD의 추천 맛집임을 인정하며, 매우 만족스러운 식사였다고 총평했습니다.'),
('스시로 명동성당점', '서울 중구 명동길 58 1층, 2층', '0507-1333-7728', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=RaAVsPj5EIU', 37.5637522, 126.9855885, '서울특별시', '쯔양은 한국에 처음 도입된 ''디지로'' 시스템을 갖춘 스시로 명동성당점을 방문하여, 디지털 화면으로 주문하고 게임을 즐기는 방식이 매우 재미있다고 평가했습니다[attached_file:1, 0:82, 1:41]. 100가지가 넘는 다양한 메뉴에 만족감을 표하며, 전반적으로 생선이 신선하다고 언급했습니다[attached_file:1, 1:23, 2:28]. 특히 통영산 구운 삼치, 후추 마요 새우, 부드러운 가리비, 식감이 좋은 항정살, 트러플 가리비 등 독특한 메뉴들을 추천했습니다[attached_file:1, 2:72, 3:63, 3:81, 4:89, 7:43]. 또한 튀김류의 완성도가 높다고 칭찬했으며, 치즈케이크 같은 디저트도 훌륭하다고 평가했습니다[attached_file:1, 6:33, 11:33]. 전반적으로 게임과 다양한 메뉴 덕분에 아이들도 좋아할 만한 재미있는 맛집이라고 총평하며 100접시를 먹었습니다[attached_file:1, 12:02, 12:18].'),
('탐나는피자', '경기도 화성시 동탄대로 14길 6-18, 1층 103호', '1811-9290', ARRAY['피자'], 'https://www.youtube.com/watch?v=rEwwiHK97nc', 37.184349, 127.1029529, '경기도', '쯔양은 ''탐나는피자''가 기름지지 않고 담백해서 좋았다고 평가했습니다. 특히 빵(도우)이 쫄깃하며, 특제 마늘 소스와 와사비를 섞어 먹으면 느끼함을 잡아줘 맛있다고 추천했습니다. 가장 인상 깊었던 메뉴로 ''크레이지 핫 치킨 피자''와 ''프렌치 핫도그 피자''를 꼽았습니다. ''크레이지 핫 치킨 피자''는 매우 맵지만 소스가 맛있어 매운 음식을 좋아하는 사람들에게 추천했고, ''프렌치 핫도그 피자''는 피자 조각보다 큰 소시지와 소시지가 들어간 엣지를 극찬하며 재구매 의사를 밝혔습니다. 전반적으로 느끼하지 않고 끝까지 맛있게 즐길 수 있었다고 긍정적인 리뷰를 남겼습니다.'),
('남해식당', '서울 중구 남대문시장4길 42-1', '02-319-7245', ARRAY['한식'], 'https://www.youtube.com/watch?v=fFSyYTu6y70', 37.5583148, 126.9770226, '서울특별시', '쯔양은 9,000원 스페셜 세트의 엄청난 가성비와 푸짐한 양에 감탄했습니다. 맛은 아주 특별하기보다는 ''마음을 따뜻하게 해주는 집밥 같은 맛''이라고 표현했습니다. 진한 멸치육수의 칼국수, 쫄깃한 수제비, 고소한 보리비빔밥, ''예술''이라고 칭한 된장국 등 모든 메뉴를 맛있게 먹었습니다. 시장 특유의 분위기는 정겹지만 위생에 예민하다면 방문이 어려울 수 있다고 덧붙였습니다.'),
('조폭떡볶이', '서울 마포구 어울마당로 60', '+82-2-337-9933', ARRAY['분식'], 'https://www.youtube.com/watch?v=YOWsK4S5zmE', 37.5504074, 126.9213812, '서울특별시', '쯔양은 이 집을 고등학생 때부터 10년간 다닌 단골집이라고 소개했습니다[attached_file:1, ts:68, 245]. 떡볶이 소스가 다른 곳에서는 맛볼 수 없는 독특하면서도 익숙한 맛이라고 평가했으며, 10년 전과 맛이 변함이 없다고 말했습니다[attached_file:1, ts:77, 281]. 떡은 쫀득하고 식감이 좋으며, 소스는 맵지 않고 순하지만 약간의 칼칼함이 중독성 있다고 설명했습니다. 이번 방문에서 처음 먹어본 라면이 매우 맛있다고 놀라워했으며, 순대(특히 내장), 튀김, 어묵 등 다른 메뉴들도 맛있게 먹었습니다[attached_file:1, ts:451, 479]. 특히 튀김은 바삭함을 유지하기 위해 소스에 찍어 먹는 것을 선호한다고 언급했습니다. 또한, 손님들이 가게 직원들의 덩치가 큰 것을 보고 ''조폭이 운영하는 곳이냐''고 농담을 한 것에서 ''조폭떡볶이''라는 이름이 유래되었다는 사실을 알게 되어 신기해했습니다[attached_file:1, ts:694-709].'),
('샤브올데이 별내신도시점', '경기도 남양주시 두물로27번길 37 101호', '0507-1490-4467', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=TAsK5DHQPqQ', 37.6588616, 127.1255047, '경기도', '쯔양은 2만원 대 가격에 즐길 수 있는 최고의 뷔페 중 하나라고 극찬했습니다. 소셜 미디어에서 보고 방문을 계획했을 정도로 기대가 컸으며, 방문 후 매우 만족스러워했습니다. 넓고 고급스러운 매장 분위기와 한식, 중식, 일식, 양식을 아우르는 60여 가지의 다양한 음식에 감탄했습니다. 특히 20가지가 넘는 신선한 채소와 7가지의 다양한 소스를 장점으로 꼽았습니다. 4가지 육수(표고버섯, 사천 마라, 양지, 얼큰)를 모두 맛본 후, 개인적으로는 표고버섯 육수가 가장 맛있었다고 평가했습니다. 소고기는 질기거나 잡내가 없어 품질이 좋다고 언급했으며, 30분마다 새로 나오는 미나리 삼겹살은 매우 맛있어서 알람까지 맞춰놓고 먹을 정도였습니다. 또한, 호텔에서나 볼 수 있는 애플망고를 디저트로 제공하는 점과 맥주가 무제한이라는 점에 놀라움을 표했습니다. 전반적으로 음식의 맛, 다양성, 가성비 모든 면에서 높은 점수를 주며 모든 음식이 맛있다고 평가했습니다.'),
('미타우동 본점', '서울 송파구 송파대로49길 31 1층', '0507-1390-5212', ARRAY['아시안'], 'https://www.youtube.com/watch?v=u_waamv9-kE', 37.5066589, 127.1014407, '서울특별시', '쯔양은 석촌동에 위치한 우동 맛집 ''미타우동''을 방문하여 다양한 메뉴를 맛보았습니다. 이 식당은 면, 소스, 육수를 모두 직접 만드는 곳으로, 특히 이틀간 숙성시킨 자가제면의 쫄깃하고 잘 불지 않는 식감을 극찬했습니다. 여러 메뉴 중 ''김치카츠나베''를 가장 맛있는 메뉴로 꼽았으며, 신맛만 나는 다른 식당과 달리 깊은 감칠맛이 인상적이라고 평가했습니다. 사이드 메뉴 중에서는 웬만한 돈카츠 전문점보다 맛있다며 ''돈카츠''를 최고로 선택했습니다. 그 외에도 ''덴뿌라 우동''의 진한 육수, ''명란 앙카케 우동''의 부드러움, ''토리텐 부카케 우동''의 육즙 가득한 닭튀김 등 대부분의 메뉴에 만족감을 표현했습니다. 쯔양은 총 2kg가 넘는 양의 면을 먹으며 전반적으로 모든 메뉴가 훌륭했다고 평가했습니다.'),
('금성식당', '광주광역시 동구 제봉로222번길 2', '062-227-4717', ARRAY['고기'], 'https://www.youtube.com/watch?v=fXxl-YDU2uQ', 35.1550398, 126.9138819, '광주광역시', '쯔양은 이 식당을 개인적인 방문을 포함해 세 번째 방문할 정도로 좋아하는 곳이라고 밝혔습니다. 주 메뉴인 삼겹살과 김치찌개를 극찬했으며, 특히 삼겹살은 ''믿을 수 없을 정도''로 맛있다고 평가했습니다. 김치찌개에는 묵은지가 통째로 들어가 깊은 맛을 낸다고 설명했습니다. 또한, 할머니가 구워주시던 맛이 나는 ''구운 김''을 특별 메뉴로 추천했으며, 독특한 식감의 파절이와 쫄깃한 갈치속젓도 별미로 꼽았습니다. ''쯔양 공인 미슐랭 3스타''라고 장난스럽게 칭하며 집 앞에 옮겨놓고 싶을 정도의 맛집이라고 만족감을 표했습니다. 과거의 맛을 뛰어넘는 최고의 맛이었다며 ''인생 맛집''으로 꼽았습니다.'),
('영창식당', '광주 서구 천변좌로 224-1 복개상가 2층', '062-365-1372', ARRAY['한식'], 'https://www.youtube.com/watch?v=YV4Z94DvWdA', 35.1550942, 126.9013648, NULL, '쯔양은 이곳이 44년 전통의 불고기 백반 전문점이라고 소개했습니다. 불고기 국물이 일반적인 불고기와 달리 짜거나 달지 않고, 샤부샤부를 오래 끓인 듯한 깊고 풍부한 맛이 난다고 평가했습니다. 평소 채소를 많이 먹지 않는 자신조차 콩나물 반찬을 한번에 다 먹을 정도로 맛있다며, 파김치와 오징어무침을 포함한 모든 반찬의 간이 절묘하다고 극찬했습니다. 1인분에 12,000원이라는 가격에 푸짐한 반찬까지 제공되는 가성비에 놀라워했으며, 몸 상태가 좋지 않았음에도 불구하고 식사를 시작하자마자 입맛이 돌아왔다고 언급했습니다. 식사를 마친 후 ''진짜 너무 완벽한 한 끼''였다며 높은 만족감을 표현했습니다.'),
('금은옥', '전북 순창군 팔덕면 찬물내기길 2', '0507-1427-2391', ARRAY['한식'], 'https://www.youtube.com/watch?v=R4l1zUbM-dM', 35.3799051, 127.102122, '전라북도', '쯔양은 순창삼합의 구성(고추장 장어구이, 간장김치, 청국장 수육)이 처음에는 생소했지만, 먹어보니 각 재료의 맛이 서로를 보완하며 환상적인 조화를 이룬다고 극찬했습니다. 그녀는 순창의 장맛이 현대적으로 재해석된 이 음식을 많은 사람들이 맛보길 강력히 추천하며, 순창의 미식 관광 잠재력을 높이 평가했습니다.'),
('대궁', '전북 순창군 순창읍 순창5길 20', '063-653-8234', ARRAY['한식'], 'https://www.youtube.com/watch?v=R4l1zUbM-dM', 35.373588, 127.1404268, '전라북도', '쯔양은 순창삼합을 맛본 후, 익숙하지 않은 조합이지만 맛이 매우 조화롭고 훌륭하다고 감탄했습니다. 순창의 3대 장(고추장, 간장, 된장/청국장)을 활용해 만든 장어구이, 간장김치, 수육의 맛을 높이 평가하며, 많은 사람들이 순창을 방문해 이 맛을 직접 느껴보기를 바란다고 말했습니다.'),
('녹원', '전북 순창군 순창읍 순창5길 28', '063-653-2673', ARRAY['한식'], 'https://www.youtube.com/watch?v=R4l1zUbM-dM', 35.3738416, 127.1397271, '전라북도', '쯔양은 순창삼합이 처음 접하는 조합임에도 불구하고 각 재료의 맛이 훌륭하게 어우러진다고 평가했습니다. 특히 순창의 전통 장을 활용한 고추장 장어구이, 간장김치, 청국장 소스를 곁들인 수육의 독특한 맛을 칭찬하며, 시청자들에게 순창에 방문하여 이 특별한 음식을 맛보라고 강력히 추천했습니다.'),
('뜨란채', '전북 순창군 팔덕면 강천로 664-26', '063-653-1305', ARRAY['한식'], 'https://www.youtube.com/watch?v=R4l1zUbM-dM', 35.4159064, 127.0775047, '전라북도', '쯔양은 순창삼합에 대해 처음 먹어보는 조합임에도 불구하고 매우 조화롭고 맛있다고 평가했습니다. 순창의 특산물인 고추장, 간장, 된장을 활용한 고추장 장어구이, 간장김치, 청국장 수육의 조합을 극찬하며, 이 맛을 다른 사람들도 꼭 경험해보기를 추천했습니다. 또한 강천산 등 순창의 다른 볼거리와 먹거리도 함께 언급하며 방문을 독려했습니다.'),
('넘버원양꼬치', '서울 용산구 대사관로 76 2층', '02-797-6518', ARRAY['고기'], 'https://www.youtube.com/watch?v=JTRm4YWo8IU', 37.533047, 127.0064931, '서울특별시', '쯔양은 한남동에 위치한 40년 전통의 양꼬치 맛집 ''넘버원양꼬치''를 방문하여 양꼬치뿐만 아니라 다양한 요리 메뉴를 맛보았습니다. 쯔양은 이곳이 요리류가 특히 맛있다고 언급하며, 꿍바오새우, 철판도가니, 마파두부, 모닝글로리, 황진위미, 양갈비, 양등심 등 여러 메뉴를 주문했습니다. 각각의 요리에 대해 상세한 맛 평가를 남겼습니다. ''꿍바오새우''는 새우 식감이 좋고 마라가 들어간 새콤한 소스가 독특하다고 평했습니다. ''양갈비''는 육즙이 풍부하고 고기가 부드러워 뜯는 맛이 일품이라고 극찬했습니다. 평소 두부를 즐기지 않음에도 ''마파두부''는 입에서 녹는 부드러운 식감과 적당한 마라 향이 인상 깊었다고 합니다. ''황진위미(옥수수 요리)''는 바삭하고 달콤한 맛으로 다이어트를 잊게 할 정도라고 표현했습니다. ''모닝글로리''는 태국에서 먹던 맛 그대로라며 술안주로 제격이라고 말했습니다. ''양등심''은 탱탱한 식감이 특징이라고 언급했습니다. 쯔양은 전반적으로 모든 요리가 실패 없이 맛있으며, 왜 사람들이 줄 서서 먹는지 알겠다고 총평하며 만족감을 드러냈습니다.'),
('르 팔레 (Le Palais)', '17F, Palais de Chine Hotel, 3, Section 1, Chengde Road, Datong District, Taipei, 103, Taiwan', '+886-2-2181-9950', ARRAY['중식'], 'https://www.youtube.com/watch?v=XFIdY5DKdHs', 25.0492706, 121.5169525, NULL, '쯔양은 ''르 팔레''에서의 식사 경험이 전반적으로 매우 고급스럽고, 손님으로서 존중받는 느낌을 받았다고 평가했습니다. 특히 ''바삭한 랍스터 새우 창펀''을 2024년 최고의 음식으로 꼽으며 강력히 추천했습니다[attached_file:1, ts:1408, 1414]. 이 메뉴는 겉은 바삭하고 속은 촉촉하며, 랍스터와 새우가 풍성하게 들어있어 10개라도 더 먹고 싶을 만큼 맛있었다고 합니다. 광둥식 오리 구이는 부위별로 다양한 식감과 풍미를 즐길 수 있었으며, 특히 오리 다리살의 풍부한 육즙과 쫄깃한 껍질을 극찬했습니다. 다른 요리들에 대해서도 익숙하면서도 세련된 맛이라고 평가했으며, ''전복을 올린 쇼마이''와 ''식초 소스 돼지갈비 튀김'' 등 대부분의 음식에 만족감을 표했습니다. 다만, 거위 발 요리는 비주얼 때문에 먹기 힘들어했으며[attached_file:1, ts:884, 891], 오리 뼈죽에서는 익숙하지 않은 한약재 같은 향이 느껴졌다고 언급했습니다. 디저트 중에서는 커스터드 번이 덩어리 없이 부드럽고 완벽하게 달콤하여 특히 마음에 들어 했습니다. 총평으로 음식의 맛뿐만 아니라 서비스와 플레이팅까지 모든 면에서 훌륭한 레스토랑이었다고 요약했습니다[attached_file:1, ts:1421, 1429].'),
('딘타이펑 타이베이 101점', 'B1, No. 45, Shifu Rd, Xinyi District, Taipei City, Taiwan 110', '+886 2 8101 7799', ARRAY['중식'], 'https://www.youtube.com/watch?v=M36TycatOOY', 25.0339, 121.5651, NULL, '쯔양은 딘타이펑에 대해 전반적으로 매우 만족하며, 오랜 대기 시간을 감수할 가치가 있는 맛집이라고 평가했습니다. 특히 ''새우 돼지고기 샤오마이''를 가장 맛있는 메뉴로 꼽았으며, ''거대 돼지고기 찐빵''과 ''닭고기 샤오롱바오''의 풍부한 육즙을 극찬했습니다. 트러플 샤오롱바오는 인공적이지 않은 깊은 풍미가 인상적이라고 언급했고, 간장 소스의 ''돼지고기 완탕''은 한국의 잡채가 생각나는 맛이라며 추천했습니다. 반면, ''찹쌀 돼지고기 샤오마이'', 쓴맛이 나는 ''여주 갈비탕'', ''야채 샤오롱바오''는 자신의 입맛에는 맞지 않았다고 밝혔습니다. 디저트 중에서는 ''초콜릿 찐빵''을 1위로 꼽았습니다. 전체적으로 향신료가 느껴지지만 대부분의 메뉴가 대중적으로 맛있게 즐길 수 있는 맛이라고 총평했습니다.'),
('우마왕 스테이크 스린 점 (牛魔王牛排 士林店)', 'No. 83, Danan Rd, Shilin District, Taipei City, Taiwan 111', '+886228838891', ARRAY['고기'], 'https://www.youtube.com/watch?v=ZNg4ydyfUqY', 25.0866, 121.5254, NULL, '쯔양은 이곳을 대만 현지 분위기를 느낄 수 있는 옛날 스타일의 스테이크 맛집이라고 소개했습니다. 방문 당시 등심, 티본, 치킨, 대구, 안심 스테이크 다섯 종류를 주문했으며, 총 가격은 약 52,000원이었습니다. 기본으로 제공되는 옥수수 수프와 홍차는 무한리필이 가능하며, 옥수수 수프는 한국보다 묽지만 중독성 있는 맛이라고 평가했습니다. 소스는 후추 맛이 강한 ''핫 스파이시'', ''마일드'', ''노 스파이시'' 세 가지가 있으며, 돈가스 소스와 비슷하지만 단맛이 적고 후추 향이 강한 것이 특징이라고 설명하며 ''핫 스파이시'' 소스를 추천했습니다. - **대구 스테이크**: 입에서 녹을 정도로 부드러워 숟가락으로 떠먹을 수 있을 정도라며, 이곳의 1위 메뉴로 꼽았습니다. - **등심 스테이크 (8,000원)**: 거대한 크기에도 불구하고 부드럽고 아주 맛있으며, 고기 질이 훌륭하다고 극찬했습니다. - **치킨 스테이크**: 뼈 없는 닭다리 살로, 두껍고 육즙이 풍부하며 껍질이 쫄깃해서 맛있다고 평가했습니다. - **티본 스테이크 (약 13,900원)**: 기름지지 않고 담백하며, 덜 익은 부분이 특히 부드럽고 맛있었다고 합니다. - **안심 스테이크**: 마시멜로처럼 으깨지는 독특한 식감이 특징이며 맛있다고 언급했습니다. 최종적으로 쯔양은 대구 스테이크를 1위, 등심 스테이크를 2위, 치킨 스테이크를 3위로 선정하며, 만약 두 가지만 먹는다면 대구와 치킨을 선택하겠다고 밝혔습니다.'),
('오단이꼬마김밥', '경북 김천시 평화순환길 8', '054-434-7924', ARRAY['분식'], 'https://www.youtube.com/watch?v=IPYGtzB-Yzk', 36.1255176, 128.1068412, '경상북도', '30년 전통의 꼬마김밥으로, 어묵과 단무지만 들어간 단순한 구성이지만 중독성이 강하다고 평가했습니다. 처음에는 평범하게 느껴지지만 씹을수록 고소하고 짭짤하며 단맛이 올라와 질리지 않는 맛이라고 설명했습니다(ts:210, 238). 특히 어묵의 쫄깃한 식감과 완벽한 간을 칭찬하며, 마지막 한입까지 맛있게 먹었다고 언급했습니다(ts:223, 367).'),
('다담김밥', '경상북도 김천시 구름다리3길 12-12 (평화동)', '010-3062-5515', ARRAY['분식'], 'https://www.youtube.com/watch?v=IPYGtzB-Yzk', 36.1253792, 128.1170668, '경상북도', '지금껏 먹어본 김밥 중 가장 맛있었다며 극찬했습니다. 특히 소고기김밥을 ''역대급''이라고 평가하며, 촉촉한 소불고기 맛이 일품이라고 했습니다. 참치김밥은 내용물이 가득 차 매우 촉촉하고 밥 양이 적어 좋았다고 말했습니다. 함께 먹은 떡볶이와 새우 향이 나는 어묵우동도 소스가 훌륭하고 맛있다고 칭찬했습니다(ts:503, 529).'),
('선비꼬마김밥 김천1호점', '경상북도 김천시 혁신3로 16 로제니아 제1동 105호', '054-431-8855', ARRAY['분식'], 'https://www.youtube.com/watch?v=IPYGtzB-Yzk', 36.1175931, 128.1819973, '경상북도', '기본 꼬마김밥 자체로도 밥에 간이 잘 되어있어 매우 고소하고 맛있다고 평가했습니다. 이 식당의 가장 큰 특징으로 다양한 소스를 꼽았는데, 마크니 커리 소스와 청양고추 소스가 특히 인상적이었다고 언급했습니다(ts:890, 906). 함께 주문한 라면과도 궁합이 좋았고, 매콤한 진미채 김밥도 맛있게 먹었다고 전했습니다(ts:754, 805).'),
('500원부침개', '서울 동대문구 전농로 145', '010-4923-6634', ARRAY['분식'], 'https://www.youtube.com/watch?v=dKicDGqKkrs', 37.5777327, 127.0572239, '서울특별시', '쯔양은 23년간 부침개 가격을 500원으로 유지한 것에 대해 크게 감탄하며 사장님에 대한 존경심을 표했습니다. 부침개 맛은 기름지지 않고 담백하며, 마치 할머니가 만들어준 것 같은 맛이라고 평가했습니다. 얇은 반죽에 배추와 부추 등 채소가 풍부하게 들어 있으며, 고추가 들어가 끝맛이 살짝 매콤하다고 설명했습니다. 아주 특별한 맛은 아니지만, 계속해서 먹게 되는 중독성 있는 맛이라며 만족감을 표현했습니다.'),
('성미찻집', '서울 종로구 종로 212 광장시장 동부 A35호', '02-2272-2827', ARRAY['분식'], 'https://www.youtube.com/watch?v=WkQrMzwqKv4', 37.5712134, 127.0011286, '서울특별시', '쯔양은 ''라면의 달인''이 있다는 소문을 듣고 식당을 방문했다. 그녀는 총 10종류의 라면을 먹으며 각각의 맛을 상세히 평가했다. 신라면은 면이 완벽하게 익었고 국물이 잘 배어있다고 칭찬했으며, 짜파게티는 완벽하게 졸여진 상태와 계란 프라이의 조화를 극찬하며 두 그릇을 먹었다. 오징어짬뽕은 진한 해물 맛, 팔도비빔면은 완벽한 국물 양을 장점으로 꼽았다. 너구리는 계란 없이 먹는 것이 더 맛있다며, 두 번째 주문 시에는 더 짜게 끓여달라고 요청하기도 했다. 전반적으로 사장님의 라면 끓이는 솜씨가 매우 뛰어나 어떤 라면이든 맛있게 만들어낸다고 극찬했으며, 망고주스와 수박주스 등 과일 음료도 내용물이 가득 차 맛있다고 언급했다.'),
('영양보리밥', '서울특별시 종로구 종로5.6가동 동호로 403-3', '02-2265-9351', ARRAY['한식'], 'https://www.youtube.com/watch?v=WkQrMzwqKv4', 37.5709477, 126.9778787, '서울특별시', ''),
('7-ELEVEN 류푸먼시 점 (六福門市)', '108 Taipei City, Wanhua District, Section 2, Hankou St, 73 1', '+886223311176', ARRAY['분식'], 'https://www.youtube.com/watch?v=KQdyVGZnKeU', 25.046151, 121.5052561, NULL, '대만식 샌드위치는 홍루이젠보다 덜 달아서 맛있고, 유부초밥은 매우 촉촉해서 집에서 만든 맛 같다고 평가함. 에그타르트로 착각한 타로 파이는 치즈와 타로가 들어간 듯하며 매우 맛있다고 함. 특히 편의점 샤오롱바오는 식었음에도 피가 쫄깃하고 육즙이 풍부해 식당에서 파는 것만큼 맛있다고 극찬함. 레이즈 김맛 감자칩은 계란 프라이 맛이 난다고 신기해했으며, 파인애플 빵과 ''국민 과자''로 소개된 코코넛 과자도 맛있다고 언급함. 새우 컵라면은 국물이 맑고 시원하며 담백해서 해장용으로 좋고, 향신료 맛이 전혀 나지 않아 한국인 입맛에 잘 맞는다고 평가함.'),
('아종면선 (阿宗麵線)', 'No. 8-1, Emei St, Wanhua District, Taipei City, 108, Taiwan', '+886 2 2388 8808', ARRAY['분식'], 'https://www.youtube.com/watch?v=KQdyVGZnKeU', 25.0432921, 121.5077098, NULL, '시먼딩에서 먹은 곱창국수가 매우 맛있어서 깜짝 놀랐다고 함. 가쓰오부시의 맛과 향이 진하게 나지만 아주 맛있어서, 마지막 날 비슷한 메뉴로 촬영할지 고민할 정도라고 평가함.'),
('꽃새우 영번지 역삼점', '서울 강남구 언주로 536', '02-501-2050', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=Eru0qdlHTAU', 37.5061935, 127.0413727, '서울특별시', '쯔양은 처음에는 살아 움직이는 새우를 보고 무서워하는 반응을 보였지만, 이내 맛을 본 후에는 “맛있는 애들이구나”라고 말하며 두려움이 사라졌다고 언급합니다. “이 맛 참을 수 없어”라고 감탄하며, 새우 머리를 손질하는 시간을 “행복한 머리 해체 타임”이라고 표현할 정도로 맛에 대해 높은 만족감을 드러냈습니다.'),
('국수리국수집', '경기 양평군 양서면 경강로 1061', '031-772-2433', ARRAY['한식'], 'https://www.youtube.com/watch?v=hL_x_2K7qBE', 37.5132134, 127.4038759, '경기도', '유튜버는 ''국수리 국수집''에서 칼국수를 먹었습니다. 면발이 두껍고 쫀득쫀득해서 자신이 가장 좋아하는 식감이라고 극찬하며, 정말 맛있다고 평가했습니다. 영상 마지막에 ''확실히 국수리 국수는 맛있네요''라고 언급하며 맛집임을 강조했습니다.'),
('한촌설렁탕&갈비 부천본점', '경기도 부천시 경인로 92', '032-668-2566', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=xueEUH34TXA', 37.4835689, 126.7653857, '경기도', '쯔양은 한촌설렁탕을 50번 이상 방문했을 정도로 매우 좋아하는 단골 맛집이라고 소개했습니다. 영상에서 특설렁탕, 얼큰설렁탕, 꼬리곰탕, 누룽지반계탕, 도가니탕, 한촌불고기 등 다양한 메뉴를 맛보았습니다. 도가니탕은 국물이 매우 진하고, 도가니가 입에서 녹을 정도로 쫀득한 식감이라고 평가했습니다. 특설렁탕은 일반 설렁탕보다 고기가 2배 많고 부드럽다고 언급하며, 국밥의 맛을 좌우하는 김치의 중요성을 강조했습니다. 특히 꼬리곰탕과 신메뉴인 누룽지반계탕을 그날의 ''원픽''으로 꼽으며 극찬했습니다. 꼬리곰탕은 국물이 진하고 간을 하지 않아도 맛있으며, 꼬리뼈의 살이 매우 부드럽다고 평했습니다. 누룽지반계탕은 닭고기가 매우 부드러워 젓가락만으로도 살이 발라질 정도이며, 국물이 진국이라 삼계탕 전문점 못지않다고 감탄했습니다. 전반적으로 모든 메뉴가 맛있다고 평가했으며, 더운 여름 ''이열치열'' 보양식으로 즐기기 좋은 곳이라고 추천했습니다.'),
('양평솥뚜껑닭볶음탕', '경기 양평군 청운면 오목골길 33', '0507-1369-3401', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=1WWZmyl9NoA', 37.5603833, 127.7350748, '경기도', '영상에서 쯔양은 75도의 뜨거운 찜질방에서 음식을 먹으며 ''이열치열''을 언급합니다. 이후 아이스방으로 이동해 ''천국이야, 진짜 시원하고 너무 좋다''며 만족감을 표현하고, 야외 풍경을 볼 수 있는 점도 좋다고 말합니다. 다른 정보에 따르면 쯔양은 이 식당의 대표 메뉴인 대왕 솥뚜껑 닭볶음탕을 먹고 난 뒤 볶음밥과 식혜까지 모두 먹으며 식사를 마무리했습니다.'),
('가평휴게소 양양방향', '경기도 가평군 설악면 미사리로540번길 51', '031-584-8200', ARRAY['한식'], 'https://www.youtube.com/watch?v=bmhPsEmz2Ss', 37.7019216, 127.5467986, '경기도', '전반적으로 가평휴게소 음식에 대해 ''맛있는 게 너무 많다'', ''맛집이다''라며 극찬했습니다. 각 메뉴에 대한 평가는 다음과 같습니다. - 열무국수: 면발이 굵고 쫄깃하며, 더위가 싹 가시는 시원한 맛으로 여름에 인기가 많을 것이라 예상했습니다. - 파닭꼬치: 주문 즉시 구워주며, 파가 달고 수분이 많아 맛있다고 평가했습니다. 특히 매운맛 꼬치는 달콤하면서도 알싸한 매운맛이 점차 올라온다고 언급했습니다. - 제육덮밥: 출시 예정인 신메뉴로, 색깔부터 맛있어 보이며, 달고 짠맛과 감칠맛이 일품인 집밥 같은 맛이라고 칭찬했습니다. - 갈떡갈떡: 처음 보는 메뉴로, 떡갈비가 매우 육즙이 풍부하고 함께 제공되는 소스는 달지 않고 매콤한 맛이 특징이라고 설명했습니다. - 부추불고기라면: 라면에 부추와 불고기가 더해져 고급스러운 맛이 난다고 평가했습니다. - 옛날돈까스: 특별한 맛 평가보다는 통째로 들고 뜯어 먹는 즐거움을 보여주었습니다. - 어묵우동: 휴게소의 인기 메뉴로, 어묵의 퀄리티가 좋다고 언급했습니다. - 잣 호두과자: 가평 특산물인 잣이 들어가 가장 좋아하는 호두과자이자 세상에서 제일 맛있다고 극찬했습니다. - 어묵바: 생선 함량이 높아 속이 하얗고 매우 쫄깃하다고 평가했습니다. - 떡볶이: 쌀떡으로 만들어졌으며, 남은 국물에 만두를 찍어 먹는 모습을 보였습니다.'),
('군만두의달인', '서울 동대문구 전농로2가길 13', '010-6487-2465', ARRAY['분식'], 'https://www.youtube.com/watch?v=u7CdpfMxPrk', 37.5674579, 127.0572558, '서울특별시', '쯔양은 군만두 1개가 200원이라는 매우 저렴한 가격에 놀라며, 100개를 주문해 먹었습니다. 만두피는 쫄깃하면서도 바삭하고, 속은 간이 잘 배어 있어 간장을 찍지 않아도 맛있다고 평가했습니다. 특히 일반적인 만두와는 다른 속 재료가 들어있어 독특하고 중독성 있는 맛이라고 칭찬하며, 먹고 나서도 속이 편안하다고 언급했습니다. 쯔양은 1,000개를 팔아도 남는 것이 없을 것 같다며 사장님을 걱정하는 모습을 보였고, 맛에 감탄하여 집에서 먹을 만두를 추가로 포장해갔습니다.'),
('피자먹다 광교점', '경기도 수원시 영통구 센트럴타운로 111 광교스타힐스 1층 106호', '031-211-9990', ARRAY['피자'], 'https://www.youtube.com/watch?v=2-HzvxrREac', 37.2925601, 127.0491306, '경기도', '쯔양은 1인용 25cm 네모 피자라는 컨셉이 간편하고 혼자 먹기 좋다고 평가했습니다. 특히 가격이 매우 저렴함에도 불구하고, 매일 숙성시켜 겉은 바삭하고 속은 쫀득한 도우와 100% 자연 치즈를 사용하는 등 높은 퀄리티에 감탄했습니다. 쯔양은 비프스테이크, 통통새우, 스위트불고기, 치즈불닭 등 다양한 피자를 맛보았고, 각각의 피자가 토핑뿐만 아니라 베이스 소스(토마토, 살사, 특제소스 등)도 달라 맛이 완전히 차별화된다는 점을 장점으로 꼽았습니다. 가장 매운 치즈불닭 피자는 불닭볶음면보다 맵다고 느꼈으며, 고구마 피자와 포테이토 피자를 개인적으로 가장 좋아한다고 밝혔습니다. 로제 파스타 역시 피자와 잘 어울리는 맛이라고 언급하며 전반적으로 모든 메뉴가 맛있고, 여러 종류를 골라 먹을 수 있어 만족스럽다는 리뷰를 남겼습니다.'),
('인사동항아리수제비', '서울 종로구 인사동8길 14-1', '02-735-3361', ARRAY['한식'], 'https://www.youtube.com/watch?v=ojZB1DHDzwE', 37.5741563, 126.9860418, '서울특별시', '쯔양은 이곳이 자신이 좋아하는 수제비 맛집이라며, 33년 전통을 가진 곳이라고 소개했습니다. 항아리에 담겨 나오는 푸짐한 양을 여러 차례 강조했으며, 2인분이 거의 3인분에 가깝다고 언급했습니다. 그녀는 기본, 얼큰, 들깨 수제비와 해물파전을 주문했습니다. 기본 수제비는 해산물 육수 베이스에 굴이 들어가며, 반죽의 두께와 식감이 완벽하다고 평가했습니다. 얼큰 수제비는 김치가 들어가지 않았음에도 시원하고 칼칼한 맛이 일품이며, 특히 숙취 해소에 좋다고 극찬하며 가장 맛있는 메뉴로 꼽았습니다. 들깨 수제비는 고소하고 맛있으며, 약간 식었을 때 풍미가 더 살아난다고 평했습니다. 해물파전은 밀가루보다 계란의 맛이 더 느껴지는 점을 특징으로 꼽았고, 함께 제공되는 겉절이 김치는 먹어본 것 중 최고라고 칭찬했습니다. 쯔양은 이 식당을 자신의 ''수제비 맛집 TOP 5'' 중 하나로 꼽았습니다.'),
('옵 아러이 타운 인 타운', '1329 53 Lat Phrao 94 Alley, Phlabphla, Wang Thongla Bangkok 10310', '+66658766555', ARRAY['아시안'], 'https://www.youtube.com/watch?v=SYB13wqDt0A', 13.7575271, 100.5978348, '태국', ''),
('조선닭꼬치 가락점', '서울 송파구 송파대로30길 27-1', '02-6956-1222', ARRAY['치킨'], 'https://www.youtube.com/watch?v=iyUTkrVrdKs', 37.4955802, 127.120176, '서울특별시', '쯔양은 대표 메뉴인 ''세종대왕꼬치''에 대해 1미터에 달하는 거대한 크기에 놀라며, 닭다리살로 만들어져 기름지면서도 담백하고 숯불 향이 강하게 느껴져 아주 맛있다고 평가했습니다. ''와인 슬러시''는 일반적인 포도 슬러시와 달리 와인 맛이 진하게 나며 여름에 마시기 좋고, 레드, 화이트, 하프앤하프 세 종류 모두 각기 다른 매력이 있다고 언급했습니다. 그 외에도 ''장어계란말이''는 계란의 단맛과 장어의 쫄깃함이 어우러져 맛있고, ''버터크리미옥수수''는 튀긴 옥수수의 터지는 식감과 독특한 맛이 술안주로 제격이라고 칭찬했습니다. ''닭껍질만두''의 바삭함과 잡내 없는 속, ''어묵탕''의 진한 가쓰오부시 국물 맛도 훌륭하다고 평가했습니다. 전반적으로 음식들이 독특하고 맛있으며, 특히 술과 함께 즐기기 좋은 메뉴가 많아 다음에 다시 방문해 술을 마시고 싶다고 말하며 만족감을 표현했습니다.'),
('즉떡이네', '서울 강동구 천호옛길 96', '02-477-9267', ARRAY['분식'], 'https://www.youtube.com/watch?v=iRVsSHvinkk', 37.537097, 127.1261801, '서울특별시', '쯔양은 사장님이 맛없다고 겸손하게 말하는 것과는 달리, 1인분에 2,000원이라는 저렴한 가격에 감탄하며 떡볶이를 매우 맛있게 먹었습니다. 특히, 기본맛과 짜장맛이 섞인 ''믹스'' 맛을 추천했으며 국물이 텁텁하지 않고 깔끔하다고 평가했습니다. 떡볶이 외에 야채곱창 등의 다른 메뉴도 함께 주문하여 즐겼습니다.'),
('준코노래타운 신림2호점', '서울특별시 관악구 신림로59길 14 지하1층, 2층', '02-877-1243', ARRAY['야식'], 'https://www.youtube.com/watch?v=UUwpPowvgSM', 37.4832997, 126.9287733, '서울특별시', '쯔양은 이곳을 채널 최초의 노래방 먹방 장소로 선택했습니다. 방문 목적은 ''준코라면''으로, 이곳의 라면이 특히 맛있다고 여러 번 강조했습니다. 라면 국물에서 청양고추의 칼칼한 맛이 느껴져 맛있다고 평가하며, ''준코라면은 준코에서 먹어야 제맛''이라고 말했습니다. 또한, 칠리새우, 프라이드치킨, 돈까스 등 다양한 안주를 주문했으며, 셀프바에서 제공되는 과자류와 기본 안주가 무한리필이라는 점도 언급했습니다.'),
('인주 한옥점', '충남 아산시 인주면 아산만로 1608', '041-532-1010', ARRAY['카페·디저트'], 'https://www.youtube.com/watch?v=2VO9YRB1qY4', 36.8674471, 126.874819, '충청남도', '카페에 들어서자마자 넓고 아름다운 한옥 건물과 바로 뒤로 펼쳐진 논 풍경에 감탄했습니다. 대표 메뉴인 ''인주쌀빵''을 먹어보고는 찹쌀떡처럼 매우 쫀득한(''쫜득함'') 식감에 놀라워하며, 이 빵은 오직 이 카페에서만 맛볼 수 있다고 언급했습니다. ''땅콩크림빵'' 또한 맛있다고 평가했으며, ''인주라떼''는 매우 크리미하고 맛있다고 말했습니다. 쯔양은 인주 장어촌이나 염치 한우촌에서 식사 후 디저트를 즐기기 위해 방문하기 좋은 곳이라고 추천했습니다.'),
('빤타리', '9 Soi Sukhumvit 8, Khlong Toei, Bangkok 10110, Thailand', '+66868015477', ARRAY['아시안'], 'https://www.youtube.com/watch?v=Qq4TaFlxErQ', 13.74023, 100.55671, '태국', '쯔양은 튀긴 쏨땀을 처음 먹어본다고 언급하며, 튀김과 소스가 아주 맛있다고 평가했습니다. 또한, 태국 음식을 처음 접하는 사람도 쉽게 즐길 수 있는 맛이며, 한국인 입맛에 80% 이상 맞을 것이라고 확신하며 강력히 추천했습니다.'),
('빤타리', '11, 13 Soi Sukhumvit 8, Khlong Toei, Bangkok 10110, Thailand', '+66 86 801 5477', ARRAY['아시안'], 'https://www.youtube.com/watch?v=f8t6SPwiSr4', 13.7395278, 100.5561659, '태국', '쯔양은 첫 방문 때의 맛을 잊지 못해 다시 찾아온 ''로컬 찐맛집''이라고 소개했다. 특히 튀김 쏨땀을 별미로 꼽으며 모두가 좋아할 맛이라 평가했고, 한국에서는 입맛에 맞지 않았던 푸팟퐁커리도 이곳에서는 스모크 향과 부드러운 계란의 조화가 훌륭하다고 극찬했다. 팟 카파오 무쌉은 매우 맵지만 감칠맛이 강해 한국인 99%가 좋아할 맛이라고 확신했다. 돼지고기 오믈렛은 먹어본 것 중 최고라며 짭짤한 간과 부드러운 식감을 칭찬했고, 닭날개 튀김은 ''튀김 강국인 우리나라를 긴장시킬 정도''로 부드럽고 맛있다고 감탄했다. 전반적으로 주문한 11가지 메뉴 모두에 대해 높은 만족도를 보였으며, 한국인의 80% 이상이 성공할 맛집이라고 강력히 추천했다.'),
('KHAO-SO-i', '14/2-3 Convent Rd, Khwaeng Silom, Khet Bang Rak, Krung Thep Maha Nakhon 10500, Thailand', '+66625913791', ARRAY['아시안'], 'https://www.youtube.com/watch?v=xcBRA39XB5s', 13.7255, 100.533, '태국', '태국식 밀크티가 한국에서 맛본 것과 차원이 다르다며 감탄했다 . 볶음 카오소이는 크리미한 그린 커리 맛이, 랍스터 카오소이는 고기가 매우 맛있다고 평가했다 . 특히 와규 볶음 카오소이는 불맛이 인상적이고 중독성이 강해 강력 추천했으며, 향신료 초보자도 즐길 수 있을 만큼 크리미하다고 언급했다 .'),
('청년고기장수 독산점', '서울 금천구 시흥대로 336 1층', '0507-1465-8703', ARRAY['고기'], 'https://www.youtube.com/watch?v=sU7es-L8YRI', 37.463617, 126.8978613, '서울특별시', '쯔양은 신메뉴인 ''숯불뼈구이''를 맛보기 위해 방문했으며, 국내 최초로 뼈구이를 무한리필로 제공하는 점이 인상적이라고 언급했습니다. 뼈구이는 전문점 못지않게 맛있고, 살이 부드럽고 연하며, 매콤한 소스를 찍어 먹으면 더욱 맛있다고 평가했습니다. 돼지갈비는 ''역대급''으로 맛있다며, 고기 질감이 매우 부드럽고 양념이 완벽하다고 극찬했습니다. 9가지 종류의 숙성 고기 모두 품질이 뛰어나, 일반적인 무한리필 고깃집에 대한 편견을 깰 만큼 맛있다고 놀라워했습니다. 또한 제육볶음, 떡볶이 등 다양한 메뉴가 있는 샐러드 바에도 만족감을 표했으며, 특히 호박 샐러드와 여러 종류의 논알콜 하이볼을 맛있게 먹었습니다. 전반적으로 2만 원이 안 되는 가격에 10가지 이상의 고기와 샐러드 바, 음료, 디저트까지 무한으로 즐길 수 있어 가성비가 매우 뛰어나다고 총평했습니다.'),
('나이쏘이', '100/4-5 Phra Athit Rd, Chana Songkhram, Phra Nakhon, Bangkok 10200, Thailand', '+66 62-064-3934', ARRAY['아시안'], 'https://www.youtube.com/watch?v=sBI-MFkdwyI', 13.7626427, 100.4945246, '태국', '고기가 만지기만 해도 부서질 정도로 매우 부드럽다고 언급했습니다. 또한 한국의 쌀국수 면과는 다른 태국 쌀국수 면의 식감을 매우 선호하며, 면이 아주 ''쫀득쫀득''하다고 평가했습니다.'),
('나이쏘이', '100/2-3 Phra Athit Rd, Chana Songkhram, Phra Nakhon, Bangkok 10200, Thailand', '+66 83 495 3129', ARRAY['아시안'], 'https://www.youtube.com/watch?v=P4ySapvK798', 13.7626204, 100.4944529, '태국', '쯔양은 12년 전 방문했던 이 식당을 잊지 못해 태국에 다시 왔을 정도로 가장 좋아하는 곳이라고 밝혔습니다. 12년 전과 맛이 똑같다며 감탄했고, 특히 국물이 한국의 갈비탕과 비슷해 한국인 입맛에 잘 맞는다고 평가했습니다. 갈비국수의 고기는 매우 부드러워 입에서 녹는다고 표현했으며, 면은 기본(중간), 얇은 면, 두꺼운 면 세 종류가 있는데 기본으로 제공되는 중간 면이 가장 맛있다고 추천했습니다. 비빔국수는 간장 베이스의 달고 짭짤한 맛이 잡채와 비슷하다고 했고, 함께 먹은 스프링롤과 수박 주스도 매우 맛있다고 칭찬했습니다. 50년 동안 장사한 사장님이 쯔양이 먹는 양을 보고 신기록이라고 말할 정도로 많은 양의 음식을 먹었습니다.'),
('Shabushi Gateway Ekamai', 'G110, G floor, Gateway Ekamai Building, Khwaeng Phra Khanong, Khet Khlong Toei, Krung Thep Maha Nakhon 10110, Thailand', '+6621874112', ARRAY['아시안'], 'https://www.youtube.com/watch?v=BdmMYL3WJ2M', 13.7191137, 100.5852778, '태국', '쯔양은 방콕의 회전 샤브샤브 무한리필 전문점 ''샤부시''를 방문하여 120접시를 먹었습니다. 영상에서 쯔양은 회전 레일을 통해 제공되는 다양한 종류의 고기, 채소, 해산물 등을 쉴 새 없이 개인 냄비에 넣어 먹으며, 먹은 접시를 높게 쌓아 탑을 만드는 모습을 보여주었습니다. 영상에 직접적인 맛 평가는 없지만, 엄청난 양의 음식을 즐겁게 먹는 모습을 통해 샤브샤브 뷔페에 매우 만족한 것으로 보입니다.'),
('옵 아러이 타운 인 타운', '1329 53 Lat Phrao 94 Alley, Phlabphla, Wang Thongla, Bangkok 10310, Thailand', '+66658766555', ARRAY['아시안'], 'https://www.youtube.com/watch?v=FcblabtVQKo', 13.7580375, 100.5978616, '태국', '유튜버는 징거미 새우를 맛본 후 ''진짜 맛있다''고 여러 번 감탄하며, 특히 새우 내장의 풍부한 맛을 강조했습니다. 영상 말미에는 태국에서 저렴하고 현지 분위기가 나는 해산물 식당을 찾는다면 이곳을 방문하는 것이 정말 좋을 것이라고 강력하게 추천했습니다.'),
('Ob Aroi Town In Town', '1329 53 Lat Phrao 94 Alley, Phlabphla, Wang Thonglang, Bangkok 10310, Thailand', '+66 65 876 6555', ARRAY['아시안'], 'https://www.youtube.com/watch?v=s7Dk0PU_B-A', 13.7718781, 100.6090164, '태국', '태국 현지인들이 추천하는 해산물 맛집으로, 야외 분위기가 좋고 모든 음식이 맛있다고 극찬했습니다. 특히 징거미새우는 살이 통통하고 쫄깃하며, 머리 내장이 계란 노른자처럼 고소하고 진해서 감동적인 맛이라고 평가했습니다. 대표 메뉴인 농어 튀김은 겉은 바삭하고 속은 촉촉하며, 간이 완벽해 그냥 먹어도 맛있다고 추천했습니다. 게살 볶음밥은 ''레전드''라고 칭하며 게살이 많이 들어있고 감칠맛이 최고라고 언급했고, 포장까지 해갔습니다. 굴은 비린 맛 없이 달고 맛있으며, 마늘 버터 가리비, 모닝글로리 볶음, 게 요리 등 주문한 모든 메뉴에 대해 만족감을 표현했습니다. 디저트로 먹은 망고 스티키 라이스는 생소한 조합이었지만 맛있게 먹었으며, 수박 주스(땡모반)는 태국 도착 후 마신 것 중 최고라고 말했습니다. 전반적으로 음식, 분위기 모두 완벽한 성공적인 첫 태국 촬영이었다고 마무리했습니다.'),
('남영돈', '서울 용산구 한강대로80길 17', '02-793-3598', ARRAY['고기'], 'https://www.youtube.com/watch?v=j1F9Bsg0Nm4', 37.5427549, 126.9737787, '서울특별시', '쯔양은 ''남영돈''을 정말 맛있는 곳이라며, 연예인들도 많이 방문하는 곳으로 알고 있어서 특별한 게스트인 비를 위해 이 장소를 선택했다고 밝혔습니다. 쯔양과 비는 돼지 항정살, 가브리살, 삼겹살, 목살 등 다양한 부위 3kg과 함께 김치찌개, 한정판 메뉴인 후추 떡볶이, 냉쫄면을 주문했습니다. 쯔양은 특히 돼지 목살이 ''육즙이 많다''고 평가했으며, 항정살은 ''쫄깃하고 맛있다''고 언급했습니다. 또한 기름진 고기를 먹은 후, 뜨거운 찌개와 떡볶이를 먹고, 차가운 냉쫄면으로 이어지는 음식의 조합이 최고라고 만족감을 표현했습니다. 쯔양은 음식이 너무 맛있어서 ''혀가 미쳐버릴 것 같다''고 감탄했으며, 후식으로 아이스크림까지 먹을 수 있겠다고 말했습니다. 게스트인 비 역시 이 집의 단골임을 밝히며 음식 맛을 칭찬했습니다.'),
('사리원 본점', '대전광역시 서구 둔산로31번길 77', '042-487-4209', ARRAY['고기'], 'https://www.youtube.com/watch?v=dafYPuBJ5fE', 36.355267, 127.3772825, '대전광역시', '쯔양은 70년 전통의 불고기 맛집 ''사리원''을 방문하여 불고기 6인분과 비빔냉면을 주문했습니다. 메인 메뉴인 불고기는 달콤한 맛의 서울식 불고기로, 쯔양이 가장 좋아하는 스타일이라고 극찬했습니다. 함께 나온 밑반찬인 육회, 잡채, 우거지탕도 모두 훌륭하다고 평가했습니다. 특히 서비스로 나온 김치비빔은 아삭한 식감이 살아있어 달콤하고 신선한 김치 같다고 좋아했습니다. 평양식 비빔냉면은 예상과 달리 밍밍하지 않고 맛이 풍부했으며, 함께 나온 냉면 육수는 따로 추가해서 마실 정도로 상쾌하고 맛이 깊어 초심자도 좋아할 맛이라고 평가했습니다. 전반적으로 모든 음식이 맛있었고, 가족 외식 장소로도 완벽하다고 리뷰를 마무리했습니다.'),
('갓튀긴후라이드 본점', '대구광역시 달서구 신당로 6', '053-582-8257', ARRAY['치킨'], 'https://www.youtube.com/watch?v=QTmPGMaNOxI', 35.8535118, 128.4929415, '대구광역시', '쯔양은 ''갓튀긴후라이드''를 가성비가 매우 좋은 치킨집으로 소개하며, 포장 시 13,000원이라는 저렴한 가격을 강조했습니다(0:47). 후라이드 치킨에 대해서는 ''갓 튀겨서 고기가 부드럽고 촉촉하며'', ''겉은 매우 바삭하다''고 평가하며 전형적이면서 모두가 좋아할 만한 맛이라고 설명했습니다(2:47, 2:56). 튀김옷은 얇고 바삭한 식감이 특징이며, 식어도 바삭함이 유지된다고 덧붙였습니다(4:54, 6:62). 양념치킨은 ''달콤하고 맛있는 소스''가 인상적이며, 식을수록 더 맛있어진다고 언급했습니다(3:59, 4:81). 또한, 숙취가 있는 컨디션이 좋지 않은 상태임에도 불구하고 5마리의 치킨을 다 먹을 수 있을 정도로 맛있었다고 극찬했습니다(11:35). 사이드 메뉴로 주문한 떡볶이는 파가 올라가 있으며, 기분 좋게 달콤하고 고소한 맛이라고 평가했고(6:12), 치킨과 잘 어울리는 조합으로 라면(너구리, 신라면)도 함께 먹었습니다(8:01, 9:38).'),
('남이분식', '서울 종로구 종로40가길 3', '02-2273-8203', ARRAY['분식'], 'https://www.youtube.com/watch?v=3MLTE9Zqcoo', 37.5702886, 127.0064934, '서울특별시', '유튜버 쯔양은 ''남이분식''을 오래된 감성이 좋은 곳이라고 소개했다. 이곳의 대표 메뉴인 수제비 라면은 양이 매우 푸짐하며, 매일 직접 반죽하는 수제비는 두툼하고 쫄깃한 식감이 일품이라고 평가했다. 김치가 들어가 개운한 맛을 더한다고 언급했다. 또 다른 인기 메뉴인 짜장 떡볶이는 일반적인 짜파게티와는 다른 독특한 짜장 맛이 나며, 달지 않고 고소한 맛이 특징이라고 했다. 너구리 라면은 면이 완벽하게 익혀져 나와 특별히 맛있다고 감탄했으며, 참치 라면은 참치 풍미가 진하고 맛의 비율이 완벽하다고 칭찬했다. 마지막으로 맛본 들깨 수제비는 채소 없이 들깨 국물과 수제비만으로 맛을 낸 고소하고 전통적인 맛이 인상적이었으며, 소금을 더하면 풍미가 살아난다고 했다. 전반적으로 할머니가 해주는 집밥처럼 모든 재료를 푸짐하게 주는 인심과 특별한 라면 맛에 크게 만족하며 식사를 마무리했다.'),
('덕순루', '서울특별시 용산구 한강대로80길 11', '02-326-1888', ARRAY['중식'], 'https://www.youtube.com/watch?v=4BahYG3xw5Q', 37.5427004, 126.9734516, '서울특별시', '쯔양은 70년 전통의 맛에 감탄하며 여러 메뉴를 맛보았습니다. ''깐풍기''는 겉은 바삭하고 속은 촉촉하며 간장 베이스 소스가 맛있다고 평했습니다. ''짜장면''은 옛날식 맛이 나며 면이 가늘고 불지 않아서 좋다고 했습니다. 특히 ''군만두''는 한 입 베어 물면 육즙이 터져 나와 꼭 먹어봐야 할 메뉴로 꼽았습니다. ''탕수육''은 찹쌀이 아닌 부드럽고 바삭한 옛날식 탕수육이라고 설명했습니다. ''깐쇼새우''는 새콤하고 풍미가 깊은 맛이 특징이라고 언급했습니다. ''새우볶음밥''에서는 불맛과 파기름 향이 느껴진다고 했고, ''짬뽕''은 맑아 보이는 국물과 달리 육개장처럼 매우 깊고 진한 맛이 나 해장에 제격이라고 극찬했습니다.'),
('명륜진사갈비 서울성균관대점', '서울특별시 종로구 성균관로 31', '02-747-9279', ARRAY['고기'], 'https://www.youtube.com/watch?v=qYKCtBTpPNc', 37.5854879, 126.9967251, '서울특별시', '쯔양은 ''고기 테마파크''로 리뉴얼된 매장에 방문하여 다양한 메뉴를 즐겼습니다. 특히 신메뉴인 ''후려페퍼 스테이크''에 대해 ''모두가 좋아할 맛있는 스테이크''라며 극찬했고, 후추의 매콤함과 달콤한 소스의 조화가 훌륭하다고 평가했습니다. 이 메뉴는 쯔양이 가장 마음에 들어 한 메뉴가 되었습니다. 대표 메뉴인 숯불돼지갈비 역시 ''너무 맛있다''고 했으며, 통삼겹살도 맛있다고 언급했습니다. 셀프바를 활용하여 스테이크 버거를 만들어 먹는 등 다양한 음식을 즐기는 모습을 보였고, 된장찌개와 하이볼도 곁들여 먹었습니다. 전반적으로 무한리필 시스템과 다양한 메뉴 구성에 큰 만족감을 표현했으며, 특히 후려페퍼 스테이크의 맛에 놀라워했습니다.'),
('송옥', '서울 중구 남대문로1길 11', '02-752-3297', ARRAY['한식'], 'https://www.youtube.com/watch?v=vsyr8N53ye4', 37.5615621, 126.9773925, '서울특별시', '쯔양은 이곳이 62년 전통을 자랑하는 서울 3대 메밀국수 맛집이라고 소개했습니다. 메밀국수 육수는 일반적인 맛과 달리 매우 진하고 직접 우려낸 깊은 맛이 특징이라고 평가했습니다. 면에 육수가 잘 배어 있고, 1인분에 2판이 나오는 푸짐한 양을 칭찬했습니다. 함께 주문한 유부초밥도 퍽퍽하지 않고 새콤달콤한 맛이 잘 살아있어 맛있다고 언급했습니다. 메밀국수를 다 먹은 후에는 양이 많은 냄비우동을 추가로 주문하여, 차가운 음식을 먹고 난 뒤 뜨거운 음식을 먹는 조합을 즐겼습니다. 전반적으로 ''맛집다운 전통 있는 맛''이라고 최종적으로 평가했습니다.'),
('솥뚜껑생삼겹살', '서울 강동구 천중로 17', '02-472-9209', ARRAY['고기'], 'https://www.youtube.com/watch?v=HrUVx1xnbAs', 37.5459197, 127.1239111, '서울특별시', '쯔양은 13년 된 무쇠 솥뚜껑에 구워 먹는 삼겹살의 풍미가 엄청나고 고소하다고 평가했습니다. 특히 고기와 비계의 비율이 완벽하고, 옛날 방식의 얇은 고기가 인상적이라고 언급했습니다. 추가로 주문한 제육볶음은 양념보다 고기 맛이 진하게 느껴져서 좋았고, 양푼 김치찌개는 깔끔하고 시원한 맛이라고 칭찬했습니다. 당일 배송받은 두부를 사용하는 등 음식에 대한 사장님의 진심이 느껴지며, 모든 음식이 맛있어서 다시 방문하고 싶은 ''진짜 맛집''이라고 결론지었습니다.'),
('우대포 분당직영점', '경기도 성남시 분당구 황새울로335번길 5 앤타운빌딩 1층 106-1호', '0507-1335-6139', ARRAY['고기'], 'https://www.youtube.com/watch?v=xbnVNevm8FI', 37.3860493, 127.1216975, '경기도', '쯔양은 이곳의 대표 메뉴인 ''깍둑꽃살''에 대해 마블링과 품질이 훌륭하고, 씹을수록 육즙이 풍부하며 쫄깃한 식감이 일품이라고 극찬했습니다[ts:208, ts:315, ts:339, ts:353]. 특히 10년 숙성된 소금을 사용해 고기의 풍미를 더한다고 언급했습니다[ts:287, ts:393]. ''왕갈비''는 입에서 녹을 정도로 부드러우면서도 양념이 잘 배어있고, ''양념소갈비''는 쫄깃함과 부드러움을 동시에 느낄 수 있는 다채로운 식감이 특징이라고 평가했습니다[ts:534, ts:571, ts:679]. 사이드 메뉴인 ''소고기 된장찌개''는 고기가 듬뿍 들어있고 칼칼한 맛이 좋다고 했으며, 70년 전통의 ''김치말이국수''는 면발이 가늘면서도 매우 쫄깃해 고기와 곁들여 먹기 좋다고 추천했습니다[ts:764, ts:850, ts:877]. 쯔양은 세 가지 바비큐 메뉴 모두 각기 다른 매력으로 훌륭하다고 총평했습니다.'),
('송정식당', '서울 종로구 종로40가길 13', '02-2267-2817', ARRAY['한식'], 'https://www.youtube.com/watch?v=sYxpwthA4qo', 37.5702388, 127.0058617, '서울특별시', '미국에서 귀국 후 시차 적응에 어려움을 겪다가 한식이 먹고 싶어 방문한 38년 전통의 백반집. 대표 메뉴인 ''불꼬지 백반''은 연탄에 구워 불향이 가득하며, 살짝 탄 부분의 바삭한 식감과 잘 졸여진 양념의 맛이 일품이라고 평가했다. 특히 새콤달콤한 무채와 함께 쌈으로 즐기는 조합을 극찬했다. ''우렁된장찌개''는 감칠맛이 좋고, ''오징어볶음''은 통통하고 쫄깃한 식감이 살아있다고 언급했다. ''김치찌개''는 다른 재료 없이 김치 본연의 맛으로만 승부하여 아주 깔끔한 맛을 낸다고 하였으며, 평소 즐겨 먹지 않는 두부마저 맛있다고 감탄했다. 주문한 모든 메뉴가 맛있었다며, 해외에 나갔다 돌아오면 꼭 다시 방문하고 싶은 곳이라고 만족감을 표현했다.'),
('DJ''s Wild West Junction', '321 E Rte 66, Williams, AZ 86046 미국', '+1 928-635-4512', ARRAY['양식'], 'https://www.youtube.com/watch?v=fnJr_CsQOKE', 35.2521117, -112.1847481, NULL, '쯔양은 미국 서부 애리조나 주 윌리엄스에 위치한 이 식당에서 스테이크와 폭립을 포함한 거의 모든 메뉴를 주문하여 먹었습니다. 그녀는 음식이 맛있다고 평가했으며, 특히 고기의 부드러움에 만족감을 표했습니다. 그녀의 엄청난 식사량에 식당 주인과 직원들이 모두 놀라워하며 박수를 보냈고, 이는 영상의 주요 내용 중 하나입니다. 쯔양은 이 경험을 통해 식당에 깊은 인상을 남겼으며, 식당 측도 그녀의 방문을 자랑스럽게 여기고 있습니다.'),
('BCD Tofu House', '3575 Wilshire Blvd, Los Angeles, CA 90010', '+12133826677', ARRAY['한식'], 'https://www.youtube.com/watch?v=gldiNIUx6e4', 34.0620939, -118.3026547, NULL, '영상은 짧은 분량으로 상세한 맛 평가는 없으나, 쯔양은 순두부찌개, 갈비, 돌솥밥 등 다양한 메뉴를 맛있게 먹는 모습을 보여줍니다. 영상 내 자막에는 ''한국인이라면 꼭 와야 되는 필수 코스''라고 언급되어 있으며, 이는 쯔양이 이곳을 매우 긍정적으로 평가하고 추천한다는 것을 시사합니다. 대표 메뉴인 순두부찌개와 여러 한식 메뉴를 즐기는 모습으로 보아 음식 맛에 만족한 것으로 보입니다.'),
('BCD Tofu House', '3575 Wilshire Blvd, Los Angeles, CA 90010, USA', '+1 213-382-6677', ARRAY['한식'], 'https://www.youtube.com/watch?v=-LGODBDAg1c', 34.0620939, -118.3026547, '미국', '쯔양은 LA에 거주하는 지인들에게 ''LA 최고의 맛집''으로 강력 추천받아 이곳을 방문했습니다. 그녀는 돼지고기 순두부, 해물 순두부, 곱창 순두부와 함께 LA 갈비, 제육볶음 등 다양한 메뉴를 주문했습니다. 특히 LA 갈비에 대해 ''살코기와 비계의 비율이 완벽하고, 숯불에 구운 듯한 맛이 일품''이라며 그날 먹은 메뉴 중 최고라고 극찬했습니다. 돼지고기 순두부는 ''한국보다 맛있는 것 같다''고 평가하며, 미국에 있어 달게 만들었을 것이라는 예상과 달리 한국의 맛을 그대로 재현했다고 놀라워했습니다. 제육볶음 역시 ''진짜''라며 칭찬을 아끼지 않았고, 매운맛의 해물 순두부와 곱창 순두부도 그 특유의 맛을 즐겼습니다. 전반적으로 ''미국인데도 한국에 온 것 같다''고 느낄 만큼 만족했으며, LA에 산다면 매일 방문하고 싶을 정도로 맛있다고 총평했습니다. 해외 거주 한국인들에게 강력 추천하는 맛집이라고 마무리했습니다.'),
('Heart Attack Grill', '450 Fremont St, Las Vegas, NV 89101-5623', '+1 702-706-7568', ARRAY['패스트푸드'], 'https://www.youtube.com/watch?v=RSZVP4M1bQ0', 36.1709, -115.1436, NULL, '쯔양은 이곳에서 가장 큰 버거인 ''옥튜플 바이패스 버거''와 치즈 프라이를 주문했습니다. 그녀는 버거가 매우 크고 무겁지만, 보기와는 다르게 짜지 않고 소고기 맛이 풍부해서 맛있다고 평가했습니다. 특히, 패티는 일반 패티의 3~4배 크기이며 베이컨은 칩처럼 바삭하다고 언급했습니다. 쯔양은 버거와 프라이를 모두 먹어치웠고, 식당의 즐겁고 활기찬 분위기 덕분에 미국 여행 중 가장 휴가 온 기분을 느낄 수 있었다고 말했습니다.'),
('KJ Dim Sum & Seafood', '3700 W Flamingo Rd, Las Vegas, NV 89103, USA', '+1 702-777-2333', ARRAY['아시안'], 'https://www.youtube.com/watch?v=RTbRDh2rs1g', 36.1189881, -115.1861673, '미국', '라스베이거스 리오 호텔 내에 위치한 딤섬 맛집으로, 카트를 밀며 즉석에서 원하는 딤섬을 제공하는 홍콩식 스타일이 특징입니다. 쯔양은 샤오롱바오의 풍부한 육즙과 꽉 찬 소, 그리고 새우가 통으로 들어간 튀김만두에 감탄했습니다. 특히 에그타르트는 ''인생 최고''라고 극찬하며, 얇고 바삭한 페이스트리와 맛있는 커스터드 크림의 조화를 칭찬했습니다. 이 외에도 LA갈비, 돼지고기 슈마이, 차슈바오, 로터스 잎밥 등 다양한 메뉴를 맛보았고, 대부분의 딤섬이 속이 꽉 차 있고 크기가 커서 한입에 먹기 어려울 정도라고 평가했습니다. 다만, 두부피를 쓴 메뉴는 개인적으로 불호라고 밝혔고, 닭발은 크기가 너무 커서 낯설다고 언급했습니다. 딤섬은 점심시간(오후 2시까지)에만 제공되며, 저녁에는 요리 메뉴를 판매합니다.'),
('Pink''s Hot Dogs', '709 N La Brea Ave, Los Angeles, CA 90038, USA', '+1 323-931-4223', ARRAY['패스트푸드'], 'https://www.youtube.com/watch?v=seDyRioy4P0', 34.0838816, -118.3442849, '미국', '쯔양은 총 14개의 핫도그를 주문했으나, 강풍과 비 등 악천후로 인해 8개만 먹고 나머지는 포장했습니다. 베이컨 치즈 프라이와 어니언 링을 먼저 맛본 뒤 맛있다고 평가했습니다. 가장 기본인 ''클래식 핫도그''는 육즙이 풍부하고 기름지며 짭짤한 맛이 특징이지만 맛있다고 언급했고, 특히 칠리 소스가 마음에 든다고 했습니다. ''베이컨 핫도그''는 짠 음식을 좋아하는 자신의 입맛에는 맞지만, 다른 사람에게는 매우 짤 수 있다고 평가했습니다. 고기가 가득한 ''필리 치즈 스테이크 핫도그''와 할라피뇨가 들어간 매콤한 ''점보 소시지 핫도그''도 맛보았습니다. 전반적으로 미국 음식의 양이 많고 짠 편이라는 소감을 남겼습니다.'),
('우이락 망원본점', '서울 마포구 포은로8길 22', '0507-1438-5594', ARRAY['한식'], 'https://www.youtube.com/watch?v=1qslQO_PC9g', 37.5564437, 126.9059919, '서울특별시', '쯔양은 평소 채소를 좋아하지 않음에도 불구하고, 우이락의 ''대왕 고추튀김''을 맛본 후 극찬을 아끼지 않았습니다. ''이렇게 큰 고추튀김은 처음 본다''며 크기에 놀라워했고, 튀김이 전혀 퍽퍽하지 않고 육즙이 풍부해 부드럽고 촉촉하다고 평가했습니다. 특히 오리지널 맛 외에도 콘소메, 양념, 치즈링 등 다양한 맛의 고추튀김을 모두 맛있게 즐겼습니다. 쯔양은 대표 메뉴인 고추튀김 외에 다른 안주 메뉴들도 모두 훌륭하다고 평가했는데, 부드러운 ''육전'', 막걸리가 들어가 풍미가 좋은 ''바지락 술찜'', 그리고 면발이 맛있는 ''비빔국수'' 등을 언급하며 모든 요리가 맛있다고 놀라워했습니다. 그중에서도 ''비빔국수와 고추튀김''의 조합은 ''장난이 아니다''라며 강력 추천했습니다.'),
('고향손칼국수', '경기 고양시 일산서구 중앙로 1371 뉴서울프라자 지하1층', '031-914-9866', ARRAY['한식'], 'https://www.youtube.com/watch?v=nPrzl_IW6y8', 37.6665693, 126.7659699, '경기도', '쯔양은 전반적으로 할머니가 해주시던 음식을 떠올리게 하는 추억의 맛이라고 평가하며, 먹는 내내 감동하며 눈물까지 보였습니다. 칼국수는 멸치 육수 베이스에 직접 만든 면이 쫄깃하고 밀가루 맛이 나지 않아 맛있다고 언급했습니다. 수제비는 두툼한 두께와 쫄깃한 식감을 선호하는 자신의 취향에 완벽하게 부합하며, 특히 김치수제비가 ''진짜''라고 극찬했습니다. 대표 메뉴인 소고기 주먹밥은 계란에 말아져 나오는데, 어릴 적 먹던 볶음밥처럼 고소하고 익숙한 맛이라 누구나 좋아할 것이라고 말했습니다. 맛에 대한 평가를 넘어, 30년 된 가게의 정겨운 분위기와 푸짐한 양, 할머니를 떠올리게 하는 맛 때문에 매우 만족스러운 식사였다고 총평했습니다.'),
('고기랑', '경기 수원시 팔달구 권광로196번길 49', '031-221-6780', ARRAY['고기'], 'https://www.youtube.com/watch?v=Sj2mblusg3o', 37.2645217, 127.0358968, '경기도', 'KT 소속 운동선수들과 6kg의 돼지갈비를 두고 5대 1 먹방 대결을 펼쳤습니다. 이 영상은 KT의 유료 광고를 포함하고 있어 음식 자체의 맛 평가보다는 삼성 갤럭시 AI 기능 시연에 초점이 맞춰져 있습니다. 쯔양은 식사량(하루 2~5끼), 한 달 식비(약 700만 원) 등 대식가로서의 면모를 보여주었고, 식사를 마친 후 "오늘도 맛있게 잘 먹었다"고 만족감을 표현했습니다. 함께한 선수들 또한 음식이 훌륭했다고 언급했습니다.'),
('스시도쿠 왕십리본점', '서울특별시 성동구 왕십리광장로 6 1층', '0507-1320-3255', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=oI-sMs0BF3w', 37.5609528, 127.0360724, '서울특별시', '영상에서 쯔양은 초대형 초밥의 크기에 압도되어 "오늘은 제가 졌습니다"라고 말하며 패배를 인정합니다. 그는 초밥이 상상했던 것보다 훨씬 크다며 "진짜 말도 안 돼"라고 감탄하고, 일반 초밥과의 크기 차이를 보며 "굉장히 무서운 애들이네요"라고 덧붙입니다.'),
('스시도쿠 왕십리본점', '서울 성동구 왕십리광장로 6 1층', '0507-1320-3255', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=aoBuPnqrOFo', 37.5609528, 127.0360724, '서울특별시', '쯔양은 5XL 점보 스시의 엄청난 크기에 놀라움을 표하며, 일반 스시의 5배가 아닌 10배는 커 보인다고 말했습니다. 가장 먼저 맛본 광어 뱃살은 매우 두툼하고 기름지면서도 고소한 맛이 일품이라고 평가했습니다. 스시의 크기를 자신의 갤럭시 울트라 스마트폰과 비교하며 그 크기를 강조했습니다. 특히 오징어 초밥을 강력 추천하며, 일반적인 오징어 초밥과 달리 매우 부드러우면서도 쫀득한 식감이 일품이고, 마치 곶감 같다고 묘사했습니다. 점보 스시의 양이 너무 많아 5개밖에 먹지 못하고 ''패배''를 선언했지만, 음식의 맛 자체에는 매우 감탄하며, 크기에 놀랐지만 맛에는 더욱 놀랐다고 총평했습니다. 세트로 나온 우동과 가라아게도 맛있게 먹었습니다.'),
('육미제당 성남이마트점', '경기도 성남시 수정구 시민로 172 1층', '031-749-4948', ARRAY['고기'], 'https://www.youtube.com/watch?v=CrCTpTdj_w0', 37.4435249, 127.1430177, '경기도', '쯔양은 해당 음식점이 1인당 19,900원에 다양한 고기와 뷔페를 무제한으로 즐길 수 있어 가성비가 매우 뛰어나다고 평가했습니다. 특히 메인 메뉴인 ''대장갈비''는 미리 조리되어 나와 숯불에 살짝 데우기만 하면 바로 먹을 수 있는 점이 특징입니다. 텍사스 대장갈비는 입에서 녹을 정도로 부드럽고, 양념 맛이 조화롭다고 극찬했습니다. 간장맛은 전통적인 등갈비 맛, 양념맛은 중독성 있는 매운맛이라고 설명했습니다. 또한 프렌치랙의 마블링과 식감에 감탄했으며, 뷔페 코너의 피자가 예상외로 매우 맛있어 고기와 함께 쌈을 싸 먹는 등 다양한 조합을 시도했습니다. 전반적으로 고기가 매우 부드럽고 뼈와 살이 쉽게 분리되는 점을 높이 평가했으며, 약 5kg의 립을 먹고 피자 5판을 포장해갈 정도로 만족스러운 먹방이었습니다.'),
('미우', '서울 강남구 압구정로 113-22 지하일층 미우', '02-544-7775', ARRAY['고기'], 'https://www.youtube.com/watch?v=NksEaXk7e3c', 37.5247281, 127.0196138, '서울특별시', '쯔양은 이곳을 ''먹방 인생 중 최고인 집'' 중 하나로 꼽을 만큼 매우 맛있었다고 소개했습니다. 함께 출연한 박명수는 제비추리의 고소하고 쫄깃한 식감, 안심의 풍부한 육즙과 숙성된 풍미를 극찬하며 ''근래 먹어본 안심 중 제일 맛있다''고 평가했습니다. 또한 안창살은 잡내 없이 향이 좋다고 했고, 등심과 새우살은 입에서 녹는다고 표현했습니다. 특히 마지막에 맛본 차돌박이와 김장김치 조합에 대해 ''이게 찐이다''라며 크게 만족했습니다. 다만, 우설은 다른 부위에 비해 입맛에 덜 맞는다고 언급했습니다. 영상 전반에 걸쳐 고기 품질이 매우 뛰어나다는 점이 여러 차례 강조되었습니다.'),
('복성원', '강원 춘천시 춘천로 195', '033-251-3125', ARRAY['중식'], 'https://www.youtube.com/watch?v=FSsr6NanwkM', 37.8769817, 127.7356841, '강원특별자치도', '쯔양은 50년 전통의 노포 중식당인 이곳의 시그니처 메뉴인 사천짜장과 사천밥을 포함해 짜장면, 짬뽕, 탕수육을 맛봤습니다. 사천짜장은 짜장 맛이 거의 나지 않는, 오징어, 소라 등 해산물이 들어간 새로운 맛의 음식이라고 평가했습니다. 사천밥은 볶음밥에 낙지볶음 같은 소스를 곁들여 먹는 느낌이라고 표현했습니다. 함께 주문한 짜장면은 후추 향이 강한 옛날 간짜장 스타일이며, 탕수육은 케첩이 들어가지 않은 맑은 소스와 바삭한 튀김이 특징이라고 설명했습니다. 짬뽕은 국물이 맑고 개운하면서도 매우 얼큰하고 맛있다고 언급했습니다. 전반적으로 손으로 직접 반죽한 부드러운 면발을 칭찬했으며, 무심한 듯 친절한 사장님에 대한 좋은 인상과 함께 단골이 많은 이유를 알겠다고 리뷰를 마무리했습니다.'),
('산북동달구지 군산본점', '전북 군산시 칠성6길 144', '063-468-3534', ARRAY['고기'], 'https://www.youtube.com/watch?v=gJ4StqhlXqE', 35.9684433, 126.678563, '전라북도', '쯔양은 이 식당의 소곱창을 ''지금까지 먹어본 소곱창 중 역대급''이라고 극찬했다. 당일 도축한 신선한 한우 곱창을 사용해 쓴맛이나 잡내가 전혀 없다고 평가했다. 소곱창은 겉이 바삭하고 속은 쫀득하며, 곱이 가득 차 있어 고소함이 풍부하다고 언급했다. 추가로 주문한 대창은 스모크 향이 느끼함을 잡아주어 일본식 대창덮밥 같다고 평했으며, 막창은 ''베이징덕 수준''으로 겉이 바삭하다고 감탄했다.'),
('곱창파는고깃집 공덕본점', '서울 마포구 마포대로 173-14 마포센텀슬로우스퀘어 401호', '0507-1384-9245', ARRAY['고기'], 'https://www.youtube.com/watch?v=AAcmK7mCK_s', 37.5510075, 126.9536224, '서울특별시', '쯔양은 이 식당을 세 번째 방문했으며, 한국에 돌아오자마자 가장 먹고 싶었던 음식으로 이곳의 곱창을 꼽았다. 곱창에 대해 겉은 바삭하고 속은 곱으로 꽉 차 촉촉하며, 입에서 녹을 정도로 부드럽지만 씹는 맛도 있다고 평가했다. 특히 곱창을 김치와 함께 볶아 먹는 조합을 ''밥도둑''이라며 극찬했다. 곱창 외에도 ''쫄깃살''이라는 특수부위의 독특한 식감과 짭짤한 맛을 칭찬했으며, 3,000원짜리 된장찌개는 가성비가 매우 좋다고 언급했다. 이날 총 50인분을 5시간 동안 먹으며, 지난 5년간 먹은 양 중 가장 많은 서빙 수를 기록했다고 밝혔다. 유독 이 식당에만 오면 많이 먹게 된다며 매우 만족스러운 식사였다고 총평했다.'),
('Sambal Bakar Indonesia Grogol', 'Jl. Dr. Susilo Raya No.10, RT.1/RW.3, Grogol, Kec. Grogol petamburan, Kota Jakarta Barat, Daerah Khusus Ibukota Jakarta 11450, Indonesia', '+6287840245116', ARRAY['아시안'], 'https://www.youtube.com/watch?v=HY4EmkarhMo', -6.168, 106.795, '인도네시아', '해당 영상은 짧은 쇼츠 영상으로 쯔양의 직접적인 음성 리뷰는 포함되어 있지 않습니다. 하지만 영상에서 쯔양은 매우 긴 영수증을 보고 놀라워하며, 이후 테이블에 가득 차려진 28가지의 다양한 요리를 보여줍니다. 이는 해당 식당의 방대한 메뉴와 푸짐함을 시각적으로 강조하는 것입니다. ''Sambal Bakar''는 고객이 선택한 여러 음식을 뜨거운 ''삼발(Sambal)'' 소스와 함께 핫플레이트에 곁들여 먹는 컨셉의 인도네시아 현지 인기 레스토랑입니다. 쯔양의 표정과 주문한 음식의 양으로 보아 이곳의 다양하고 특색 있는 메뉴를 즐기는 모습을 확인할 수 있습니다.'),
('Sate Maranggi Haji Yetty', 'Jl. Raya Cibungur, Purwakarta 41181 Indonesia', '+62 264 351077', ARRAY['아시안'], 'https://www.youtube.com/watch?v=Ra0AhAkYDho', -6.5543, 107.5287, '인도네시아', '쯔양은 처음에는 염소, 소, 닭 꼬치를 합쳐 총 70개를 주문했으나, 염소 꼬치를 맛본 후 맛있다며 20개를 즉시 추가 주문했습니다. 염소 고기에서 잡내가 전혀 나지 않고, 지방은 부드러우며 살코기는 쫄깃하다고 평가했습니다. 함께 맛본 소뼈 수프(sop buntut)는 한국의 소고기 뭇국과 비슷하면서도 더 진하고 감칠맛이 돌아 훌륭하다고 칭찬했습니다. 소고기는 입에서 녹을 정도로 부드럽고, 양념은 한국의 갈비찜과 비슷하다고 느꼈습니다. 쯔양은 식당의 기존 최고 기록인 100개를 넘어 총 101개의 꼬치를 먹어 신기록을 세웠으며, 그날 먹은 것 중 염소 꼬치가 최고였다고 극찬했습니다.'),
('Restoran Garuda', 'Jalan Haji Agus Salim No.59, RT.3/RW.1, Kb. Sirih, Menteng, Kota Jakarta Pusat, Daerah Khusus Ibukota, Jakarta 10340 Indonesia', '+62 21 3142466', ARRAY['아시안'], 'https://www.youtube.com/watch?v=Ra0AhAkYDho', -6.1895, 106.8256, '인도네시아', '쯔양은 101개의 사테를 먹은 직후, 뷔페식으로 다양한 음식을 접시에 담아 제공하는 파당(Padang) 전통 가정식 식당인 이곳을 방문했습니다. 치킨 커리, 양고기 커리, 렌당(소고기) 등 다양한 음식을 맛보았습니다. 동행한 제작진은 향신료가 강하다고 했지만, 쯔양은 자신에게는 괜찮다고 말했습니다. 특히 소고기 요리인 렌당은 한국의 장조림과 비슷하면서 맛있다고 평가했습니다. 향신료가 강한 인도네시아 음식이 입에 맞지 않을까 걱정했지만, 먹어본 모든 음식이 맛있었다고 만족감을 표현했습니다.'),
('한추', '서울 강남구 논현로175길 68', '02-541-0969', ARRAY['치킨'], 'https://www.youtube.com/watch?v=dcWbnUq1MO4', 37.5240857, 127.0234631, '서울특별시', '쯔양은 이곳을 30년 전통의 매우 유명한 실내 포차라고 소개했습니다. 대표 메뉴인 고추튀김에 대해 튀김옷이 매우 맛있고 속이 꽉 차 쫀득하다고 평가했으며, 떡볶이는 어릴 적 어머니가 해주시던 맛이 나서 맥주와 잘 어울린다고 말했습니다. 후라이드 치킨은 튀김옷에 청양고추가 박혀있어 바삭하고 옛날 통닭 맛이 난다며 칭찬했습니다. 음식들의 양이 전반적으로 매우 푸짐하다고 언급했으며, 어렸을 때 먹던 맛이 난다고 덧붙였습니다. 다만, 촬영 당일 숙취 때문에 컨디션이 좋지 않아 평소만큼 많이 먹지는 못하고 방송을 일찍 마무리했습니다.'),
('원조마산할매아구찜', '서울 서초구 강남대로99길 10', '0507-1362-2774', ARRAY['한식'], 'https://www.youtube.com/watch?v=2F1DQ2aaDQI', 37.5154134, 127.0188518, '서울특별시', '쯔양은 3대째 이어온 40년 전통의 게장 맛집으로, 간장게장 10마리와 양념게장 10마리를 주문했습니다. 간장게장은 전혀 짜지 않고 살이 쫀득하며 찰기가 넘친다고 평가했습니다. 특히 양념게장은 ''미쳤다''고 표현할 정도로 극찬하며, 달콤하면서 살짝 매콤하고 잡미 없이 깔끔한 맛이 일품이라고 했습니다. 간장게장을 100점, 양념게장을 200점으로 평가하며 양념게장을 강력 추천했습니다. 서비스로 받은 해물탕은 된장 맛이 강하지 않고 무국처럼 아주 맑고 시원한 맛이라고 칭찬했습니다. 게딱지 내장과 알을 밥에 참기름과 함께 비벼 먹으며 맛에 감탄했고, 양이 많음에도 불구하고 남김없이 모두 먹어치우며 만족스러운 식사였음을 보여주었습니다.'),
('칸다소바 해운대점', '부산 해운대구 구남로30번길 8-3 1층', '051-731-1660', ARRAY['아시안'], 'https://www.youtube.com/watch?v=HZaDW00sldo', 35.1612896, 129.1600904, '부산광역시', '쯔양은 칸다소바의 여러 메뉴에 대해 극찬했습니다. 특히 ''이에케 라멘''은 지금까지 먹어본 돈코츠 라멘 중 최고라고 평가하며, 돼지 냄새가 전혀 나지 않는 진한 국물 맛이 일본 현지에서 오랜 시간 끓여낸 것 같다고 감탄했습니다. ''아부라소바''는 기름진 느낌 없이 고소하고 살짝 매콤해서 맛있다고 했으며, ''돼지껍데기 아부라소바''의 돼지껍데기는 필수적으로 추가해야 할 만큼 훌륭하다고 언급했습니다. 과거에 방문했을 때 먹어본 ''마제소바''는 더 맛있어졌다며, 짠맛이 줄고 감칠맛과 부드러움이 더해졌다고 평가했습니다. 67가지 재료가 들어갔다는 사실에 놀라워하며 남은 소스에 밥을 비벼 먹는 것까지 완벽했다고 말했습니다. 전반적으로 모든 메뉴에 크게 만족하며, 집 근처에 있다면 일주일에 두 번은 올 것이라고 할 정도로 높은 만족감을 표현했습니다.'),
('스시선', '서울특별시 도봉구 도봉로 684 모비우스스퀘어 1층', '0507-1368-6667', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=GHZM7LgiVws', 37.6653467, 127.0435897, '서울특별시', '쯔양은 오랜만에 회전 초밥을 먹기 위해 방학동 모비우스 스퀘어 1층에 위치한 ''스시선''에 방문했습니다. 접시당 1,300원부터 시작하는 가격에 100접시 이상 먹는 것을 목표로 삼았습니다. 그녀는 초밥이 마르지 않고 따뜻한 점에 감탄하며, 계란새우마요, 연어아보카도, 도미뱃살, 갑오징어, 육회 타다끼 등 다양한 메뉴를 맛보았습니다. 특히 갑오징어 초밥의 식감, 불닭 소스를 곁들인 초밥, 그리고 부드러운 케이크를 극찬했습니다. 1,300원짜리 우동 또한 가격 대비 훌륭한 양과 퀄리티라고 평가하며, 사이드 메뉴와 디저트까지 정성이 느껴진다고 언급했습니다. 최종적으로 113접시를 먹으며 만족스러운 식사를 마쳤습니다.'),
('유가장', '경기 여주시 여주읍 창리 157-1', '031-884-1412', ARRAY['중식'], 'https://www.youtube.com/watch?v=387DTnvUyTg', 37.3, 127.633, '경기도', '여주에 위치한 ''유가장''은 ''무한도전'' 방송 이후 유명해진 짬뽕 전문점이다. 하루 4시간만 운영하며 대기가 길다. 메뉴는 맵기 단계별 짬뽕이 특징이다. 가장 순한 맛은 겉보기와 달리 틈새라면 정도로 맵지만 국물이 무국처럼 시원하고 깔끔하다. 중간 단계는 불닭볶음면보다 매우며, 무의 감칠맛이 나는 맛있는 국물이 특징이다. 가장 매운 2단계는 ''머리가 핑 도는 맛''으로 표현되며, 면까지 붉은색을 띠지만 가장 맛있다고 평가했다. 속에서부터 올라오는 강렬한 매운맛이 특징이지만 맛있게 맵다고 한다. 함께 주문한 군만두는 매운맛을 중화시켜주는 ''구세주'' 같은 존재로, 부드럽고 촉촉하여 반드시 주문해야 할 메뉴로 추천했다.'),
('바담칼국수 오이도본점', '경기 시흥시 오이도로157번길 1', '0507-1322-8458', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=SS6bm0HEwcE', 37.3470257, 126.6885588, '경기도', '쯔양은 가게의 대표 메뉴인 ''꽃쟁반 해물 칼국수'' 4인분을 주문했습니다. 처음에는 육수에 소고기와 채소를 샤부샤부처럼 익혀 먹고, 그 다음 문어, 가리비, 제철 조개 등 다양한 해산물을 넣어 먹었습니다. 그는 해산물이 신선하고 양이 매우 푸짐하다고 평가했으며, 해산물과 고기의 조화로운 맛에 만족감을 표했습니다. 마지막으로 칼국수 면과 수제비를 넣어 식사를 마무리하며, 바다 풍경과 함께 즐길 수 있는 점을 긍정적으로 언급했습니다.'),
('남해달인횟집', '부산 사하구 사리로 40', '051-292-8838', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=zswATtu8Iyo', 35.103598, 128.9990966, '부산광역시', '쯔양은 구독자인 사장님이 운영하는 ''남해달인횟집''을 방문하여 대표 메뉴인 ''회 + 돔백반''과 계절 메뉴인 ''감성돔구이''를 주문했습니다. 숙성회의 식감에 대해 ''단단한 부드러움''이라고 표현하며 극찬했고, 비린내가 전혀 나지 않아 누구나 즐길 수 있을 것이라고 평가했습니다. 특히 광어 지느러미 부위는 10판도 먹을 수 있겠다며 만족감을 표했습니다. 함께 나온 지리탕 국물은 인공적인 맛이 없는 진한 육수라고 칭찬했으며, 감성돔구이는 달짝지근하고 고소한 맛이 일품이라고 말했습니다. 사장님이 서비스로 제공한 돌돔구이와 돌돔머리찜 역시 매우 맛있게 먹으며, 조리법에 따라 달라지는 식감의 재미를 언급했습니다. 쯔양은 유쾌한 사장님과 특색있고 맛있는 음식 덕분에 완벽한 식사였다고 총평하며, 부산에 다시 길게 여행 오고 싶을 만큼 좋은 경험이었다고 밝혔습니다(ts:1037-1051).'),
('원조범일동매떡', '부산 부산진구 골드테마길 52-2', '051-633-0166', ARRAY['분식'], 'https://www.youtube.com/watch?v=zFFdNu6cUB4', 35.1440629, 129.0602461, '부산광역시', '쯔양은 ''한국에서 제일 매운 떡볶이''로 알려진 부산의 ''매떡''에 도전했습니다. 매운 음식을 잘 먹지 못하는 쯔양은 첫 입에 단맛을 느꼈지만, 이내 몰려오는 극강의 매운맛에 눈물을 흘리며 힘들어했습니다. 그는 몸이 떨리고 지옥 같은 느낌이라고 표현하며, 매운맛을 중화시키기 위해 쿨피스와 우유를 계속 마셨습니다. 함께 주문한 팥빙수가 매운 떡볶이와 잘 어울린다고 평가했으며, 평소 통팥을 좋아하지 않음에도 맛있게 먹는 모습을 보였습니다.'),
('수제돈가스', '충북 제천시 남산로5길 13', '043-645-3939', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=OzHPMTZXs8U', 37.1335824, 128.2094517, '충청북도', '쯔양은 돈까스가 자신의 손 4개를 합친 것보다 큰 압도적인 크기와 두께에 놀라움을 표했습니다. 이렇게 큰 돈까스는 기름지기 마련인데, 이 집 돈까스는 느끼하지 않고 고기가 부드럽고 쫄깃해서 맛있다고 평가했습니다. 소스는 약간의 카레향이 나는 경양식 스타일이라고 언급했습니다. 함께 나온 된장찌개와 볶음김치도 칭찬했습니다. 추가로 주문한 물냉면은 칡냉면이며, 동치미와 육수를 섞은 국물이 시지 않고 조화로워 매우 맛있다고 극찬했습니다. 면 위에 올라간 등심 고명도 독특하고 맛있다고 평가했습니다. 식후에 제공된 수정과까지 직접 만드신다는 점에 감탄하며, 맛집은 이유가 있다는 말로 리뷰를 마무리했습니다.'),
('숙성육관', '서울 마포구 토정로37길 41 2층', '02-712-9929', ARRAY['고기'], 'https://www.youtube.com/watch?v=f5SSnbtKr1Q', 37.542715, 126.94672, '서울특별시', '쯔양은 72일 드라이에이징(건식 숙성) 한우의 새로운 맛에 크게 감탄하며 ''새로운 세상의 문이 열리는 느낌''이라고 표현했습니다. 웻에이징(습식 숙성) 안심은 부드럽고 육즙이 풍부하지만 어느 정도 씹는 맛이 살아있다고 평가했습니다. 반면, 72일 드라이에이징 등심은 숯불 향처럼 깊고 진한 향이 나며 입에서 녹는 식감이라고 극찬했고, 육즙이 고기 안에 갇혀있어 핏물이 흐르지 않는 점을 신기해했습니다. 특히 T본 부위는 ''평범한 와인과 수천만 원짜리 와인의 차이''에 비유하며, 다른 반찬 없이 소금만 찍어 먹어도 될 정도로 고기 자체의 맛이 완벽하다고 평가했습니다. 치즈처럼 고소한 풍미가 있어 와인이나 위스키와 잘 어울릴 것 같다고도 언급했습니다. 숙성 방식과 부위에 따라 맛과 식감이 명확하게 달라지는 점이 인상적이라고 요약했으며, 드라이에이징 한우의 맛을 잊고 싶지 않아 웻에이징 고기는 포장해 갔습니다.'),
('바이킹스워프 코엑스점', '서울 강남구 영동대로 513 코엑스 컨벤션센터 2층', '1644-4446', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=fAJ5qPMchfE', 37.5118239, 127.0591591, '서울특별시', '쯔양은 이곳이 예약하기 힘든 유명한 맛집이라고 언급하며 방문에 대한 기대감을 표현했습니다. 처음에 제공된 랍스터 회를 맛보고 ''정말 맛있다''며 감탄했고, 뷔페 코너를 둘러보며 흥분을 감추지 못했습니다. 특히, 랍스터 무한리필에 대해 여러 차례 놀라움을 표했으며, 치즈 랍스터 구이의 내장 맛이 일품이라고 극찬하며 최소 10마리는 먹어야겠다고 다짐했습니다. 또한, 스시의 밥(*)이 기계식이 아닌 따뜻하고 양념이 잘 된 점, 새우튀김이 인생 최고였다는 점, 전복죽이 믿을 수 없을 정도로 진하고 맛있었다는 점 등 개별 요리의 품질이 매우 높다고 평가했습니다. 디저트 역시 일반적인 뷔페 수준을 넘어선 ''카페 퀄리티''라고 칭찬했으며, 특히 젤라또가 입맛을 개운하게 해줘 더 많이 먹을 수 있게 한다고 말했습니다. 전반적으로 음식의 다양성과 높은 품질에 크게 만족했으며, 3시간이라는 식사 시간이 짧게 느껴질 정도였다고 아쉬움을 표했습니다.'),
('만리장성', '대구 중구 공평로 95', '053-425-2412', ARRAY['중식'], 'https://www.youtube.com/watch?v=5VT7nV3XTu8', 35.8725125, 128.6007012, '대구광역시', '쯔양은 2,000원이라는 믿을 수 없는 가격에 크게 놀라며, 자신이 가본 가성비 식당 중 최고라고 극찬했습니다. 저렴한 가격과 달리 짜장 소스가 매우 진하고 양도 일반 중식당만큼 푸짐하며, 큼직한 감자 등 건더기도 풍부해 맛이 훌륭하다고 평가했습니다. 7,000원짜리 ''미니'' 탕수육은 2인분으로 보일 정도로 양이 많고, 튀김이 쫄깃하고 맛이 뛰어나다고 칭찬했습니다. 50년 전통을 가진 가게이며, 어려운 사람들을 위해 10년 넘게 저렴한 가격을 유지하고 있다는 사장님의 운영 철학에 감동을 표현하기도 했습니다.'),
('신전떡볶이 본점', '대구 북구 칠성로17길 13', '053-425-6339', ARRAY['분식'], 'https://www.youtube.com/watch?v=su68Sm9TNys', 35.8798531, 128.5981126, '대구광역시', '쯔양은 신전떡볶이의 신메뉴인 쌀떡볶이와 납작만두를 먹기 위해 대구 본점을 방문했다. 쌀떡볶이는 쌀떡볶이만을 위한 전용 소스로 만들어져 기존 메뉴와는 다른 맛을 낸다고 언급했다. 떡의 쫀득한 식감을 칭찬하며 매우 맛있다고 반복해서 말했다. 또한, 대구의 명물인 납작만두를 떡볶이 국물에 찍어 먹는 조합을 즐겼으며, 바삭한 만두와 매콤달콤한 떡볶이 소스의 조화가 훌륭하다고 평가했다. 영상은 신전떡볶이의 유료 광고로 제작되었으며, 쯔양은 신메뉴의 특징과 맛을 긍정적으로 소개하는 데 집중했다.'),
('김밥천국 신음점', '경상북도 김천시 시청로 66', '054-436-4527', ARRAY['분식'], 'https://www.youtube.com/watch?v=-X47382RRus', 36.1341951, 128.1178889, '경상북도', '쯔양은 돈까스김밥, 짬뽕라면, 쫄면, 김치수제비, 스페셜떡볶이, 제육덮밥, 고구마치즈돈까스를 주문했습니다. 이 중 ''김치수제비''를 최고의 메뉴로 선정하며, 반죽의 두께와 짜지도 싱겁지도 않은 완벽한 간을 칭찬했습니다. 짬뽕라면은 매콤하고 진짜 짬뽕 맛이 나며, 돈까스김밥은 크기가 매우 크고 머스타드 소스가 특징이라고 언급했습니다. 쫄면은 새콤달콤하고 시원하며, 제육덮밥은 추억을 떠올리게 하는 맛이라고 평가했습니다. 전반적으로 꿈에 그리던 방문이었으며, 특히 더 훌륭한 식사였다고 만족감을 표현했습니다.'),
('백년화편', '서울특별시 강동구 양재대로81길 32', '02-472-1988', ARRAY['카페·디저트'], 'https://www.youtube.com/watch?v=Xy7Cp6rA3BM', 37.5233047, 127.1325494, '서울특별시', '대표 메뉴인 ''밥알찹쌀떡''은 매우 쫄깃하며, 팥앙금과 호두가 풍부하고 밥알이 씹히는 식감이 독특하고 맛있다고 평가했습니다 . ''밥알흑임자떡''은 고소하고 약간 달콤하며 아주 쫄깃하다고 언급했습니다 . 떡을 과일과 함께 먹거나 호떡처럼 팬에 구워 먹는 등 다양한 방법을 제안했으며, 특히 구웠을 때 바삭하고 뜨거워 맛있다고 칭찬했습니다 . 가게에서 특별히 만들어준 ''통가래떡 라면''에 들어간 떡이 매우 맛있어 라면의 맛을 한층 더 높여준다고 말했습니다 .'),
('고고스빨간오뎅', '서울 강동구 천호대로168가길 29', '02-474-1779', ARRAY['분식'], 'https://www.youtube.com/watch?v=Xy7Cp6rA3BM', 37.5351651, 127.130711, '서울특별시', '선물 전달을 위해 잠시 방문하여 가게의 대표 메뉴인 빨간 어묵을 소스에 찍어 먹으며 ''너무 맛있다''고 짧게 평가했습니다 . 이번 영상에서는 상세한 맛 평가보다는 사장님과의 재회에 초점이 맞춰졌습니다.'),
('독', '서울 강동구 천호대로158길 15', '0507-1354-3253', ARRAY['고기'], 'https://www.youtube.com/watch?v=Xy7Cp6rA3BM', 37.53679, 127.1264654, '서울특별시', '해당 영상에서는 음식에 대한 리뷰가 없으며, 과거 방문에 대한 감사의 표시로 떡을 전달하기 위해 방문했습니다. 사장님의 언급에 따르면, 쯔양 방문 이후 빚을 갚을 정도로 장사가 잘 되었다고 합니다 .'),
('오마카세 오사이초밥 잠실송리단길점', '서울 송파구 백제고분로45길 17-3 3층', '0507-1314-5422', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=m-8xT2PIknc', 37.5095574, 127.109429, '서울특별시', '쯔양은 가성비 좋은 오마카세 맛집으로, 저렴한 가격에도 불구하고 맛이 뛰어나 역대급 초밥이었다고 극찬했다. 특히 밥알이 입에서 녹을 정도로 맛있고 간이 완벽하다고 평가했다. 가장 인상 깊었던 메뉴로는 ''간장새우초밥'', ''가지튀김초밥'', ''우니(성게알)초밥'', ''전복찜초밥''을 꼽았다. 가지튀김초밥은 평소 가지를 즐겨 먹지 않음에도 불구하고 입에서 녹는 식감과 맛이 일품이라고 했으며, 우니는 산처럼 쌓아주는 넉넉한 양과 신선함에 감탄했다. 전복찜초밥의 내장 소스는 ''미친 맛''이라고 표현할 정도로 만족감을 드러냈으며, 모든 메뉴가 하나같이 맛있어서 먹는 내내 다음에 나올 초밥을 기대하게 된다고 말했다. 또한, 1인 8역을 주문했음에도 우니, 장어 등 고가의 메뉴 위주로 훨씬 많은 양을 먹었으며, 모든 음식을 맛있게 즐기는 모습에 셰프도 감사함을 표했다.'),
('연하동 연남본점', '서울 마포구 연남로 6', '0507-1419-3781', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=sgAEgRhwL38', 37.5605159, 126.9235536, '서울특별시', '쯔양은 이곳을 ''연어의 성지''라고 칭하며 전반적으로 모든 메뉴가 맛있고 비주얼도 훌륭하다고 극찬했습니다. 특히 주 방문 목적인 ''연어국수''는 예상보다 훨씬 맛있다며, 달콤하고 맛있는 육수가 메밀면보다 연어와 더 잘 어울린다고 평가했습니다. ''거대 꼬꼬동''은 소스가 맛있어 맛이 없을 수 없는 메뉴라고 했으며, ''거대 연어초밥''은 회와 밥의 비율이 완벽하다고 칭찬했습니다. 그 외에 ''거대 연어김밥'', 간장 베이스의 ''육회덮밥'', 트렌디한 맛의 ''매콤 까르보나라'' 등 주문한 모든 메뉴에 만족감을 표했습니다. 만약 재방문한다면 연어국수, 거대 연어초밥, 꼬꼬동은 꼭 다시 주문할 것이라고 밝혔습니다.'),
('돈까스 먹는 용만이', '서울 노원구 한글비석로20길 52', '0507-1438-8870', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=IpEnAbgpK_g', 37.6612676, 127.0746277, '서울특별시', '쯔양은 10년 만에 재방문한 어린 시절 추억이 담긴 맛집이라고 소개했습니다. 1000가지 이상의 돈까스를 개발한 사장님의 열정에 감탄하며, 다양한 퓨전 돈까스를 맛보았습니다. 특히 ''까르보나라 돈까스''는 느끼하지 않고 고소한 크림소스가 일품이라고 평했으며, ''고구마치즈 돈까스''는 달콤한 고구마 무스와 풍부한 치즈, 매콤한 소스의 조화가 천상의 맛이라고 극찬했습니다. 또한, 서비스로 받은 ''약밥 돈까스''는 상상 이상의 맛이라며 ''한국식 퓨전 돈까스''의 새로운 지평을 열었다고 평가했습니다. 이외에도 ''칠리마늘 돈까스''의 수제 마늘 후레이크, 부드러운 ''안심 돈까스'', 추억의 맛 ''기본 돈까스''와 사이드 ''스파게티''까지 모든 메뉴에 만족감을 표했습니다. 쯔양의 개인적인 순위로는 1위 고구마치즈 돈까스, 2위 눈꽃치즈칠리 돈까스, 3위 칠리마늘 돈까스를 꼽으며, 약밥 돈까스도 3위 안에 들 만한 맛이라고 덧붙였습니다.'),
('송화산시도삭면 본점', '서울 광진구 뚝섬로27길 48', '02-6052-7826', ARRAY['중식'], 'https://www.youtube.com/watch?v=EuSqOJ1YjSQ', 37.5379085, 127.0665259, '서울특별시', '쯔양은 이 식당의 음식에 대해 극찬을 아끼지 않았습니다. 특히 ''샤오롱바오''는 최근 먹어본 것 중 최고라고 평가하며, 육즙이 풍부하고 피가 얇고 쫄깃한 점을 높이 샀습니다. ''도삭면''은 향신료 걱정과 달리 아주 맛있었고, 한국식 칼국수보다는 수제비에 가까운 쫄깃한 식감이 일품이라고 했습니다. 간장 베이스의 ''충유면''보다는 매콤한 기본 도삭면을 더 선호했습니다. ''가지튀김''은 ''겉은 바삭하고 속은 촉촉한'' 맛의 정석이라며, 먹어본 가지튀김 중 최고라고 극찬했습니다. ''쇼마이''는 다른 곳보다 훨씬 크고 통통해서 입안을 가득 채우는 점이 특징이라고 언급했습니다. 이 외에도 ''건두부 감자볶음''은 감자 애호가라면 꼭 주문해야 할 메뉴라고 추천했습니다. 전반적으로 음식 양이 푸짐하고, 다시 방문하면 샤오롱바오와 가지튀김은 꼭 다시 먹을 것이라고 다짐할 정도로 만족스러운 식사였다고 총평했습니다.'),
('피씨나인', '서울 용산구 청파로47나길 13 지하1층', '0507-1374-1305', ARRAY['고기'], 'https://www.youtube.com/watch?v=mo6pcqz7gm0', 37.5455801, 126.9668288, '서울특별시', '쯔양은 PC방 내부에 정육 코너가 마련되어 있고, 주문 즉시 삼겹살과 목살 등 신선한 숙성육을 구워주는 시스템에 크게 감탄했습니다. 그녀는 흑돼지 삼겹살과 목살을 비롯해 짜파게티, 신라면, 새우삼선볶음밥, 피카츄, 핫도그, 김말이, 닭다리, 갈비만두, 떡볶이 등 엄청난 양의 메뉴를 주문했습니다. 쯔양은 음식의 양이 너무 많아 아르바이트생에게 미안함을 표현했으며, 게임은 뒷전으로 하고 먹방에 집중하는 모습을 보였습니다. 전반적으로 PC방에서 기대 이상의 고품질 음식을 맛볼 수 있다는 점, 특히 정육점에서 바로 고기를 받아보는 듯한 이색적인 경험을 매우 긍정적으로 평가하며 모든 음식을 맛있게 먹었습니다.'),
('이디야커피 IBK본점', '서울특별시 중구 을지로 79', '02-318-6427', ARRAY['카페·디저트'], 'https://www.youtube.com/watch?v=s2JFIvXsvgc', 37.566496, 126.9865832, '서울특별시', '쯔양은 이디야커피의 겨울 딸기 신메뉴 8종(음료 5종, 디저트 3종)을 모두 시식했습니다. 디저트 중에서는 ''생딸기 허니리코타 프렌치토스트''가 가장 맛있다고 평가하며, 유명 카페 디저트보다 낫다고 칭찬했습니다. 겉은 바삭하고 속은 쫄깃한 식감과 신선한 딸기, 고소한 크림치즈의 조화를 높이 평가했습니다. 음료 중에서는 ''딸기 바나나 크림 라떼''를 최고로 꼽았으며, 좋아하는 딸기 우유 사탕 맛이 난다고 언급했습니다. 프로모션 세트 메뉴로는 ''생딸기 허니리코타 프렌치토스트''와 따뜻한 ''생딸기 허니 블랙티''를 직접 선택했습니다. 딸기 메뉴 외에도 피자, 부리토, 주먹밥 등 다양한 식사 메뉴도 맛있게 먹었습니다.'),
('원효굴찜', '서울특별시 용산구 원효로 143 지하1층', '02-701-8965', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=RPIdUNqytys', 37.5344728, 126.9589134, '서울특별시', '쯔양은 겨울철 별미인 굴을 먹기 위해 ''원효굴찜''을 방문하여 총 13kg에 달하는 굴 요리를 맛보았습니다. 먼저 생굴을 맛본 뒤 전혀 비리지 않고 맛있다고 감탄했으며, 산더미처럼 쌓인 굴찜은 신선하고 속이 꽉 차 우유처럼 부드럽다고 평가했습니다. 특히 크기가 매우 큰 ''만두 굴''에 만족감을 표했습니다. 추가로 주문한 굴전은 ''미쳤다''고 표현하며 100개도 먹을 수 있을 정도로 극찬했으며, 생굴보쌈 역시 김치, 무말랭이와 함께 즐기며 맛있다고 평가했습니다. 마지막으로 해물라면에 굴을 추가해 먹으며 굴 맛이 깊게 우러난 국물에 감탄하며 ''피날레''라고 칭하며 완벽한 식사였다고 총평했습니다.'),
('성이네천원김밥', '서울 중랑구 중랑역로 150', '02-976-5648', ARRAY['분식'], 'https://www.youtube.com/watch?v=YQ3Ympo8DDk', 37.6067737, 127.0773693, '서울특별시', '쯔양은 1,000원짜리 김밥을 먹기 위해 방문했지만, 김밥뿐만 아니라 다른 모든 메뉴가 기대 이상으로 맛있어서 ''인생 맛집''을 찾았다고 극찬했습니다. 1,000원 김밥은 가격이 믿기지 않을 정도로 밥이 맛있고 참기름이 고소하며, 특히 다시마가 들어있어 식감이 좋다고 평가했습니다. 또한, 꽁치김치찌개, 직접 만든 손만두, 오징어볶음, 떡볶이, 콩나물 라면, 매생이 떡국 등 주문한 모든 음식이 하나도 빠짐없이 매우 맛있다고 반복해서 감탄했습니다. 그녀는 밑반찬부터 맛있어서 메인 메뉴도 맛있을 것이라 예상했고, 그 예상이 정확했다고 말했습니다. 쯔양은 시청자들에게 이곳에 방문하면 김밥만 먹지 말고 다양한 메뉴를 함께 즐겨서, 이렇게 좋은 가게가 오래 유지될 수 있도록 도와주면 좋겠다는 바람을 전했습니다.'),
('자매분식', '서울특별시 중구 을지로36길 23', '02-2268-1719', ARRAY['분식'], 'https://www.youtube.com/watch?v=ACjBDrlUdbM', 37.5656676, 127.0017236, '서울특별시', '쯔양은 20년 전통의 을지로 노포인 ''자매분식''을 방문하여 사장님의 손맛에 크게 감탄했습니다. 가장 먼저 맛본 **설탕 토스트**는 달콤하고 고소한 맛이 일품인 추억의 맛이라고 평했으며, **제육볶음**은 큰 기대를 하지 않았음에도 매우 맛이 좋아 밥을 부르는 맛이라고 칭찬했습니다. **김치볶음밥**은 젓갈 맛이 더해져 감칠맛이 풍부하다고 언급했고, 메뉴판에는 없지만 주문이 가능했던 **비빔국수**는 고소하고 중독성 있는 맛이라고 평가했습니다. **칼국수**는 진하고 깊은 국물 맛이 일품이며, 갓 담근 겉절이 김치와 잘 어울린다고 말했습니다. 마지막으로 맛본 **라면**은 꼬들꼬들하게 잘 끓여졌으며, 가게의 분위기 덕분에 더욱 맛있게 느껴진다고 했습니다. 쯔양은 전반적으로 모든 음식이 맛있고 사장님이 친절하여 매우 만족스러운 식사였다고 총평했습니다.'),
('편편집 강남역점', '서울 서초구 서초대로77길 31 2층', '02-535-1582', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=yiWPCX7Qwug', 37.5006169, 127.0253986, '서울특별시', '쯔양은 편백찜, 월남쌈, 샤브샤브를 모두 무한리필로 즐길 수 있다는 점을 강조하며, 강남이라는 위치를 고려할 때 가격이 매우 저렴하다고 평가했습니다. 편백찜의 소고기는 감칠맛이 풍부하고, 쪄내서 기름기가 빠져 담백하고 고소하다고 언급했습니다. 특히 편백과 팽이버섯의 향이 매우 향기롭다고 감탄했습니다. 월남쌈은 다양한 재료를 넣어 다채로운 맛을 즐길 수 있어 좋아했으며, 채소를 좋아한다면 더욱 만족할 것이라고 덧붙였습니다. 샤브샤브는 해물 육수와 매운 육수 두 가지를 맛보았는데, 해물 육수는 그 자체로 맛있고 매운 육수는 고기와 잘 어울린다고 말했습니다. 식사 후에는 남은 육수에 칼국수와 죽을 만들어 먹었는데, 특히 해물 육수로 만든 죽이 ''미쳤다''고 할 정도로 맛있다고 극찬하며, 국수와 죽까지 완벽해야 진정한 맛집이라고 평가했습니다. 전반적으로 ''완벽한 식사''였다고 결론 내리며, 샤브샤브나 월남쌈을 좋아하거나 독특한 편백찜을 맛보고 싶은 사람에게 강력히 추천했습니다.'),
('도산정육 청담본점', '서울 강남구 선릉로155길 12 1층', '0507-1304-9206', ARRAY['고기'], 'https://www.youtube.com/watch?v=Oq0Ad1hZDNg', 37.5255563, 127.0388229, '서울특별시', '쯔양은 이곳에서 다양한 부위의 돼지고기 총 3.5kg을 먹었습니다. 주요 메뉴로는 고인돌 뼈삼겹, 제주 금삼겹, 항정껍데기, 벌집껍데기, 오겹살, 목살 등을 맛보았습니다. 쯔양은 고기를 굽는 무쇠 판이 온도를 일정하게 유지해 고기 맛을 좋게 한다고 평가했습니다. 또한, 고기를 멜젓이나 들깻가루 등 다양한 소스와 곁들여 먹으며 그 조화로운 맛을 칭찬했습니다. 특히 항정살 껍데기의 쫀득하고 고소한 식감과 두툼하면서도 부드러운 고기의 질감에 감탄했으며, 된장찌개와 젓갈밥도 함께 맛있게 먹었습니다.'),
('이문설농탕', '서울특별시 종로구 우정국로 38-13', '02-733-6526', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=A6Eek_QDG_4', 37.5727716, 126.9838991, '서울특별시', '쯔양은 121년 전통의 이문설농탕을 방문하여 국물이 매우 진하고 풍부한 맛이 입안에 오래 남는다고 극찬했습니다. 대표 메뉴인 설렁탕 외에도 도가니탕, 머리탕, 수육, 우설(소혀), 마나(비장) 등 다양한 메뉴를 맛보았습니다. 도가니는 매우 부드럽고 훌륭하다고 평가했으며, 평소 냄새 때문에 잘 먹지 못하던 우설도 잡내가 완벽히 제거되어 맛있게 먹었다고 합니다. 특히 ''마나''라는 생소한 부위는 돼지 간처럼 부드럽고 고소한 맛이 나며 예상외로 맛있었다고 평가했습니다. 전반적으로 어르신들이 좋아할 만한 전통적인 맛이라고 언급하며, 진한 국물 맛에 큰 만족감을 표현했습니다.'),
('프랭크버거 송파문정점', '서울 송파구 송파대로 167 테라타워 A동 지하 1층 117호', '02-2054-8170', ARRAY['패스트푸드'], 'https://www.youtube.com/watch?v=AxxW-TwgNZk', 37.4848354, 127.1210395, '서울특별시', '쯔양은 프랭크버거의 다양한 메뉴를 맛보며 리뷰를 남겼습니다. 기본 ''프랭크 버거''는 100% 순 쇠고기 패티의 담백하고 깔끔한 맛과 육즙, 그리고 쫄깃하고 고소한 번이 특징이라고 평가했습니다. ''쉬림프 버거''는 새우 살이 통으로 들어있어 식감이 좋다고 언급했고, ''JG버거''는 푸짐한 치즈 소스 덕분에 퍽퍽하지 않고 촉촉하다고 말했습니다. 신메뉴 중 ''카츠버거''는 페스츄리 돈카츠가 매우 부드러워 입에서 녹는다고 극찬했으며, ''비프&카츠버거''는 소고기 패티가 더해져 풍미가 깊어졌다고 설명했습니다. ''크리스피 치킨버거''는 겉은 바삭하고 속은 촉촉한 치킨 다리살 패티가 인상적이라고 했고, ''핫 빅 불고기 버거''는 매콤하면서도 맛있다고 평가했습니다. 여러 메뉴를 맛본 후, 쯔양은 최종적으로 소고기 패티와 치킨 패티가 함께 들어간 ''비프&치킨버거''를 그날의 1위 메뉴로 꼽았습니다. 사이드 메뉴인 감자튀김과 오징어튀김, 바닐라 쉐이크도 맛있게 먹으며, 특히 햄버거 20개 먹기 챌린지에 성공하여 뜻깊은 기부에도 동참할 수 있어 즐거웠다고 소감을 밝혔습니다.'),
('호석촌', '서울 송파구 백제고분로39길 36', '0507-1418-2459', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=PqyGw4oPDYU', 37.5073263, 127.1034134, '서울특별시', '쯔양은 16시간 이상 끓여낸 국물이 매우 진하고 얼큰하며, 해장으로도 훌륭하다고 극찬했습니다. 또한, 고기와 부속물이 매우 푸짐하게 들어있어 만족감을 표했으며, 특히 돼지 허파가 들어간 점을 특별하게 언급했습니다. 개인적으로 선호하는 선지 순대가 아닌 당면 순대를 사용한 점에 대해 아쉬움을 표하면서도, 국물이 잘 스며들어 부드럽고 맛있다고 평가했습니다. 함께 주문한 수육은 이장우가 직접 개발한 특제 소스와 잘 어울리며 아삭한 식감이 좋다고 언급했습니다. 전반적으로 매우 만족스러운 식사였으며, 많은 사람들이 찾을 맛집이라고 예측했습니다.'),
('국립암센터', '경기도 고양시 일산동구 일산로 323', '1577-8877', ARRAY['양식'], 'https://www.youtube.com/watch?v=oKIenUI_Qdw', 37.6632301, 126.7834097, '경기도', '쯔양은 환자에게 음식이 배식되기 전, 조리된 음식을 확인하는 ''검식'' 과정에서 타워햄버그스테이크를 맛봅니다. 시식 후 ''오 맛있어요! 햄버그스테이크가 진짜 엄청 부드러워요''라고 말하며, 맛과 부드러운 식감에 대해 긍정적으로 평가했습니다. 또한, 병원 측이 항암치료로 식사를 잘 못 하는 아이들을 위해 떡볶이, 돈가스와 같은 친숙한 메뉴로 소아식을 개편하여 식사 순응도를 높이려 노력했다는 설명을 듣습니다{ts:598-ts:615}.'),
('초원튀김전문점', '경기 고양시 덕양구 마상로154번길 34', '031-964-2911', ARRAY['분식'], 'https://www.youtube.com/watch?v=POEIbq0SArQ', 37.6575984, 126.8382133, '경기도', '전체적으로 모든 음식이 매우 맛있다고 평가했다. 특히 1,000원짜리 떡볶이는 너무 달지 않으면서도 매콤하고 소스가 진해 훌륭하다고 언급했으며, 밀떡이 아닌 쌀떡을 사용한다는 점에 매우 놀라워했다. 튀김류 역시 맛있으며, 떡볶이 소스에 찍어 먹는 것을 추천했다. 어묵(2개 1,000원)과 떡꼬치(2개 1,000원)도 저렴한 가격에 비해 맛이 훌륭하다고 칭찬했다. 32년간 가격을 올리지 않은 사장님의 따뜻한 마음에 감동받았으며, 가성비뿐만 아니라 맛과 정이 넘치는 곳으로 ''엄청난 발견''이라 표현하며 재방문 의사를 밝혔다.'),
('미아리우동집 본점', '서울 성북구 종암로 160', '02-919-7270', ARRAY['분식'], 'https://www.youtube.com/watch?v=De-UKbpxEXY', 37.6040209, 127.032272, '서울특별시', '쯔양은 40년 전통의 이 식당을 어릴 적 자주 찾던 단골집으로 소개하며, 모든 메뉴가 훌륭해 순위를 정할 수 없다고 평가했습니다. 대표 메뉴인 **우동**은 직접 반죽한 생면을 사용해 면발이 부드럽고 통통하며 국물 간이 완벽하다고 칭찬했습니다. **비빔국수**는 푸짐한 양과 고소한 참기름 향이 특징이고, **잔치국수**는 진한 멸치 육수와 양념장의 칼칼한 조화가 일품이라고 언급했습니다. 또한, **짜장밥**은 남녀노소 누구나 좋아할 맛이며, **참치김밥**은 팔뚝만 한 크기에 속이 꽉 차 있다고 감탄했습니다. 특히 이곳의 시그니처인 **양념 단무지**와 직접 끓인 **옥수수냉차**, 매일 담그는 신선한 **김치** 맛을 극찬하며 40년간 꾸준히 사랑받는 이유를 알겠다고 말했습니다.'),
('중앙갈치식당', '서울 중구 남대문시장길 22-12', '02-752-2892', ARRAY['한식'], 'https://www.youtube.com/watch?v=axMRwmYxKx8', 37.5597924, 126.9770787, '서울특별시', '쯔양은 갈치조림이 먹고 싶어 남대문시장의 64년 전통 맛집인 이곳을 방문했습니다. 갈치조림, 고등어조림, 삼치구이, 코다리 양념구이, 꽁치구이, 가자미구이, 자반구이, 청국장 등 메뉴 대부분을 주문해 ''생선 파티''를 벌였습니다. 갈치조림은 양념이 진하고 맛있어 밥도둑이라며 지금껏 먹어본 중 최고라고 극찬했습니다. 특히 부드러운 삼치구이는 입에서 녹는다고 표현했고, 바삭하게 튀겨져 뼈째 먹을 수 있는 코다리 양념구이는 양념치킨 같다고 평가했습니다. 또한, 고등어조림에 들어간 묵은지와 무, 청국장 등 다른 메뉴들도 모두 맛있다고 만족감을 표했으며, 음식이 너무 맛있어 포장 주문까지 했습니다.'),
('저스트 스테이크', '서울 강남구 언주로152길 11-7', '02-544-9357', ARRAY['고기'], 'https://www.youtube.com/watch?v=CHvhhACncY8', 37.5231488, 127.0343928, '서울특별시', '쯔양은 이곳을 ''서울 3대 스테이크 맛집'' 중 하나로 소개하며, 드라이에이징된 스테이크 본연의 맛을 높이 평가했습니다. 특히 소스가 따로 필요 없을 정도로 고기 맛이 훌륭하다고 언급했습니다. T본 스테이크의 안심은 매우 부드럽고 촉촉하며 탄력 있는 식감, 등심은 두툼하고 씹는 맛이 좋다고 평가했습니다. 숯불에 구워 향이 좋다는 점도 강조했습니다. 함께 주문한 매쉬드 포테이토와 트러플 향이 나는 버섯구이도 맛있다고 칭찬했으며, 식전빵은 겉이 바삭하고 속이 부드러워 만족스러워했습니다. 전반적으로 연말 분위기와 잘 어울리는 곳이며, 콜키지 프리 정책 덕분에 가성비 좋게 즐길 수 있는 점을 장점으로 꼽았습니다.'),
('하영각', '서울특별시 강남구 개포로31길 8', '02-572-5593', ARRAY['중식'], 'https://www.youtube.com/watch?v=rHzVZMDmclI', 37.4796425, 127.0497957, '서울특별시', '쯔양은 30년 전통의 수타면 전문점인 ''하영각''을 방문하여 다양한 메뉴를 맛보았습니다. 대표 메뉴인 수타 짜장면은 면발이 굵고 쫄깃하며, 어릴 적 먹던 옛날 짜장면의 맛을 떠올리게 한다고 평가했습니다. 특히 이곳의 잡채밥은 채소를 선호하지 않음에도 불구하고 ''인생 최고의 잡채밥''이라고 극찬하며, 진한 간장 소스 맛과 쫄깃한 당면이 인상적이라고 말했습니다. 탕수육은 소스가 부어져 나오는 옛날 스타일로, 튀김옷이 부드럽고 소스와 잘 어우러져 본래 찍먹파임에도 불구하고 부먹을 인정하게 만드는 맛이라고 언급했습니다. 짬뽕은 기본적인 맛에 충실하며, 모든 메뉴의 양이 매우 푸짐하다는 점을 여러 차례 강조했습니다. 70대가 넘는 사장님이 직접 수타로 면을 뽑는 모습과, 옛날 감성을 간직한 숨은 맛집이라는 점을 높이 평가하며 전반적으로 매우 만족스러운 식사였다고 요약했습니다.'),
('진오뎅이랑정종', '서울 관악구 남현1길 58 남현58길 덕인빌딩1층', '02-581-8950', ARRAY['분식'], 'https://www.youtube.com/watch?v=ygVTaZ-XaPg', 37.4756293, 126.9805104, '서울특별시', '쯔양은 영상에서 사당역에 위치한 오뎅바 ''진오뎅이랑정종''을 방문합니다. 영상의 주된 내용은 다양한 종류의 어묵(오뎅), 곤약, 물떡 등을 맛보는 먹방입니다. 쯔양은 여러 종류의 꼬치를 대량으로 먹으며 맛있게 즐기는 모습을 보여주며, 이는 음식에 대한 긍정적인 평가로 해석됩니다. 특히 어묵 국물과 함께 사케를 곁들이며, 가게의 아늑하고 정겨운 분위기를 함께 전달합니다. 영상 내에서 직접적인 맛에 대한 상세한 설명보다는 먹는 모습 자체를 통해 맛을 표현하는 데 집중합니다.'),
('눈나무집', '서울특별시 종로구 삼청로 136-1', '02-739-6742', ARRAY['한식'], 'https://www.youtube.com/watch?v=ayjSkDH_Vtw', 37.5874862, 126.9818818, '서울특별시', '쯔양은 30년 전통의 맛집으로 국수를 팔아 빌딩을 세웠다는 이야기에 방문했다고 밝혔습니다. 다양한 메뉴를 주문했으며 각 음식에 대한 평가는 다음과 같습니다. ''떡갈비''는 양념이 맛있고 향이 진하며, 이름처럼 떡이 같이 나오는 것이 특징이라고 언급했습니다. ''김치말이국수''는 김치 맛이 강하지 않고 동치미 육수처럼 슴슴한, 평양냉면 같은 스타일로 먹을수록 감칠맛이 올라온다고 평가했습니다. 반면 ''비빔국수''는 새콤달콤하고 자극적인 맛이라 입맛에 더 잘 맞는다고 했습니다. ''녹두빈대떡''은 숙주가 들어가 향이 좋고, 얇고 부드러우면서도 식감이 살아있어 식어도 맛있다며 필수 메뉴로 꼽았습니다. ''김치볶음밥''은 고깃집 볶음밥과 비슷한 느낌이라고 했고, ''멸치국수''는 진한 멸치 육수의 고소한 맛과 탱글탱글한 면이 좋다고 평가했습니다.'),
('산골닭갈비', '서울 광진구 구의강변로7길 5', '02-444-7985', ARRAY['고기'], 'https://www.youtube.com/watch?v=KJy_UrYG1as', 37.5381861, 127.0932386, '서울특별시', '쯔양은 이곳이 춘천에서 시작해 구의동에서 30년 가까이 운영된 숨은 맛집이라고 소개했습니다. 대표 메뉴인 뼈 없는 닭갈비 12인분, 우동 사리, 볶음밥, 그리고 사이다 7병을 먹었습니다. 닭갈비에 들어있는 쌀떡이 매우 쫄깃하고 맛있다고 칭찬했으며, 닭고기는 매우 부드럽고 양념은 자극적이지 않으면서도 깊은 풍미가 있다고 평가했습니다. 특히 무쇠 철판에 눌어붙은 양념이 누룽지처럼 별미라고 언급했습니다. 하루 25인분 한정으로 판매되는 우동 사리는 한 시간 동안 삶아내어 일반 우동면과 달리 밀가루 국수 같은 독특한 식감과 맛이 일품이라고 했습니다. 마지막으로 볶음밥까지 맛본 후, ''독특하고 아주 맛있는 닭갈비''라며 자신만 알고 싶은 맛집이라고 극찬하며 식사를 마무리했습니다.'),
('빨간세상 라면학교', '경기 의정부시 시민로 83 광장타워 1층', '031-837-3334', ARRAY['분식'], 'https://www.youtube.com/watch?v=HR6dMTps16w', 37.7387725, 127.0445231, '경기도', '쯔양은 6년 전 의정부에 살 때 40번 이상 방문했던 단골집이라고 소개했다 . 그는 이곳의 다양한 라면 메뉴(빨간반, 부대반, 해물반, 북어반, 짜짜로니, 치즈반)와 불주먹밥을 주문했다 . 각 메뉴에 대한 평가는 다음과 같다: 은 위 보호를 위해 가장 먼저 먹었으며, 치즈 풍미가 진하고 국물이 맛있다고 평가했다 . 은 불고기 소스 맛의 주먹밥에 간장을 뿌려 먹는 방식으로 라면과 잘 어울린다고 언급했다 . 은 실제 부대찌개 맛이 나며 약간 맵고, 햄과 소시지가 풍부하다고 했다 . 은 시원하고 깊은 맛의 국물이 해장용으로 좋고 숨겨진 맛있는 메뉴라고 칭찬했다 . 는 가게의 특제 소스가 들어가 생각보다 맵다고 놀랐다 . 은 오징어, 떡, 새우가 들어있어 깊고 구수한 해물 맛이 난다고 했다 . 메인 메뉴인 은 신라면의 10배 매운맛으로, 목 뒤를 찌르는 강렬하지만 기분 좋은 매운맛이라고 평가했다 . 국물은 걸쭉해서 떡볶이 국물 같다고 했으며, 과거에는 이보다 더 맵게 먹었다고 회상했다 . 결국 너무 매워서 국물은 다 먹지 못했다 .'),
('남영돈', '서울특별시 용산구 한강대로80길 17', '02-793-3598', ARRAY['고기'], 'https://www.youtube.com/watch?v=HsxX7VMM718', 37.5427549, 126.9737787, '서울특별시', '쯔양은 남영돈을 ''서울 3대 고기 맛집'' 중 한 곳으로 소개하며, 2~4시간의 대기가 필요할 정도로 인기가 많다고 언급했습니다 . 직원이 직접 고기를 구워주는 서비스와 고기 두 점을 구운 후 숯을 교체해주는 세심함에 만족감을 표했습니다 . 특히 가브리살은 육즙이 풍부하고 식감이 부드러워 소고기 같다고 극찬했으며 , 항정살, 삼겹살, 목살 등 모든 부위의 품질이 매우 높다고 평가했습니다. 기본으로 제공되는 김치찌개는 시큼하고 간이 완벽해 입맛에 딱 맞았고 , 사장님의 아내가 직접 담갔다는 보쌈김치와 파김치도 훌륭하다고 칭찬했습니다 . 식사 중 우연히 만난 배우 이진욱과의 만남으로 즐거워하기도 했습니다 . 쯔양은 총 12인분의 고기를 먹으며 마지막 한 점까지 완벽한 식사였다고 총평했습니다 .'),
('위찜 청주 산남점', '충북 청주시 서원구 두꺼비로78번길 63-1 1층', '0507-1348-4552', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=1FrJg-bH63w', 36.6117672, 127.4678032, '충청북도', '쯔양은 햄지의 단골 가게인 청주 ''위찜''에 방문하여 랍스타가 포함된 조개갈비찜을 먹었습니다. 쯔양은 음식이 나오자마자 거대한 크기에 감탄했으며, 특히 문어가 전혀 질기지 않고 완벽하게 익었다고 칭찬했습니다. 해산물을 좋아하는데 여행 와서 먹으니 더욱 맛있다며, 국물 맛 또한 훌륭하다고 평가했습니다. 갈비는 처음에 ''맵다''고 반응했으나 이내 뜨거운 것이라고 정정하며 맛있게 먹었습니다. 랍스타의 거대한 집게발을 즐기는 등 전반적으로 음식에 대해 ''너무 맛있다'', ''최고다''라며 극찬을 아끼지 않았습니다.'),
('원조 쯔왕돈까스', '서울 동작구 동작대로23길 33 1층', '0507-1464-0435', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=Ot49a_phXuI', 37.4841565, 126.9798664, '서울특별시', '쯔양은 자신이 운영하는 식당 ''쯔왕돈까스''의 메뉴인 함박스테이크를 밀키트로 출시했다고 밝혔습니다. 이 함박스테이크는 갈빗살과 설도 부위를 7:3 비율로 섞어 만들었으며, 고기를 갈지 않고 직접 썰어 넣어 풍부한 육즙과 부드러운 식감을 강조했습니다. 특히 팬에 조리했을 때 육즙이 가장 풍부하다고 설명하며, HACCP 인증을 받은 위생적인 시설에서 만들었다는 점도 언급했습니다. 아이들이 있는 가정에서 인기가 많으며 밥과 함께 먹으면 훌륭한 한 끼 식사가 된다고 추천했습니다. 이 제품은 롯데홈쇼핑 라이브 방송을 통해 판매되며, 수익금의 일부는 기부될 예정이라고 밝혔습니다.'),
('영동장어', '서울 강남구 언주로148길 8', '02-3448-9991', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=Zfan5Rmea3k', 37.5203144, 127.0353321, '서울특별시', '쯔양은 ''인생에서 가장 비싼 식사''였다고 말하며, ''오늘 죽어도 여한이 없을 것 같다''고 극찬할 정도로 만족스러운 식사였다고 평가했습니다. 강화 갯벌장어에 대해서는 기존에 먹어본 장어와는 다른 새로운 종류의 장어 같다고 말하며, 생선 살처럼 부서지지 않고 매우 통통하며 쫄깃한 식감에 감탄했습니다. 특히 1.8kg짜리 가장 큰 장어는 부드러운 식감이 일품이라고 언급했습니다. 함께 먹은 독도새우(곱새우)와 머리 튀김은 감칠맛이 좋고 전혀 질기지 않다고 평가했으며, 간장게장 역시 짜지 않고 맛있다고 칭찬했습니다. 성게알과 한우육회 조합은 ''행복한 맛''이라고 표현했습니다. 다만, 장어 쓸개즙은 맛이 없어서 뱉었다고 합니다.'),
('평화김해뒷고기 건대점', '서울 광진구 아차산로31길 9-1 1층', '02-465-7290', ARRAY['고기'], 'https://www.youtube.com/watch?v=J-8YlExkAnI', 37.5415668, 127.0693396, '서울특별시', '쯔양은 ''평화김해뒷고기''의 모든 메뉴에 대해 극찬했습니다. 메인 메뉴인 뒷고기는 소스 없이 먹어도 매우 맛있으며, 단단하면서도 부드러운 식감이 일품이라고 평가했습니다. 특히 HACCP 인증을 받은 국내산 고품질 돼지고기를 사용한다는 점을 긍정적으로 언급했습니다. 또한 해물 된장찌개와 김치찌개는 물론, 특제 간장 소스와 매운 소스도 맛있다고 칭찬했습니다. 사이드 메뉴인 ''평화 껍데기''는 바삭하고 고소하며, ''치즈 김치 볶음밥''은 계란과 치즈의 조화가 훌륭하고 누룽지까지 즐길 수 있어 특별하다고 말했습니다. 마지막으로 ''물비빔냉면''은 고깃집 후식의 완벽한 마무리라고 평가하며, 고기, 소스, 사이드 메뉴까지 모든 것이 완벽하게 맛있어서 친구들과 꼭 다시 방문하고 싶은 곳이라고 총평했습니다.'),
('지하식당', '광주 서구 천변좌로 154', '062-364-1448', ARRAY['중식'], 'https://www.youtube.com/watch?v=j1CqEj3awPg', 35.1591244, 126.8956101, NULL, '쯔양은 3000원이라는 저렴한 가격에 놀라움을 표하며, 메뉴판의 전반적인 가격대도 훌륭하다고 평가했습니다, ). 짜장면은 참깨가 들어가 고소한 향이 나며, ), 요즘 짜장면처럼 자극적이지 않고 순한 ''옛날 짜장면'' 맛이라고 설명했습니다, , ). 개인적으로는 짭짤한 맛을 선호해 약간 순하게 느꼈지만, 특유의 고소한 맛이 이를 보완해준다고 덧붙였습니다, ). 총 8그릇을 먹고 24,000원이라는 가격에 감탄하며, 저렴하고 좋은 음식을 제공하는 사장님들에 대한 감사함을 표현했습니다, , ).'),
('금성식당', '광주 동구 제봉로222번길 2', '062-227-4717', ARRAY['한식'], 'https://www.youtube.com/watch?v=j1CqEj3awPg', 35.1550398, 126.9138819, NULL, '영상에서 쯔양은 ''금성식당''의 삼겹살과 김치찌개를 조합해서 먹었는데 정말 맛있었다고 회상합니다, ). 웹 검색 결과에 따르면, 쯔양은 이곳을 ''인생 삼겹살'' 맛집으로 극찬했으며 여러 번 재방문한 것으로 확인됩니다. 그녀가 즐겨 먹는 삼겹살과 김치전골 조합은 ''쯔양 세트''라는 메뉴로 만들어질 정도로 유명해졌습니다.'),
('서울뼈구이매운족발', '서울 동대문구 왕산로 274-1', '02-965-5838', ARRAY['한식'], 'https://www.youtube.com/watch?v=9tv92qClTuE', 37.5850444, 127.051295, '서울특별시', '쯔양은 가장 매운맛인 ''아주 매운맛'' 뼈구이를 주문했습니다. 첫입부터 극강의 매운맛에 놀라면서도, 숯불 향이 은은하게 배어 있고 양념이 잘 스며들어 맛있게 맵다고 평가했습니다. 특히 고기가 매우 부드러워 뼈와 살이 쉽게 분리되는 점을 극찬했습니다. 매운맛을 중화시키기 위해 날치알 주먹밥과 서비스로 제공된 계란찜을 함께 먹으며, 극심한 매움에도 불구하고 중독성 있는 맛 때문에 계속 먹게 된다고 언급했습니다. 땀을 매우 많이 흘리면서도 ''맛있게 맵다''는 점을 반복해서 강조하며 만족스러운 반응을 보였습니다.'),
('산청숯불가든 을지로', '서울 중구 을지로 114-6 1층', '02-2273-8188', ARRAY['고기'], 'https://www.youtube.com/watch?v=JAh27fYryjw', 37.5658389, 126.9906186, '서울특별시', '쯔양은 먼저 대표 메뉴인 재래식 소금구이를 맛보았습니다. 두툼한 흑돼지 고기는 육즙이 풍부하고 식감이 쫄깃하며 고소하다고 평가했습니다. 특히 함께 구운 쪽파와 명란 쌈장, 우렁조림 등 다양한 곁들임 반찬과의 조합을 즐겼습니다. 다음으로 먹은 고초장 양념구이는 매콤한 맛이 특징이라고 언급했습니다. 식사 마무리로는 산청볶음밥을 먹으며 만족감을 표했습니다. 쯔양은 긴 대기 시간에도 불구하고 방문할 가치가 충분한 맛집이라고 긍정적으로 평가했습니다.'),
('전주집', '서울 종로구 종로40가길 5', '02-2267-6897', ARRAY['한식'], 'https://www.youtube.com/watch?v=Eb5AYxy_7ag', 37.5702657, 127.0063922, '서울특별시', '쯔양은 새벽 6시에 방문하여 ''진짜 집밥'' 같다고 평가했습니다. 40년 전통의 맛집으로, 대표 메뉴인 오징어볶음과 생선구이를 극찬했습니다. 오징어볶음은 통오징어로 나와 양이 푸짐하고 통통하며, 양념이 정말 맛있다고 감탄했습니다. 생선구이는 갈치와 임연수가 매우 크고 살이 부드러우며 신선하다고 평가했고, 특히 갈치와 오징어볶음은 꼭 먹어봐야 할 메뉴로 추천했습니다. 김치찌개는 엄마가 끓여준 맛과 같다고 했으며, 된장찌개 또한 한식의 최고봉이라고 칭찬했습니다. 전체적으로 모든 음식이 다 맛있어서 여러 명이 함께 방문해 다양한 메뉴를 맛보길 권했으며, 음식 맛에 감탄하며 밥을 3공기나 먹고 오징어볶음과 제육볶음은 포장까지 했습니다.'),
('영식품', '서울특별시 성동구 성수이로 126', '02-469-2900', ARRAY['한식'], 'https://www.youtube.com/watch?v=YwHVzstKtD8', 37.5461114, 127.0577706, '서울특별시', '쯔양은 이곳을 최고의 ''가맥집'' 중 하나로 꼽으며, 주문한 모든 메뉴가 맛있다고 극찬했습니다(''ts:208'', ''ts:392'', ''ts:887''). 특히 입에서 녹을 정도로 부드러운 수육(''ts:380''), 훌륭한 맛의 김치(''ts:246'')와 무김치(''ts:392''), 계란물을 입혀 부쳐낸 특별한 김밥전(''ts:291'', ''ts:545'')을 인상 깊게 평가했습니다. 또한 수육과 차가운 무김치 국수의 조합이 환상적이라고 언급했습니다(''ts:474''). 그 외 너구리 라면, 오징어, 햄전, 서대구이, 굴전 등 주문한 8가지 모든 음식이 맛있고, 술안주로 완벽하다고 평가하며 운전 때문에 술을 마시지 못해 아쉬워했습니다(''ts:728'', ''ts:887'').'),
('세광양대창 강남점', '서울 강남구 역삼로5길 22', '02-568-9231', ARRAY['고기'], 'https://www.youtube.com/watch?v=a1dVcHANmYg', 37.4953441, 127.0320369, '서울특별시', '쯔양은 ''세광양대창 강남점''의 분위기가 술과 함께 즐기기 좋다고 평가했습니다. 특히 신메뉴인 ''마늘 소갈비살''은 달콤한 양념과 마늘, 훈연향의 조화가 뛰어나고 부드러우면서도 쫄깃한 식감에 감탄하며 추가로 주문할 만큼 만족스러워했습니다. ''한우곱창''은 속이 꽉 차 있으며 마늘 기름장과 함께 먹을 때 마늘향이 풍미를 더해 술안주로 완벽하다고 언급했습니다. 또한, 기본 안주로 나오는 순두부찌개와 느끼함을 잡아주는 고추 장아찌를 극찬했으며, 얼그레이 하이볼과 위스키 하이볼도 맛있게 마셨습니다. 기존 메뉴인 대창과 특양은 쫄깃한 식감과 고소한 맛이 특징이며, 이 집의 가장 큰 강점은 ''양념''이라고 강조했습니다. 그 외에도 1++ 등급 한우 차돌박이, 꼭 먹어봐야 할 메뉴로 꼽은 카레라이스, 해장국수 등 다양한 메뉴를 즐기며 전반적으로 높은 만족도를 보였고, 가격이 저렴하다는 점도 장점으로 꼽았습니다.'),
('BBQ치킨 빌리지 송리단길점', '서울 송파구 석촌호수로 284', '02-2203-8292', ARRAY['치킨'], 'https://www.youtube.com/watch?v=25hLzjL0hgA', 37.5107414, 127.107, '서울특별시', '쯔양은 BBQ에서 새로 리뉴얼된 양념치킨을 극찬했습니다. 이전 양념치킨은 신맛이 강해 좋아하지 않았지만, 이번 신제품은 완전히 달라졌다고 평가했습니다. 소스는 옛날 스타일의 클래식한 맛이며, 튀김옷이 매우 얇아 소스가 잘 배어들고 전혀 느끼하지 않다고 설명했습니다. 최근 먹어본 양념치킨 중 최고라고 말하며, 질리지 않고 다섯 마리를 다 먹을 수 있을 정도로 맛있다고 했습니다. 심지어 BBQ의 대표 메뉴인 황금올리브보다 훨씬 맛있다고 평가하며, 당분간은 이 치킨만 먹을 것 같다고 만족감을 표현했습니다. 치킨이 약간 식었을 때는 닭강정처럼 쫄깃하고 맛있다고 덧붙였습니다. 함께 마신 ''스파클링 레몬 보이'' 음료도 치킨과 잘 어울리는 깔끔한 맛이라고 언급했습니다.'),
('마포원조떡볶이', '서울 마포구 도화2길 3', '02-719-2005', ARRAY['분식'], 'https://www.youtube.com/watch?v=jChwfg251IM', 37.5403361, 126.9487963, '서울특별시', '쯔양은 이 식당의 떡볶이가 온라인상의 정보와는 달리 밀떡으로 만들어졌다고 밝혔습니다. 떡의 식감은 쫄깃하기보다는 부드러우며, 소스는 색깔만큼이나 맛이 진하고 먹을수록 매워진다고 평가했습니다. 매운맛을 중화시키기 위해 어묵 국물에 섞어 먹는 방법을 추천하며 맛있다고 언급했습니다. 함께 주문한 김밥에 대해서는 속 재료가 단순하지만 밥에 양념이 잘 되어있고 매우 맛있다고 여러 차례 칭찬했습니다. 튀김 중에서는 특히 야끼만두가 소스와 잘 어울리고, 어린 시절 먹던 맛이 난다며 가장 맛있었던 메뉴로 꼽았습니다. 순대 내장(허파)도 맛있다고 언급했으며, 어묵 국물은 국물이 매우 진하다고 평가했습니다.'),
('꼭대기집약수터', '인천 강화군 길상면 장흥로101번길 31-11', '0507-1442-3578', ARRAY['고기'], 'https://www.youtube.com/watch?v=DncejNvRvTM', 37.611888, 126.5106203, '인천광역시', '쯔양은 이곳의 야외 분위기와 자연 경관을 극찬하며, 캠핑하는 느낌이 들어 음식 맛이 더 좋게 느껴진다고 평가했습니다. 메인 메뉴인 삼겹살은 매우 신선하고 고소하여 소금만 찍어 먹어도 맛있다고 언급했습니다. 특히 솥뚜껑에 구운 감자는 겉은 바삭하고 속은 촉촉해 ''미쳤다''고 표현할 정도로 감탄했으며, 오븐에 구운 감자 웨지 같다고 했습니다. 의외의 발견으로 버터 향이 나는 부드러운 오징어 구이를 꼽았고, 달고 촉촉한 가지 구이도 인생 최고의 맛이라고 칭찬했습니다. 또한, 시골 스타일의 시큼한 김치와 삼겹살, 와사비의 조합을 최고의 조합으로 추천했습니다. 전반적으로 음식뿐만 아니라 분위기까지 완벽한 곳으로, 주말에는 예약이 필수라고 강조하며 가족이나 친구와 함께 방문하기를 추천했습니다.'),
('신길동매운짬뽕', '서울 영등포구 영등포로62길 10-1', '010-5395-1151', ARRAY['중식'], 'https://www.youtube.com/watch?v=3Zyb_DU2jFg', 37.5153258, 126.9165068, '서울특별시', '쯔양은 매운맛 유튜버 맵하니와 대결하기 위해 신길동 매운짬뽕을 방문했습니다. 대표 메뉴인 매운짬뽕을 먹으며 이전 방문 때보다 훨씬 맵다고 하며 눈물을 흘렸고, 결국 대결에서 패배를 인정했습니다. 하지만 캡사이신을 사용하지 않고 고춧가루로 매운맛을 내는 점을 긍정적으로 평가했습니다. 이후 얼큰차돌짬뽕, 짜장면, 김밥을 추가로 주문하여 먹었고, 얼큰차돌짬뽕 또한 맵지만 맛있다고 언급했습니다. 너무 매운 매운짬뽕 국물을 제외하고는 대부분의 음식을 다 먹었습니다.'),
('영화장', '서울 동대문구 휘경로 3-8', '02-967-9595', ARRAY['중식'], 'https://www.youtube.com/watch?v=GeRkd99WZbU', 37.5965718, 127.0609522, '서울특별시', '쯔양은 이 식당의 모든 음식이 맛있다고 극찬하며, 방문했던 중식당 중 모든 메뉴가 맛있었던 적은 처음이라고 감탄했습니다. 특히 짜장면은 감자가 들어간 옛날 스타일로, 인생 짜장면이라고 칭하며 매일 시켜 먹고 싶을 정도라고 평가했습니다. 탕수육은 서울 3대 탕수육으로 불릴 만하며, 소스가 부어져 있음에도 매우 바삭하고 맛있다고 언급했습니다. 고추짬뽕은 사골 국물처럼 진하고 매우면서도 상쾌한 맛이 특징이며, 면이 얇고 해산물이 풍부하다고 설명했습니다. 후추소고기는 기대를 안 했지만 매우 부드러워 놀랐다고 했고, 양주볶음밥은 햄이 들어가 고소하고 맛있다고 했습니다. 마늘새우는 숨겨진 보물 같은 메뉴라고 칭찬했지만, 깐쇼새우는 생강 향이 강해 아쉬웠다고 평했습니다. 전반적으로 70년 역사에 걸맞은 깊은 맛을 가진 곳으로, 꼭 다시 방문하고 싶다고 밝혔습니다.'),
('돈까스산골녹차냉면', '서울특별시 용산구 효창원로 147 1층', '0507-1368-1990', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=1ada3VIR1fQ', 37.5412975, 126.9618496, '서울특별시', '쯔양은 이 식당의 모든 메뉴를 주문하여 리뷰를 진행했다. 식전 수프는 전형적인 서양식 수프로 크리미하고 맛있다고 평가했다. ''왕돈까스''는 매우 크고 두툼하며, 소스에 잠긴 부분은 부드럽고 다른 부분은 바삭하여 두 가지 식감을 즐길 수 있다고 언급했다. 특히 ''비빔냉면''은 녹차 면으로 만들어져 독특하며, 새콤달콤하고 상쾌한 맛이 일품이라고 극찬하며 ''오늘의 MVP''로 꼽았다. ''생선까스''는 일반적인 타르타르 소스가 아닌 머스타드 맛이 나는 특별한 소스가 인상적이며, 생선 살이 매우 부드럽다고 호평했다. ''메밀전병''은 겉은 바삭하고 속은 쫄깃하며, 만두소 같은 내용물도 맛있다고 평가했다. ''매운 돈까스''는 신라면 정도의 맵기이며, 오리지널보다 소스가 더 맛있고 풍미가 좋다고 말했다. ''물냉면''도 맛있지만 비빔냉면이 더 낫다고 평가했으며, 전반적으로 모든 음식의 양이 푸짐하고 만족스러운 식사였다고 총평했다.'),
('월곡동대머리곱창', '서울특별시 강북구 숭인로 65-10, 1층', '02-985-7002', ARRAY['고기'], 'https://www.youtube.com/watch?v=vrPyXja4oaY', 37.6128194, 127.0289215, '서울특별시', '13년 만에 재방문한 곳으로, 어머니의 단골집이라고 소개했다. 소금 막창 12인분을 주문했으며, 겉은 바삭하고 속은 질기지 않고 쫄깃하며 맛있다고 평가했다. 특히 옛날에 먹었던 맛이 그대로 느껴진다며 만족감을 표했다. 바삭한 것보다 촉촉한 막창을 선호하지만 이곳의 바삭한 막창도 맛있다고 언급했다. 쌈장과 사이다를 섞어 막장과 비슷한 소스를 직접 만들어 먹는 팁을 보여주었다. 들깻잎, 구운 마늘, 볶은 김치 등과 함께 먹으며 매우 만족스러워했고, ''막창 천국''이라고 표현하며 행복해했다. 식사 후에는 옛 추억이 떠오르는 따뜻한 곳이었다고 소감을 밝혔다.'),
('공간미학', '경기 평택시 오성면 신2리길 59-18', '0507-1350-2791', ARRAY['카페·디저트'], 'https://www.youtube.com/watch?v=zXlveWbjCls', 37.0077785, 127.0102063, '경기도', '뒤에 펼쳐진 논밭 뷰가 아름답고, 카페가 넓고 멋지다고 평가함. 통창이 있어 편안한 느낌을 주며, 비 오는 날 창밖을 보며 빵을 먹는 분위기를 즐김. 경기도의 유명 쌀빵들을 모아놓고 맛볼 수 있는 공간이라는 점을 긍정적으로 언급함.'),
('생제비', '경기 가평군 설악면 한갑골길 76-20', '0507-1330-6228', ARRAY['카페·디저트'], 'https://www.youtube.com/watch?v=zXlveWbjCls', 37.6724253, 127.4802409, '경기도', '가평 잣 만쥬는 속이 꽉 차 있고, 부드럽지 않고 단단한 질감의 소가 자연적인 느낌을 준다고 평가함. 가평 잣 쿠키도 맛있다고 언급함.'),
('서울쭈꾸미 영동직영점', '서울 강남구 학동로4길 21', '02-545-6234', ARRAY['한식'], 'https://www.youtube.com/watch?v=N4nuqaAs79g', 37.5100841, 127.0232471, '서울특별시', '유튜버는 1단계부터 3단계까지의 매운맛 쭈꾸미를 주문합니다. 1단계는 맛있게 매콤한 정도이며, 2단계부터는 매운맛이 확 올라와 땀이 나기 시작합니다. 3단계는 극강의 매운맛으로, 유튜버가 먹다가 결국 포기할 정도의 수준입니다. 쭈꾸미는 통통하고 식감이 좋으며, 함께 나오는 깻잎, 날치알, 마요네즈 소스와의 조합이 좋다고 평가합니다. 매운맛을 중화시키기 위해 계란찜과 쿨피스를 함께 먹습니다.'),
('푸른하늘', '서울특별시 동대문구 경희대로6길 3-4', '02-960-3394', ARRAY['분식'], 'https://www.youtube.com/watch?v=z0TENHkJmzA', 37.5935467, 127.0530848, '서울특별시', '쯔양은 경희대학교 인근에 위치한 이 분식점을 방문하여, 가성비가 매우 뛰어나다고 평가했습니다. 특히 팔뚝만 한 크기를 자랑하는 ''왕김밥''에 대해 속이 꽉 차 있고, 밥이 쫀득하며 간이 완벽하다고 극찬하며 인생 최고 수준의 김밥 중 하나라고 언급했습니다. 참치김밥은 마늘이 들어가 독특한 맛이 나고, 제육김밥도 맛있다고 평가했습니다. 또한, 일반 분식점에서는 보기 드문 ''토종순대''를 잡내 없이 훌륭하며, 함께 제공된 쌈장과의 조화가 좋다고 여러 번 칭찬했습니다. 치즈라볶이는 달콤하고 매콤한 맛의 조화가 좋고, 양이 매우 푸짐하다고 언급했습니다. 전체적으로 대학가 상권의 특징인 저렴한 가격과 푸짐한 양에 큰 만족감을 드러냈습니다.'),
('천우목장', '서울특별시 용산구 한강로1가 234-5 1층', '0507-1466-1069', ARRAY['고기'], 'https://www.youtube.com/watch?v=iig0YSPArE0', 37.5329065, 126.9719271, '서울특별시', '쯔양은 이전에 팀 회식으로 방문했을 때 고기와 특히 무생채가 매우 맛있어서 다시 찾아왔다고 밝혔습니다. 소금구이 소갈비는 육즙이 풍부하고 고기 향이 진하며, 잡내가 전혀 없이 고소하다고 평가했습니다. 또한 질긴 부위 하나 없이 부드러우면서도 쫄깃한 식감이 일품이라고 칭찬했습니다. 양념 소갈비는 ''짝갈비'' 형태로 등심, 안창살 등 여러 부위가 섞여 다양한 맛과 식감을 즐길 수 있는 점이 좋았다고 합니다. 양념은 과하지 않은 단맛으로 고기 본연의 맛을 해치지 않으며, 먹을수록 더 맛있게 느껴진다고 했습니다. 여러 번 리필해 먹은 무생채는 ''악마의 무생채''라고 부를 정도로 극찬했으며, 코를 톡 쏘지 않으면서 향긋한 와사비와의 조합도 좋았다고 평가했습니다. 함께 주문한 된장찌개와 육회도 양념이 잘 되어 있고 맛이 훌륭하다고 언급하며 전반적으로 매우 만족스러운 식사였다고 총평했습니다.'),
('엄마찬스분식 본점', '대전 서구 갈마중로 27', '042-822-8384', ARRAY['분식'], 'https://www.youtube.com/watch?v=fsxL5bd7xoE', 36.3477476, 127.3723582, '대전광역시', '쯔양은 떡볶이에 대해 맵고 달콤한 맛이 조화로워 누구나 좋아할 만한 ''교과서 같은 맛''이라고 평가했습니다. 특히 순대의 신선도에 감탄했는데, 간이 전혀 퍽퍽하지 않고 매우 부드럽고 쫄깃하다고 칭찬했습니다. 분식집에서 순대와 함께 막장을 제공하는 것에 놀라워하며 만족감을 표했습니다. 또한 꼬마김밥은 김과 밥 자체가 맛있다며 칭찬을 아끼지 않았고, 음식이 식어도 맛있을 것 같다며 전반적인 맛에 크게 만족하며 서울에도 분점을 내달라고 요청했습니다.'),
('불공장', '서울 강남구 강남대로156길 31-9', '02-545-1231', ARRAY['고기'], 'https://www.youtube.com/watch?v=_oYJdQvFxKo', 37.5190826, 127.0214274, '서울특별시', '쯔양은 신사동에 위치한 ''불공장''을 방문하여, 대구에서 당일 도축해 KTX로 배송받는 뭉티기와 성게알 조합에 큰 감명을 받았습니다. 특히, 접시를 뒤집어도 떨어지지 않는 뭉티기의 신선함과 대구식인 결 반대로 썬 뭉티기의 부드러운 식감을 ''역대급 뭉티기''라고 극찬했습니다. 캐나다, 러시아, 보스턴, 보스턴 프리미엄 4종의 성게알을 비교하며 모두 각자의 매력이 있고 비린 맛 없이 훌륭하다고 평가했습니다. 뭉티기와 성게알의 조합은 환상적이라고 표현했으며, 차돌 오드레기, 쭈꾸미 불고기, 소고기뭇국, 볶음밥 등 다른 메뉴들도 맛있다고 언급했습니다. 전반적으로 음식이 펍(주점) 형태에 맞게 짭짤한 편이라고 설명하며, ''인생 맛집'' 중 하나로 꼽고 재방문 의사 100%를 밝혔습니다.'),
('쌍다리돼지불백 본점', '서울 성북구 성북로23길 4', '02-743-0325', ARRAY['한식'], 'https://www.youtube.com/watch?v=2zX2zFonIEE', 37.5935196, 126.9957164, '서울특별시', '쯔양은 이 식당의 대표 메뉴인 돼지불백을 시작으로 떡갈비, 돼지갈비, 주꾸미, 냉면, 된장찌개 등 다양한 메뉴를 주문하여 리뷰했습니다. 돼지불백은 고기가 질기지 않고 부드러우면서도 쫄깃하며, 숯불 향이 강하고 양념이 과하지 않아 고기 본연의 맛을 잘 느낄 수 있다고 평가했습니다. 칡냉면은 시판 육수 맛이 아닌 동치미가 섞인 듯한 건강하고 상쾌한 맛이라고 칭찬하며 고기와 함께 먹는 조합을 추천했습니다. 떡갈비는 불고기와는 또 다른 맛을 가졌으며, 된장찌개는 시골된장으로 끓인 집밥 같은 맛에 우렁이 들어있어 맛있다고 언급했습니다. 전반적으로 음식의 양념이 강하지 않아 재료 본연의 맛을 살린 점을 높이 평가했으며, 모든 연령대가 좋아할 만한 맛이라고 결론지었습니다. 특히 돼지불백, 된장찌개, 냉면 세 가지의 조합이 훌륭하다고 강조했습니다.'),
('중화가정 용산역점', '서울특별시 용산구 새창로 213 지상2층 (한강로2가)', '02-3785-3332', ARRAY['중식'], 'https://www.youtube.com/watch?v=TA-aeCFktME', 37.5304792, 126.9672652, '서울특별시', '쯔양은 4-5년 만에 ''괴물짜장면'' 도전을 위해 중화가정 용산점을 재방문했습니다. 음식이 나오자 ''냄새가 정말 좋다'', ''훈제향이 확 올라온다''며 맛에 대한 기대감을 표현했고, ''맛있다''고 평가했습니다. 2kg가 넘는 많은 양이었지만 12분 챌린지에 성공하며 여전한 대식가의 면모를 보여주었습니다. 다만 과거의 기록을 깨지 못한 것에 아쉬움을 표하며, ''예전에도 맛있었고 지금 먹어도 맛있다''고 말해 맛 자체에 대해서는 만족스러운 후기를 남겼습니다.'),
('엄마네한우', '경기도 남양주시 진접읍 양진로926번길 24-13', '1877-4495', ARRAY['고기'], 'https://www.youtube.com/watch?v=m3HTdYfHpD4', 37.7036049, 127.1819033, '경기도', '쯔양은 ''엄마네한우''의 1++ 등급 한우 선물세트가 정육점에서 막 사 온 것처럼 매우 신선하다고 평가했습니다. 그는 고급스러운 포장과 고기 품질에 감탄하며, 특히 고밀도 스티로폼과 완벽한 진공 포장 덕분에 육즙 손실이나 핏물 고임이 없는 점을 높이 샀습니다. 쯔양은 등심, 채끝, 살치살 등 다양한 부위를 맛본 후, 모든 부위가 소금을 찍지 않아도 될 정도로 육즙이 풍부하고 감칠맛이 뛰어나며 매우 부드럽다고 극찬했습니다. 평소 즐기지 않는 부위조차 맛있었다고 언급하며 제품에 대한 높은 만족감을 표현했고, 감사한 분들을 위한 선물로 적극 추천했습니다.'),
('따뜻한밥상 연신내', '서울 은평구 연서로 260 2층', '010-9626-1371', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=ET36pk-i4U0', 37.6199655, 126.9236744, '서울특별시', '쯔양은 이 식당의 김치찌개를 ''MSG가 들어가지 않은 집밥 같은 맛''이라고 평가하며, 국물이 진하고 김치 본연의 맛이 잘 살아있다고 말했습니다. 특히 가격이 3,000원임에도 불구하고 고기가 아주 푸짐하게 들어있고, 질기지 않고 부드럽고 쫄깃해서 좋은 재료를 쓴다고 느꼈다고 합니다. 밥이 무한리필이라는 점과 8,000원짜리 김치찌개와 비교해도 손색없는 맛과 양이라고 극찬했습니다. 또한, 주머니가 가벼운 사람들을 위해 저렴하고 따뜻한 식사를 제공하려는 사장님의 좋은 취지를 응원하며, 더 많은 사람들이 방문하여 식당이 오래 유지되기를 바란다고 말했습니다.'),
('착한고깃집 안산월피점', '경기 안산시 상록구 충장로 586', '0507-1441-1979', ARRAY['고기'], 'https://www.youtube.com/watch?v=l0qUMLzy_2E', 37.3302541, 126.8510354, '경기도', '쯔양은 코미디언 권재관의 추천으로 안산에 위치한 고깃집 ''착한고깃집''을 방문하여 뒷고기, 뒤통수살, 두항정살, 삼겹살 등 다양한 부위를 총 32인분(5.2kg) 주문했습니다. 식당에서 직접 만든 쌈장과 숙성된 고기 맛에 감탄했으며, 특히 부위별 맛 평가를 상세하게 남겼습니다. 다릿살(뒷고기)은 매우 쫄깃하고 바삭한 식감이 일품이라고 했고, 뒤통수살은 기름지지 않고 쫄깃한 지방 부위가 매력적이라고 평가했습니다. 삼겹살 역시 맛있다고 언급했으며, 마지막으로 먹은 두항정살은 우유 맛이 날 정도로 고소하고 육즙이 풍부하여 그날 먹은 부위 중 1위로 꼽았습니다. 처음에는 실수로 많은 양을 주문했지만, 맛에 매우 만족하여 거의 모든 고기를 먹어 치웠습니다.'),
('빽찐라면', '서울 동작구 상도로 295', '02-6397-4186', ARRAY['분식'], 'https://www.youtube.com/watch?v=Td-nXxKGqT0', 37.5014468, 126.949575, '서울특별시', '쯔양은 이 식당의 라면들이 일반 인스턴트 라면이 아닌 ''제대로 된 요리'' 같다고 극찬했습니다. 그녀는 찐라면, 빽라면, 마라라면 세 종류를 모두 맛보았습니다. ''찐라면''은 다진 마늘이 듬뿍 들어가 국물이 매우 진하고 얼큰하며, 순두부찌개나 짬뽕에 비유할 만큼 깊은 맛이 난다고 평가했습니다. 특히 해장용으로 최고라고 언급하며 개인적인 원픽으로 꼽았습니다. ''빽라면''은 맵지 않고 고소한 국물이 특징으로, 계란 노른자를 터뜨려 햄, 면과 함께 먹는 방식이 인상적이라고 했습니다. ''마라라면''은 새로 출시된 메뉴로, 얼얼한 마라 맛이 매우 강하면서도 국물 베이스의 깊은 맛이 조화롭다고 설명했습니다. 쯔양은 세 메뉴 모두 면을 공중에서 계속 섞어주는 조리법 덕분에 면발이 특히 쫄깃하고 맛있다고 여러 번 강조했습니다.'),
('동대문엽기떡볶이 신촌점', '서울특별시 서대문구 연세로5가길 14 2층', '02-365-8592', ARRAY['분식'], 'https://www.youtube.com/watch?v=2p1-JhJ_PZM', 37.557437, 126.9359782, '서울특별시', '쯔양은 품절 대란인 마라 엽떡을 먹기 위해 10곳 이상 전화한 끝에 신촌점에서 주문에 성공했습니다. 처음에는 마라맛이 너무 강하지 않고 얼얼한 맛도 미묘해서 좋다고 평가했지만, 먹을수록 혀가 얼얼하고 마비되는 느낌에 힘들어했습니다. 일반적인 매운 음식과 달리 마라 특유의 얼얼함 때문에 땀을 많이 흘렸으며, 중간중간 쿨피스를 많이 마셨습니다. 떡, 소고기, 중국당면, 분모자, 꿔바로우, 튀김 등 다양한 토핑을 추가했으며, 특히 꿔바로우와 마라 떡볶이의 조합이 좋다고 언급했습니다. 전반적으로 떡볶이보다는 졸인 마라탕에 가까운 맛이라고 표현했으며, 매운 것보다 얼얼한 것을 잘 못 먹는 자신을 발견했다고 말했습니다. 결국 너무 맵고 혀가 타는 듯한 느낌 때문에 다 먹지 못하고 식사를 중단했습니다.'),
('우성닭갈비', '서울 종로구 삼일대로17길 17', '02-733-9690', ARRAY['한식'], 'https://www.youtube.com/watch?v=G_Oq32bGM74', 37.5690643, 126.9865096, '서울특별시', '쯔양은 닭갈비 8인분, 닭 내장 2인분, 우동 사리를 주문했습니다. 닭갈비는 우리가 아는 클래식한 맛이라고 평가했으며, 소스가 맛있다고 언급했습니다. 특히 닭고기로 부드러운 닭다리살을 사용하는 점과, 쫄깃한 쌀떡을 칭찬했습니다. 처음 먹어본 닭 내장(난소)은 잡내가 없고 곱창보다 더 쫄깃하고 마른 식감이라고 설명했습니다. 닭갈비와 최고의 조합으로 동치미를 꼽았고, 깻잎, 상추, 무쌈 등 다양한 쌈 조합을 즐겼습니다. 개인적인 취향으로 마요네즈를 요청해 찍어 먹으며 맛있다고 반복했습니다. 아쉽게도 감자 사리가 없는 점을 아쉬워했습니다. 마무리로 볶음밥 1인분을 주문했으며, 닭갈비를 먹은 후에는 볶음밥이 필수라고 강조했습니다. 특히 새 양념으로 볶아주는 볶음밥과 바삭하고 쫄깃한 누룽지의 식감이 훌륭하다고 극찬했습니다.'),
('고고s 빨간오뎅 길동점', '서울특별시 강동구 양재대로116길 42', '010-8391-0728', ARRAY['분식'], 'https://www.youtube.com/watch?v=liIJBuuJV9k', 37.5381097, 127.1426783, '서울특별시', '쯔양은 대표 메뉴인 빨간 어묵이 ''불닭볶음면''에 가까울 정도로 맵지만, 소스가 아주 맛있고 지금껏 먹어본 빨간 어묵 중 손에 꼽을 정도라고 극찬했습니다. 빨간 떡볶이 떡은 매우 부드럽고 쫀득한 식감이 일품이라고 평가했으며, 일반 어묵과 어묵 국물도 맛있다고 언급했습니다. 또한, 사장님이 매우 친절하시다며, 많은 단골이 찾는 이유인 것 같다고 말했습니다. 전반적으로 매우 만족스러운 식사였다고 평가하며 어묵 국물까지 남김없이 다 먹었습니다.'),
('향원', '서울 도봉구 노해로 289', '02-995-9494', ARRAY['중식'], 'https://www.youtube.com/watch?v=uMLZaJ4Xwuo', 37.6518422, 127.0400044, '서울특별시', '쯔양은 2,000원이라는 저렴한 가격에도 불구하고 짜장면이 고기를 포함하고 있으며, 기대 이상으로 맛있다고 평가했습니다. 옛날 짜장면 맛이 난다고 언급하며 가성비에 크게 감탄했습니다. 찹쌀 탕수육은 소스가 맛있고 고기가 두툼해 꿔바로우 같다고 했으며, 메뉴에 없던 깐쇼새우는 케첩 없이도 맛있다며 그날 먹은 메뉴 중 최고로 꼽았습니다. 차돌짬뽕은 양이 푸짐하고, 삼선짜장은 간짜장처럼 볶아내어 맛이 완전히 다르다고 설명했습니다. 10년 넘게 가격을 올리지 않고 주변의 어려운 이웃을 위해 저렴한 가격을 유지하는 사장님에 대한 존경심을 표하며 매우 만족스러운 식사였다고 총평했습니다.'),
('청간막국수', '서울 서초구 서초대로78길 22 홍우빌딩 2층', '02-523-7304', ARRAY['한식'], 'https://www.youtube.com/watch?v=VXSIQ7XuUQ8', 37.4958166, 127.0275715, '서울특별시', '쯔양은 오픈한 지 얼마 안 된 식당임에도 줄을 서서 먹는 이유를 알겠다며, 집 근처에 있다면 단골이 되었을 것이라고 극찬했습니다. 특히 네 가지 수육 메뉴에 대해 깊은 인상을 받았는데, ''한우 차돌수육''은 지방과 살코기의 완벽한 비율과 녹는 듯한 식감 때문에 가장 맛있었다고 평가했습니다. ''도가니수육''은 딱딱하지 않고 입에 착 달라붙는 쫀득함이 일품이라고 했으며, ''꼬리수육''은 잡내 없이 깔끔하고 부드러워 방문의 주된 목적을 만족시켰다고 합니다. 소 목뼈 부위인 ''따귀''는 감자탕처럼 보이지만 살이 훨씬 많고 장조림보다 부드럽게 찢어진다며 감탄했습니다. 세 종류의 막국수 중에서는 항아리에 숙성시킨 진짜 동치미 국물을 사용한 ''동치미 막국수''와 매콤한 맛이 좋은 ''명태회 비빔 막국수''를 인상 깊게 평가했습니다. 전반적으로 모든 음식이 맛있어서 많은 양을 먹었음에도 물리지 않았고, 다음에는 술과 함께 즐기고 싶다는 말을 남기며 만족스러운 식사였음을 표현했습니다.'),
('에이피엠떡볶이', '충북 청주시 상당구 상당로59번길 37-2', '043-256-5671', ARRAY['분식'], 'https://www.youtube.com/watch?v=waeLgP8c0cA', 36.6335384, 127.4884587, '충청북도', '쯔양은 이곳이 학창 시절에 먹던 맛과 똑같다며 ''추억의 맛''이라고 평가했습니다. 떡볶이는 맵고 덜 달며, 얇은 떡에 소스가 잘 배어있다고 언급했습니다. 20가지 종류의 수제 튀김은 기름지지 않고 바삭하며, 특히 떡갈비 튀김과 순대 튀김이 맛있다고 했습니다. 오이가 빠진 김밥은 갓 만든 것처럼 폭신하고 맛이 뛰어나다고 극찬했으며, 떡볶이 소스에 찍어 먹는 조합을 추천했습니다. 또한, 평범한 순대가 가장 마음에 들었다고 꼽았고, 칡냉면, 라면, 어묵 등 주문한 모든 메뉴가 맛있다고 평가하며 만족감을 표현했습니다. 사이드 메뉴로 주문한 슬러시를 마시며 ''뇌가 얼어붙는'' 경험을 이야기하기도 했습니다.'),
('bhc치킨 석촌점', '서울 송파구 백제고분로39길 6', '02-416-9282', ARRAY['치킨'], 'https://www.youtube.com/watch?v=BCnteF--YUo', 37.5050337, 127.1054734, '서울특별시', 'bhc치킨의 신메뉴 ''마법클''을 먹어본 쯔양은 마늘과 버터 향이 강하게 나는 ''단짠단짠''한 맛이라고 평가했습니다. 특히 마늘과 빵가루를 튀겨 만든 ''마법클 플레이크''가 매우 바삭하고 식감이 뛰어나다고 언급하며 ''신의 한 수''라고 극찬했습니다. 순살 메뉴는 부드럽고 육즙이 풍부한 닭다리살을 사용해 맛있다고 하였고, 전반적으로 중독성이 강해 다시 생각날 맛이라고 요약했습니다. 기존에 없던 새로운 맛으로 남녀노소 누구나 좋아할 것 같다고 덧붙였습니다.'),
('원조태평소국밥 본관', '대전 유성구 온천동로65번길 50', '042-525-5820', ARRAY['한식'], 'https://www.youtube.com/watch?v=RCAalQ-bgmE', 36.3574875, 127.3502189, '대전광역시', '쯔양은 밤 11시에도 줄을 서는 모습에 놀라며 맛집임을 확신했습니다. 소국밥, 내장탕, 갈비탕, 육사시미, 육회를 주문했습니다. 가장 먼저 맛본 육사시미는 매우 부드러우면서도 쫄깃한 식감이 일품이며 입에서 녹는다고 극찬했습니다. 소국밥은 익숙하면서도 깊고 진한 국물 맛이 특징이며, 고기가 푸짐하게 들어있어 모두가 좋아할 맛이라고 평가했습니다. 내장탕은 소국밥과 전혀 다른 매력의 맛으로, 자신의 단골집과 비슷한 느낌의 얼큰하고 맛있는 국물이라고 설명했습니다. 갈비탕 역시 고기가 매우 부드러워 뼈와 쉽게 분리될 정도이며, 국물도 진하고 맛있다고 언급했습니다. 고추장 양념 베이스의 육회 또한 특색있고 맛있다고 평가했으며, 밥과 함께 ''육회초밥''으로 만들어 먹기도 했습니다. 전반적으로 모든 메뉴가 만족스러웠으며, 특히 늦은 시간에도 불구하고 푸짐하고 맛있는 식사를 할 수 있었던 점에 크게 만족감을 표했습니다.'),
('나이쏘이 강남점', '서울 강남구 강남대로102길 11 2층', '0507-1385-9923', ARRAY['아시안'], 'https://www.youtube.com/watch?v=dbDeFwNox5A', 37.5019226, 127.0267526, '서울특별시', '쯔양은 10년 전 태국 여행에서 매일 두세 번씩 갈 정도로 좋아했던 갈비 국수 맛집 ''나이쏘이''가 한국에 생겼다는 소식을 듣고 강남점을 방문했습니다. 10년 만에 맛보는 갈비 국수는 향수 어린 냄새와 함께 10년 전과 똑같은 맛이라고 감탄하며 ''행복해서 죽을 것 같다''고 표현했습니다. 국물은 갈비탕처럼 진하면서도 이국적인 풍미가 있고, 고기는 입에서 녹을 정도로 부드럽다고 극찬했습니다. 쯔양은 평소 쌀국수를 즐겨 먹지 않음에도 불구하고, 이 집 갈비 국수는 ''지금까지 먹어본 쌀국수 중 가장 맛있다''고 평가하며 최고의 메뉴로 꼽았습니다. 함께 주문한 ''텃만꿍''(새우 너겟)은 속이 꽉 차 매우 맛있고, ''수제 점보 스프링롤''은 겉은 바삭하고 속은 쫄깃해 다른 곳보다 훨씬 훌륭하다고 말했습니다. 매운 것을 좋아하는 사람에게는 ''우삼겹 쌀국수''를, 밥 메뉴로는 고기가 훌륭한 ''갈비 국밥''을 추천했습니다. 처음에는 향 때문에 머뭇거렸던 ''카오팟꿍''(새우 볶음밥)도 건조 바질이라는 것을 알고 난 후 맛있게 먹었습니다. 쯔양은 태국 현지의 맛과 90% 일치한다며 전반적으로 모든 음식이 매우 맛있었고, 특히 갈비 국수는 누구도 이길 수 없는 최고의 메뉴라고 종합적인 평을 남겼습니다.'),
('백로식당 본점', '충북 청주시 흥덕구 1순환로 418', '043-273-0713', ARRAY['고기'], 'https://www.youtube.com/watch?v=1oItBKdDg_8', 36.6535631, 127.4707505, '충청북도', '1976년에 개업한 노포로, 한방 양념 불고기와 식사 후 볶아 먹는 ''땡밥''이 대표 메뉴입니다. 쯔양은 양념 불고기의 독특한 한약재 향이 나는 달고 매콤한 양념 맛을 긍정적으로 평가했습니다. 특히, 고기를 먹고 난 후 종이 포일에 볶아주는 김치볶음밥인 ''땡밥''을 별미로 즐겼으며, 이는 많은 방문객들이 이 식당을 찾는 주된 이유 중 하나로 꼽힙니다.'),
('순창맛이레', '전북 순창군 순창읍 순창11길 31-16', '0507-1411-1402', ARRAY['한식'], 'https://www.youtube.com/watch?v=aTClipeffE8', 35.377005, 127.1396087, '전라북도', '첫 번째로 방문한 식당. 고추장불고기는 어깨살 부위를 사용하며, 일반적인 불고기보다 갈비나 등심 같은 식감이라고 평가함. 소스가 특히 맛있다고 칭찬함. 함께 나온 청국장은 매우 걸쭉하고 진한 맛이 일품이라고 언급. 밥과 함께 먹기에 완벽한 조합이라고 함.'),
('함양식당', '전북 순창군 순창읍 순화로 27', '063-652-8677', ARRAY['한식'], 'https://www.youtube.com/watch?v=aTClipeffE8', 35.3764126, 127.1368808, '전라북도', '44년 전통의 두 번째 식당. 고추장 맛과 불고기 맛이 모두 강하게 느껴지는, 정석적인 맛이라고 평가. 순한맛과 매운맛 두 가지 버전이 있으며, 매운맛은 상당히 맵다고 함. 고기는 아삭한 비계와 쫄깃한 살코기가 잘 어우러져 퍼즐처럼 섞인 듯한 식감이라고 묘사. 미나리가 함께 제공되지만 본인은 미나리를 먹지 않아 빼고 먹음.'),
('해뜨는집', '전북 순창군 순창읍 남계로 94', '0507-1344-9969', ARRAY['한식'], 'https://www.youtube.com/watch?v=aTClipeffE8', 35.3749459, 127.1459985, '전라북도', '세 번째로 방문한 식당. 고추장불고기에 커다란 주꾸미와 고구마 스틱이 들어간 점이 독특하다고 함. 숯불 향이 매우 강렬하게 느껴지는 것을 특징으로 꼽았으며, 주꾸미와 고추장불고기의 조화가 훌륭하다고 평가. 함께 나온 청국장은 색이 옅지만 아주 고소한 맛이라고 언급함.'),
('미소식당', '전북 순창군 순창읍 장류로 290', '010-5713-3755', ARRAY['한식'], 'https://www.youtube.com/watch?v=aTClipeffE8', 35.3757376, 127.1343535, '전라북도', '마지막으로 방문한 식당. 두툼한 고기가 마치 돼지갈비 같고 맛 또한 갈비와 비슷하다고 함. 청국장은 가장 전통적인 맛에 가까우며, 약간 슴슴하면서도 매우 고소하다고 평가. 특히 남은 고추장 소스와 청국장을 섞어 밥을 볶아 먹는 것을 ''진짜''라며 극찬했고, 일반적인 청국장 볶음밥보다 훨씬 맛있다고 언급함.'),
('해주냉면 본점', '서울 송파구 백제고분로7길 8-16', '02-424-7192', ARRAY['한식'], 'https://www.youtube.com/watch?v=Tiw7_yiBiX8', 37.5096592, 127.0797935, '서울특별시', '쯔양은 서울 5대 매운 냉면으로 유명한 ''해주냉면'' 잠실 본점을 방문했습니다. 물냉면, 비빔냉면, 물만두를 주문했습니다. 물냉면은 함흥냉면 면에 평양냉면 육수 맛이 나는 슴슴하면서 중독성 있는 맛이라고 평가했으며, 식초, 겨자, 설탕을 넣어 먹는 방법도 시도해보고 감칠맛이 살아난다고 했지만, 본연의 맛을 더 선호했습니다. 비빔냉면은 핵불닭볶음면의 2~3배 맵기라고 소개되었으며, 쯔양은 기본 양념에 두 숟가락을 더 추가하여 도전했습니다. 처음에는 맛있게 맵다고 했으나, 시간이 지나면서 눈알이 튀어나올 것 같은 강렬한 매운맛을 경험했습니다. 그럼에도 스트레스가 풀리는 맛있는 매운맛이라며 만족감을 표했습니다. 두 번째 비빔냉면 그릇에는 양념을 더 많이 넣었다가 너무 매워 물냉면 육수와 참기름을 추가했으며, 참기름을 넣으니 훨씬 맛있어졌다고 언급했습니다. 전반적으로 매우 맵지만 맛있어서 다시 방문하고 싶은 맛집이라고 평가하며, 매운 것을 못 먹는 사람들은 주의해야 한다고 조언했습니다.'),
('문배동육칼 본점', '서울특별시 용산구 백범로90길 50', '02-713-6204', ARRAY['한식'], 'https://www.youtube.com/watch?v=-HyRSLWcOeA', 37.5366298, 126.9703261, '서울특별시', '쯔양은 이 식당을 한국 최초의 ''육개장 칼국수'' 집이자 약 50년 전통을 가진 곳으로 소개했습니다[attached_file:1: 52-60]. 그녀는 국물을 맛본 후 ''완전 취향 저격''이라며 매우 진하고 깊은 맛이 일품이라고 극찬했습니다[attached_file:1: 192-208]. 면발은 쫄깃한 칼국수 면으로, 국물에 조금씩 적셔 먹는 방식이 흥미롭다고 언급했습니다[attached_file:1: 259, 561-608]. 또한, 고기가 매우 푸짐하게 들어있고 오랜 시간 끓여낸 깊은 맛이 느껴진다고 평가했습니다. 특히 깍두기(무김치)가 맛있어서 여러 번 감탄했으며, 숙취 해소에 최고라고 여러 차례 언급했습니다. 전반적으로 진한 국물과 푸짐한 건더기, 쫄깃한 면의 조화에 크게 만족하며 ''정말 맛있게 먹었다''고 최종 평가를 내렸습니다[attached_file:1: 903-917].'),
('연교', '서울 마포구 연희로1길 65', '02-333-4561', ARRAY['중식'], 'https://www.youtube.com/watch?v=N82HhUgsV6I', 37.5616084, 126.9266791, '서울특별시', '쯔양은 이곳을 ''숨겨진 고수가 운영하는 보석 같은 곳''이라고 칭하며, 화려하진 않지만 ''단백하고 맛있다''고 평가했습니다. 딤섬에 대해, 주문 즉시 쪄서 나오는 점을 칭찬했으며, 특히 다른 곳과 달리 피가 매우 얇다고 강조했습니다. 돼지고기 샤오롱바오의 육즙은 매우 풍부하고 진하며, 피는 쫄깃하고 소는 입에서 녹는다고 말했습니다. 새우 샤오롱바오는 간장 없이 먹어도 맛있고, 쇼마이는 뜨거울 때 바로 먹는 것이 최고라고 했습니다. 총 20판의 딤섬을 먹은 후 주문한 우육면에 대해서는, ''오늘의 디저트''라 칭하며 국물이 진하고 독창적이라고 극찬했습니다. 전체적으로 음식의 육즙이 풍부해서 즐겁게 식사했다고 마무리했습니다.'),
('이삭토스트 서울 한티역점', '서울 강남구 도곡로63길 16 1층', '02-557-3060', ARRAY['패스트푸드'], 'https://www.youtube.com/watch?v=ujPAYx-zMe8', 37.4980157, 127.0543158, '서울특별시', '쯔양은 이삭토스트의 신메뉴에 대해 전반적으로 매우 긍정적인 평가를 내렸습니다. ''더블치즈 불고기''는 불고기의 진한 훈제 향과 풍부한 치즈의 조화가 뛰어나다고 칭찬했으며, 별도의 소스 없이 재료 본연의 맛을 느낄 수 있는 점을 특징으로 꼽았습니다. ''불고기 스페셜''은 양배추와 소스가 어우러져 또 다른 매력을 보여주며, 기존 패티가 아닌 진짜 불고기를 사용한 점을 높이 평가했습니다. 여러 메뉴를 맛본 후, 불고기 메뉴 중에서는 ''불고기 스페셜''을 최고로 선택했습니다. 치킨 메뉴 중에서는 ''치킨 스페셜''의 가성비와 매장에서 직접 튀겨낸 바삭하고 촉촉한 패티 품질에 감탄했습니다. ''핫 베이컨 치킨''은 매콤하고 육즙이 풍부하다고 평가했으며, 특히 ''칠리마요 치킨''의 소스가 훌륭하다며 치킨 메뉴 중 가장 맛있는 메뉴로 꼽았습니다. 쯔양은 이삭토스트 특유의 맛을 좋아하며, 신메뉴들이 양도 푸짐하고 든든한 한 끼 식사로 손색없다고 총평했습니다.'),
('조개일번지 미아사거리 본점', '서울특별시 강북구 도봉로8길 37 1층', '0507-1363-1093', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=cTvq6AL-CyY', 37.6121331, 127.0322137, '서울특별시', '쯔양은 이곳이 역대급으로 푸짐한 양의 조개찜을 제공한다고 극찬했습니다[0:957]. 랍스터와 다양한 조개가 가득한 비주얼에 감탄하며, 특히 랍스터 내장의 고소한 맛이 최고라고 평가했습니다[0:377][0:419]. 가리비는 완벽하게 익었고 매우 통통하며 맛있다고 언급했으며[0:161-0:171], 모래가 씹히지 않는 깔끔한 해감 상태에 만족감을 표했습니다[0:586]. 또한 매콤하고 시원한 국물 맛도 칭찬했으며[0:538], 마지막에 넣어 먹은 삼색 칼국수 역시 맛있게 즐겼습니다[0:871]. 전반적으로 양과 맛 모든 면에서 크게 만족하며 ''역대급 조개찜''이었다고 총평했습니다[0:957].'),
('청년다방 양재시민의숲역점', '서울특별시 서초구 강남대로12길 23-15', '02-2088-1214', ARRAY['분식'], 'https://www.youtube.com/watch?v=Tbto4_gKTVg', 37.4702176, 127.0397597, '서울특별시', '쯔양은 청년다방의 신메뉴 ''맵도전 떡볶이'' 1~4단계를 모두 주문하여 리뷰했습니다. 1단계는 신라면 정도의 맵기로, 오징어 튀김 토핑과 함께 먹으며 쫄깃하고 맛있지만 약간의 매운맛이 느껴진다고 평가했습니다. 2단계는 청양고추 수준의 맵기로, 소스는 맛있지만 많이 맵다고 느꼈습니다. 3단계는 불닭볶음면 수준으로, 색부터 맵고 냄새는 맛있지만 한 조각만으로도 매우 힘들어했습니다. 그러나 소고기 토핑은 맛있다고 언급했습니다. 마지막 4단계는 핵불닭볶음면 수준으로, 직원들과 함께 릴레이 먹방을 진행했으며 극심한 매운맛 때문에 거의 먹지 못했습니다. 전체적으로 맵도전 떡볶이의 소스는 단맛이 적고 고소한 맛이 나며 맛있게 맵다고 총평했습니다. 함께 주문한 신메뉴 ''버터치킹''과 ''스파이시치킹''에 대해서는, 특히 버터치킹이 매운 떡볶이와 잘 어울리고 치킨 전문점처럼 맛있다고 칭찬했습니다.'),
('자코비버거 본점', '서울 용산구 신흥로 38 1층 자코비버거', '02-3785-0433', ARRAY['패스트푸드'], 'https://www.youtube.com/watch?v=az5gTY6wb44', 37.5418075, 126.9874232, '서울특별시', '쯔양은 이곳의 시그니처 메뉴인 ''내장파괴버거''에 대해 크기가 매우 커서 분해해서 먹어야 했지만, 풍부한 치즈 맛과 불맛이 나는 패티가 인상적이었다고 평가했습니다. 이 외에도 ''자코비 버거''는 신선한 재료와 위아래로 깨가 박힌 특별한 참깨빵이 특징이며 과카몰리를 추가하면 더 촉촉하고 맛있다고 언급했습니다. ''새우버거''는 튀긴 양파가 들어있어 고소한 맛이 일품이라고 추천했으며, ''블루 하와이안 베이컨 버거''는 구운 파인애플과 의외의 조합인 블루베리 잼이 달콤하고 조화롭게 어울린다고 평했습니다. 마지막으로 ''아보카도 베이컨 버거''는 부드러운 아보카도가 듬뿍 들어가 입에서 녹는 식감이 좋았다고 말했습니다. 전반적으로 모든 버거의 크기가 크고 푸짐하며, 칠리 소스와 감자튀김 등 사이드 메뉴도 맛있다고 만족감을 표현했습니다.'),
('해랑스시', '서울 중구 통일로 10 연세세브란스빌딩 지하1층', '0507-1385-0099', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=FgDCbXyv0UY', 37.5570913, 126.9736575, '서울특별시', '쯔양은 이 회전초밥 전문점에서 총 110접시를 먹으며 높은 만족감을 표현했습니다. 그녀는 이곳을 자신이 방문했던 회전초밥 식당 중 ''TOP 3 또는 TOP 5''에 들 정도로 만족스러운 곳이라고 평가했습니다(1:150). 계란 초밥은 카스테라처럼 부드럽고 달콤하다고 했으며(0:267), 마요네즈를 곁들인 소라 초밥의 쫄깃한 식감을 칭찬했습니다(0:317). 특히 직원이 추천한 후토마키를 한입에 먹으며 축복을 기원했고(0:382), 다양한 맛이 조화롭게 어우러져 최고라고 극찬했습니다(0:412). 간장새우, 연어 뱃살, 크림치즈 라이스볼 등 다양한 메뉴를 맛보았고, 모든 음식이 맛있다고 여러 차례 언급하며(7:97) 전반적으로 음식의 맛과 가성비에 크게 만족하는 모습을 보였습니다.'),
('라칸티나', '서울 중구 을지로 19 삼성빌딩 지하1층', '02-777-2579', ARRAY['양식'], 'https://www.youtube.com/watch?v=ZoQf6XgFzRw', 37.566308, 126.9799748, '서울특별시', '쯔양은 한국 최초의 이탈리안 레스토랑인 라칸티나를 방문하여 전반적으로 모든 음식이 맛있고 누구나 좋아할 맛이라고 호평했습니다. 특히 봉골레를 그날의 최고 메뉴로 꼽으며, 삼성 이병철 전 회장이 즐겨 찾았다는 일화를 소개했습니다. 어니언 수프는 곰탕처럼 맛있다며 밥을 말아 먹고 싶다고 표현했고, 랍스터는 버터향이 진하고 속살까지 간이 잘 배어 있다고 감탄했습니다. 스테이크는 매우 부드럽고, 녹색 면의 크림 파스타는 독특한 감자향과 쫄깃한 식감이 인상적이라고 평가했습니다. 마늘 오일 파스타는 마늘향이 매우 강렬해 ''마늘 파스타''라고 불러도 될 정도라고 했으며, 토마토 파스타는 소스와 면이 따로 나오는 옛날 방식과 잘 익은 가리비를 특징으로 꼽았습니다. 맛과 더불어 오래된 레스토랑의 분위기를 그대로 간직한 점도 훌륭하다고 언급했습니다.'),
('모퉁이집', '서울 강남구 테헤란로1길 20', '02-562-5948', ARRAY['분식'], 'https://www.youtube.com/watch?v=P6sTH0NiKN8', 37.4996752, 127.0278204, '서울특별시', '쯔양은 1988년부터 운영된 강남에서 가장 오래된 분식집이라는 역사와 7가지의 다양한 라면이 있다는 점 때문에 이곳을 방문했습니다. 계란라면, 치즈라면, 고추짬뽕라면, 수제비라면, 짬뽕라면, 치즈부대라면 등 총 6종의 라면과 제육김밥, 묵은지참치김밥을 주문했습니다. 라면 국물은 일반 라면과 달리 특제 소스가 들어간 것처럼 진한 맛이 특징이라고 평가했습니다. 특히 고추짬뽕라면은 매우 맵지만 맛있다고 언급했고, 수제비라면의 수제비는 직접 만든 것이라며 감탄했습니다. 김밥은 밥이 쫀득하고 속이 꽉 차 있어 매력적이라고 평가했으며, 전반적으로 모든 메뉴가 매우 맛있었다며 만족스러운 식사였다고 총평했습니다.'),
('본가진미간장게장', '서울 송파구 백제고분로 420 1층', '0507-1342-5081', ARRAY['한식'], 'https://www.youtube.com/watch?v=8RdkFuFK1DY', 37.5083344, 127.1113296, '서울특별시', '쯔양은 이 식당의 간장게장이 전혀 짜지 않고 살이 달콤하며 비린내가 나지 않는다고 극찬했습니다. 특히 ''미쳤다''고 표현할 정도로 내장과 알이 풍부하다고 언급했습니다. 특대 사이즈 게는 크기가 엄청나고 살이 꽉 차 있다고 만족감을 표했습니다. 양념게장은 맵지만 맛있어서 멈출 수 없는 맛이라고 평가했습니다. 서비스로 나온 꽃게탕에 대해서도 살이 꽉 차고 국물이 훌륭해 따로 방문하고 싶을 정도라고 말했으며, 함께 나온 새우장과 전복장 등 다른 해산물 장도 훌륭하다고 평가했습니다. 전반적으로 음식 맛이 짜지 않고 매우 만족스러웠으며, 총 14마리의 게를 먹으며 식사를 마무리했습니다.'),
('세광식당', '전남 순천시 북문길 40', '061-752-4895', ARRAY['한식'], 'https://www.youtube.com/watch?v=NrLPC4raEh4', 34.958649, 127.4850485, '전라남도', '국밥 2인분 이상 주문 시 수육 한 접시가 서비스로 제공되는 순천 웃장만의 문화에 감탄함. 국밥은 국물이 맑고 깔끔하면서도 깊은 맛을 내며 잡내가 전혀 없다고 칭찬함. 서비스로 나온 수육 역시 매우 부드럽고 맛있다고 평가하며 김치와의 조합을 즐김.'),
('파이브가이즈 강남', '서울 서초구 강남대로 435 주류성빌딩 1층, 2층', '070-8834-7900', ARRAY['패스트푸드'], 'https://www.youtube.com/watch?v=Y8KeqoGtSNA', 37.5011826, 127.0255738, '서울특별시', '쯔양은 미국에서 감자튀김만 먹어보고 버거는 처음 먹어본다며 큰 기대감을 보였습니다. 먼저 감자튀김은 미국과 비슷한 맛을 내기 위해 보성 감자를 사용했다는 점을 언급하며, 완벽하게 짜고 부드러워서 계속 손이 가는 맛이라고 극찬했습니다. 버거에 대해서는 패티의 육즙과 부드럽고 촉촉한 번을 칭찬했으며, 특히 토핑을 마음대로 추가해도 추가 비용이 없는 점을 큰 장점으로 꼽았습니다. ''올웨이(All the way)'' 옵션을 추천하며, 토핑 조합에 따라 완전히 다른 맛을 즐길 수 있다고 평가했습니다. 치즈버거는 토핑 없이도 치즈의 꾸덕하고 진한 맛이 훌륭하다고 언급했습니다. 또한, 다양한 조합의 쉐이크가 매우 맛있다고 여러 번 감탄했으며, 일반적인 프랜차이즈가 아닌 수제버거 같은 퀄리티라고 총평했습니다.'),
('국민낙곱새 망포점', '경기도 수원시 영통구 영통로 136 1층 121호', '031-203-0958', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=bt2kahtnrzE', 37.2396921, 127.0561768, '경기도', '쯔양은 ''국민낙곱새''가 전국적으로 낙곱새를 알린 프랜차이즈라고 언급하며, 여러 메뉴를 맛보았다. - **한우대창 낙곱새**: 소스가 약간 매우면서도 누구나 즐길 수 있는 맛이고, 대창이 아주 고소하다고 평가했다. 특히 소스에 조리되어 느끼함 없이 고소함이 극대화된다고 말했다. 깻잎, 마요네즈, 단무지와의 조합은 입안에서 파티가 열리는 맛이라고 극찬했다. - **소곱창 낙곱새**: 곱이 가득 차 있으며, 맛있다고 언급했다. - **마라 낙곱새**: 기존 낙곱새와 완전히 다른 정통 마라 맛으로, 더 맵지만 균형이 잘 잡혀있다고 평가했다. 마라 향이 강하지 않아 누구나 즐길 수 있으며, 양념이 진하면서도 텁텁하거나 짜지 않아 기대 이상으로 맛있었다고 한다. - **소곱창 전골**: 소주를 부르는 맛으로, 사골 육수의 진하고 얼큰한 국물이 일품이라고 했다. 끓일수록 국물 맛이 깊어져 텀블러에 담아 다니고 싶을 정도라고 감탄했다. - **기타**: 서비스로 나오는 계란찜은 매우 부드러워 입에서 녹는 식감이라고 칭찬했으며, 떡사리도 쫄깃하고 맛있다고 언급했다. 전반적으로 재료가 신선하고 소스와 육수가 완벽해 처음부터 끝까지 만족스러운 식사였다고 총평했다.'),
('정인면옥', '서울 영등포구 국회대로76길 10', '02-2683-2615', ARRAY['한식'], 'https://www.youtube.com/watch?v=1DnKb2BrsTg', 37.5306764, 126.9215711, '서울특별시', '쯔양은 정인면옥이 50년 전통의 맛집으로 미쉐린과 블루리본을 매년 받은 곳이라고 소개했다. 그녀는 이곳의 평양냉면을 맛본 후, 지금까지 먹어본 평양냉면 중 가장 높은 수준의 맛이라고 평가했다. 국물은 슴슴하면서도 고소하고 깊은 맛이 나며, 면은 쫄깃하기보다는 툭툭 끊어지는 부드러운 식감이라고 설명했다. 함께 주문한 녹두전은 겉이 매우 바삭하고 속은 부드러워 냉면과 잘 어울린다고 극찬했으며, 특히 양파절임과 함께 먹는 것을 추천했다. 아롱사태 수육은 차가운 편이지만 질기지 않고 부드러운 식감이 좋다고 평했다. 만두는 속이 꽉 찬 북한식 만두 맛이 난다고 언급했다. 비빔냉면의 양념은 맵고 새콤하며 맛있다고 평가했다. 쯔양은 평양냉면 초보자는 식초를 넣기도 하지만, 자신은 넣어보니 본연의 맛을 해치는 것 같다고 말했다. 전반적으로 자극적이지 않고 질리지 않는 맛이라 계속 생각나는 중독성이 있다고 총평하며, 평양냉면 고수들에게 4탄 맛집을 추천해달라고 요청하며 영상을 마무리했다.'),
('옛날중국집', '서울특별시 성북구 성북로8길 8', '02-764-0094', ARRAY['중식'], 'https://www.youtube.com/watch?v=0FACIBa9Jfg', 37.5908428, 127.0044031, '서울특별시', '쯔양은 이 식당의 음식 맛과 따뜻한 인심에 깊은 감명을 받았습니다. 특히 ''탕수육''은 꿔바로우처럼 튀김옷이 푹신하고 고기가 부드러워 지금껏 먹어본 적 없는 특별한 맛이라고 극찬했습니다. ''짜장면''은 소스가 매우 진하고 고급 밀가루를 사용해 잡내가 없다고 평가했으며, ''삼선짬뽕''은 국물이 사골 국물처럼 깊고 진하며 신선한 해산물이 풍부하다고 언급했습니다. ''볶음밥''은 완벽한 불맛이 일품이라고 칭찬했고, 쯔양의 입맛을 고려해 케첩 없이 조리된 ''깐쇼새우''와 매콤한 ''깐풍기''도 맛있게 먹었습니다. 쯔양은 매달 어르신들에게 무료로 식사를 대접하는 사장 부부의 선행에 감동하며, 맛과 인심을 모두 갖춘 곳이라고 종합적으로 평가했습니다.'),
('원할머니보쌈족발 본점', '서울 중구 난계로 201', '02-2232-3232', ARRAY['족발·보쌈'], 'https://www.youtube.com/watch?v=h_PBOLpfoCk', 37.5696506, 127.0231752, '서울특별시', '쯔양은 원할머니보쌈의 신메뉴 ''불맛낙지원쌈''을 맛보기 위해 방문했습니다. 특히 불맛 나는 낙지와 보쌈, 그리고 이곳의 시그니처인 쌈떡의 삼합 조합을 최고의 맛으로 꼽았습니다 . 보쌈 고기는 육즙이 풍부하고 지방 부분은 부드러우며 살코기는 쫄깃하다고 평가했고 , 따뜻하게 유지되는 점을 칭찬했습니다 . 다양한 색과 맛을 가진 쌈떡을 매우 마음에 들어하며, 이 떡 때문에 이곳을 방문할 정도였다고 언급했습니다 . 이 외에도 달콤하고 맛있는 보쌈김치 , 쫄깃한 족발 , 그리고 사이드 메뉴인 들기름 막국수와 된장술밥에 대해서도 훌륭한 맛이라고 평가했습니다 . 전반적으로 여러 조합으로 즐길 수 있어 먹는 재미가 있고, 단체 식사에도 적합한 곳이라며 만족스러운 식사였다고 총평했습니다 .'),
('승우네식당', '서울 종로구 종로 190-4 지상1층 승우네식당', '02-2268-8589', ARRAY['한식'], 'https://www.youtube.com/watch?v=HyWn4MjoxXU', 37.5704887, 126.9988221, '서울특별시', '쯔양은 아침 7시에 광장시장 근처에 숨겨진 노포 맛집인 ''승우네식당''을 방문했다. 우거지찌개, 청국장찌개, 순두부찌개, 오징어볶음, 제육볶음 등 푸짐한 아침 식사를 주문했다. 이곳의 우거지찌개는 시골에서 먹는 것처럼 구수하고 국물이 일품이며 우거지가 부드럽다고 극찬했다. 청국장 역시 제대로 만든 맛이라며 감탄했다. 특히 모든 반찬은 새벽 3시부터 사장님이 직접 만드시는데, 주문하지 않은 계란말이조차 기대보다 3배는 맛있다고 놀라워했다. 개인적으로는 우거지찌개와 제육볶음이 가장 맛있다고 평했으며, 제육볶음은 첫입부터 맛있고 오징어볶음은 먹을수록 맛이 깊어진다고 둘 다 좋아했다. 양이 매우 푸짐해서 ''간단한 아침''이 아닌 평소 먹방처럼 되었다며, 결국 반찬은 다 먹지 못했지만 매우 만족스러운 식사였다고 마무리했다.'),
('밴건디 스테이크하우스', '서울 서초구 사평대로22길 5 1층', '02-595-6062', ARRAY['양식'], 'https://www.youtube.com/watch?v=WgFh2MJRpoU', 37.4993545, 126.9977539, '서울특별시', '쯔양은 식전빵부터 부드러워서 만족감을 표했습니다. 메인 메뉴인 스테이크에 대해서는 포터하우스, 등심, 안심 모두를 주문했으며, 미디엄 레어로 완벽하게 조리되었다고 평가했습니다. 특히 포터하우스 스테이크는 이제껏 먹어본 것 중 가장 육즙이 풍부하고 부드럽다며 극찬했고, 등심 부위가 전혀 질기지 않다고 언급했습니다. 안심(필레미뇽)은 믿을 수 없을 정도로 부드럽다고 여러 번 감탄했으며, 뉴욕 스트립 스테이크 또한 훌륭하다고 평가했습니다. 사이드 메뉴인 통 베이컨은 짜지 않고 완벽한 간에 부드러운 식감과 스모키한 풍미가 일품이라고 말했으며, 으깬 감자는 수프처럼 매우 부드러운 질감이 독특하고 맛있다고 설명했습니다. 전반적으로 매우 만족스러운 식사였으며 ''완벽한 스테이크 식사''였다고 총평했습니다.'),
('뜨돈 동탄본점', '경기 화성시 여울로 158-60', '031-222-1379', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=4X078jlC35k', 37.210181, 127.0573292, '경기도', '쯔양은 ''뜨돈''의 음식과 분위기에 대해 전반적으로 매우 만족스러운 평가를 내렸으며, ''내일 또 생각날 맛''이라고 요약했습니다. 주요 메뉴에 대한 리뷰는 다음과 같습니다. - **뜨돈 돈까스**: 두툼한 두께와 부드러운 육질을 칭찬했으며, 특히 양파가 들어간 특제 소스는 이전에 맛보지 못한 특별한 맛이라고 극찬했습니다. 최고급 국내산 ''도드람'' 등심을 사용해 고기 자체가 맛있다고 언급했습니다. - **치즈 돈까스**: 치즈의 고소한 감칠맛이 뛰어나다고 평가하며, 조카가 추천한 이유를 알겠다고 말했습니다. - **베이컨 크림 스파게티**: 소스가 매우 진하고 고소하며, 감자가 들어가 느끼함을 잡고 담백한 맛을 낸다고 분석했습니다. 돈까스와 함께 먹는 조합을 추천했습니다. - **기타 메뉴**: 로제 떡볶이는 시판용 소스가 아닌 진짜 파스타 소스 맛이 나고, 치킨까스는 닭다리살을 사용해 매우 촉촉하고 맛있다고 평가했습니다. 함께 제공된 빵으로 만든 돈까스 버거와 돈까스와 잘 어울리는 새콤달콤한 비빔면도 별미로 꼽았습니다. - **종합 평가**: 방문한 식당의 분위기가 숲속에 있는 것처럼 아름답다고 여러 번 언급했으며, 그날 먹은 메뉴 중 ''베이컨 크림 스파게티''와 ''치즈 돈까스''를 최고의 메뉴로 선택했습니다.'),
('기절초풍물닭갈비 상도점', '서울특별시 동작구 성대로1길 6 1층', '02-824-4636', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=m43t03-DziE', 37.500349, 126.9328432, '서울특별시', '쯔양은 오리지널 맛과 매운맛 물닭갈비 ''지화자''(닭 한 마리) 사이즈 두 개를 주문했으며, 라면 사리와 볶음밥도 추가했습니다. 이 음식은 과거 태백 탄광 광부들을 위해 고기에 국물을 부어 양을 늘려 나눠 먹던 것에서 유래했다고 언급됩니다. 오리지널 육수는 닭볶음탕과 달리 맑고 개운하며 담백한 맛이 특징으로, 처음에는 다소 슴슴하게 느껴지지만 끓일수록 맛있어지고 중독성이 강해진다고 평가했습니다. 쌀떡은 쫄깃하고 부드러우며, 닭고기는 질기지 않고 매우 쫄깃쫄깃한 식감이 일품이라고 극찬했습니다. 매운맛은 스트레스가 풀릴 정도의 기분 좋은 매운맛이지만, 개인적으로는 오리지널 맛을 더 선호한다고 밝혔습니다. 맑은 국물에 라면 사리가 아주 잘 어울리며, 남은 국물에 감자를 으깨 넣어 볶은 볶음밥도 별미로 꼽았습니다. 전체적으로 자극적이지 않고 슴슴한 맛으로 시작해 계속 먹게 되는 중독성 있는 맛이라며 아주 맛있게 식사했다고 총평했습니다.'),
('청수우동메밀냉면', '서울 영등포구 국제금융로 112', '02-784-1559', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=lx9-ecadk7U', 37.5183821, 126.9339014, '서울특별시', '쯔양은 40년 전통이 느껴지는 맛이라고 평가했습니다 . **메밀국수**는 국물이 달고 고소하며 일반적인 메밀국수 국물보다 더 진한 맛이 난다고 언급했습니다. 면발은 아주 부드럽다고 합니다 . **돌솥우동**은 양이 푸짐하고, 면발이 우동과 칼국수의 중간 식감으로 훌륭하다고 평가했습니다. 또한, 국물이 약간 달아서 더 맛있다고 느꼈습니다 . **유부초밥**은 다른 식당과 달리 건조하지 않고 촉촉해서 좋았으며, 메밀국수 국물에 찍어 먹는 것을 추천했습니다 . **고기만두**는 뜨거울 때 먹는 것이 가장 맛있다고 언급했습니다 . 전체적으로 여름에 먹기 좋은 맛있는 식사였다고 만족감을 표현했습니다 .'),
('청기와타운 영등포본점', '서울 영등포구 영중로10길 32-4', '0507-1316-1474', ARRAY['고기'], 'https://www.youtube.com/watch?v=iGUcA6B8zvg', 37.5184128, 126.9084652, '서울특별시', '쯔양은 전반적으로 식사에 매우 만족했습니다. LA 한인타운 콘셉트의 독특하고 힙한 인테리어와, 콜키지 프리가 가능한 점, 그리고 다양한 와인을 저렴하게 즐길 수 있는 점을 긍정적으로 평가했습니다. 음식에 대해서는, 애피타이저로 먹은 ''육회''는 아보카도, 배, 트러플이 어우러져 신선하고 식감이 훌륭하다고 극찬했습니다. ''1++ 등급 한우 생등심''은 육즙이 풍부하고 향이 진하며 입에서 녹는다고 평가했습니다. 메인 메뉴인 ''수원왕갈비''는 너무 달거나 짜지 않은 완벽한 양념과 부드럽고 쫄깃한 식감이 일품이며 밥을 부르는 맛이라고 했습니다. ''LA갈비''는 일반적인 LA갈비와 달리 두툼해서 고기 본연의 맛이 강하게 느껴지는 점이 특징이라고 언급했습니다. 또한, 일반 된장찌개와는 다른 깊은 맛의 ''토장찌개''와 달달한 무채가 인상적인 ''무채 볶음밥''도 맛있게 먹으며, 육회를 시작으로 볶음밥으로 마무리하는 식사를 완벽한 코스 요리에 비유하며 만족감을 표현했습니다.'),
('옥자회관', '서울 마포구 성암로 219-6 1층', '02-375-5057', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=raDdfpVDIbw', 37.5788387, 126.8951706, '서울특별시', '쯔양은 이 식당을 ''인생 최고의 돈까스''일 수 있다며 극찬했습니다. 특히 안심 돈까스는 육즙이 풍부하고 매우 부드러워 돼지고기 같지 않다고 평가했고, 등심 돈까스는 육즙이 많고 탄력 있는 식감이 마치 소고기 스테이크 같다고 언급했습니다. 치즈 돈까스는 염지된 모짜렐라 치즈가 들어있어 매우 고소하고, 튀김임에도 불구하고 느끼하지 않다고 말했습니다. 사이드 메뉴인 카레는 한국식과 일본식이 섞인 맛있는 스타일이라고 했고, 갓김치가 들어간 크림치즈 고로케도 맛있게 먹었습니다. 고기를 두 번 튀기고 숙성시키는 조리법이 맛의 비결이라고 영상에서 소개되었습니다.'),
('마장동김씨 교대직영점', '서울 서초구 서초대로50길 89 1층', '02-585-8592', ARRAY['고기'], 'https://www.youtube.com/watch?v=xVNgs8OTxV8', 37.4894166, 127.0136282, '서울특별시', '쯔양은 전국 상위 0.3%에 해당하는 특별한 품종인 ''얼룩 돼지''를 맛볼 수 있는 곳이라고 식당을 소개했습니다. 고기를 한 입 먹자마자 육즙이 터져 나오며, 질기지 않고 쫄깃한 식감에 감탄하며 인생 최고의 돼지고기라고 극찬했습니다. 특히, 보통 퍽퍽해서 즐겨 먹지 않는 목살이 전혀 퍽퍽하지 않고 쫄깃하며 맛있다고 여러 번 강조했고, 결국 추가로 주문해서 먹을 정도로 만족했습니다. 돼지고기 외에도 100마리의 꽃게를 넣어 끓인다는 꽃게된장찌개는 반드시 시켜야 할 메뉴로 꼽았으며, 오징어젓갈볶음밥과 냉면 등의 사이드 메뉴도 고기와 잘 어울려 전반적인 식사에 만족감을 더했다고 평가했습니다. 또한, 직원이 직접 고기를 구워주어 먹기 편한 점과 옷에 냄새가 배지 않도록 개별 옷장을 제공하는 세심한 서비스를 장점으로 언급하며, 역대급으로 만족스러운 식사였다고 총평했습니다.'),
('현래장', '서울특별시 마포구 마포대로 20 다보빌딩 지하1층', '02-712-0730', ARRAY['중식'], 'https://www.youtube.com/watch?v=kF0V4Hrqluo', 37.538375, 126.9449196, '서울특별시', '쯔양은 옛날짜장면, 유니짜장면, 냉짬뽕, 탕수육, 깐쇼새우, 전복가리비 해물볶음, 군만두 등 총 7가지 메뉴를 주문했습니다. 모든 면 요리는 수타면이라 면의 굵기가 일정하지 않고 쫄깃한 식감이 특징이라고 평가했습니다. **옛날짜장면**은 옛날 맛이 나는 순한 소스가 인상적이었고, 해물이 들어간 **유니짜장면**은 소스가 더 진해 개인적으로 더 맛있다고 언급했습니다. **탕수육**은 과자처럼 바삭한 튀김옷과 새콤달콤한 소스의 조화가 훌륭하다고 칭찬했으며[attached_file_1], **군만두**는 겉은 바삭하고 속은 찹쌀처럼 쫀득해 꼭 먹어봐야 할 메뉴로 추천했습니다. **깐쇼새우**는 양이 푸짐하고 안에 들어간 새우가 매우 크다고 만족감을 표했습니다. 반면 **전복가리비 해물볶음**은 고급스러운 요리지만 본인 입맛에는 익숙하지 않아 잘 맞지 않는다고 솔직하게 평가했습니다.'),
('진주집', '서울 영등포구 국제금융로6길 33 여의도백화점 지하1층', '02-780-6108', ARRAY['한식'], 'https://www.youtube.com/watch?v=CPWwPVs5Ib4', 37.5207575, 126.9269566, '서울특별시', '쯔양은 40년 전통의 여의도 ''진주집''을 방문하여 전 메뉴를 주문했습니다. 가장 기대를 안했던 비빔국수를 ''달콤새콤 완벽하다''며 최고의 메뉴로 꼽았고, 한 그릇을 더 추가 주문했습니다. 대표 메뉴인 콩국수에 대해서는 국물이 매우 진하고 고소하며 두유 같은 맛이 난다고 평가했고, 면발은 얇지만 쫄깃하다고 했습니다. 닭칼국수는 ''이열치열''이라며 더운 여름에도 즐기기 좋은 뜨끈한 국물 맛을 칭찬했으며, 양이 매우 푸짐하다고 언급했습니다. 함께 나온 김치는 보쌈김치와 비슷하며 무가 매우 달고 맛있다고 극찬했습니다.'),
('대공원포도밭', '경기 과천시 대공원대로 26', '02-503-6132', ARRAY['고기'], 'https://www.youtube.com/watch?v=F1ms0elgPLQ', 37.4364296, 127.0031954, '경기도', '쯔양은 과천 서울대공원 인근에 위치한 ''대공원포도밭''을 방문하여 대표 메뉴인 오리주물럭을 먹었습니다. 영상에서는 비닐하우스 스타일의 야외 느낌이 나는 식당 분위기가 특징적으로 나타납니다. 쯔양은 매콤달콤한 양념의 오리주물럭을 맛있게 먹고, 남은 양념에 볶음밥까지 볶아 먹으며 만족스러운 반응을 보였습니다. 푸짐한 양과 할머니 직원들의 독특한 운영 방식 또한 이 식당의 특징으로 언급됩니다.'),
('감나무집기사식당', '서울 마포구 연남로 25', '02-325-8727', ARRAY['한식'], 'https://www.youtube.com/watch?v=w8Kdp0OoP0U', 37.561905, 126.9219009, '서울특별시', '쯔양은 이 식당에 나이 많은 손님들이 많은 것을 보고 ''보장된 맛집''이라고 확신했습니다. 그는 저렴한 가격에도 불구하고 모든 메뉴가 평균 이상의 맛을 내는 점을 칭찬하며 주방장의 실력이 매우 뛰어나다고 평가했습니다. 특히, 된장찌개는 간이 완벽하고 맛이 매우 깊다고 말했으며, 돼지불백은 기본에 충실한 맛이라고 언급했습니다. 오징어볶음의 양념은 밥과 완벽하게 어울린다고 극찬했고, 뚝배기 불고기에 들어있는 당면을 좋아했으며, 즉석 소불고기는 국물을 졸여서 먹는 것을 추천했습니다. 또한, 떡볶이가 반찬으로 나오는 것에 만족감을 표하며, 운전기사 외에 다양한 연령층이 찾는 것을 보고 이곳이 진정한 맛집임을 다시 한번 강조했습니다.'),
('자담치킨 서울가산점', '서울 금천구 가산로 89', '02-858-9003', ARRAY['치킨'], 'https://www.youtube.com/watch?v=TUfnKHP55x4', 37.4739406, 126.8943245, '서울특별시', '신메뉴 ''티키타코 순살치킨''은 토마토 칠리와 과카몰리 소스가 더해져 전에 없던 멕시코 타코 같은 맛이라고 평가했습니다. 특히 나초를 부숴 뿌려 먹는 방식이 독특하며, 바삭한 식감을 더해준다고 언급했습니다. 순살은 부드러운 닭다리살을 사용했고, 소스는 새콤하고 상큼하면서도 풍미가 깊다고 했습니다. 과카몰리 소스는 약간 매콤해서 느끼함을 잡아준다고 덧붙였습니다. 또한, 또띠아에 싸서 부리토처럼 먹는 방법을 추천하며, 밥 대신 들어간 나초칩의 식감 덕분에 완전히 다른 특별한 맛이 난다고 극찬했습니다. 대표 메뉴인 ''맵슐랭치킨''은 꽤 맵다고 평가했으며, 사이드 메뉴인 감자튀김은 매우 바삭하고, 치즈볼 또한 바삭해서 맛있다고 했습니다. 천연 재료로 만든 치킨무도 인상 깊었다고 언급하며 전반적으로 매우 만족스러운 식사였다고 총평했습니다.'),
('신전떡볶이 방배점', '서울특별시 서초구 서초대로1길 19-5 1층', '0507-1419-3866', ARRAY['분식'], 'https://www.youtube.com/watch?v=IZoaoUWGmr8', 37.4879822, 126.9829178, '서울특별시', '몇 달 전부터 신전떡볶이가 먹고 싶었다고 말하며, 특히 후추 맛이 강하게 나는 국물과 떡볶이를 그리워했다고 밝혔습니다. 중간맛 치즈떡볶이는 불닭볶음면과 비슷한 맵기라고 평가했으며, 많은 국물 양에 만족감을 표했습니다. 처음 먹어본 로제 떡볶이는 기존 신전의 맛에 크리미함이 더해져 더 맛있다고 극찬했습니다. 튀김류 중에서는 치즈스틱과 예전부터 즐겨 먹던 어묵튀김, 잡채튀김을 언급했고, 닭껍질 튀김은 새로운 최애 메뉴가 되었다고 합니다. 신전치즈김밥에 대해서는 김치볶음밥에 치즈가 들어간 형태로, 일반 김밥보다는 질척한 식감이라고 설명했습니다. 참치마요 컵밥과 바삭불고기 컵밥도 주문했는데, 참치마요는 떡볶이와 잘 어울리고, 바삭불고기는 푸짐해서 든든한 느낌이라고 평가했습니다. 전반적으로 학창 시절의 추억이 담긴 장소에서 그리워하던 메뉴들을 맛있게 먹으며 만족스러운 식사였다고 총평했습니다.'),
('칭따오양꼬치', '서울특별시 동작구 노량진로8길 70', '02-817-9751', ARRAY['고기'], 'https://www.youtube.com/watch?v=MPPRr8U3Ki8', 37.5119486, 126.9388965, '서울특별시', '쯔양은 양꼬치, 마라 양꼬치, 소고기 꼬치, 소혈관 꼬치, 양깃머리, 양갈비, 새우구이 등 다양한 메뉴를 맛보았습니다. 기본 양꼬치는 육즙이 풍부하고 식감이 쫄깃하며 양고기 특유의 냄새가 없어 만족스럽다고 평가했습니다. 특히 마라 양꼬치는 매콤하고 양념이 완벽하게 배어있어 LA 갈비 맛이 난다며 극찬했습니다. 소고기 꼬치는 아주 맛있는 스테이크 같다고 했고, 소혈관과 양깃머리는 독특하고 쫄깃한 식감이 일품이라고 언급했습니다. 양갈비는 기름지고 소갈비와 비슷한 느낌이라고 평가하며 정말 맛있다고 여러 번 강조했습니다. 전체적으로 모든 메뉴에 만족하며 총 140개의 꼬치를 먹었고, 아주 즐거운 식사였다고 마무리했습니다.'),
('뽕사부 약수점', '서울 중구 동호로 186-3 1층', '02-2253-8882', ARRAY['중식'], 'https://www.youtube.com/watch?v=a9aWUqaRKkY', 37.5547701, 127.0111895, '서울특별시', '쯔양은 이 식당의 대표 메뉴인 짬뽕에 대해 한우뼈로 우려낸 국물이 매우 진하고 깊은 맛을 낸다고 평가했습니다. 면은 첨가물 없이 직접 뽑아 쫄깃하고 고소하며, 해산물은 신선하다고 언급했습니다. 특히 가지튀김은 육즙이 가득하고 고기 소스와의 조화가 훌륭하며, 탕수육은 찹쌀 반죽으로 만들어 쫀득하고 소스가 너무 시지 않고 달콤하다고 칭찬했습니다. 깐풍기는 부드러운 닭고기와 쫄깃한 식감이 특징이라고 설명했습니다. 이 외에도 순한 짬뽕, 냉짬뽕, 크림새우 등 다양한 메뉴를 맛보았으며, 전반적으로 모든 요리가 훌륭하다며 메뉴에 10점 만점을 주었습니다. 짬뽕을 좋아하는 사람들에게 강력히 추천하는 맛집이라고 최종적으로 평가했습니다.'),
('오장동 흥남집 본점', '서울특별시 중구 마른내로 114', '02-2266-0735', ARRAY['한식'], 'https://www.youtube.com/watch?v=HmphRR9IdOk', 37.5643493, 127.0005678, '서울특별시', '쯔양은 해당 식당의 모든 메뉴(회냉면, 고기 비빔냉면, 섞임냉면, 물냉면, 온면, 회무침, 수육, 만두)를 주문하여 먹었습니다. 특히 면이 다른 곳보다 더 굵고 오징어 먹물이 들어가 쫄깃하며, 양념이 맛있다고 평가했습니다. 회냉면의 회무침은 부드러우면서 아삭하고, 소고기 비빔냉면은 간장 베이스 양념의 감칠맛이 특징이라고 언급했습니다. 물냉면은 평양냉면보다 간이 있는 편이며 설탕을 넣어 먹는 조합을 극찬했습니다. 온면은 해장에 좋을 것 같다고 말했으며, 모든 메뉴에 대해 전반적으로 만족하며 식당의 신기록을 세웠습니다.'),
('초와밥', '서울 동작구 동작대로5길 8 2층', '02-523-5937', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=yzsrWBp3nFo', 37.4791436, 126.9810062, '서울특별시', '쯔양은 이 식당을 ''인생 초밥집''이라고 극찬하며, 자신의 취향에 맞는 최고의 초밥집 중 하나로 꼽았습니다. 특히 입에 넣자마자 부드럽게 풀어지는 공기층이 살아있는 밥알을 극찬했으며, 직접 레시피를 물어보고 싶어할 정도로 만족했습니다. 가장 인상 깊었던 메뉴로는 입에서 녹는 ''참치 뱃살(도로)'' 초밥과 값비싼 ''살치살''을 사용한 ''소고기'' 초밥을 공동 1위로 선정했습니다. 소고기 초밥은 살치살 부위임을 정확히 맞혔고, 만약 알았다면 20개를 주문했을 것이라고 말했습니다. 그 외에도 부드러운 식감의 장어, 두툼한 전복, 식감이 좋은 광어 지느러미 등 모든 초밥이 맛있다고 평가했습니다. 평소 즐겨 먹지 않던 새우초밥마저 편견을 깨뜨릴 정도로 맛있었다고 언급하며, 제공되는 모든 메뉴에 높은 만족감을 표현했습니다. 맛이 너무 뛰어나 자신의 최고 기록인 240개를 깰 수 있을 것 같다고 말할 정도로 폭발적인 반응을 보였습니다.'),
('뮌헨호프', '서울 중구 을지로14길 30', '02-2273-2288', ARRAY['야식'], 'https://www.youtube.com/watch?v=LnpoLJ1PLFM', 37.5648895, 126.9920033, '서울특별시', '쯔양은 이곳이 을지로 골뱅이로 유명한 곳이라고 소개하며 야외 테이블에서 식사했습니다. 메인 메뉴인 골뱅이에 대해 ''크기가 엄청나다'', ''부드럽고 맛있다''고 평가했습니다. 이 외에도 돈까스, 계란말이, 순두부찌개, 마늘치킨 등 다양한 안주를 주문했으며, 특히 사장님이 추천한 마늘치킨을 ''눈이 번쩍 뜨이는 맛''이라고 칭찬했습니다. 함께 마신 ''켈리'' 맥주에 대해서는 ''부드러우면서도 강렬한 탄산감의 반전 있는 맛''이라고 상세히 묘사하며 음식과의 조화를 즐겼습니다. 낮술을 즐기기 좋은 분위기와 저녁에는 만석이 되는 인기 맛집이라는 점을 언급하며 전반적으로 만족감을 표현했습니다.'),
('송산칼국수', '경기도 화성시 송산면 송산포도로 116-2', '031-357-8381', ARRAY['한식'], 'https://www.youtube.com/watch?v=rilnZ_dW2Hg', 37.2145389, 126.7360506, '경기도', '쯔양은 우연히 방문한 식당임에도 음식 맛이 매우 훌륭하다고 여러 차례 감탄했습니다. 특히 제부도 갯벌에서 매일 아침 직접 잡아온 신선한 낙지를 사용하는 점을 높이 평가했으며, 살아있는 낙지를 쓰는데도 가격이 저렴하다는 점에 놀라워했습니다. 주문한 모든 메뉴에 대해 긍정적인 평가를 남겼습니다. ''낙지볶음''은 전설적인 맛이라고 극찬했고, ''해물칼국수''는 국물이 시원하고 면이 쫄깃하며 낙지가 부드럽다고 평했습니다. 또한 ''김치칼국수''는 국물이 진하고 면의 식감이 좋다고 말했으며, ''바지락 수제비''의 얇고 쫄깃한 식감에도 만족감을 표했습니다. 전반적으로 유명하지 않은 곳에서 발견한 맛집이라며 큰 만족감을 드러냈습니다.'),
('김밥나라 남성역점', '서울 동작구 사당로 196', '02-598-7182', ARRAY['분식'], 'https://www.youtube.com/watch?v=02LzJVZCqt0', 37.4849593, 126.9699257, '서울특별시', '쯔양은 리뷰가 2,000개가 넘는 유명한 ''김밥나라 남성역점''에 방문하여 그 인기를 실감했습니다. 그녀는 소고기 김밥, 참치 김밥, 참치김치찌개, 치즈돈까스, 치즈라면, 김치수제비, 돌솥비빔밥 등 7가지 메뉴를 주문했습니다. 특히 팔뚝보다 두꺼운 김밥의 엄청난 크기에 놀라움을 표하며, 가격 대비 양이 매우 푸짐하다고 평가했습니다({ts:196-200, 298}). 김밥 속 계란이 부드럽고, 소고기 김밥에는 저렴한 고기 대신 진짜 다진 소고기가 들어있다고 칭찬했습니다. 참치김치찌개는 재료가 아낌없이 들어갔고, 치즈돈까스는 꼭 먹어야 할 메뉴라고 추천했으며, 김치수제비는 2인분 같은 양이라고 언급했습니다. 쯔양은 저렴한 가격, 집밥처럼 맛있는 음식, 그리고 엄청난 양이 이 식당의 인기 비결이라고 결론 내렸습니다({ts:489, 804-812}).'),
('미스터피자 발산점', '서울특별시 강서구 강서로 289', '02-2665-1067', ARRAY['피자'], 'https://www.youtube.com/watch?v=hM9LGb1vdrc', 37.5516081, 126.835982, '서울특별시', '쯔양은 34년 전통의 ''미스터피자''에 방문하여 신메뉴 ''미피포게더'' 피자와 ''판타스틱 3'', 그리고 ''MP 샌드위치'' 등을 먹었습니다. ''미피포게더''는 4가지 맛(스위트 포테이토, 치즈 블라썸 스테이크, 킹 브레드 쉬림프 골드 칠리, 포테이토 골드)을 한 번에 즐길 수 있는 피자로, 쯔양은 특히 스위트 포테이토 피자가 입에서 녹을 정도로 부드럽고 맛있다고 평가했습니다. 골드 무스 크러스트 또한 매우 만족스러워했습니다. 칠리 소스가 들어간 피자는 느끼함을 잡아주어 끝까지 맛있게 먹을 수 있었다고 언급했습니다. 사이드 메뉴인 ''MP 떡볶이''는 츄러스 모양의 떡이 독특하며, 매콤한 소스가 피자와 잘 어울린다고 말했습니다. ''판타스틱 3''와 ''MP 샌드위치''는 혼자 먹기 좋은 메뉴로, 특히 치아바타 빵을 사용한 ''포테이토 골드 샌드위치''를 가장 맛있는 빵으로 꼽았습니다. 전반적으로 모든 메뉴를 질리지 않고 맛있게 즐겼다고 총평했습니다.'),
('뚝방닭구이 용산본점', '서울 용산구 한강대로54길 25', '0507-1381-3344', ARRAY['고기'], 'https://www.youtube.com/watch?v=v0Uf-GJDDeM', 37.5326123, 126.9730043, '서울특별시', '쯔양은 숯불 닭구이를 먹기 위해 삼각지에 위치한 ''뚝방닭구이''에 방문했습니다. 과거에 방문했을 때 맛있게 먹은 기억이 있는데, 현재는 웨이팅이 매우 긴 맛집이 되었다고 언급했습니다. 스페셜 모둠 구이를 주문했으며, 다양한 닭 특수부위(목살, 넓적다리, 염통, 근위, 날개 등)를 맛보았습니다. 특히 닭 목살의 오독오독한 식감과 촉촉함에 감탄했고, 근본인 다리 살도 역시 맛있다고 평가했습니다. 처음 먹어보는 구운 닭 날개는 껍질이 바삭하고 쫀득해 맛있다고 칭찬했습니다. 간장 양념 구이는 부드럽고 간이 적당하며, 고추장 양념 구이는 매콤달콤해서 간장보다 더 맛있다고 느꼈지만 꽤 맵다고 했습니다. 된장찌개에는 특이하게 어묵이 들어가 있고 시골 된장 맛이 난다고 설명했습니다. 전반적으로 다양한 부위의 식감을 즐길 수 있어 먹는 재미가 쏠쏠한 맛있는 닭구이였다고 최종 평가했습니다.'),
('경아식당 삼성코엑스점', '서울특별시 강남구 테헤란로87길 21 지하1층', '0507-1362-1962', ARRAY['고기'], 'https://www.youtube.com/watch?v=aQgrA3YISDw', 37.5090572, 127.0582694, '서울특별시', '쯔양은 ''신도시부부''와 함께 경아식당 삼성코엑스점을 방문하여 묵은지 삼겹살 10인분을 주문했습니다. 삼겹살은 아주 두툼하고 품질이 좋으며, 특히 알맞게 잘 익은 묵은지와의 조합이 환상적이라고 극찬했습니다. 고기 두 점을 넣어 쌈을 싸 먹는 등 매우 만족스러운 식사를 했고, 함께 주문한 부대찌개 역시 맛있다고 언급했습니다.'),
('떡참 경기안성점', '경기도 안성시 아양1길 33-4 1층 102호', '031-8057-8882', ARRAY['분식'], 'https://www.youtube.com/watch?v=9oLhNKQUq-M', 37.0108376, 127.2564077, '경기도', '쯔양은 ''떡참''의 다양한 메뉴를 맛보았습니다. 기본 떡볶이는 남녀노소 좋아할 맛이며, 로제 떡볶이는 특유의 맛이 살아있다고 평가했습니다. 트러플 크림 떡볶이는 새로운 종류의 크림 떡볶이로, 양파 향이 더해져 맛있다고 언급했습니다. 28cm ''대왕 오징어 튀김''은 크고 속이 꽉 차 있으며, 떡볶이 소스와 잘 어울린다고 했습니다. 순살치킨은 바삭하고 맛있으며, 특히 트러플 크림 소스에 찍어 먹는 조합을 최고로 꼽았습니다. 미니 김밥은 속이 푸짐하고 가성비가 좋다고 칭찬했습니다. 특별 메뉴로 제공된 매운 가래떡 떡볶이는 트러플 마요 소스와의 조합이 인상적이라고 평하며 정식 출시를 기대했습니다. 전반적으로 1인분 양이 푸짐하고, 미니언즈와 콜라보한 포장이 귀엽다는 점도 언급했습니다.'),
('함평육회 본점', '서울 송파구 올림픽로32길 22-19 1층', '0507-1385-3336', ARRAY['고기'], 'https://www.youtube.com/watch?v=p4kSz4VJj4Q', 37.5135501, 127.1085735, '서울특별시', '쯔양은 당일 도축되어 매우 신선한 뭉티기와 육회를 맛보기 위해 서울 방이동에 위치한 ''함평육회''에 방문했습니다. 뭉티기는 매우 붉고 선명한 색을 띠며, 식감이 아주 쫄깃하고 아삭한 소리가 날 정도라고 평가했습니다. 일반적인 부드러운 육사시미와는 다른 독특한 식감을 극찬했습니다. 쯔양은 뭉티기를 기름장, 초밥, 특제 고추장 소스, 백김치, 성게알(우니) 등 다양한 방식으로 즐겼습니다. 육회 또한 뭉티기만큼 신선하고 맛있어서 추가로 주문했으며, 육회탕탕이의 부드러운 낙지도 언급했습니다. 특히 뭉티기와 육회 같은 메뉴는 소주와 잘 어울린다고 말하며, 식사를 마친 후 집에서 2차로 즐기기 위해 뭉티기를 포장해갈 정도로 만족감을 표현했습니다.'),
('중앙해장', '서울 강남구 영동대로86길 17', '02-558-7905', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=oIekVa6OA-8', 37.5082934, 127.0654986, '서울특별시', '유튜버 쯔양은 ''중앙해장''을 방문하여 대표 메뉴인 ''곱창전골''을 먹었습니다. 영상 제목에서 알 수 있듯이, 곱창이 3kg이나 들어간 엄청난 양에 놀라움을 표했습니다. 쯔양은 곱이 가득 찬 신선한 곱창과 진하고 깊은 맛의 국물을 극찬하며 ''인생 맛집''이라고 평가했습니다. 전골을 먹은 후에는 우동 사리를 추가하고, 한국식 후식인 볶음밥으로 식사를 마무리하며 내내 만족스러운 반응을 보였습니다.'),
('뻘하우스', '서울 중구 다산로47길 15 리더스빌딩1층', '02-2231-7292', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=JNkmE4CX84E', 37.5665317, 127.0151137, '서울특별시', '쯔양은 특대 사이즈 조개찜에 조개 플래터, 가리비, 키조개를 추가 주문하여 먹방을 시작했다. 조개찜에는 다양한 조개와 함께 닭 한 마리가 통째로 들어있는 것이 특징이다. 가리비는 매우 통통하고 부드러우며, 한 입 베어 물면 육즙이 터져 나올 정도로 촉촉하다고 평가했다. 붉은 가리비는 작지만 살이 꽉 차고 맛있다고 언급했다. 키조개는 거대한 크기와 쫄깃하면서도 아삭한 식감이 일품이라고 극찬했다. 조개들이 질기지 않고 촉촉하게 아주 잘 익었다고 만족감을 표했으며, 함께 나온 치즈 퐁듀와의 궁합도 훌륭하다고 말했다. 조개와 닭을 우려낸 시원하고 깊은 맛의 육수에 칼국수 사리를 넣어 ''조개닭 칼국수''로 마무리했는데, 면이 매우 부드럽고 맛있다고 평가했다.'),
('꽃새우 영번지 역삼점', '서울특별시 강남구 언주로 536', '02-501-2050', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=tkXHVfZ8noU', 37.5061935, 127.0413727, '서울특별시', '쯔양은 진로 제로 슈거 소주가 당이 없음에도 불구하고 기존 소주와 맛이 동일하며, 오히려 더 깔끔하고 부드러운 목 넘김을 가지고 있다고 평가했습니다. 특히 해산물 안주와의 궁합을 극찬하며, 여러 메뉴 중에서도 통통한 ''반건조 오징어 구이''와 ''아보카도 명란 구이''를 최고의 메뉴로 꼽았습니다. 또한, 알이 꽉 찬 ''열빙어 구이''와 식감이 좋은 ''개불''도 맛있게 먹었으며, 푸짐한 해물이 들어간 ''해물 라면''의 국물 맛이 일반 라면과 다른 고급스러운 요리 같다고 감탄했습니다. 전반적으로 모든 안주가 소주와 완벽하게 어울린다고 만족감을 표현했습니다.'),
('마포만두 합정점', '서울 마포구 양화로7길 12', '02-333-9842', ARRAY['분식'], 'https://www.youtube.com/watch?v=bLU28fVWX_s', 37.5514084, 126.9151788, '서울특별시', '쯔양은 갈비만두로 유명한 마포만두 합정점에 방문하여 다양한 메뉴를 맛보았습니다. 그는 이곳의 시그니처 메뉴인 갈비만두를 ''최고''라고 평가하며, 오랜만에 먹어도 매우 맛있고 속이 촉촉하여 입에서 녹는다고 극찬했습니다. 결국 갈비만두만 두 판을 추가 주문할 정도로 만족감을 보였습니다. 쯔양은 개인적인 순위로 1위 갈비만두, 2위 김치만두, 3위 카레만두를 꼽았습니다. 김치만두는 신라면보다 맵다고 평가했고, 카레만두는 예상보다 카레 향이 매우 강하고 진하다고 언급했습니다. 반면 ''개성만두''로 추정되는 스페셜 만두는 청주 미친만두가 연상될 정도로 극심하게 매워 먹기 힘들다고 평하며 포장했습니다. 만두 외에 주문한 치즈라면은 집에서 끓인 것과 달리 특별히 더 맛있다며 감탄했고, 쌀떡으로 만든 떡볶이와 어묵도 맛있게 먹었습니다. 전반적으로 최근 먹은 갈비만두 중 최고였다며 만족스러운 식사였다고 마무리했습니다.'),
('감탄계숯불치킨 안양범계점', '경기 안양시 동안구 평촌대로223번길 11 2층 201호', '031-382-9997', ARRAY['치킨'], 'https://www.youtube.com/watch?v=snpnv6kBB3U', 37.3910091, 126.954994, '경기도', '쯔양은 참숯 향이 인상적인 여러 메뉴를 맛보았습니다. ''양념구이''는 숯불 향이 진하고 매우 부드럽고 촉촉하며 양념이 맛있다고 평가했습니다(0:244, 0:265). ''소금구이''는 겉은 과자처럼 바삭하고 속은 육즙이 가득해 상상 이상으로 맛있다고 감탄하며, 퍽퍽하지 않은 점을 장점으로 꼽았습니다(0:301, 0:351). ''소시지 파꼬치''는 숯불에 구운 파가 부드럽고 달콤해 소시지와 잘 어울린다고 칭찬했습니다(0:403, 0:419). 닭고기를 싸 먹는 ''나초칩''은 바삭한 식감을 더해주는 독특한 조합이라고 언급했습니다(0:368). 양념과 잘 어울리는 ''볶음면''은 숯불 향과 매콤한 맛이 특징이라고 설명했습니다(0:561, 0:589). 전반적으로 모든 메뉴의 조합이 훌륭하고 양도 만족스럽다고 평가했으며, 소금구이와 양념구이 중 하나를 고르기 어려울 정도로 둘 다 맛있다고 극찬했습니다(0:717, 0:832). 쯔양이 먹은 메뉴 구성은 ''쯔양세트''라는 이름으로 한정 판매될 예정이라고 영상에서 언급되었습니다(0:730).'),
('연소바', '서울 관악구 남부순환로 1802', '02-871-2221', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=ZsJ7y3NSXIM', 37.4811802, 126.9503221, '서울특별시', '쯔양은 60년 전통의 1세대 메밀 장인에게 직접 전수받은 레시피로 운영되는 곳이라며 기대를 보였습니다. 판메밀 국수를 맛본 후, 국물 맛이 매우 진하고 맛있으며, 면은 얇지만 쫄깃하고 부드럽다고 극찬했습니다. 함께 주문한 돈까스는 튀김옷이 얇고 고기가 두툼하고 부드러워 정말 맛있다고 평가했으며, 메밀 만두 또한 속이 촉촉하고 메밀의 맛이 잘 느껴져 맛있다고 했습니다. 쯔양은 주문한 모든 음식이 맛있다며 감탄했고, 판메밀 5판을 다 먹은 뒤 아쉬워하며 한 판을 더 추가 주문해서 먹었습니다.'),
('프로간장새우 본점', '서울 강남구 강남대로122길 20', '0507-1416-7477', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=di27zwr6s9I', 37.5080568, 127.0246335, '서울특별시', '쯔양은 영상 제목에서 ''짜계치''와 ''간장새우''의 조합을 ''의외의 환상조합''이라고 표현하며 매우 긍정적으로 평가했습니다. 주 메뉴인 간장새우는 짜지 않고 맛있어 밥과 함께 비벼 먹는 ''밥도둑''으로 알려져 있습니다. 또한, 별미인 ''짜계치''(짜파게티, 계란, 치즈)와 간장새우의 조합을 특히 인상 깊게 평가한 것으로 보입니다. 쯔양은 이 두 메뉴의 독특한 조합에 큰 만족감을 드러냈습니다.'),
('홍천닭갈비', '서울특별시 동작구 흑석로 95-1 (흑석동)', '02-817-8637', ARRAY['한식'], 'https://www.youtube.com/watch?v=Ybz9loB46ew', 37.5075894, 126.9602381, '서울특별시', '30년 전통의 노포 분위기가 정겹다고 언급했습니다. 대표 메뉴인 닭갈비는 국내산 생닭을 사용하여 고기가 매우 부드럽고 육즙이 풍부하며, 퍽퍽한 부위가 하나도 없다고 극찬했습니다. 양념은 자극적이지 않고 순한 맛이며, 깻잎에 싸 먹는 조합을 특히 선호했습니다. 함께 먹은 밀가루 떡은 부드럽고 쫄깃하며, 서비스로 받은 우동 사리 또한 양념과 잘 어울린다고 평가했습니다. 저녁 시간이 되어 손님이 많아지자 아쉽게도 볶음밥은 먹지 못하고 식사를 마쳤습니다.'),
('홍제동우동국수', '서울특별시 은평구 서오릉로 242', '02-388-5929', ARRAY['한식'], 'https://www.youtube.com/watch?v=qp5ZhELz-OI', 37.6163517, 126.9078301, '서울특별시', '쯔양은 대표 메뉴인 순두부우동, 부추우동, 냉우동을 모두 맛보았습니다. **순두부우동**은 순두부찌개 같은 맛에 칼칼하고 해장에 좋을 것 같다고 평가했으며, 자극적이지 않고 담백한 매운맛이 특징이라고 설명했습니다. 남은 국물에 밥을 말아 먹으며 맛있다고 감탄했습니다. **부추우동**은 부추 향이 강하게 나는 점을 칭찬하며, 자극적이지 않고 감칠맛이 있어 개인적인 취향에 더 잘 맞는다고 말했습니다. **냉우동**은 냉면 육수와 비슷한 시원한 맛으로 여름에 먹기 좋은 별미라고 평가했습니다. 면발은 일반 우동면보다 가늘어 우동과 국수의 중간 같다고 언급했습니다.'),
('랜떡 송파직영점', '서울특별시 송파구 백제고분로41길 27-1 1층 1호', '02-3432-1118', ARRAY['분식'], 'https://www.youtube.com/watch?v=qp5ZhELz-OI', 37.5081168, 127.1067558, '서울특별시', '쯔양은 이곳이 경북 영주의 유명 맛집인 ''랜떡''의 서울 직영점이라고 소개했습니다. 떡볶이, 순대, 튀김 등을 주문하여 시식했습니다. 맛은 영주 본점과 90% 정도 비슷하며 아주 맵다고 평가했습니다. 특히 쌀떡의 쫀득하고 부드러운 식감을 매우 칭찬하며 ''떡이 정말 맛있다''고 여러 번 강조했습니다. 튀김 중에서는 오징어튀김이 맛있다고 추천했으며, 삶은 계란을 떡볶이 국물에 으깨 먹는 것을 즐겼습니다. ''랜떡''이라는 이름은 과거 영주 본점 가게가 랜드로버 매장 앞에 있었기 때문에 붙여진 것이라고 설명했습니다.'),
('옛날왕솥뚜껑생삼겹살', '서울 서대문구 통일로39길 22-58 1층', '02-394-2188', ARRAY['고기'], 'https://www.youtube.com/watch?v=sdDrR_L_ncQ', 37.5899264, 126.9417001, '서울특별시', '쯔양은 이 식당에서 삼겹살, 목살, 우삼겹, 차돌박이 등 총 14인분을 주문했습니다. 고기와 함께 나온 파채 양념이 맛있고 고기 두께가 적당해서 완벽하고 행복하다고 평가했습니다. 구운 김치와 고기를 함께 먹는 조합을 ''진정한 행복''이라고 표현하며 극찬했고, 1,000원짜리 된장찌개도 가성비가 좋고 맛있다며 만족감을 표했습니다. 특히, 영상 후반부에는 남은 고기와 김치, 파채 등을 이용해 자신만의 ''김치 짜글이''를 만들어 먹으며 ''정말 기가 막힌 발상''이라고 자평하는 등 전반적으로 식사에 매우 만족했습니다.'),
('하나비카레', '서울 서초구 강남대로101안길 18-1 1층', '0507-1365-7788', ARRAY['아시안'], 'https://www.youtube.com/watch?v=5P9YmF-GjLI', 37.516266, 127.017587, '서울특별시', '쯔양은 3.5kg의 거대 카레 먹기 도전을 진행했습니다. 카레 소스는 ''지금까지 먹어본 일본 카레 중 최고''라고 극찬했으며, 고기 고명이 식감을 더해준다고 평가했습니다(0:328). 돈까스, 새우튀김, 닭튀김(가라아게), 크로켓, 소시지 등 다양한 튀김 토핑이 올라가 있었는데, 특히 닭튀김이 겉은 바삭하고 속은 촉촉하여 가장 맛있다고 꼽았습니다(0:840). 날달걀 노른자, 다진 마늘, 파를 섞어 먹는 조합도 즐겼습니다. 양이 매우 많았음에도 불구하고, 음식이 전반적으로 맛있어서 즐겁게 도전할 수 있었다고 소감을 밝혔습니다(0:680, 0:964). 3.5kg 카레를 다 먹는 데 성공했습니다(0:925).'),
('신길동매운짬뽕', '서울특별시 영등포구 신길동 48-20', '010-5395-1151', ARRAY['중식'], 'https://www.youtube.com/watch?v=czjsOPq0sDc', 37.5153387, 126.9165242, '서울특별시', '쯔양은 극강의 매운맛으로 유명한 ''신길동매운짬뽕''의 대표 메뉴인 매운짬뽕 도전 먹방을 진행했습니다. 이 짬뽕은 다 먹으면 ''평생 무료''라는 타이틀이 걸려있으며, 청양고추와 베트남 고추를 사용해 극심한 매운맛을 내는 것이 특징입니다. 쯔양은 영상에서 매운맛에 고통스러워하면서도 땀을 흘리며 면과 건더기를 모두 먹는 데 성공했습니다. 하지만 국물까지 전부 마시는 것에는 실패하여 최종 도전에는 성공하지 못했습니다. 그녀는 엄청나게 매운 와중에도 국물이 깔끔한 편이라고 평가했으며, 매운맛을 중화시키기 위해 우유를 함께 마셨습니다.'),
('보슬보슬 압구정본점', '서울 강남구 압구정로 216 지상 1층 16, 17, 18, 19호', '0507-1365-1261', ARRAY['분식'], 'https://www.youtube.com/watch?v=skXGx1pIam8', 37.528095, 127.031045, '서울특별시', '쯔양은 이곳의 시그니처 메뉴인 키토김밥을 포함해 김밥 5종, 라면 2종, 떡볶이, 튀김만두 등 다양한 메뉴를 주문했습니다. 김밥의 크기가 일반 김밥의 1.5~2배에 달할 정도로 매우 크고 속이 꽉 차 있다고 여러 차례 감탄했습니다(1:39, 3:14, 6:09). 특히 ''제육묵은지김밥''을 가장 맛있는 메뉴로 꼽으며, 마치 제육쌈밥을 먹는 것 같은 맛이라고 평가했습니다(12:37). ''묵은지참치 키토김밥''은 2위로 선정하며 다이어트하는 사람들에게 추천했습니다(5:18, 12:18). 기본 키토김밥인 ''베이컨키토마요''는 맛이 매우 순하다고 평가했습니다(4:25). 함께 주문한 ''스팸해장라면''은 사골 국물처럼 구수하고 진한 맛이 일품이라고 극찬했으며(3:32), ''보슬마늘떡볶이''는 양이 매우 푸짐하다고 언급했습니다(2:58). 전반적으로 모든 메뉴의 양이 푸짐하고 맛이 뛰어나다며 만족감을 표현했고, 특히 김밥의 압도적인 크기와 맛의 조화에 대해 긍정적인 평가를 남겼습니다.'),
('야키토리잔잔 광교점', '경기 수원시 영통구 법조로 38 광교 더샵 레이크파크 판매시설동 지하1층 비28, 비29, 비30호', '0507-1330-3470', ARRAY['고기'], 'https://www.youtube.com/watch?v=MN5cxevTa_M', 37.2870073, 127.0625014, '경기도', '쯔양은 오랜만에 술과 함께 안주를 즐기기 위해 광교 호수공원 야경이 보이는 ''야키토리잔잔 광교점''을 방문했습니다. 이곳은 수제 요리를 제공하는 일본식 주점으로, 쯔양은 25가지 종류의 꼬치 전체, 투뿔 한우 육회, 차돌 매콤 짬뽕 등을 주문했습니다. 쯔양은 다양한 꼬치 중에서도 겉은 바삭하고 속은 부드러운 ''떡 삼겹 꼬치''를 가장 맛있는 메뉴로 꼽았습니다. 또한, 육즙이 풍부한 버섯 꼬치와 소고기 부채살 꼬치도 맛있게 먹었으며, ''명란 닭가슴살 꼬치''는 추가로 더 먹을 정도로 만족스러워했습니다. ''차돌 매콤 짬뽕''은 소주와 잘 어울리는 칼칼한 국물과 푸짐한 건더기를 칭찬했고, ''투뿔 한우 육회''는 양이 많고 신선하다고 평가했습니다. 특히 볏짚으로 구운 ''시샤모 구이''는 독특한 풍미가 일품이라며 100개도 먹을 수 있겠다고 극찬했습니다. 전반적으로 모든 안주가 맛있고 술과 잘 어울려 친구들과 다시 방문하고 싶은 맛집이라고 총평했습니다.'),
('머거보까매운갈비찜', '서울 중구 다산로10길 5-4', '02-2234-4544', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=Dzo7cB0MtbI', 37.5536907, 127.01065, '서울특별시', '쯔양은 돼지갈비찜 보통맛과 소갈비찜 매운맛, 그리고 순두부탕을 주문했습니다. 돼지갈비찜은 고기가 매우 부드럽고 잡내가 없으며, 맛있게 맵다고 평가했습니다. 특히 매운 음식을 잘 먹는 사람이라도 갈비 본연의 맛을 더 잘 느낄 수 있는 보통맛을 추천했습니다. 소갈비찜 매운맛은 ''지옥'', ''용암''에 비유할 정도로 극강의 매운 비주얼이었지만, 못 먹을 정도는 아니라고 했습니다. 온라인 후기와는 달리 개인적으로는 돼지갈비찜보다 더 부드러운 소갈비찜을 선호한다고 밝혔습니다. 함께 나온 맑은 순두부탕은 매운맛을 중화시켜주어 만족스러웠으며, 갈비찜에 들어있는 감자를 밥과 함께 으깨 먹는 방법을 강력 추천했습니다. 스트레스가 풀리는 맛있는 매운맛이라고 총평하며, 40년 전통의 기본에 충실한 맛집이라고 언급했습니다.'),
('제일곱창 본점', '서울 성동구 고산자로 281', '010-8690-9792', ARRAY['고기'], 'https://www.youtube.com/watch?v=WG6E8dCo3sE', 37.5648198, 127.0359945, '서울특별시', '쯔양은 왕십리의 ''제일곱창''이 주말에는 3시간을 기다려야 할 정도로 유명한 맛집이라고 소개했습니다. 기본 안주로 나오는 통 낙지가 들어간 해물 순두부찌개를 메인 메뉴급이라며 극찬했습니다. 메인 메뉴로 곱창, 대창, 특양, 염통 등 총 20인분을 주문했으며, 곱창 위에 강황가루가 뿌려져 나오는 것이 특징이라고 언급했습니다. 염통은 질겨지기 전에 먹어야 하며 두툼하고 쫄깃하다고 평가했고, 곱창은 속이 꽉 차 있고 매우 고소하며 전혀 질기지 않다고 말했습니다. 특히 특양(양깃머리)은 매우 부드럽고 쫄깃하여 다른 곳과 달리 질긴 맛이 전혀 없다고 감탄했으며, 대창은 기름지고 고소한 맛이 일품이라고 평가했습니다. 이 집의 명물인 파김치는 달고 시원한 맛이 곱창의 느끼함을 잘 잡아준다고 여러 번 언급하며 생으로도, 구워서도 맛있게 먹었습니다. 전반적으로 숙취가 있었음에도 불구하고 맛있게 먹을 수 있을 정도로 느끼하지 않았으며, 곱이 터져 나올 정도로 속이 꽉 찬 곱창의 품질을 높이 평가했습니다.'),
('천하보쌈', '서울 종로구 창덕궁1길 8', '02-744-1614', ARRAY['족발·보쌈'], 'https://www.youtube.com/watch?v=LNj0S7B5sEY', 37.5794502, 126.988851, '서울특별시', '쯔양은 보쌈 고기가 투박하게 썰려 나왔지만 매우 부드럽고 기름져서 고소하다고 평가했습니다. 특히 김치가 예술이라며, 인위적이지 않은 단맛과 매콤함이 어우러져 감칠맛이 난다고 극찬했습니다. 보쌈김치보다 겉절이가 더 맛있다고 여러 차례 언급하며, 평소 채소를 잘 먹지 않음에도 불구하고 겉절이는 계속 먹게 된다고 했습니다. 된장찌개 또한 중독성이 강해 계속 떠먹게 된다고 말했으며, 문어 숙회도 쫄깃한 식감이 좋다고 평가했습니다. 전반적으로 음식에 크게 만족하며 ''미쳤다'', ''역대급''이라는 표현을 사용하며 맛을 극찬했습니다.'),
('오뚜기돈까스', '경기 광명시 오리로 991', '02-2616-1316', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=zPy7VeF0YSY', 37.4796203, 126.8529788, '경기도', '쯔양은 40년 전통의 수제 돈까스 맛집으로 알려진 이곳을 방문하여, 정식을 제외한 모든 단품 메뉴(왕돈까스, 돈까스, 생선까스, 돈까스&생선까스, 함박스테이크)를 주문했습니다. 돈까스는 옛날 경양식 스타일로, 달고 신맛이 나는 소스가 특징이며 고기가 부드럽고 다른 곳보다 두껍다고 평가했습니다. 소스에 젖어 부드러운 부분과 바삭한 부분이 공존하는 것이 매력이라고 언급했습니다. 생선까스는 바삭하고 생선살이 입에서 녹는다고 했으며, 함박스테이크는 일반적인 맛과는 다른 ''전''이나 ''미트볼'' 같은 독특한 맛으로 아이들이 좋아할 것 같다고 말했습니다. 식사와 함께 여러 병의 요구르트를 마시며 돈까스와의 조합이 좋다고 만족감을 표현했고, 주문한 5가지 메뉴를 모두 깨끗이 비웠습니다.'),
('몽탄', '서울특별시 용산구 백범로99길 50', '0507-1418-8592', ARRAY['고기'], 'https://www.youtube.com/watch?v=lhs_QyVeEgs', 37.5360031, 126.9722473, '서울특별시', '쯔양은 ''몽탄''이 우대갈비로 한국에서 가장 유명하며, 주말에는 8~9시간을 기다려야 할 정도로 인기가 많다고 소개했습니다. 대표 메뉴인 우대갈비는 짚불에 초벌하여 숯불과는 다른 독특하고 익숙한 향이 특징이라고 평가했습니다. 고기가 매우 부드럽고 육즙이 풍부하며, 양념이 강하지 않아 그냥 먹거나 다양한 반찬과 곁들여도 좋다고 언급했습니다. 특히 양파김치, 갓김치와 같은 특색 있는 반찬들을 높이 평가했으며, 냉이가 들어간 된장찌개 또한 반드시 먹어봐야 할 메뉴로 꼽았습니다. 쯔양은 긴 대기 시간에 따른 높은 기대감을 완전히 충족시키는 맛이라고 극찬하며, ''천국에 온 것 같다''고 표현할 정도로 매우 만족스러운 식사였다고 총평했습니다.'),
('김영섭초밥', '서울 마포구 월드컵북로 352-18', '02-3152-0900', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=enAwNKQDpxM', 37.5776624, 126.8933236, '서울특별시', '쯔양은 마포구 상암동에 위치한 ''김영섭초밥''을 ''동네에서 유명한 초밥집''으로 소개하며 방문했습니다. 그녀는 김영섭초밥, 모듬초밥, 특선초밥을 포함해 장어, 소고기, 새우, 전복 등 총 87피스의 다양한 초밥과 굴튀김을 주문했습니다. 오늘의 스페셜 메뉴인 명란 광어초밥을 시작으로, ''입에서 녹는다''고 표현한 장어초밥, 소스가 훌륭한 훈제 소고기초밥, ''화가 날 정도로 맛있다''고 극찬한 연어초밥 등 대부분의 메뉴에 높은 만족도를 보였습니다. 특히 밥의 양보다 생선이 훨씬 크고 두툼하며, 식감이 부드럽다고 여러 차례 강조했습니다. 또한, 밥알의 익힘 정도도 완벽하다고 평가했습니다. 초밥과 잘 어울리는 된장국을 8번이나 리필할 정도로 식사를 즐겼으며, 맛과 친절한 서비스 모두에 크게 만족하며 ''정말 만족스러웠다''는 총평을 남겼습니다.'),
('옛날맛짜장', '서울 송파구 가락로 113', '02-425-3533', ARRAY['중식'], 'https://www.youtube.com/watch?v=CopqpabihGk', 37.5016889, 127.1086545, '서울특별시', '쯔양은 20년 된 옛날 짜장면 맛집을 찾아왔다며, 일반 짜장면 6그릇과 해물 짜장면 2그릇을 주문했습니다. 일반 짜장면은 원하던 옛날 맛 그대로라며, 약간 달면서 춘장 맛이 강하고 소스가 꾸덕한 것이 특징이라고 평가했습니다. 면은 쌀가루가 들어가 부드럽고 쫄깃하며, 해물 짜장면에는 오징어와 새우가 풍부하게 들어있다고 언급했습니다. 함께 제공된 짬뽕 국물은 매우 개운하고 깔끔한 맛이라고 칭찬했으며, 고춧가루를 뿌려 먹으니 훨씬 맛있다고 덧붙였습니다. 총 8그릇을 모두 비우며 정말 맛있게 먹었다고 만족감을 표현했습니다.'),
('아라치치킨 홍대직영점', '서울 마포구 와우산로29길 14-4 1층', '02-336-6300', ARRAY['치킨'], 'https://www.youtube.com/watch?v=LyxdItZU_4I', 37.555165, 126.9290154, '서울특별시', '쯔양은 70년 전통의 간장 회사 ''삼화식품''에서 만든 치킨 브랜드 ''아라치치킨''을 방문했습니다. 특히 대표 메뉴인 ''애간장치킨''에 대해 극찬을 아끼지 않았습니다. 깊고 진한 단짠의 풍미가 질리지 않고 고급스러우며, 소스가 너무 맛있어서 집에서 만든 잘 만든 소스 같다고 평가했습니다. 결국 한 마리를 추가 주문할 정도로 만족했으며, 본인의 최애 메뉴로 꼽았습니다. ''메가크리스피치킨''은 100% 현미유로 튀겨내어 겉은 바삭하고 속은 촉촉한 ''겉바속촉''의 정석이라며 튀김옷의 황금 비율을 칭찬했습니다. ''파티파티치킨''은 파와 고추가 어우러져 매콤, 달콤, 짭짤한 맛이 마치 중국요리를 먹는 느낌이라고 했으며, ''클래식양념치킨''은 삼화고추장으로 만들어 깊고 맛있는 단맛이 인상적이라고 평했습니다. 사이드 메뉴인 ''아라치 비빔면''과 ''7080 국물떡볶이'' 역시 소스가 특별하고 매우 맛있다고 언급하며 전반적으로 모든 메뉴에 높은 만족감을 표현했습니다.'),
('제일분식', '서울 강북구 숭인로 65-3', '0507-1364-7334', ARRAY['분식'], 'https://www.youtube.com/watch?v=VwdegbFqNaI', 37.6125852, 127.0289574, '서울특별시', '쯔양은 ''제일분식''을 자신의 ''최애'' 떡볶이 맛집이자 어릴 때부터 다닌 ''추억의 맛집''이라고 소개했습니다. 방송에서 이미 두 번이나 다루었을 정도로 좋아한다고 밝혔습니다. 떡볶이는 고추장 베이스의 소스가 아주 맵고 꾸덕하며, 쫀득한 쌀떡의 식감이 최고라고 평가했습니다. 특히 떡볶이와 함께 먹은 맛탕이 ''진짜 찐''이라며 매우 맛있다고 여러 차례 강조했습니다. 이날 먹방은 야식으로 떡볶이 5인분, 꼬마김밥, 순대, 맛탕을 포장해 와서 먹는 구성이었습니다.'),
('촌놈횟집', '인천 연수구 옥련로99번길 42 아주아파트 103동 정면상가 108호', '0507-1354-2645', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=VfNeiJ3ZXzY', 37.4266713, 126.6524414, '인천광역시', '쯔양은 겨울 제철을 맞아 16kg짜리 숙성 대왕방어를 먹기 위해 인천 송도에 위치한 ''촌놈횟집''을 방문했습니다. 방어는 총 12가지 특수부위(아가미 뱃살, 목살, 볼살, 갈비살, 눈살, 머리살, 배꼽살, 등살, 속살, 사잇살, 뱃살 등)로 제공되었으며, 각 부위의 독특한 식감과 맛에 감탄했습니다. 특히 가장 맛있다고 알려진 ''아가미 뱃살''은 참치 목살 같은 아삭한 식감과 입안을 코팅하는 기름진 맛이 일품이라고 평했습니다. 또한, 뱃살 부위로 직접 초밥을 만들어 먹으며 고급 스시집에 온 것 같다고 극찬했고, 숙성회 특유의 감칠맛과 고급스러운 풍미를 높이 평가했습니다. 기름진 맛을 달래기 위해 매운탕을 주문하여 남은 회를 샤부샤부처럼 데쳐 먹기도 했는데, 특히 사잇살 부위는 익히니 소고기처럼 녹는 식감이 일품이라고 언급했습니다.'),
('우불식당', '서울 송파구 송파대로28길 27 성원상떼빌 상가 102동 124호', '0507-1439-0006', ARRAY['한식'], 'https://www.youtube.com/watch?v=HvTLbeasXS4', 37.4950169, 127.1203666, '서울특별시', '쯔양은 이 식당의 대표 메뉴인 즉석 우동, 갈비 한 판, 모듬 어묵을 모두 맛보았습니다. 즉석 우동 국물에 대해 술을 마시지 않았는데도 해장되는 느낌이라며 극찬했고, 튀김 유부와 어묵이 푸짐하게 들어있어 좋다고 평가했습니다. 특히 매운 양념을 추가하면 칼칼한 맛이 더해져 더욱 맛있다고 언급했습니다. 갈비 한 판은 남녀노소 모두가 좋아할 만한 맛이라고 칭찬하며, 함께 제공된 빵, 마카로니 샐러드, 단무지를 이용해 햄버거를 만들어 먹는 방법을 선보이며 아주 맛있다고 평가했습니다. 모듬 어묵은 술안주로 제격이며, 국물이 시원해서 속이 풀리는 느낌이라고 말했습니다. 전반적으로 옛날 포장마차 감성이 느껴지는 분위기와 푸짐한 양에 만족감을 표했습니다.'),
('우면동소나무집', '서울 서초구 식유촌길 71', '02-577-9292', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=yupbldBCjE4', 37.4584122, 127.0115738, '서울특별시', '쯔양은 45년 전통의 예약 필수 맛집인 이곳에서 ''청국장 닭볶음탕''과 ''원조 닭볶음탕'' 두 가지 메뉴를 모두 맛보았습니다. 기본으로 제공되는 매우 바삭한 감자전과 두부김치에 감탄했습니다. ''원조 닭볶음탕''은 할머니가 해주시던 것처럼 진하고 깊은 맛이 일품이며, 닭고기가 매우 부드럽다고 평가했습니다. 독특한 ''청국장 닭볶음탕''은 청국장 맛이 강하지 않아 청국장을 즐기지 않는 사람도 맛있게 먹을 수 있는, 고추장찌개와 섞인 듯한 맛이라고 설명했습니다. 특히 1시간 이상 푹 익혀 으깨질 정도로 부드러운 감자를 밥과 국물에 비벼 먹는 것을 극찬했으며, 개인적으로는 다시 방문한다면 질리지 않는 기본에 충실한 ''원조''를 선택할 것 같다고 말했습니다. 우동 사리를 필수로 추가해야 한다고 강조했으며, 남은 국물에 밥을 볶아 먹으며 ''올해의 맛집''이라고 극찬하며 식사를 마무리했습니다.'),
('보글이 생태탕왕코다리 서초구청점', '서울 서초구 강남대로37길 56-18 서초에메랄드빌딩 1층', '0507-1388-7709', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=79LHvfqyC_0', 37.4854676, 127.0305941, '서울특별시', '쯔양은 대왕철판 해물찜(해물철판) 대 자 2판에 가리비, 전복, 알을 추가하여 주문했습니다. 음식이 나오자 엄청난 양에 감탄하며 예술이라고 표현했습니다. 갓 익힌 알은 부드럽고 맛있으며, 주꾸미는 살짝 익혔을 때와 완전히 익혔을 때 모두 통통하고 쫄깃하며 맛있다고 평가했습니다. 전복의 식감이 매우 뛰어나다고 언급했으며, 가리비, 조개, 새우 등 모든 해산물이 신선하고 양념이 잘 배어 있다고 말했습니다. 특히 여러 해산물에서 우러나온 국물이 매우 맛있다고 칭찬하며, 오랜만에 먹어서 아주 맛있는 식사였다고 총평했습니다.'),
('향미네짬뽕', '대전 서구 둔산서로 59 1층', '0507-1474-8254', ARRAY['중식'], 'https://www.youtube.com/watch?v=AAfhrt88mws', 36.3518442, 127.3825456, '대전광역시', '쯔양은 대표 메뉴인 꼬막짬뽕을 비롯해 유니짜장면, 소고기 로제짬뽕, 사천탕면, 유린기, 동파육, 크림새우 등 총 7가지 메뉴를 맛보았습니다. 꼬막짬뽕에 대해 ''진짜 진하다'', ''국물이 끝내준다''고 극찬하며, 큼직하고 푸짐한 꼬막과 진하고 매콤한 국물의 조화가 뛰어나다고 평가했습니다. 특히 홍합이나 바지락보다 꼬막이 짬뽕과 더 잘 어울린다고 언급하며, 이곳의 최고 메뉴로 꼽았습니다. 동파육은 부드러운 식감과 저렴한 가격(16,000원)에 만족감을 표했고, 유린기는 바삭한 튀김과 촉촉한 닭고기 식감을 칭찬했습니다. 또한, 하얀 국물의 사천탕면은 굴이 푸짐하게 들어있어 국물이 사골국물보다 진하고 깊은 맛이 난다며 감탄했습니다. 전반적으로 다양한 요리를 합리적인 가격에 맛볼 수 있는 점을 큰 장점으로 꼽았지만, 그중에서도 꼬막짬뽕을 가장 인상적인 메뉴로 강력 추천했습니다.'),
('남북통일', '서울 마포구 동교로18길 37', '02-3141-4113', ARRAY['한식'], 'https://www.youtube.com/watch?v=dRO4cbYyNvE', 37.5538067, 126.9179503, '서울특별시', '쯔양은 이 식당을 우연히 발견한 ''숨은 맛집''이라고 칭하며 전반적으로 극찬했습니다. 특히 여러 메뉴에 대한 구체적인 평가를 남겼습니다. - **닭칼국수**: 기존에 알던 맑은 국물이 아닌, 육개장과 비슷한 빨간 비주얼과 얼큰한 맛이 특징이라고 언급했습니다. 진한 사골 국물 베이스에 빨간 기름이 더해져 깊고 얼큰한 맛을 모두 잡았다고 평가하며, 면발 또한 쫄깃하다고 덧붙였습니다. - **녹두빈대떡**: 먹어본 녹두빈대떡 중 ''탑급''이라고 표현할 정도로 극찬했습니다. 겉이 매우 바삭하고 속은 부드러운 ''겉바속촉''의 정석이며, 맛 자체가 훌륭하다고 평가했습니다. - **이북식 만두**: 겉보기와 달리 속이 꽉 차 있으며, 일반적인 이북식 만두의 슴슴한 간과 달리 간이 세서 더 맛있었다고 합니다. 먹어본 이북식 만두 중 가장 맛있다고 평가했습니다. - **사골칼국수 & 떡만둣국**: 국물이 매우 진한 ''진짜 사골 국물''이라 밥을 말아 먹어도 될 정도라고 칭찬했습니다. 전반적으로 식당의 외관만 보고는 맛을 기대하기 어려웠으나, 막상 먹어보니 ''어어어엉?!'' 할 정도로 놀랍도록 맛있는 반전이 있는 곳이라고 요약했습니다. 자극적이지 않으면서 깊은 맛을 내는 이북식 음식을 좋아하는 사람들에게 추천했습니다.'),
('초원 남영본점', '서울 용산구 한강대로80길 7', '02-749-5949', ARRAY['고기'], 'https://www.youtube.com/watch?v=SVtf7xT5J64', 37.5427723, 126.9733505, '서울특별시', '쯔양은 이 식당의 대표 메뉴인 우설을 맛보고 ''완전 신세계''라며 극찬했습니다. 기존에 먹어본 소고기와는 전혀 다른, 버섯처럼 아삭아삭한 식감에 육즙이 풍부하고 잡내가 전혀 없다고 평가했습니다 . 여러 고기 부위 중 우설을 1위로 꼽았고, 2위는 특수부위, 3위는 갈비살, 4위는 등심 순으로 순위를 매겼습니다 . 함께 주문한 된장찌개에 대해서도 ''진짜 고깃집 된장찌개''라며 깊고 맛있는 맛이라고 칭찬했으며 , 볶음밥 또한 양파와 파 향이 진하게 나서 맛있다고 언급했습니다 . 전체적으로 매우 만족스러운 식사였으며, 특히 우설은 지금껏 먹어본 것 중 가장 맛있었다고 마무리했습니다 .'),
('소소라면 닭꼬치', '서울 용산구 한강대로 268-1 1층', '02-749-4949', ARRAY['분식'], 'https://www.youtube.com/watch?v=IYJ9NDTHOPs', 37.5422533, 126.9730622, '서울특별시', '쯔양은 추운 날씨에 따뜻한 국물과 닭꼬치가 생각나 남영동의 ''소소라면 닭꼬치''를 방문했다. 최루탄라면, 계떡라면, 치즈라면과 함께 닭꼬치, 염통꼬치, 닭모래집꼬치 등 다양한 꼬치류를 주문했다. 가장 매운 100단계의 최루탄라면은 국물이 거의 없는 비빔면 스타일에 매우 빨간 색을 띠고 있으며, 한 입 먹자마자 몸이 더워질 정도로 강력한 매운맛이지만 스트레스가 풀리는 맛있는 매운맛이라고 평가했다. 꼬치류에 대해서는 전반적으로 소스가 맛있다고 언급했으며, 특히 염통꼬치는 크고 촉촉하며 쫀득해서 반드시 먹어봐야 할 메뉴로 꼽았다. 소금구이 닭꼬치는 겉은 쫀득하고 속은 촉촉하게 완벽히 구워졌다고 칭찬했다. 여러 라면 중에서는 치즈라면이 가장 맛있다고 했으며, 전체 메뉴 중에서는 염통꼬치와 치즈라면을 최고로 선택했다.'),
('가양칼국수버섯매운탕', '서울 영등포구 국제금융로 78 홍우빌딩 지하 1층', '0507-1399-0438', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=f0CLSz_6LDE', 37.5208744, 126.9313093, '서울특별시', '쯔양은 이 식당의 버섯매운탕에 대해 마늘 맛이 나는 시원하고 칼칼하면서도 버섯의 풍미가 구수하게 느껴지는 국물 맛이 일품이라고 평가했습니다. 소고기는 질이 좋고 누린내 없이 쫄깃하며, 기본으로 나오는 버섯과 미나리도 푸짐하다고 언급했습니다. 특히 푹 익은 감자가 매우 맛있다고 칭찬했으며, 야채, 밥, 면사리가 무한리필이라는 점을 장점으로 꼽았습니다. 칼국수 면은 우동면보다 두꺼워 수타 우동 같은 독특한 쫄깃함이 있다고 설명했습니다. 마지막으로 남은 국물에 감자를 으깨고 잘게 다진 소고기와 밥을 넣어 직접 만든 죽을 ''쯔양표 죽''으로 소개하며, 으깬 감자와 소고기, 밥알의 조합이 환상적이라며 극찬했습니다.'),
('장수회관', '서울 동대문구 전농로16길 16', '02-2243-5678', ARRAY['고기'], 'https://www.youtube.com/watch?v=X1glIwxFfVQ', 37.5781957, 127.0582705, '서울특별시', '쯔양은 40년 전통의 한옥 스타일 식당 분위기와 서울식 불고기에 대한 기대감을 표현했습니다. 한우 불고기 10인분과 영양 돌솥밥 2인분을 주문하여 먹방을 진행했습니다. 그녀는 불고기 고기가 매우 부드럽고 국물은 짜지 않으면서도 깊은 맛이 나는 완벽한 양념이라고 극찬했습니다. 특히 요즘 찾기 힘든 서울식 불고기를 맛볼 수 있어 만족스러워했으며, 함께 나오는 당면과 겨자 맛이 나는 소스의 조화도 훌륭하다고 평가했습니다. 여러 반찬 중 깻잎쌈이 가장 맛있다고 언급했고, 버섯, 단호박, 콩이 들어간 영양 돌솥밥과 불고기를 함께 먹으며 ''미쳤다'', ''대박이다''라며 감탄사를 연발했습니다. 식사를 마친 후에도 전혀 배부르지 않다며 다음에는 삼겹살과 등심도 먹어보고 싶다고 말할 정도로 음식에 대한 높은 만족도를 보였습니다.'),
('답십리별미', '서울특별시 동대문구 답십리로48길 98 1층', '02-2248-1419', ARRAY['한식'], 'https://www.youtube.com/watch?v=vpxPTnUK1SY', 37.5683634, 127.0575594, '서울특별시', 'PD의 추천으로 방문한 곳으로, 처음에는 PD와 입맛이 달라 반신반의했지만, 모든 음식이 기대 이상으로 맛있다고 극찬했습니다. 특히 직접 갈아 만든 감자전의 바삭하고 쫄깃한 식감에 감탄했으며, 손으로 만든 만두는 속이 꽉 차고 맛이 진하다고 평가했습니다. 칼제비는 쫄깃한 면발과 수제비, 감자가 듬뿍 들어간 국물이 일품이라고 언급했으며, 비빔국수, 제육덮밥, 코다리구이 등 주문한 모든 메뉴가 양이 푸짐하고 훌륭한 맛을 자랑한다고 말했습니다. 전반적으로 모든 음식이 맛있어 매우 만족스러운 식사였다고 총평했습니다.'),
('야마타니우동', '서울 성동구 왕십리로21길 11 1층', '0507-1425-4677', ARRAY['아시안'], 'https://www.youtube.com/watch?v=zfgk125p558', 37.5613512, 127.0332651, '서울특별시', '쯔양은 100% 수제로 만든 우동면을 극찬했습니다. 면발이 매우 길고(약 75cm) 쫄깃하며, 삶는 데 15분이 걸린다고 언급했습니다. 그녀는 총 6가지 종류의 우동(카케, 카마타마, 카레, 붓카케, 쇼유, 안가케 카마고토지)과 튀김을 먹었습니다. 특히 차갑게 먹는 ''쇼유 우동''의 면발이 더욱 풍성하고 쫄깃하다며 감탄했고, 온센 타마고를 추가해 고소함을 더했습니다. 새우 튀김은 튀김 옷이 얇고 바삭하며 새우가 통통하다고 추천했습니다. 나중에 발견한 튀김 부스러기(텐카스)를 추가하면 기름진 고소함이 더해져 훨씬 맛있다고 강조했습니다. 최종적으로 다음에 방문하면 ''붓카케 우동''에 튀김 부스러기를 추가해서 먹겠다고 밝혔습니다.'),
('장수식당', '서울특별시 송파구 삼전로 95 태성빌딩', '02-415-4148', ARRAY['고기'], 'https://www.youtube.com/watch?v=6O0fYDDFJbk', 37.5070486, 127.0899231, '서울특별시', '쯔양은 김치삼겹살의 비주얼이 꽃처럼 예쁘다고 여러 번 칭찬했습니다. 맛에 대해서는 짜지 않고 깔끔하면서도 고소하며, 고기가 부드럽다고 평가했습니다. 특히 김치가 맛을 더해주고, 돼지기름에 튀긴 마늘이 별미라고 언급했습니다. 부대찌개는 소시지 맛이 풍부하고 건더기가 푸짐하며 국물이 진하고 고소하다고 말했습니다. 음식에 완전히 몰입하여 말을 잊을 정도로 맛있게 먹었으며, 소주 안주로도 훌륭할 것이라고 덧붙였습니다.'),
('빨간부산오뎅', '서울특별시 송파구 백제고분로48길 36 빨간오뎅', '02-6439-5050', ARRAY['분식'], 'https://www.youtube.com/watch?v=f4pAHt-6BJ8', 37.5104131, 127.1168325, '서울특별시', '쯔양은 과거 제천에서 먹었던 빨간 어묵이 생각나 서울에서 검색하여 방이시장의 ''빨간부산오뎅''을 찾아 방문했다. 매운 어묵 6인분, 일반 어묵 1인분, 물떡 1인분을 주문하여 총 40개의 꼬치를 먹었다. 매운 어묵에 대해 처음에는 ''맛있다''고 평가했지만, 이내 ''맛있는데 확실히 맵다''며 매운맛에 힘들어하는 모습을 보였다. 특히 제천의 어묵보다 훨씬 크고 두껍다는 점을 강조했다. 매운맛을 중화시키기 위해 일반 어묵 국물과 코코팜 음료를 마셨으며, 나중에는 일반 국물에 매운 어묵을 헹궈 먹기까지 했다. 물떡은 ''치즈 같다'', ''부드럽고 쫀득하다''며 매우 만족스러워했다. 어묵 국물은 ''너무 맛있다''며 밥을 말아 먹고 싶다고도 했다. 마지막에는 남은 어묵을 가위로 잘라 국물과 함께 어묵탕처럼 먹는 방식을 시도했고, ''이렇게 먹으니 더 맛있다''며 만족감을 표했다.'),
('꽃피다한우', '경기 광명시 소하로109번길 15 소하토피아 8층', '02-876-9800', ARRAY['고기'], 'https://www.youtube.com/watch?v=Prxzs65MhZE', 37.4473056, 126.885006, '경기도', '쯔양이 자신의 ''최애 맛집''이라고 소개한 한우 전문점이다. 총 3kg의 소고기를 주문했으며, 안심, 등심, 갈비살, 살치살, 제비추리, 토시살, 안창살 등 다양한 부위를 맛보았다. 특히 안심은 매우 부드럽고 육즙이 풍부하며, 기름기가 없어 담백하다고 평가했다. 등심은 안심보다 기름져서 더 고소한 맛이 난다고 언급했다. 쫄깃한 식감의 제비추리는 된장과 잘 어울린다고 했으며, 안창살은 결이 느껴지는 식감과 함께 깻잎과의 조화를 칭찬했다. 가장 비싼 부위인 토시살에 대해서는 식감과 육즙, 고기 향이 완벽하다고 극찬했다. 오랜 단골로서 이전에 즐겨 먹었던 살치살은 와사비를 곁들이니 고소함이 극대화된다고 말했다. 또한, 된장찌개가 너무 맛있어서 여러 번 리필했으며, 사장님이 서비스로 주신 육회와 육사시미의 신선함에 감탄하며 소주와 함께 먹고 싶다고 아쉬워했다. 전반적으로 고기의 품질이 매우 뛰어나고, 사장님이 직접 구워주는 서비스에 만족감을 표하며 촬영 내내 매우 들뜬 모습을 보였다.'),
('등마루족발연구소', '서울특별시 영등포구 선유로49길 32-1', '02-2678-4060', ARRAY['족발·보쌈'], 'https://www.youtube.com/watch?v=gbVrYovcd7g', 37.5371229, 126.8943508, '서울특별시', '쯔양은 이 식당의 대표 메뉴인 ''족발 수육'' 12인분을 주문했습니다. 이 요리는 따뜻한 해물 육수 기반의 맑은 된장국 위에 특수 제작된 나무판을 올리고, 그 위에 족발을 올려 먹는 독특한 방식입니다. 쯔양은 음식을 먹는 내내 따뜻하게 즐길 수 있다는 점을 큰 장점으로 꼽았습니다. 족발은 잡내가 전혀 없고 콜라ген 부위가 매우 쫄깃하며, 고기 자체는 마르지 않고 촉촉하다고 평가했습니다. 특히 된장국은 13가지 재료가 들어간 해물 육수로 만들어져 매우 시원하고 깔끔한 맛이라고 언급했습니다. 족발을 국물에 담가 먹으면 느끼함이 해소되고 더욱 맛있다고 말했으며, 가게에서 직접 말린 무말랭이가 쓰지 않고 달고 맛있다고 칭찬했습니다. 식사 후반부에는 남은 족발을 모두 국물에 넣어 ''족발 스튜''처럼 만들어 먹었고, 마지막에는 진하게 졸아든 국물에 칼국수 사리를 추가하여 된장 칼국수로 마무리했는데, 이 또한 별미라고 극찬했습니다.'),
('광주식당', '서울특별시 동대문구 경동시장로2길 51', '02-969-4403', ARRAY['한식'], 'https://www.youtube.com/watch?v=qdrjjcJE-KI', 37.580494, 127.0438155, '서울특별시', '이른 아침부터 방문할 정도로 인기가 많은 맛집으로, 다양한 한식 메뉴를 주문했습니다. 음식들이 전반적으로 조미료 맛이 강하지 않고 ''집밥''처럼 깊고 맛있는 맛이라고 평가했습니다. 특히 서비스로 나온 고등어구이와 메인 메뉴인 청국장을 ''시골 할머니가 해준 맛''에 비유하며 극찬했습니다. 양은냄비밥의 쫀득한 식감과 구수한 누룽지도 칭찬했으며, 며칠간 없던 입맛이 돌아올 정도로 만족스러운 식사였다고 밝혔습니다.'),
('나래궁', '전북 고창군 고창읍 동리로 41', '063-561-3356', ARRAY['중식'], 'https://www.youtube.com/watch?v=MnLGiP3e714', 35.4332499, 126.696791, '전라북도', '쯔양은 이 식당의 여러 메뉴를 맛보고 상세한 평가를 남겼습니다. 시그니처 메뉴인 ''비빔 짬짜면''에 대해서는 짜장과 짬뽕을 섞어 먹는 새로운 맛이라고 평가하며, 상상과 달리 이상하지 않고 무척 맛있다고 감탄했습니다. 특히 불맛이 느껴지는 매콤한 짜장 맛과 부드러운 해산물이 조화롭다고 칭찬했습니다. ''탕수육''은 찹쌀 탕수육인 듯하며, 튀김옷이 매우 바삭해서 ''미쳤다''고 표현할 정도로 극찬했습니다. 소스를 부어 먹는 것보다 찍어 먹는 것이 더 맛있다고 추천했습니다. ''짜장면''은 양이 매우 푸짐한 대왕 사이즈이며, 옛날 짜장면처럼 진한 춘장 맛과 감칠맛이 풍부하다고 평가했습니다. 마지막으로 ''차돌박이 짬뽕''은 새싹보리를 넣어 만든 초록빛의 특이한 면을 사용하며, 국물에서 소뼈 육수처럼 진하고 그윽한 훈연향이 나서 아주 맛있다고 말했습니다. 쯔양은 전체적으로 음식 맛에 크게 만족하며, 특히 짬짜면은 다시 먹고 싶은 맛이라고 여러 번 강조했습니다.'),
('중화호반닭갈비막국수 본점', '서울 중랑구 봉화산로 20 1층', '02-439-1656', ARRAY['한식'], 'https://www.youtube.com/watch?v=xHruMcbr-Wg', 37.6014264, 127.0763693, '서울특별시', '쯔양은 옛날식 철판 닭갈비가 먹고 싶어 중화동에 위치한 20년 된 노포를 방문했다. 맵기 2단계(신라면보다 덜 매운맛)로 닭갈비 5인분과 닭목살 3인분을 주문했다. 18인치에 달하는 거대한 철판과 다른 곳보다 1.5배 많은 양에 감탄했다. 특히 닭목살은 뼈 오도독뼈를 먹는 것처럼 쫀득하고 맛있다고 평가했다. 이후 우동사리(필수), 치즈를 추가했으며, 마지막으로 들기름으로 볶은 볶음밥은 유난히 쫀득하고 맛있다며 극찬했다. 함께 나온 동치미는 슴슴해서 짭짤한 닭갈비와 잘 어울린다고 언급했다.'),
('보리올', '전라남도 영광군 영광읍 옥당로 179 영광농업인회관 1층', '061-351-5250', ARRAY['한식'], 'https://www.youtube.com/watch?v=UpeQmYJCpMQ', 35.2777435, 126.5000393, '전라남도', '쯔양은 전남 영광의 특산품인 보리로 만든 다양한 요리를 맛보고 전반적으로 매우 긍정적인 평가를 했습니다. 특히 보리 제품 특유의 식감에 대해 자주 언급했습니다. - **보리국수(비빔/온)**: 밀가루 국수보다 쫄깃하고 메밀국수보다 부드러워 두 가지의 장점만 모은 것 같다고 평가했으며, 100% 보리로 만들어 소화가 잘된다는 점을 언급하며 매우 마음에 들어 했습니다. - **보리떡볶이**: 쌀떡과 달리 아삭하고 쫄깃한 식감이 독특하고 정말 좋다고 평가했습니다. - **구워먹는 치즈 및 치즈스틱**: 매우 고소하고 맛있다고 칭찬하며, 특히 캠핑 요리로 좋을 것 같다고 추천했습니다. - **보리핫도그**: 소시지의 식감과 맛이 좋으며, 떡볶이 소스에 찍어 먹는 조합을 즐겼습니다. - **보리비빔밥과 보리집장**: 보리밥 자체를 좋아하며, 건무가 들어간 특제 집장과 참기름을 넣어 비벼 먹으며 맛있다고 평가했습니다. - **보리식혜**: 처음에는 일반 식혜 맛이지만 끝 맛에서 보리의 구수한 맛이 느껴져 색다르고 맛있다고 했습니다. - **기타 디저트**: 보리로 만든 빵, 요거트, 마들렌, 도넛 등 다양한 디저트를 맛보며 맛있고 건강한 간식이라고 평가했습니다. 전체적으로 모든 음식이 맛있고 건강에도 좋다며, 해당 제품들이 모두 밀키트 형태로 온라인 ''보리올'' 사이트에서 구매 가능하다는 점을 강조했습니다.'),
('모꼬지에', '서울 송파구 송파대로36길 5-13 지하', '02-424-6150', ARRAY['분식'], 'https://www.youtube.com/watch?v=57ctQLkl1ts', 37.5004684, 127.1123215, '서울특별시', '쯔양은 ''모꼬지에''를 서울 3대 즉석떡볶이 맛집 중 마지막으로 방문한 곳으로 소개했습니다. 대표 메뉴인 즉석떡볶이는 짜장이 들어갔음에도 텁텁하지 않고 깔끔한 국물 맛이 일품이며, 평소 쌀떡을 선호함에도 불구하고 이곳의 밀떡은 매우 부드럽고 말캉해서 맛있다고 평가했습니다. 단골들만 안다는 ''순두부라면''은 익숙하면서도 추억을 떠올리게 하는 분식 맛이라고 설명했고, ''순두부쫄면'' 또한 밥과 함께 비벼 먹으며 맛있다고 감탄했습니다. ''비빔만두''의 양념과 ''튀김''의 바삭함도 칭찬했습니다. 식사 후에는 남은 떡볶이 국물에 치즈를 듬뿍 넣은 볶음밥을 먹으며 ''대박''을 외쳤고, 마지막으로 ''딸기빙수''를 먹으며 매운 입맛을 초기화시키는 완벽한 마무리라고 극찬했습니다. 특히 옛날 방식으로 얼음을 갈아 만든 빙수가 셔벗처럼 부드러워 떡볶이를 먹은 후 반드시 먹어야 할 메뉴로 강력 추천했습니다.'),
('남영탉', '서울 용산구 한강대로80길 12 1층', '070-8733-5949', ARRAY['치킨'], 'https://www.youtube.com/watch?v=BubHdc2NayQ', 37.5425398, 126.9734774, '서울특별시', '쯔양은 이곳의 모든 메뉴를 주문하여 먹어보았습니다. 오리지널 통닭인 ''남영탉''은 튀김옷이 없어 담백하고, 어느 소스와도 잘 어울린다고 평가했습니다. 특히 간장 베이스의 소스와의 조합을 추천했습니다. ''오리엔탈 치킨''은 마라 향이 강하지 않아 마라를 잘 못 먹는 사람도 즐길 수 있을 것이라고 말했습니다. ''웨스턴 치킨''은 참나물과 바질로 만든 소스와 함께 제공되며, 처음에는 채소에 대한 걱정이 있었지만 먹어본 후 맛있다고 평가했습니다. 닭 무릎 연골 튀김은 부드러운 식감이 깐풍기나 닭강정 같아 맛있다고 감탄했으며, 닭 염통 볶음, 멕시코 스타일의 ''뼨킹 치킨'', 마라 비빔면 등 다양한 사이드 메뉴도 모두 훌륭하다고 평가했습니다. 특히 컵라면을 이용한 ''탉개장''에서는 라오간마 소스의 맛을 정확히 맞추며, 매우 맛있다는 반응을 보였습니다.'),
('우리나라 본점', '경기 의정부시 동일로128번길 11', '031-876-6999', ARRAY['한식'], 'https://www.youtube.com/watch?v=BFIw0bXtMq0', 37.7006148, 127.055876, '경기도', '쯔양이 자신의 ''인생 1등 국밥 맛집''이라고 소개하며, 20살 때부터 다닌 단골집이라고 밝혔습니다. 대표 메뉴인 빨간 국밥(우리국밥)은 국물이 매우 진하고 중독성 있는 맛이며, 간이 세다고 느껴지면 육수를 추가해서 먹는 것을 추천했습니다. 내용물인 우거지를 잘라 먹으면 국물이 잘 넘어간다고 자신만의 팁을 공유하기도 했습니다. 처음 먹어본 갈비탕은 진한 버섯 수프 같은 맛이라고 평가했고, 냉면은 전문점만큼 맛있다고 칭찬했습니다. 함께 주문한 완자는 느끼하지 않고 담백해서 다른 메뉴와 잘 어울린다고 언급했습니다. 쯔양은 여러 국밥집을 다녀봐도 결국 이 집으로 돌아오게 된다며, 이곳만의 독보적인 맛이 있다고 극찬했습니다.'),
('요거트월드 하양점', '경북 경산시 하양읍 대학로305길 51-2 2층', '0508-8189-1519', ARRAY['카페·디저트'], 'https://www.youtube.com/watch?v=RafmGHmD8NM', 35.9108417, 128.8168658, '경상북도', '쯔양은 요거트 아이스크림의 베이스(플레인, 딸기 등)와 다양한 토핑을 직접 선택해 조합할 수 있다는 점을 가장 큰 장점으로 꼽았습니다. 딸기 요거트는 매우 상큼하고 맛있다고 평가했으며, 오레오와 초콜릿 조합은 누구나 아는 맛있는 조합이라고 언급했습니다. 또한 망고, 파인애플 등 열대과일 토핑과 벌집 토핑의 조합도 훌륭하다고 칭찬했습니다. 요거트 아이스크림이라 많이 먹어도 부담이 적고, 상큼한 맛과 달콤한 토핑의 조화가 좋다고 전반적으로 긍정적인 평가를 내렸습니다.'),
('고든 램지 스트리트 피자 서울숲점', '서울 성동구 왕십리로 83-21 디타워 포레스트 B1', '+82 2-6080-7799', ARRAY['피자'], 'https://www.youtube.com/watch?v=O_hj9Ge-Fdk', 37.5441546, 127.0433577, '서울특별시', '쯔양은 고든 램지 스트리트 피자를 방문하여 무한리필로 제공되는 다양한 종류의 피자와 사이드 메뉴를 맛보았습니다. 이곳은 정해진 가격(29,800원)에 피자를 무제한으로 즐길 수 있는 곳으로, 버거 매장에 비해 가성비가 좋다고 평가했습니다 . 피자에 대한 평가는 다음과 같습니다: - **클래식 마르게리타**: 느끼하지 않고 담백하며 향이 매우 좋다고 평가했습니다 . - **콘 & 초리조**: 맛있고 독특한 향신료 향이 강하지 않고 향기롭다고 언급했습니다 . - **햄혹 & 파인애플**: 파인애플 피자를 좋아한다고 밝히며, 소스가 상큼하고 약간 신맛이 난다고 했습니다 . - **페퍼로니**: 가장 맛있는 피자로 꼽았습니다 . - **탄두리 할루미**: 향신료 맛이 강하고 이국적인 피자라고 설명했습니다 . - **기타**: 펜넬 소시지 피자는 미트볼이 생각나는 익숙한 맛이라고 했고 , 라구 피자는 너무 매운 음식을 먹은 직후라 맛을 제대로 느끼기 어려웠다고 합니다 . 전반적으로 피자들이 얇고 가벼워 일반 피자보다 먹기 편하다고 총평했습니다 . 사이드 메뉴 중 ''J.F.C 더티 프라이''는 닭고기가 부드럽고 맛있지만 소스가 매우 맵다고 했고 , 윙 중에서는 ''스위트 칠리 김치''는 김치 맛이 거의 나지 않는다고 했으며, ''초콜릿 바비큐''는 호불호가 갈릴 맛, ''스트리트 핫 소스''는 너무 매워 먹기 힘들었다고 합니다 . 또한, 영상에서 고든 램지를 직접 만나 영광스럽고 신기했다고 소감을 밝혔습니다 .'),
('대승곱창', '서울 마포구 동교로38길 4 2층', '0507-1472-1503', ARRAY['고기'], 'https://www.youtube.com/watch?v=6KDmeK_6qsI', 37.561646, 126.9245759, '서울특별시', '쯔양은 연남동에 위치한 ''대승곱창''에서 대표 메뉴인 한우 대창 4kg과 곱창전골을 먹었습니다. 그녀는 대창의 맛을 극찬하며, 기름기가 많아 느끼할 수 있는 부위임에도 불구하고 이곳의 대창은 몽글몽글하고 고소한 맛이 일품이라고 평가했습니다. 특히, 함께 나오는 파김치를 구워 대창과 곁들여 먹는 조합을 최고로 꼽았습니다. 식당에서 기본으로 제공하는 육회, 천엽, 순두부찌개 등의 서비스 메뉴에 대해서도 만족감을 표현했으며, 식사 마무리로 볶음밥까지 남김없이 먹었습니다. 다만 볶음밥은 개인적인 입맛에는 다소 짜게 느껴졌다고 언급했습니다.'),
('대선칼국수', '대전 서구 둔산로137번길 30', '042-488-8252', ARRAY['한식'], 'https://www.youtube.com/watch?v=0dldcmnMR6s', 36.3525614, 127.3894993, '대전광역시', '쯔양은 수육, 칼국수, 오삼두루치기, 비빔국수를 맛보았습니다. 수육은 부드럽고, 비계와 살코기의 비율이 완벽하며, 양념이 잘 배어 있다고 평가했습니다. 칼국수는 면이 얇고 국물이 맛있으며 수육과 함께 먹으니 더 맛있다고 했습니다. 오삼두루치기는 약간 매우면서 맛있고, 안에 들어있는 오징어가 크고 삼겹살이 쫄깃하다고 언급했습니다. 비빔국수는 면이 두꺼워 식감이 좋고, 새콤달콤한 양념이 완벽해서 이번에는 국물 있는 칼국수보다 비빔국수가 더 맛있다고 했습니다. 특히 두루치기를 칼국수 국물에 넣어 ''짬뽕 같은 맛''이 난다며 새로운 조합을 즐겼습니다. 전반적으로 대전이 칼국수와 두루치기로 유명한 명성을 확인시켜주는 맛집이라고 극찬했습니다.'),
('대림국수 성수점', '서울 성동구 연무장7가길 5-1 1층', '0507-1398-0433', ARRAY['한식'], 'https://www.youtube.com/watch?v=1xtDsmbE91k', 37.5431578, 127.0551096, '서울특별시', '쯔양은 대림국수의 국수 메뉴에 대해 면발이 상상할 수 없을 정도로 쫄깃하며 입안에서 춤추는 것 같다고 극찬했습니다. 여러 국수 중 ''빨간면''을 가장 맛있었던 메뉴로 꼽으며, 국물이 진하고 매콤한 맛이 특징이라고 설명했습니다. 또한, 따뜻한 ''온면''은 국물에 꼬치가 들어간 아이디어가 좋다고 평했고, 차가운 ''냉면''은 상쾌한 맛이 일품이라고 언급했습니다. 소 대창, 닭 껍질, 무릎 연골, 닭 날개 등 다양한 꼬치구이도 맛보았으며, 전반적으로 음식이 매우 맛있고 독특해 긴 웨이팅을 할 만한 가치가 있다고 평가했습니다.'),
('옛집국수', '서울 용산구 한강대로62길 26', '02-794-8364', ARRAY['한식'], 'https://www.youtube.com/watch?v=-RI5PUiPr3g', 37.5337992, 126.9733319, '서울특별시', '쯔양은 이 식당의 메뉴 전체(멸치국수, 비빔국수, 콩국수, 김밥, 칼국수, 수제비, 떡만두국)를 주문하여 먹었습니다. 음식의 맛이 자극적이거나 특별하기보다는 할머니가 해준 것 같은 집밥의 맛이라고 총평했습니다. 양이 푸짐하고 가격이 저렴한 점을 칭찬했으며, 특히 ''수제비''는 할머니가 만들어주던 맛과 매우 흡사하다며 가장 마음에 드는 메뉴로 꼽았습니다. 김밥 또한 소박한 재료로 어린 시절을 떠올리게 하는 맛이라고 평가했습니다. 전반적으로 매우 만족스러운 식사였다고 밝혔습니다.'),
('잠원떡볶이', '서울 서초구 잠원로4길 45', '02-591-4108', ARRAY['분식'], 'https://www.youtube.com/watch?v=OvsiOSWhDuk', 37.5134298, 127.0113962, '서울특별시', '쯔양은 떡볶이, 모듬튀김, 순대, 어묵, 김밥 등 다양한 메뉴를 주문했습니다. 떡볶이는 밀가루 떡을 사용하며, 국물은 약간 달고 매우면서도 쓴맛 없이 감칠맛이 풍부하다고 평가했습니다. 떡은 두툼하고 매우 쫄깃하며, 옛날식과 요즘 스타일의 중간 맛이라고 언급했습니다. 튀김은 겉은 바삭하고 속은 부드러운 빵 같다고 표현했으며, 순대와 간은 소금에 찍어 먹는 것이 더 맛있다고 추천했습니다. 튀긴 햄은 아이들이 좋아할 만한 맛있는 핫도그 맛이라고 했고, 어묵 국물은 떡볶이와 함께 먹으면 몸을 따뜻하게 해준다고 좋아했습니다. 특히 강남에 위치한 것치고는 떡볶이가 4,000원으로 매우 저렴하여 가성비가 좋다고 평가했으며, 전반적으로 음식이 달달하면서도 맛있다고 총평했습니다.'),
('찬양집', '서울 종로구 돈화문로11다길 5', '02-743-1384', ARRAY['한식'], 'https://www.youtube.com/watch?v=iRcaePXQRto', 37.5728296, 126.9902706, '서울특별시', '쯔양은 57년 전통의 해물칼국수와 만두를 주문했습니다. 칼국수 국물은 진하고 해산물 맛이 풍부하며, 후추를 더하면 훨씬 상쾌한 맛이 난다고 평가했습니다. 면발은 매우 쫄깃하고 떡처럼 느껴질 정도로 탄력이 있다고 묘사했습니다. 양이 매우 많아 가성비가 좋다고도 언급했습니다. 함께 나온 겉절이와 익은 김치 모두 맛있다고 칭찬했으며, 특히 익은 김치를 칼국수와 함께 먹는 것을 선호했습니다. 손만두 중에서는 김치만두가 더 맛있다고 평가했으며, 고기만두는 전통적이지만 다소 밋밋한 맛이라고 했습니다. 2017년부터 2019년까지 미쉐린 가이드에 선정된 점을 언급하며, 저렴한 국수 가게가 선정된 것이 인상 깊다고 말했습니다.'),
('텍사스 데 브라질 압구정점', '서울 강남구 논현로 854 안다즈호텔 지하1층', '02-549-2266', ARRAY['양식'], 'https://www.youtube.com/watch?v=JjxtTeogYI4', 37.5253216, 127.0288651, '서울특별시', '압구정동에 위치한 브라질 전통 스테이크 ''슈하스코'' 무한리필 전문점으로, 15종의 고기를 맛볼 수 있는 디너 메뉴를 즐기기 위해 방문함. 쯔양은 자리에 앉으면 서버들이 계속해서 고기를 가져다주는 시스템에 만족감을 표했으며, 특히 ''피카냐(Picanha)''와 ''안심(Tenderloin)''을 극찬함. 안심은 매우 부드러워 스테이크 전문점 고기 같다고 평했으며, 시그니처 메뉴인 피카냐는 육즙이 풍부하고 냄새부터 좋다고 언급함. 그 외에도 삼겹살, 갈빗살, 양갈비 등 다양한 부위를 맛보며 전반적으로 모든 고기가 맛있다고 평가함. 특히 저녁 메뉴에 나오는 안심, 피카냐, 양갈비는 꼭 먹어봐야 할 메뉴로 추천했으며, 주말 방문 시 예약은 필수라고 강조함. 마지막에는 너무 많이 먹어 미안함을 표할 정도로 만족스러운 식사였음을 보여줌.'),
('인성돼지갈비', '서울 중구 창경궁로5다길 13', '02-2272-1766', ARRAY['고기'], 'https://www.youtube.com/watch?v=fmat4NG1X7E', 37.5675331, 126.9964091, '서울특별시', '쯔양은 35년 전통의 노포 식당으로, 제육불고기를 맛본 후 ''신기록''이라며 극찬했습니다. 일반적인 제육볶음과 달리 국물이 자작한 불고기 스타일이며, 양념이 자극적이지 않으면서도 깊은 감칠맛이 특징이라고 평했습니다. 특히 고기가 매우 부드럽고 잡내가 전혀 나지 않는 점을 높이 평가하며, 오랜 내공이 느껴지는 맛이라고 감탄했습니다. 밥에 비벼 먹거나 쌈을 싸 먹는 것을 추천했으며, 서비스로 나온 껍데기 또한 쫄깃하고 고소하다고 칭찬했습니다. 쯔양은 숨겨진 골목 안에서 보물 같은 맛집을 찾았다며 전반적으로 매우 만족스러운 반응을 보였습니다.'),
('환희분식', '서울 송파구 올림픽로35길 112 장미B상가 지하1층 45호', '02-414-8307', ARRAY['분식'], 'https://www.youtube.com/watch?v=hP-t4f8te-I', 37.5178933, 127.1018273, '서울특별시', '쯔양은 30년 전통의 맛집으로 알려진 환희분식을 방문하여, 이곳의 시그니처 메뉴인 쫄라 4종(일반, 짜장, 카레, 매운맛)과 치즈볶음밥을 모두 주문했습니다. 쫄라는 쫄면과 라면이 함께 들어간 독특한 메뉴로, 일반 맛은 달달하고 살짝 매콤한 라볶이 같다고 평가했습니다. 짜장 맛은 어린 시절 학교 앞에서 먹던 추억의 맛이라고 언급했으며, 카레 맛은 향이 좋고 감칠맛이 있다고 했습니다. 매운맛은 신라면과 불닭볶음면의 중간 정도 맵기이지만 단맛이 적고 매운맛이 강해 가장 맛있다고 평가했습니다. 치즈를 추가한 볶음밥 역시 매우 맛있다고 추천하며, 전반적으로 모든 메뉴에 높은 만족감을 보였습니다.'),
('한양화로 삼성동본점', '서울 강남구 봉은사로 632', '02-563-8592', ARRAY['고기'], 'https://www.youtube.com/watch?v=6FlxXNxxwcE', 37.5147392, 127.0645427, '서울특별시', '쯔양은 구독자들과 함께 ''한맥'' 맥주가 후원하는 ''부드러운 회식'' 컨셉으로 해당 음식점을 방문했습니다. 이곳은 소고기 오마카세 전문점으로, 쯔양은 가장 비싼 소고기 메뉴 15인분(약 5kg)을 주문했습니다. 그녀는 함께 마신 한맥 맥주에 대해 "지금까지 먹어본 맥주 중 가장 부드럽다", "뒷맛이 매우 깔끔하다"고 반복해서 칭찬했습니다. 음식에 대해서는 트러플이 곁들여진 부채살, 치미추리 소스를 올린 안심 스테이크를 맛본 뒤 "정말 부드럽다", "살면서 먹어본 스테이크 중 최고"라고 극찬했습니다. 이 외에도 보리밥 된장 잠발라야, 육회 등을 먹으며 맛있다는 평가를 남겼습니다. 쯔양은 딱딱한 회식이 아닌, 좋아하는 사람들과 맛있는 음식, 부드러운 맥주를 즐기는 편안하고 즐거운 식사였다고 소감을 밝혔습니다.'),
('Mott 32 Seoul', '서울특별시 서초구 신반포로 176 센트럴시티 2F', '02-6282-0320', ARRAY['중식'], 'https://www.youtube.com/watch?v=vmhRdQ_9Cic', 37.5038952, 127.004752, '서울특별시', '쯔양은 처음 맛보는 북경오리에 대해 전혀 느끼하지 않고 잘 익혀져 누구나 좋아할 맛이라고 평가했습니다. 특히 오리 껍질은 과자처럼 바삭하고 고소하며 설탕에 찍어 먹는 맛이 일품이라고 극찬했습니다. 딤섬 중에서는 새우와 관자가 들어간 ''해산물 샤오롱바오''를 인생 최고의 샤오롱바오로 꼽았으며, 트러플 향이 강한 ''블랙 트러플 메추리알 만두''도 매우 맛있다고 언급했습니다. 오리고기로 만든 볶음밥은 고슬고슬하고 맛있다고 칭찬했으며, 디저트로 먹은 에그타르트는 속이 푸딩처럼 부드러워 인상적이었다고 말했습니다. 전반적으로 고급스러운 분위기에서 즐기는 특별한 미식 경험이었으며, 기념일 같은 특별한 날에 방문하기 좋은 곳이라고 추천했습니다.'),
('최우영스시', '서울 구로구 디지털로 288 대륭포스트타워1차 지하1층', '0507-1356-3430', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=cUb0w-1JLdk', 37.4835696, 126.8955028, '서울특별시', '쯔양은 모든 접시가 2,300원이라는 저렴한 가격임에도 불구하고 초밥의 크기가 일반 초밥의 두 배에 달할 정도로 매우 크고 두툼하여 가성비가 뛰어나다고 극찬했습니다. 특히 소고기 등심, 참치, 관자, 장어 초밥이 맛있다고 언급했으며, 갓 구운 장어는 훈연향이 일품이라고 평가했습니다. 아귀간(안키모) 초밥은 참치마요보다 더 깊은 풍미를, 성게알(우니)은店家만의 양념으로 상쾌한 맛을 낸다고 설명했습니다. 또한, 단골들만 아는 메뉴로 보이는 2,300원짜리 전복죽은 매우 진하고 맛있어서 이것 때문에라도 다시 와야겠다고 만족감을 표했습니다. 최종적으로 100접시를 먹으며 음식의 맛과 가격 모두에 대해 높은 만족도를 보였습니다.'),
('성화라멘&샤브샤브', '서울 마포구 와우산로29바길 11', '02-2296-4310', ARRAY['아시안'], 'https://www.youtube.com/watch?v=9c-UpYxc0Rs', 37.5558577, 126.9261933, '서울특별시', '쯔양은 84년 전통의 일본 라멘집 ''호프켄 혼포''의 맛을 재현한 곳이라며 기대감을 보였습니다. 돈코츠, 쇼유, 시오, 미소 라멘 등 모든 종류의 라멘과 야키 교자, 차슈를 주문했습니다. - **돈코츠 라멘**: 국물이 진하면서도 깔끔한 맛이 특징이며, 기존에 알던 돈코츠와는 다른 매력이 있다고 평했습니다. 쯔양의 원픽으로 꼽혔습니다. - **시오 라멘**: 새우젓으로 맛을 내 국물이 매우 깔끔하며, 김치와 잘 어울린다고 언급했습니다. - **미소 라멘**: 한국의 된장찌개와 비슷한 구수한 맛이 난다고 했습니다. - **쇼유 라멘**: 간장 베이스의 맛이 확실히 느껴진다고 평가했습니다. - **사이드 메뉴**: 직접 만든 야키 교자와 쫀득한 식감의 차슈 모두 훌륭하다고 칭찬했으며, 특히 파무침 차슈는 술안주로 좋다고 추천했습니다.'),
('인생아구찜 파주운정점', '경기도 파주시 청암로17번길 61 (목동동) 108,109호', '031-941-2205', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=vmyY2q-eTuk', 37.7283285, 126.7345093, '경기도', '쯔양은 이곳에서 해물찜(1단계), 아귀찜(3단계), 알찜(5단계) 세 가지 메뉴를 주문하여 리뷰했습니다. 해물찜(1단계)은 소스가 훌륭하고 문어가 매우 부드럽다고 평가하며, 1단계임에도 약간의 매운맛이 느껴진다고 언급했습니다. 아귀찜(3단계)에 대해서는 소스가 중독성 있고 아귀의 식감이 부드러우면서도 쫄깃하여 모두가 좋아할 맛이라고 칭찬했으며, 3단계가 자신에게 가장 완벽한 맵기라고 말했습니다. 5단계 알찜은 매우 맵지만 맛있고 스트레스 해소에 좋다고 평가했으며, ''소''자임에도 불구하고 콩나물보다 알과 내용물이 훨씬 많은 푸짐한 양에 감탄했습니다. 전반적으로 모든 메뉴의 소스가 매우 훌륭하고, 해산물이 신선하며, 가격 대비 양이 매우 푸짐하다고 총평했습니다. 또한 맵기 선택 팁으로 신라면이나 불닭볶음면을 즐기는 사람에게는 3단계를, 매운맛 마니아에게는 5단계를 추천했습니다.'),
('솥뚜껑삼겹살집', '서울특별시 동대문구 이문로 202', '02-969-1331', ARRAY['고기'], 'https://www.youtube.com/watch?v=gLsGulboot4', 37.6045628, 127.0622135, '서울특별시', '쯔양은 솥뚜껑 불판이 약한 불에서는 음식을 따뜻하게 유지해주고, 강한 불에서는 빨리 익혀주어 좋다고 평가했다. 삼겹살은 지방의 식감이 훌륭하고 고소하며, 쌈장이나 구운 김치, 깻잎과 함께 먹는 조합을 극찬했다. 항정살은 쫄깃한 식감이 좋고 소금이나 무와 잘 어울리며, 통으로 구우면 육즙이 더욱 풍부해진다고 언급했다. 평소 지방이 많은 부위를 선호해 목살을 즐기지 않았으나, 이 식당의 목살은 쫄깃하면서도 부드럽고 지방 맛이 훌륭하다고 칭찬했다. 함께 나온 부드러운 계란찜과 고기 기름에 볶은 김치, 콩나물도 맛있게 먹었다. 대기 손님이 많아 이 식당의 명물인 볶음밥을 먹지 못하는 것에 대해 큰 아쉬움을 표했다.'),
('스텔라떡볶이 경기안양점', '경기도 안양시 만안구 태평로52번길 47, 1층 101-1호', '031-447-2580', ARRAY['분식'], 'https://www.youtube.com/watch?v=Ew-PClo0nek', 37.3963921, 126.9315828, '경기도', '쯔양은 스텔라떡볶이가 별 모양의 튀김을 찍어 먹는 독특한 컨셉이라고 소개했습니다. 매일 아침 새 기름을 사용해 튀김이 매우 깔끔하고 바삭하다고 칭찬했습니다. 차돌, 로제, 체다치즈, 카레 등 다양한 떡볶이를 맛보았는데, 특히 차돌 떡볶이의 부드러운 떡과 맛있는 소스를 긍정적으로 평가했으며, 튀김과 떡볶이의 조합이 새롭고 식감이 좋다고 언급했습니다. 여러 맛의 별 튀김 중에서는 예상외로 카레맛 별 튀김이 가장 맛있다고 꼽았습니다. 튀김류는 시간이 지나도 바삭함이 유지되는 점을 장점으로 들었고, 전반적으로 다른 떡볶이 가게들과는 다른 특별함이 있다고 평가했습니다.'),
('무탄 압구정본점', '서울 강남구 논현로176길 22 1층', '0507-1313-9339', ARRAY['중식'], 'https://www.youtube.com/watch?v=ygU3HOOt0_c', 37.5273088, 127.0303297, '서울특별시', '쯔양은 해당 식당을 ''먹어본 중식 중 최고 중 하나''라고 극찬하며, 고급 레스토랑 같은 특별한 경험이었다고 평가했습니다. 특히 대표 메뉴인 ''스테이크 트러플 짜장면''에 대해 트러플 오일이 아닌 진짜 트러플이 올라가 있어 풍미가 고급스럽고, 스테이크가 입에서 녹을 정도로 부드럽다고 감탄했습니다. ''마카롱 멘보샤''는 거대한 크기와 새우 살로 꽉 찬 내용물을 칭찬했고, ''고추 유린기''의 튀김은 바삭함이 살아있다고 언급했습니다. ''차돌짬뽕''은 국물이 사골 국물처럼 진하고 맛있다고 했으며, ''탄탄면''은 땅콩 소스 같은 진한 국물과 중독성 있는 맛이 특징이라고 설명했습니다. 전반적으로 음식의 양이 매우 푸짐해서(1인분에 1.5인분 수준) 가격이 비싸게 느껴지지 않았다고 총평했습니다.'),
('계포동', '서울특별시 동대문구 천호대로85길 40 1층 계포동 숯불닭갈비', '02-2244-9958', ARRAY['고기'], 'https://www.youtube.com/watch?v=zGeoTSNGJXY', 37.5635892, 127.0670951, '서울특별시', '쯔양은 소금 닭목살, 양념 닭목살, 소금 닭갈비, 양념 닭갈비를 모두 주문하여 맛보았습니다. 특히 소금 닭목살의 식감에 대해 ''오돌뼈 같다'', ''부드러우면서도 오독오독 탱글탱글하다''며 극찬했고, 닭고기 같지 않은 특별한 식감이라고 평가했습니다. 닭갈비는 소금구이보다 양념구이가 더 맛있다고 했으며, 양념 닭목살은 항정살 같은 식감을 좋아한다면 추천한다고 말했습니다. 치즈 퐁듀와의 조합이 훌륭하고, 와사비를 곁들이는 것도 별미라고 언급했습니다. 전반적으로 ''닭고기를 별로 안 좋아하는데도 불구하고 최고의 맛집 중 하나''라고 평가하며 만족감을 드러냈습니다.'),
('버거앤프라이즈 신내시티프라디움점', '서울 중랑구 용마산로 670 시티원스퀘어 C동 101호', '010-6657-8347', ARRAY['패스트푸드'], 'https://www.youtube.com/watch?v=PtrjtvOD7Lw', 37.6105081, 127.1024052, '서울특별시', '쯔양은 해당 영상이 유료 광고임을 밝히고 ''버거앤프라이즈''의 여러 메뉴를 맛보았습니다. 전반적으로 매일 아침 직접 만드는 수제 패티에 대해 높이 평가하며, 육즙이 풍부하고 부드러우면서도 건강한 느낌과 감칠맛이 공존한다고 총평했습니다. 특히 신메뉴인 트러플 머쉬룸 버거는 버섯과 크림이 풍부하고 트러플 향이 조화로워 맛있다고 극찬했습니다. 또한, 베이컨 더블 치즈버거, 불고기 버거, 시그니처 싱글 버거, 몬스터 치킨 버거, 슈림프 버거 등 다양한 버거를 먹으며 각각의 개성이 뚜렷하고 맛이 다르다고 언급했습니다. 사이드 메뉴 중에서는 아보카도 튀김이 특히 맛있다고 평가했으며, 코코넛 쉬림프와 크림 소스 감자튀김 등도 긍정적으로 리뷰했습니다. 오랜만에 정말 맛있는 수제버거를 먹었다며 만족감을 표현하며 식사를 마무리했습니다.'),
('오봉집 천호점', '서울 강동구 천호대로157길 18 2층', '02-477-5585', ARRAY['한식'], 'https://www.youtube.com/watch?v=o-S8yh1YxQM', 37.5385014, 127.1275006, '서울특별시', '쯔양은 이곳이 ''가성비가 좋다''고 평가했으며, 특히 직화 낙지볶음의 강렬한 ''불맛''과 ''불향''을 여러 차례 칭찬했습니다. 낙지볶음은 맵지 않은 맛, 중간 맛, 매운 맛 세 가지를 모두 맛보았는데, 중간 맛이 가장 완벽한 맵기라고 언급했습니다. 또한, 낙지가 크고 살이 통통하여 가성비가 좋다고 느꼈습니다. 해물 칼국수는 양이 매우 푸짐하며, 국물이 맛있고 매콤한 낙지볶음과 잘 어울린다고 평가했습니다. 보쌈 역시 맛있지만, 직화 낙지볶음의 인상이 너무 강해 상대적으로 덜 주목받았다고 합니다. 전체적으로 추석의 느끼한 음식을 먹은 뒤에 먹기 좋은 매콤한 음식이라고 추천했습니다.'),
('스시도쿠 왕십리본점', '서울 성동구 무학로2길 29 1층', '0507-1320-3255', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=rRAEFB6CiD0', 37.56349, 127.033132, '서울특별시', '쯔양은 영상에서 운동선수 6명과 초밥 300개 먹기 대결을 펼칩니다. 쯔양은 압도적인 속도와 양으로 초밥을 먹으며 대결에서 가뿐히 승리하는 모습을 보여줍니다. 특히 다양한 종류의 초밥을 맛보며 즐거워하는 반응을 보이지만, 대결에 집중하는 모습이 주로 담겨 각 초밥에 대한 구체적인 맛 평가는 상세히 나타나지 않습니다. 대결 후에도 더 먹을 수 있었다고 말하며 대식가로서의 면모를 강조합니다.'),
('진미떡볶이', '서울특별시 중구 다산로38길 60', '02-2252-5889', ARRAY['분식'], 'https://www.youtube.com/watch?v=n-Oq-dLWnw8', 37.562178, 127.0188685, '서울특별시', '쯔양은 영상에서 자신이 먹어본 짜장 떡볶이 중에 최고라고 평가했습니다. 일반적인 짜장 맛이 아니라, 매콤한 떡볶이에 짜장 맛이 강하게 더해진 다채로운 맛이라고 설명했습니다. 특히 쌀로 만든 떡의 쫀득하고 찰진 식감을 극찬했으며, 어묵 또한 밀가루 맛이 나지 않고 쫄깃하다고 언급했습니다. 함께 먹은 김밥은 고소하고 참기름으로 잘 양념되어 있으며, 순대와 오징어튀김(깔라마리)도 부드럽고 맛있다고 평가했습니다. 전반적으로 음식의 조화와 식감에 대해 매우 만족스러운 반응을 보였습니다.'),
('뉴타운 생양고기', '서울 중구 난계로 205 2층', '02-2231-7712', ARRAY['고기'], 'https://www.youtube.com/watch?v=iBMCHcQRT2M', 37.5698594, 127.0232296, '서울특별시', '쯔양은 온라인에서 좋은 후기를 보고 황학동에 위치한 이 양고기 무한리필 식당을 방문했습니다. 그는 양갈비 8인분을 주문하여 직원을 놀라게 했으며, 무한리필 세트도 추가로 주문했습니다. 쯔양은 양고기의 두툼한 두께와 높은 품질에 감탄하며, 육즙이 풍부하고 잡내가 전혀 없다고 평가했습니다. 특히 미디엄 레어로 익혔을 때 소고기처럼 부드럽고 맛있다고 언급했습니다. 소금, 쯔란, 부추 등 다양한 조합을 시도했으며, 그중에서도 부추와의 조합을 최고로 꼽았습니다. 무한리필로 제공되는 양등심, 곱창, 새우, 소시지, 떡 등의 사이드 메뉴도 모두 맛있다고 칭찬하며, 특히 기름진 부위와 와사비의 조합이 좋다고 말했습니다. 쯔양은 양고기를 좋아하는 사람들에게 완벽한 장소라며 재방문 의사를 밝혔습니다.'),
('레알라면', '서울 동대문구 회기로25길 23-5', '0507-1311-4208', ARRAY['분식'], 'https://www.youtube.com/watch?v=pRx2cMwyrKU', 37.5911227, 127.0553875, '서울특별시', '유튜버는 경희대 근처에 위치한 매운 라면 맛집 ''레알라면''을 방문했습니다. 이 식당은 맵기 단계(옐로우, 오렌지, 레드 등)를 조절할 수 있는 것이 특징이며, 모든 라면에는 계란 2개와 수제비가 들어있고 밥, 치즈, 반찬이 무한리필됩니다 . 유튜버는 5가지 종류의 라면을 주문했습니다. ''옐로우''는 국물이 맛있고 순해서 아이들도 먹을 수 있을 정도라고 평가했습니다 . ''오렌지''는 불닭볶음면 수준의 매운맛이지만 맛있게 맵다고 언급했습니다 . ''스파이시 오렌지''는 오렌지보다 훨씬 매워 먹기 힘들어했으며, 가장 매운 ''레드'' 단계는 너무 매워서 순한 국물에 헹궈 먹어야 했습니다 . 스트레스 해소에 매운 음식이 좋았지만, 최종적으로는 ''옐로우''와 ''오렌지'' 단계를 추천하며 영상을 마무리했습니다 .'),
('봉황부대찌개 본점', '서울특별시 동대문구 황물로 39', '02-2247-1976', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=QvqRsI7-3Wc', 37.5737501, 127.0462656, '서울특별시', '쯔양은 30년 전통의 부대찌개 전문점인 ''봉황부대찌개''를 방문하여 부대찌개 5인분과 소시지 구이를 주문했습니다. 특히 가마솥 뚜껑에 끓여 먹는 방식이 인상적이라고 언급했습니다. 국물 맛에 대해 처음에는 깔끔하고 시원하지만, 끓일수록 햄에서 맛이 우러나와 진하고 깊은 맛이 난다고 평가했습니다. 또한, 마늘 맛이 강하게 나는 것이 특징이라고 덧붙였습니다. 밑반찬으로 나온 김치가 매우 맛있다고 칭찬했으며, 라면과 당면 사리를 맛있게 먹었습니다. 구운 소시지는 어릴 때 먹던 맛과 비슷해 추억을 불러일으킨다고 말했습니다. 밥에 국물과 콩나물을 비벼 먹으며 식사 만족도가 높은 메뉴라고 평가했고, 식당에 구비된 아이스크림을 식사 도중에 후식으로 즐기는 모습을 보여주었습니다.'),
('우육미', '서울 중구 퇴계로 373', '02-2233-1501', ARRAY['고기'], 'https://www.youtube.com/watch?v=_bgp3TAZT7M', 37.5652619, 127.0129799, '서울특별시', '쯔양은 이곳을 ''인생 스테이크''라고 칭하며 이전부터 방문하고 싶었지만 예약이 꽉 차고 대기가 길어 방문에 실패했던 인기 맛집이라고 소개했습니다(1:00). 이곳의 특징은 일반적인 수입산이 아닌 한우 1++ 등급의 티본 스테이크를 사용한다는 점이며, 쯔양은 그 맛에 크게 감탄했습니다(0:46, 5:11). 스테이크를 맛본 후 ''미쳤다'', ''역대급''이라는 표현을 연발하며, 육즙이 풍부하고 고기가 입안에서 녹는다고 극찬했습니다(6:45, 6:59). 특히 안심 부위가 인상적이었다고 여러 번 언급했으며(11:32, 19:16), 다른 어떤 티본 스테이크와도 비교할 수 없는 최고의 맛이라고 평가했습니다(7:05, 20:05). 또한, 테이블에서 직접 원하는 굽기로 구워 먹을 수 있는 점과(11:05) 매쉬 포테이토, 파채, 백김치, 갈치속젓 등 한식 밑반찬과의 조화가 훌륭하다고 칭찬했습니다(12:20, 13:08).'),
('이비가짬뽕 상암점', '서울 마포구 월드컵북로48길 31', '02-306-1577', ARRAY['중식'], 'https://www.youtube.com/watch?v=GPeeYxBVigM', 37.5773646, 126.8952373, '서울특별시', '쯔양은 VIP 카드를 사용해 ''이비가짬뽕 상암점''의 전 메뉴를 주문하여 먹방을 진행했습니다. 메뉴별 평가는 다음과 같습니다. - **이비가짬뽕 (대표 메뉴)**: 새우, 조개, 홍합 등 해산물이 들어있으며, 사골 육수 베이스임에도 해산물과 잘 어우러져 시원하고 구수한 맛이 일품이라고 평가했습니다. - **백짬뽕 (하얀짬뽕)**: 맵지 않아 아이들이나 매운 것을 못 먹는 사람들에게 좋고, 국물이 매우 진하다고 언급했습니다. 특히 영상 말미에 개인적으로 가장 맛있었던 메뉴로 꼽으며, 다른 곳의 백짬뽕과 차별화된 최고의 맛이라고 극찬했습니다(ts:1534-1543). - **고기짬뽕**: 차돌박이 베이스로, 매운맛과 고소한 맛이 조화로우며 고기가 푸짐하게 들어있다고 설명했습니다(ts:1300-1349). - **매콤로제짬뽕**: 신메뉴로, 베이컨과 눈꽃치즈가 올라가 있으며 짬뽕과 파스타가 섞인 느낌으로, 매콤함이 느끼함을 잡아주고 훈연 향이 좋다고 평가했습니다. - **한우짜장면**: 면이 두껍고 진하며, 볶은 맛과 풍미가 강렬하다고 만족감을 표했습니다. - **볶음짬뽕**: 해물볶음면 같으며, 영상에서 먹은 메뉴 중 가장 맵지만 훈연 향이 좋다고 했습니다. - **탕수육**: 겉은 바삭하고 속은 쫀득하며, 소스가 너무 달거나 시지 않고 적당해서 맛있다고 칭찬했습니다(ts:444-471). - **한우라이스**: 카레와 비슷하지만 더 가벼운 소스로, 옛날 경양식 소스 같은 느낌의 특별한 맛이라고 평가했습니다. - **칠리새우&치킨**: 소스가 맛있다고 언급했습니다. - **고추만두**: 간장보다 탕수육 소스에 찍어 먹는 것이 더 맛있다고 했습니다.'),
('대만도삭우육면 뚝섬점', '서울 성동구 상원4길 8 1층', '0507-1393-8689', ARRAY['아시안'], 'https://www.youtube.com/watch?v=VqXKT0emAxo', 37.54721, 127.0493179, '서울특별시', '쯔양은 이 식당의 도삭우육면에 빠져 3일에 한 번씩 시켜 먹을 정도로 맛있다고 극찬했습니다. 국물은 매우 진한 소고기 육수 맛이 나며, 과거 태국에서 즐겨 찾던 맛집과 비슷하다고 평가했습니다. 면발은 칼국수면보다 두껍지만 밀가루 맛이 강하지 않고, 고기는 입에서 녹을 정도로 부드럽다고 언급했습니다. 함께 먹은 양꼬치는 배달임에도 불구하고 맛이 뛰어나며 특유의 향을 좋아한다고 말했고, 가리비 구이는 신선하고 아삭한 식감이 일품이라고 덧붙였습니다. 처음에는 낯설 수 있는 향신료가 들어간 대만, 홍콩 음식에 한번 익숙해지면 중독성이 강하다고 평가했습니다.'),
('진미평양냉면', '서울 강남구 학동로 305-3', '02-515-3469', ARRAY['한식'], 'https://www.youtube.com/watch?v=gHE7_aGHE8I', 37.516151, 127.036041, '서울특별시', '쯔양은 두 번째 평양냉면 도전으로, 슴슴할 것이라는 우려와 달리 육향이 깊고 깔끔한 국물 맛이 아주 좋다고 평가했습니다. 특히 불고기를 구웠던 팬에 평양냉면을 넣어 따뜻하게 먹는 조합을 극찬했습니다. 함께 주문한 불고기는 오랫동안 먹고 싶었던 바로 그 맛이라며 만족감을 표했고, 만두는 수제 느낌의 담백한 맛, 비빔냉면은 새콤달콤하게 양념이 완벽하다고 언급했습니다. 돼지고기 및 소고기 수육은 매우 부드럽고 입에서 녹는다고 평가했습니다. 전반적으로 주문한 모든 메뉴에 대해 높은 만족도를 보이며, 다음 평양냉면 맛집 방문을 기대하게 만드는 성공적인 ''먹방''이었습니다.'),
('풍년기사님식당', '서울 마포구 대흥로 54', '02-711-0616', ARRAY['고기'], 'https://www.youtube.com/watch?v=hSvMwl4RaxE', 37.5449916, 126.9397886, '서울특별시', '쯔양은 이강인, 김민경, 이정은과 함께 택시 기사들을 돕기 위한 취지로 삼겹살 먹방 대결을 펼쳤습니다. 총 6kg의 삼겹살을 먹었으며, 음식에 대해 ''맛있다'', ''잘 익었다''고 긍정적으로 평가했습니다. 대결의 재미와 좋은 취지에 초점이 맞춰졌지만, 전반적으로 식사에 만족하는 모습을 보였습니다. 또한, 고기를 더 많이 먹기 위해 쌈을 싸 먹는 모습을 보여주기도 했습니다.'),
('안동집 손칼국시', '서울특별시 동대문구 고산자로36길 3 신관 지하1층', '02-965-3948', ARRAY['한식'], 'https://www.youtube.com/watch?v=x_1yb58NURc', 37.5789581, 127.0388573, '서울특별시', '쯔양은 경동시장 지하에 위치한 35년 전통의 식당이라고 소개하며, 모든 음식의 양이 매우 푸짐하다고 여러 번 언급했습니다. 메인 메뉴인 안동 손칼국수는 밀가루와 콩가루를 섞어 만든 면이 특징으로, 처음에는 다소 슴슴하지만 간장을 넣으면 간이 맞고 콩의 고소한 맛이 느껴진다고 평가했습니다. 국물은 감자나 멸치 육수 같다고 했으며, 면이 쉽게 불지 않는 점을 장점으로 꼽았습니다. 함께 주문한 수육은 매우 부드럽고 쫄깃하며 맛있다고 극찬했고, 차조밥을 배추에 싸 먹는 조합과 비빔밥 위에 올려 먹는 것을 추천했습니다. 비빔밥은 차조밥으로 만들어졌으며 양념이 맛있다고 했고, 부추전은 부추가 가득 들어있고 양이 엄청나다고 언급했습니다. 전반적으로 할머니가 생각나는 맛이며, 채소를 많이 먹을 수 있어 좋았다고 총평했습니다.'),
('시즌올', '서울특별시 동작구 노들로 674 노량진수산물도매시장 2층 활어 2-7', '1533-0524', ARRAY['한식'], 'https://www.youtube.com/watch?v=yEQvlQg6mWA', 37.5148237, 126.9379759, '서울특별시', '쯔양은 킹타이거 새우 라면에 대해 인스턴트 라면 같지 않은 깊고 풍부한 맛이 일품이라고 평가했습니다. 새우는 랍스터 같은 식감에 매우 살이 많다고 칭찬했습니다. 레몬과 홀그레인 버터 소스에 찍어 먹는 새우구이는 상큼하고 맛있는 맛의 폭발이라고 극찬했습니다.'),
('왕비집', '서울특별시 성동구 고산자로14길 8', '0507-1422-7275', ARRAY['고기'], 'https://www.youtube.com/watch?v=yEQvlQg6mWA', 37.5620787, 127.0372924, '서울특별시', '소갈비와 돼지 목살 구이를 맛본 쯔양은 고기가 매우 부드럽고 질이 좋으며, 특히 양념이 맛있다고 평가했습니다. 저온에서 소금으로 숙성시켜 부드러운 식감을 만들어낸다는 설명을 듣고 감탄했습니다. 특히 소갈비는 입에서 녹는 듯한 부드러움을 칭찬했습니다.'),
('ZION', '서울 강서구 공항대로61길 10-11 1,2층', '070-4106-0815', ARRAY['패스트푸드'], 'https://www.youtube.com/watch?v=yEQvlQg6mWA', 37.5514069, 126.8660986, '서울특별시', '쯔양은 ''아메리칸 더블 버거''를 먹고 패티의 바깥 부분이 튀긴 것처럼 느껴지는 점이 특이하다고 언급했습니다. 육즙이 풍부하고 고기가 매우 부드러우며, 간도 잘 되어 있어 맛있다고 칭찬했습니다.'),
('보성싱싱농원', '전라남도 보성군 조성면 조성봉산길 5', '0507-1323-9372', ARRAY['카페·디저트'], 'https://www.youtube.com/watch?v=yEQvlQg6mWA', 34.7936059, 127.2221187, '전라남도', '딸기를 매우 좋아한다고 밝힌 쯔양은 딸기 에이드가 정말 맛있고 달콤하다고 칭찬했습니다. 딸기빵에 대해서는 일반적인 빵과 달리 떡처럼 쫄깃한 식감이 독특하고 맛있다며 ''빵떡''이라는 별명을 붙였습니다.'),
('금성관나주곰탕', '서울 중구 남대문로 29 청남빌딩', '02-753-7898', ARRAY['한식'], 'https://www.youtube.com/watch?v=yEQvlQg6mWA', 37.5614288, 126.9788427, '서울특별시', '쯔양은 곰탕의 향이 매우 좋고 국물이 진하다고 평가했습니다. 일반적인 뼈 국물과는 다른, 고기 맛이 깊게 우러난 국물이라며 밥과 함께 맛있게 먹었습니다.'),
('제기식당', '서울 동대문구 홍릉로5길 14 1층', '0507-1325-6725', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=aga5WvCMGZk', 37.5827151, 127.0436072, '서울특별시', '쯔양은 이 식당의 주력 메뉴인 닭볶음탕을 주문했습니다. 그녀는 국물이 진하고 마늘 맛이 풍부하게 느껴져 아주 맛있다고 평가했으며, ''닭볶음탕의 정석 같은 맛''이라고 표현했습니다. 또한 닭고기가 부드럽고 양이 푸짐하여 가성비가 좋다고 칭찬했습니다. 식사 말미에는 남은 닭볶음탕 국물에 밥을 볶아 먹으며 마지막까지 맛있게 즐기는 모습을 보여주었고, 전반적으로 음식의 맛, 양, 가격에 큰 만족감을 드러냈습니다.'),
('온정돈까스 본점', '서울 관악구 조원로 60', '02-3281-3330', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=gyWR5sPHRmU', 37.4835575, 126.9091048, '서울특별시', '쯔양은 평소 매운 음식을 잘 먹지 못하지만, ''디진다 돈까스'' 먹기에 도전했습니다. 처음에는 ''지옥의 냄새''가 난다고 표현했으며, 한 입 먹은 후에는 눈물을 흘리고 귀가 잘 들리지 않을 정도로 힘들어했습니다. 하지만 시간이 지나자 매운맛에 점차 익숙해지며 오히려 스트레스가 풀린다고 말했습니다. 도전을 마친 후에는 입술 감각이 없고 눈과 입술이 부었지만, 위는 아프지 않고 혀만 아프다고 평가하며, 이전에 도전했던 대왕돈까스보다는 쉬웠다고 소감을 밝혔습니다.'),
('하나우동', '서울 강남구 논현로171길 12', '02-546-3051', ARRAY['분식'], 'https://www.youtube.com/watch?v=ENTR_1viik4', 37.5257063, 127.027431, '서울특별시', '쯔양은 20년 이상 전통의 우동집이지만 철판볶음밥으로 더 유명한 곳이라고 소개했습니다. 치즈 베이컨 김치볶음밥, 일반 우동, 김치 우동, 냉메밀, 돈까스 등 총 6가지 메뉴를 주문했습니다. 특히 철판볶음밥은 모든 테이블이 주문하는 인기 메뉴로, 양이 매우 푸짐하고(2인분이 3~4인분처럼 보임) 바닥의 누룽지가 바삭해서 맛있다고 평가했습니다. 우동은 면발이 부드럽고 쫄깃하며, 새우튀김과 통계란이 들어있는 점이 특이하다고 언급했습니다. 김치우동 국물은 김치찌개처럼 시원하다고 했습니다. 돈까스는 크고 부드러우며 바삭하다고 평가했고, 우동 국물에 적셔 먹는 것을 즐겼습니다. 냉메밀 국수도 맛있다고 평가하며 전반적으로 모든 메뉴의 양이 매우 푸짐하고 맛있어서 만족스러운 식사였다고 총평했습니다.'),
('하이디라오 대학로점', '서울특별시 종로구 대학로 146 혜화동씨티밸리 3층', '02-743-6868', ARRAY['중식'], 'https://www.youtube.com/watch?v=Eb_c6KR5sbg', 37.5842573, 127.0020351, '서울특별시', '쯔양은 혜화동에 위치한 훠궈 전문점 ''하이디라오''를 방문하여 버섯, 마라, 토마토, 돼지뼈 등 4가지 탕과 함께 다양한 고기, 해산물, 채소 등을 주문해 총 279,100원어치의 먹방을 선보였습니다. 그녀는 각 탕에 따라 고기 맛이 달라지는 점을 즐겼으며, 특히 마라탕의 매운맛은 땅콩 소스로 중화시키고 토마토탕과 해산물의 조화에 감탄했습니다. 냄새 때문에 걱정했던 메기는 마라탕에 넣어 먹으니 식감이 훌륭했다고 평가했습니다. 마지막으로 수타면 퍼포먼스와 함께 칼국수처럼 부드러운 면으로 식사를 마무리했고, 서비스로 나온 수박에 만족감을 표했습니다. 쯔양은 전반적으로 뛰어난 서비스와 맛에 크게 만족하며 ''진짜 행복''이라고 표현했습니다.'),
('무교동낙지', '서울 중구 무교로 20-6', '02-732-3428', ARRAY['한식'], 'https://www.youtube.com/watch?v=Zmntr44QJGg', 37.5676314, 126.9795834, '서울특별시', '쯔양은 총 4단계의 매운맛 낙지볶음을 단계별로 맛보았습니다. 처음에는 가장 안 매운맛을 먹으며 낙지가 매우 부드럽고 통통하다고 평가했습니다. 다음 단계로 넘어가면서 맛이 더 깊어지고 감칠맛이 돈다고 언급했습니다. 중간맛부터는 꽤 맵게 느껴져 계란말이와 함께 먹으며 매운맛을 중화시켰습니다. 가장 매운맛은 매우 맵지만 맛있어서 계속 먹게 된다고 평가하며(ts:540-547), 이 집 낙지볶음은 맵게 먹어야 더 맛있다는 결론을 내렸습니다. 전반적으로 ''먹을 만하게 맛있는 매운맛''이라고 요약하며, 밥에 소스를 비벼 먹고 김과 함께 싸 먹는 등 다양한 방법으로 즐겼습니다. 개인적으로는 가장 매운맛이 제일 맛있었다고 최종적으로 평가했습니다.'),
('꾸브라꼬숯불두마리치킨 문정점', '서울 송파구 동남로6길 15 1층 3호', '02-452-9282', ARRAY['치킨'], 'https://www.youtube.com/watch?v=wegI8EQjI8o', 37.4890622, 127.1249903, '서울특별시', '쯔양은 ''꾸브라꼬숯불두마리치킨''의 대표 메뉴인 숯불양념구이를 비롯해 숯불데리야끼, 후라이드 치킨 등 다양한 메뉴를 맛보았습니다. 숯불양념구이는 숯불 향이 가득하고 고기가 매우 부드럽고 촉촉하며, 맵지 않아 아이들도 즐길 수 있는 맛이라고 평가했습니다. 또한, 닭고기 조각이 매우 커서 양이 푸짐하다고 만족감을 표했습니다. 후라이드 치킨은 얇고 바삭한 튀김옷과 육즙 가득한 속살이 특징이라고 언급했습니다. 사이드 메뉴인 떡볶이는 부산식 ''물떡''이 들어간 포장마차 스타일로, 메인 메뉴로도 손색이 없을 만큼 맛있다고 극찬했습니다. 볶음우동은 불닭 소스와 비슷하지만 맵지 않은 맛이라고 설명했으며, 남은 양념에 밥과 김가루, 참기름을 비벼 ''치밥''으로 즐기는 것을 추천했습니다. 전반적으로 모든 메뉴가 맛있고 양이 푸짐하여 가성비가 좋다고 평가하며 만족스러운 식사였다고 마무리했습니다.'),
('연희네돈까스 모밀제면소 본점', '서울특별시 강동구 진황도로 9-1 1층', '010-8473-3377', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=61JJYl5deUs', 37.5399653, 127.1288577, '서울특별시', '쯔양은 이 식당의 메밀국수와 돈까스를 모두 극찬했습니다. 부산에서 시작된 50년 전통의 3대째 내려오는 맛집으로, 서울로 이전했다고 소개합니다. 메밀국수는 자가제면한 면발이 매우 쫄깃하고 신선하며, 시간이 지나도 불지 않는 점을 특징으로 꼽았습니다. 국물은 깊고 진한 맛이 일품이며 여름에 먹기 완벽한 메뉴라고 평가했습니다. 1인분에 7,000원이라는 저렴한 가격에 두 판이 나오는 푸짐한 양도 장점으로 언급했습니다. 치즈 돈까스는 수제로 만들어져 고소하고, 풍부한 치즈와 육즙의 조화가 훌륭하다고 말하며 ''무조건 먹어봐야 할 맛''이라고 강력하게 추천했습니다. 맛에 감탄하여 치즈 돈까스를 추가로 주문하기도 했습니다.'),
('빅스타피자 마곡점', '서울특별시 강서구 공항대로 103', '1566-7440', ARRAY['피자'], 'https://www.youtube.com/watch?v=sm0it_a9K3o', 37.5620748, 126.8188663, '서울특별시', '쯔양은 미국 3대 피자인 시카고, 디트로이트, 뉴욕 스타일 피자를 모두 맛보았습니다. 라자냐 시카고 피자는 과일 향이 나는 소스와 풍부한 치즈가 특징이며, 특히 치즈가 들어있는 크러스트를 갈릭 소스에 찍어 먹는 것을 추천했습니다. 페퍼로니 디트로이트 피자는 바삭하고 쫄깃한 식감의 사각형 모양 도우가 특징이며, 페이스트리 같다고 평가했습니다. 45cm 크기의 콰트로 프리미엄 뉴욕 피자는 네 가지 맛으로 구성되어 있습니다. 그 중 직화 불고기 피자는 스모키한 향과 상큼한 레몬 제스트가 인상적이라고 언급하며 마지막까지 아껴 먹을 정도로 맛있다고 극찬했습니다. 라구 미트볼 피자는 라구 소스와 미트볼, 체다 치즈의 조화가 훌륭하다고 평가하며, 인기 메뉴인 라자냐 피자보다 개인적으로 더 맛있다고 밝혔습니다.'),
('멘야하나비 신사점', '서울 서초구 강남대로101안길 18-1 1층', '0507-1365-7788', ARRAY['아시안'], 'https://www.youtube.com/watch?v=O4nc-459gyk', 37.516266, 127.017587, '서울특별시', '쯔양은 이 마제소바를 ''인생 마제소바''이자 먹어본 것 중 최고라고 극찬했습니다. 간이 짜지 않고 완벽하게 맛있으며, 진한 소스와 쫄깃한 면의 조화가 훌륭하다고 평가했습니다. 또한, 밀가루 맛이 강하지 않고 면, 소고기, 파의 맛이 잘 느껴진다고 언급했습니다. 다른 음식과 비교할 수 없는 독보적이고 중독성 강한 맛이라고 설명하며, 식초를 추가하면 새로운 풍미가 더해져 맛있다고 덧붙였습니다. 최종적으로 ''오리지널이라 불릴 만한 맛''이라고 평가하며 재방문 의사를 밝혔습니다.'),
('홍콩중화요리', '서울 동대문구 정릉천동로 107', '02-966-6779', ARRAY['중식'], 'https://www.youtube.com/watch?v=GiQlzDcTKj8', 37.5819231, 127.0355526, '서울특별시', '쯔양은 40년 전통의 숨은 맛집이라며 기대를 표했습니다. 여러 메뉴를 주문했으며, 각 음식에 대한 평가는 다음과 같습니다. 탕수육은 일반적인 바삭한 식감과 달리 매우 부드러워서 소스를 부을 필요가 없을 정도라고 극찬하며, 자신의 취향에 완벽하게 맞는다고 했습니다[attached_file:1]. 짜장면은 옛날에 먹던 맛으로, 자극적이지 않고 소스가 맛있어 아이들도 좋아할 맛이라고 평가했습니다[attached_file:1]. 볶음 짜장면은 평소 기름져서 선호하지 않지만, 이 집은 새로운 방식으로 맛있다고 언급했습니다[attached_file:1]. 짬뽕은 단골손님이 추천한 메뉴로, 국물이 자극적이지 않고 속을 편안하게 해주는 맛이라고 했습니다[attached_file:1]. 난자완스는 수제로 만들어져 쫄깃한 식감이 일품이라고 칭찬했습니다[attached_file:1]. 김치볶음밥은 밥 위에 소스처럼 볶음김치가 올라간 독특한 형태이며, 밥과 소스의 비율이 완벽하고 아주 맛있다고 평가했습니다[attached_file:1]. 전반적으로 음식의 맛과 옛날 노포의 분위기에 크게 만족하며 모든 음식을 남김없이 먹었습니다[attached_file:1].'),
('웨스턴차이나', '서울 용산구 독서당로 73', '02-795-3654', ARRAY['중식'], 'https://www.youtube.com/watch?v=iM8M-iaM1zw', 37.5342707, 127.0086312, '서울특별시', '쯔양은 50년 경력의 사장님이 운영하는 식당이라며 기대를 표했습니다. 총 25접시의 딤섬을 먹었으며, 식당 사장님은 50년 장사 동안 이런 경우는 처음이라고 놀라워했습니다. 주요 메뉴 리뷰는 다음과 같습니다: - **샤오롱바오(소룡포):** 육즙이 매우 진하고 깊은 맛이 나며, 최근 가본 유명한 곳보다 맛있다고 평가했습니다. 먹을 때마다 육즙이 터져 나와 여러 번 감탄했습니다. - **새우 하가우(새우수정딤섬):** 조개처럼 귀여운 모양에 속이 새우로 꽉 차 있으며, 최근 먹어본 딤섬 중 최고라고 극찬했습니다. - **새우 쇼마이:** 통새우 살과 다양한 해산물이 섞여있어 풍부한 식감을 느낄 수 있다고 설명했습니다. - **야채 에그롤:** 야채보다 치즈가 더 많이 들어있어 맛있다고 언급했습니다. - **왕새우살 튀김:** 겉이 과자처럼 매우 바삭하다고 평가했습니다. 전체적으로 모든 딤섬이 맛있다고 평가했으며, 특히 육즙이 풍부한 샤오롱바오와 다양한 새우 딤섬에 대해 높은 만족감을 보였습니다. 식사를 마친 후 ''최고의 식사''였다고 소감을 밝혔습니다.'),
('수제비먹는닭갈비 본점', '서울 성동구 왕십리로21다길 39', '02-2297-8522', ARRAY['한식'], 'https://www.youtube.com/watch?v=7YV9D3-fz9k', 37.559659, 127.0332331, '서울특별시', '쯔양은 닭갈비 10인분과 수제비, 여러 사리를 주문해 먹방을 진행했습니다. 먼저 나온 수제비에 대해 손으로 뜯은 면의 두께가 적당하고 국물이 매우 구수하여 만족스럽다고 평가했습니다. 이어서 닭갈비는 닭고기가 매우 부드럽고 맛있다며, 카레와 생강, 후추 향이 나는 양념이 특징이라고 언급했습니다{ts:256, 416-422}. 특히 수제비 면에 닭갈비를 싸 먹거나, 남은 닭갈비 양념에 수제비를 비벼 먹는 등 두 메뉴의 조합을 극찬했습니다. 식사 마무리로는 남은 양념에 볶음밥을 ''필수''라며 비벼 먹었고, ''최고''의 식사였다고 극찬하며 마무리했습니다.'),
('울프강 스테이크하우스 청담점', '서울특별시 강남구 선릉로152길 21', '02-556-8700', ARRAY['양식'], 'https://www.youtube.com/watch?v=hwxRjbBkSaw', 37.52449, 127.0414674, '서울특별시', '쯔양은 뉴욕 지점에 이어 한국의 울프강 스테이크하우스를 방문하여 메뉴에 있는 모든 스테이크(포터하우스, 설로인, 립아이, 양갈비, 안심)를 주문했습니다. 랍스터 비스크는 랍스터 내장 맛이 강해 호불호가 갈릴 것 같지만 본인 입맛에는 괜찮다고 평했습니다. 스테이크는 뉴욕에서 먹었을 때보다 더 부드럽고 버터 주스 풍미가 좋다고 칭찬했으며, 특히 미디엄 레어로 완벽하게 조리되었다고 언급했습니다. 사이드 메뉴로 주문한 구운 숙성 김치는 느끼함을 잡아주는 훌륭한 ''팔레트 클렌저''라고 말했습니다. 립아이 부위 중에서도 ''립아이 캡''이 매우 맛있어서 아껴 먹었고, 양갈비는 이날 먹은 것 중 최고로 꼽으며 특유의 향과 맛이 중독성 있다고 했습니다. 히든 메뉴인 ''맨해튼 김치''(토마토와 양파 요리)는 고기의 느끼함을 잡아주는 맛이라고 극찬했습니다. 전반적으로 음식과 서비스에 매우 만족했으며, 특히 한국어로 편하게 주문할 수 있어 뉴욕 방문 때보다 더 즐거운 식사를 했다고 밝혔습니다.'),
('만포막국수', '서울 중구 동호로14길 2', '02-2234-5859', ARRAY['한식'], 'https://www.youtube.com/watch?v=LrEsV9zHau4', 37.5558024, 127.0103317, '서울특별시', '쯔양은 이곳의 음식이 전반적으로 시간이 지날수록 맛이 더 깊어진다고 평가했습니다. 특히 이북식 찜닭은 부드럽고 양념이 잘 배어 있으며, 막국수와 함께 먹으면 더욱 맛있다고 언급했습니다. 물막국수는 동치미 국물 맛이 나는 시원하고 상큼한 맛이며, 비빔막국수는 적당히 매우면서도 고소한 기름 맛이 특징이라고 설명했습니다. 손으로 직접 만든 만두는 속이 꽉 차 있고 담백한 맛이 일품이며, 녹두전은 밀가루 맛이 거의 나지 않고 매우 바삭하다고 칭찬했습니다.'),
('또래끼리', '서울 광진구 군자로 103', '02-469-6684', ARRAY['분식'], 'https://www.youtube.com/watch?v=kC89Jq5lW1s', 37.5524333, 127.0713442, '서울특별시', '쯔양은 김치볶음밥을 먹고 아주 맛있다며, 오랜만에 먹어보는 맛이라고 극찬했다([`attached_file:1`]). 밥알이 고슬고슬하고 너무 달지 않으면서 풍미가 깊어 누구나 좋아할 만한 맛이라고 평가했다([`attached_file:1`](ts:214-226)). 고기와 김치가 들어있으며, 옛 추억을 떠올리게 하는 맛이라고 언급했다([`attached_file:1`]). 특히, 직접 가져온 김과 함께 먹는 조합을 최고라고 말했다([`attached_file:1`]). 함께 주문한 순두부찌개에는 쫄면이 들어있어 특이하다고 했고([`attached_file:1`]), 계란찜은 훈연향이 나고 촉촉해서 김치볶음밥과 잘 어울린다고 칭찬했다([`attached_file:1`]). 양이 매우 푸짐하고 가성비가 좋다는 점도 언급했으며([`attached_file:1`]), 식사를 마친 후 김치볶음밥 곱빼기 3인분을 포장해갈 정도로 만족스러워했다([`attached_file:1`]).'),
('대흥양다리바베큐 건대점', '서울 광진구 아차산로30길 39 1층', '02-468-6669', ARRAY['고기'], 'https://www.youtube.com/watch?v=EilSy-a-m-U', 37.5389967, 127.0674893, '서울특별시', '쯔양은 2kg가 넘는 거대한 양다리 통구이를 메인으로 먹었습니다. 직접 살을 잘라 먹는 재미가 있고, 잡내가 전혀 없이 맛있다고 평가했습니다. 특히 쯔란(큐민) 가루와 바비큐 소스를 곁들여 먹는 것을 즐겼습니다. 부위별로 부드러운 부분과 쫄깃한 부분이 있어 식감이 다양하다고 언급했습니다. 서비스로 나온 양만두는 샤오롱바오처럼 육즙이 가득하고 매우 맛있어서 추가로 주문했으며, 양고기 튀김은 돼지고기보다 부드럽고 튀김옷이 두꺼워 맛있다고 칭찬했습니다. 함께 나온 양곰탕도 고기가 많고 국물 맛이 좋다고 평가했습니다. 전체적으로 8만원이라는 가격이 합리적이라고 느꼈습니다.'),
('칙바이칙 선릉점', '서울 강남구 선릉로 523 유림빌딩 3층', '1533-7827', ARRAY['패스트푸드'], 'https://www.youtube.com/watch?v=6v7h86IWMvU', 37.5062066, 127.0478192, '서울특별시', '쯔양은 ''칙바이칙''이 패스트푸드와 캐주얼 다이닝의 중간 형태인 패스트 캐주얼 레스토랑이라고 소개하며, 재료가 신선해 보인다고 언급했습니다. 특히 자체 개발한 오븐 그릴에서 구워내는 치킨은 훈연 향이 좋고, 튀기지 않아 느끼하지 않고 담백하며, 육즙이 풍부하고 부드럽다고 극찬했습니다. 닭다리살을 사용해 식감이 좋다고도 덧붙였습니다. 햄버거 빵은 매우 부드럽고, 라이스볼에 들어가는 밥은 버터, 마늘, 치킨 스톡으로 지어 매우 맛있다고 평가했습니다. 아보카도, 해시브라운 등 다양한 재료가 들어간 샌드위치와 새우 패티가 들어간 버거 등 여러 메뉴를 맛보았으며, 전반적으로 모든 메뉴의 퀄리티가 높고 맛있다고 총평했습니다.'),
('이북만두', '서울특별시 중구 무교로 17-13', '02-776-7361', ARRAY['한식'], 'https://www.youtube.com/watch?v=_TeiHGZ2aic', 37.5672529, 126.9785285, '서울특별시', '쯔양은 여러 메뉴를 주문하여 리뷰했습니다. ''김치말이밥''에 대해 처음에는 차가운 국물에 밥이 들어간 조합이 이상할 것이라고 생각했지만, 막상 먹어보니 더운 날씨에 완벽한 음식이며 전혀 이상하지 않고 맛있다고 평가했습니다. 특히 김치 맛과 참기름 향이 가미된 국물이 밥과 잘 어울린다고 언급했습니다. ''이북식 만두''는 속이 부드럽고 후추 향이 느껴지며, 전체적으로 자극적이지 않고 담백한 맛이라고 설명했습니다. ''김치말이국수''는 참기름 향이 고소하고, 국수와 밥을 함께 즐기는 팁을 공유했습니다. ''모듬전''에 포함된 고추전은 보기와 달리 맵지 않고 맛있었으며, 특히 돼지고기 수육으로 만든 전은 두부처럼 부드럽다고 감탄했습니다. 다만, 수육에 들어간 쑥갓은 향 때문에 본인 취향이 아니라고 밝혔습니다. 식사 후 가장 인상 깊었던 메뉴로는 ''이북식 만두''를 꼽았습니다.'),
('얄개분식', '충청남도 서산시 해미면 읍성마을4길 24-1', '041-688-8327', ARRAY['분식'], 'https://www.youtube.com/watch?v=zwsgaOHP-v8', 36.7106565, 126.5462434, '충청남도', '메뉴는 모듬떡볶이 단일 메뉴이며, 양이 매우 푸짐합니다. 쯔양은 집에서 만든 떡볶이 비주얼이지만 텁텁한 맛이 전혀 없고 소스가 독특하면서 맛있다고 평가했습니다. 소스는 너무 달지 않고 감칠맛이 뛰어나며, 신라면 정도의 맵기라고 언급했습니다. 콩나물, 만두, 떡, 라면, 당면, 계란 등 다양한 재료가 들어가 식감이 좋고, 특히 어린 시절에 먹던 추억의 떡볶이 맛이 난다고 극찬했습니다.'),
('행운돈까스', '서울 성동구 마조로1길 2', '02-2296-3406', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=pQpT0kTKNb4', 37.5583711, 127.0403021, '서울특별시', '쯔양은 돈까스, 생선까스, 고구마돈까스, 치즈돈까스, 매운돈까스 등 가게의 거의 모든 돈까스 메뉴를 주문했습니다. 치즈돈까스는 치즈가 풍부하고 고기가 부드러우며, 소스는 달콤새콤한 추억의 맛이라고 평가했습니다. 일반 돈까스는 반숙 계란과 함께 먹는 조합이 매우 좋다고 언급했습니다. 생선까스는 전혀 비리지 않고 촉촉하며 부드러워서 기대 이상으로 맛있다고 칭찬했습니다. 매운돈까스는 신라면보다 맵지만 맛있게 매운맛이라 마니아들이 좋아할 것이라고 평했습니다. 쯔양이 가장 좋아한 메뉴는 고구마돈까스로, 진짜 고구마 무스가 가득 들어있어 최고라고 극찬했습니다. 함께 나온 김치볶음밥도 매우 맛있어서 단독 메뉴로 팔지 않는 것을 아쉬워했습니다. 전반적으로 가성비 좋은 푸짐한 양과 두툼하고 맛있는 고기를 장점으로 꼽았습니다.'),
('골목냉면', '서울 성동구 독서당로 295-7', '02-2235-2540', ARRAY['한식'], 'https://www.youtube.com/watch?v=IXI9t8dZG-Y', 37.5485477, 127.021996, '서울특별시', '쯔양은 3년 전 방송 촬영으로 방문한 후, 음식이 매우 독특하고 맛있었던 기억에 다시 찾아왔다고 밝혔습니다. - **물냉면**: 일반적인 고기 육수와 달리 멸치 등 해산물 베이스의 육수를 사용하여 매우 특별하고 시원하며, 달콤하고 상큼한 맛이 난다고 평가했습니다. - **비빔냉면**: 고추장 양념이 아닌 7가지 재료를 직접 갈아 만든 가루 양념을 사용하는 것이 특징이며, 깨가 들어가 고소한 맛과 향이 먼저 느껴진 후 달고 신맛이 따라온다고 설명했습니다. 사장님은 이 비빔냉면이 서울식 가루 양념 냉면의 원조라고 자부했습니다. - **매운냉면**: 청양고추 가루를 사용해 만들었으며, 먹는 순간 매운맛이 확 올라왔다가 금방 사라지는 깔끔한 매운맛이라고 합니다. 쯔양은 땀을 흘릴 정도로 맵다고 느꼈습니다. - **찐만두와 떡국**: 만두는 직접 만든 것으로 속이 부드럽고 피가 얇아 맛있다고 칭찬했으며, 떡국 국물 또한 맛있다고 언급했습니다. - **온육수**: 냉면을 먹은 후 마시는 따뜻한 육수가 매운맛을 가시게 해주어 매우 좋았다고 평가했습니다. 전반적으로 이곳의 독특한 육수와 양념 방식을 높이 평가했으며, 자신에게는 첫 방송 먹방을 진행한 의미 있는 장소라고 강조했습니다.'),
('별미분식', '서울 관악구 남현2길 46', '0507-1400-9705', ARRAY['분식'], 'https://www.youtube.com/watch?v=z9mx_MHP9Eg', 37.4756432, 126.9749176, '서울특별시', '쯔양은 전반적으로 음식의 양이 푸짐하고, 일반적인 분식점과 달리 요리의 품질이 매우 높다고 평가했습니다. 특히 차돌박이 라면은 일반 라면과 다른 깊고 훈제향이 나는 프리미엄 요리 같다고 극찬했으며, 차돌박이 떡볶이는 두툼한 차돌박이와 쌀떡의 쫄깃한 식감이 일품이라고 좋아했습니다. 참치김치날치알 주먹밥은 재료가 풍부해 그 자체로도 훌륭하고, 차돌 된장찌개는 버섯이 많이 들어가 집밥처럼 든든한 식사로 완벽하다고 언급했습니다. 새우튀김 김밥은 편의점 제품과 차원이 다른 맛이라고 했으며, 개인적으로는 꽃맛살 김밥보다 더 맛있다고 평가했습니다. 여러 종류의 돈까스도 모두 맛있다고 했으며, 특히 김치나베 돈까스는 제육볶음 같다고 표현했습니다. 떡꼬치는 학창 시절을 떠올리게 하는 추억의 맛이라고 즐거워했습니다. 전반적으로 모든 메뉴에 만족하며 쉬지 않고 10가지 메뉴를 모두 먹어치웠습니다.'),
('기절초풍왕순대', '서울 관악구 봉천로62길 2', '02-872-8805', ARRAY['한식'], 'https://www.youtube.com/watch?v=p9Uxmbu45p0', 37.4781189, 126.9584299, '서울특별시', '쯔양은 이곳의 막창순대가 자신이 본 것 중 가장 클 정도로 크고, 속이 꽉 차 터질 듯이 푸짐하다고 감탄했습니다. 순대 겉의 막창은 질기지 않고 쫄깃하며, 속은 매우 부드럽고 촉촉하다고 평가했습니다. 특히 들깨가루를 섞은 초장에 찍어 먹는 조합이 훌륭하다고 언급했습니다. 함께 나온 돼지 혀 수육은 특유의 잡내가 전혀 나지 않아 맛있게 먹었으며, 순댓국 또한 잡내 없이 국물이 매우 진하고 깔끔하여 보양식 육수 같다고 극찬했습니다. 전반적으로 맛, 식감, 푸짐한 양에 크게 만족하며 강력 추천했습니다.'),
('마피아떡볶이 본점', '인천광역시 서구 염곡로 318 1층', '032-563-4005', ARRAY['분식'], 'https://www.youtube.com/watch?v=SyH1-6gqgCw', 37.512992, 126.6690573, '인천광역시', '쯔양은 마피아떡볶이에서 국내 최초로 출시한 신메뉴 허니버터 떡볶이를 맛보기 위해 방문했습니다. 그녀는 허니버터 떡볶이를 ''로제보다 맛있다''고 평가하며, 기존의 크림이나 로제 떡볶이와는 다른 꿀과 버터의 고소하고 향기로운 맛이 일품이라고 극찬했습니다. 특히 이 맛은 3-4인분 떡볶이 메뉴들 중에서 최고라고 꼽았으며, 식어도 맛있다는 점을 강조했습니다. 또한, 가게의 대표 메뉴인 기본 마피아 떡볶이에 대해서도 소스의 감칠맛과 간이 완벽하다고 칭찬했습니다. 쯔양은 얼굴보다 더 긴 오징어튀김과 가장 인기가 많다는 김말이 등 다양한 튀김 메뉴도 허니버터 소스와 잘 어울린다며 높은 만족감을 보였습니다. 전반적으로 모든 메뉴에 크게 만족하며 재방문하여 또 먹고 싶다는 의사를 밝혔습니다.'),
('백제정육점', '서울 종로구 종로35길 34', '02-762-7491', ARRAY['고기'], 'https://www.youtube.com/watch?v=QIy9R9A8PyU', 37.5726647, 127.0040593, '서울특별시', '40년이 넘은 식당으로 예약이 필수일 정도로 인기가 많습니다. 대표 메뉴는 구운 차돌박이에 육회를 싸 먹는 조합으로, 쯔양은 따뜻하고 고소한 차돌박이와 차갑고 달콤한 육회가 어우러져 맛의 시너지가 엄청나다고 극찬했습니다. (특) 육회비빔밥은 밥보다 육회가 훨씬 많아 ''육회산'' 같다고 표현했으며, 된장찌개와 함께 먹는 조합을 추천했습니다. 감자와 육회를 함께 먹는 것도 의외로 맛있다며 ''포테이토 그라탕에 육회를 섞은 듯한 맛''이라고 평가했습니다. 가성비가 좋은 점도 장점으로 언급했습니다.'),
('하니칼국수', '서울 중구 퇴계로 411-15', '02-3298-6909', ARRAY['한식'], 'https://www.youtube.com/watch?v=lpFAg9LuVqc', 37.5661811, 127.0171786, '서울특별시', '쯔양은 이곳이 웨이팅이 1시간까지 있을 정도로 인기 있는 곳이라고 언급했습니다. 대표 메뉴인 ''알곤이 칼국수''의 국물은 칼국수라기보다 아주 맛있는 알탕 같다고 극찬하며, 알과 곤이가 푸짐하게 들어있어 감칠맛과 고소한 맛이 일품이라고 평가했습니다(ts:291, 319, 368). 11,000원이라는 가격이 믿기지 않을 정도로 양이 많고, 남은 국물에 밥까지 비벼 먹으면 생선죽처럼 맛있다며 가성비를 높이 샀습니다(ts:394-417, 911). ''해장 칼국수''는 진한 육개장 같은 맛이며, 고기와 내장이 매우 부드럽다고 설명했습니다(ts:674, 1017). ''재첩 칼국수''의 국물은 매우 시원하지만, 재첩을 발라 먹는 것이 번거롭다고 언급했습니다(ts:269, 984). 사이드 메뉴인 ''모둠 한 접시''의 동그랑땡은 아이스크림처럼 녹을 정도로 부드럽고 육즙이 풍부하며, 수육 또한 잡내 없이 맛있다고 칭찬했습니다(ts:480, 525). 전반적으로 한 번도 먹어보지 못한 특이한 메뉴들이 모두 아주 맛있었다고 총평했습니다.'),
('상주축협 명실상감한우프라자', '경북 상주시 영남제일로 1119-9', '054-531-9911', ARRAY['고기'], 'https://www.youtube.com/watch?v=bhSZ1cnMlww', 36.4141927, 128.2165364, '경상북도', '쯔양은 상주 한우에 대한 큰 기대를 안고 ''''를 방문하여 총 2.4kg의 다양한 부위를 주문했습니다. 첫 메뉴인 '''' (쇠고기 편채)는 향이 뛰어나고 기대 이상의 맛이라며 채소와 함께 먹으니 풍미가 강하고 고소하다고 극찬했습니다. 안창살, 목줄살, 꽃등심, 살치살 등 여러 부위를 맛보며, 특히 안창살의 풍부한 육즙을 ''역대급''이라 칭했고, 감 껍질을 먹여 키운 ''''의 특별함을 언급했습니다. 식사 메뉴인 '''' (차돌박이 된장찌개)는 고기가 푸짐해 ''고기찌개'' 같다고 했으며, '''' (사골냉면)은 의외의 조합이 훌륭하다고 평가했습니다. 마지막으로 상주 특산물인 곶감, 감 스무디 등 다양한 후식까지 맛보며 전반적으로 고기의 질과 맛, 메뉴 구성에 크게 만족감을 표했습니다.'),
('영화루', '경기 수원시 팔달구 정조로791번길 3', '031-255-6925', ARRAY['중식'], 'https://www.youtube.com/watch?v=3B_7UgMwjn8', 37.278534, 127.0163739, '경기도', '60년 전통의 3대째 이어오는 수원 중식 노포. 쯔양은 이곳에서 짜장면, 굴짬뽕, 중국식냉면, 새우볶음밥, 탕수육, 깐쇼왕새우 등 다양한 메뉴를 주문해 먹방을 진행함. 특히 현장에서 먹는 탕수육은 소스를 부어 먹는 ''부먹''이 맛있다고 언급함. 전반적으로 음식의 양이 푸짐하고, 오랜 전통이 느껴지는 깊은 맛에 만족감을 표하며, 특히 짜장면의 맛을 높이 평가함.'),
('일광쪽갈비', '서울 동대문구 전농로 48', '02-489-5055', ARRAY['고기'], 'https://www.youtube.com/watch?v=GLTd77dTP4Q', 37.5690793, 127.0573367, '서울특별시', '쯔양은 지인의 추천으로 서울 답십리동에 위치한 ''일광쪽갈비''를 방문하여 쪽갈비 100개 먹기 챌린지를 진행했다. 그는 이곳의 쪽갈비가 국내산 냉장육이라 매우 부드럽고, 보기와 달리 간이 적절히 배어 있으며 살짝 그을린 맛이 일품이라고 평가했다. 또한, 느끼함을 잡아주는 와사비 소스와 매우면서도 중독성 있는 매운 소스가 별미라고 덧붙였다. 함께 제공되는 부드러운 김치와 개운한 순두부찌개 역시 훌륭한 조합이라고 칭찬했다. 쯔양은 사장님의 친절함이 음식 맛을 더욱 좋게 만든다고 강조하며, 100개를 먹고도 200개까지 먹을 수 있을 것 같다고 말할 정도로 높은 만족감을 표현했다.'),
('춘천무쇠닭갈비 까치산점', '서울 강서구 곰달래로 147-1', '02-2608-6575', ARRAY['한식'], 'https://www.youtube.com/watch?v=xHXhTNOw7vg', 37.5308522, 126.8494133, '서울특별시', '과거에도 방문한 적 있는 단골 맛집으로, 닭고기가 매우 부드럽고 육즙이 풍부하다고 평가했다. 양념 소스를 맛의 핵심으로 꼽았으며, 깻잎과 무쌈을 곁들이면 더 맛있다고 추천했다. 부드럽고 쫄깃한 떡사리와 양념이 잘 밴 우동 사리도 칭찬했다. 특히 구독자 추천으로 먹은 치즈 볶음밥을 ''천재적인 조합''이라며 극찬했고, 강한 맛의 막국수도 맛있게 먹었다. 전반적으로 ''먹을수록 점점 더 맛있어지는'' 매력이 있는 곳이라고 요약했다.'),
('스테이크존', '경기도 안양시 만안구 예술공원로131번길 8 302호', '010-9509-5411', ARRAY['양식'], 'https://www.youtube.com/watch?v=kOMrLSRKufI', 37.4189521, 126.9209385, '경기도', '쯔양은 ''스테이크존&파스타''가 배달 전문점임에도 불구하고 레스토랑 수준의 높은 퀄리티를 보여준다고 평가했습니다. 특히 가성비가 매우 뛰어나다고 여러 번 강조했습니다. 토마호크 스테이크에 대해서는 육즙이 풍부하고 식어도 부드러운 식감을 유지한다고 칭찬했으며, 부채살 스테이크 역시 매우 부드럽고 소스가 독특하다고 언급했습니다. 여러 파스타 중에서는 트러플 향이 절묘하게 조화된 머쉬룸 크림 파스타를 가장 인상 깊은 메뉴 중 하나로 꼽았으며, 한우곱창 파스타의 독특한 조합과 부드러운 곱창 식감에 놀라움을 표했습니다. 또한, 해장 파스타는 얼큰해서 해장용으로 좋겠다고 평가했고, 새우 알리오 올리오는 간이 완벽하다고 말했습니다. 음식이 촬영 때문에 다소 식었음에도 불구하고 면이 불지 않고 끝까지 맛있다는 점을 여러 차례 강조하며 전반적으로 모든 메뉴에 높은 만족감을 드러냈습니다.'),
('놀부만두', '서울특별시 동대문구 망우로16길 15', '02-2241-7550', ARRAY['분식'], 'https://www.youtube.com/watch?v=Zp9NXHZnNBg', 37.5893644, 127.0614991, '서울특별시', '쯔양은 냉모밀 육수가 상쾌하고 약간 달콤하며 독특한 향이 난다고 평가했습니다. 특히 여름에 왜 줄을 서서 먹는지 알겠다며, 더운 날 시원하게 먹기 좋을 것이라고 말했습니다. 고기만두는 매우 부드러워 입에서 녹는 식감이며, 만두피는 아주 얇지만 찢어지지 않고 쫄깃하다고 칭찬했습니다. 개인적으로 김치만두보다 고기만두를 더 선호했으며, ''놀랍다''고 표현하며 집에서도 먹기 위해 포장 주문까지 했습니다. 김치만두는 전통적인 만두소 맛이며, 속이 꽉 차 있고 샤오롱바오처럼 녹는 느낌이라고 언급했습니다. 전반적으로 40년 전통의 작고 오래된 동네 만두 가게의 분위기가 느껴지며, 시원한 냉모밀과 따뜻한 만두의 조합이 매우 훌륭하다고 평가했습니다.'),
('라이너스 바베큐', '서울 용산구 이태원로 136-13', '02-790-2920', ARRAY['고기'], 'https://www.youtube.com/watch?v=vu8p_ycLUxE', 37.5338218, 126.989713, '서울특별시', '쯔양은 이곳의 미국식 바베큐 폭립이 매우 부드럽고 육즙이 풍부하며, 뼈보다 살이 훨씬 많다고 평가했습니다. 특히 고기가 6시간 동안 조리되어 매우 연하다고 언급했습니다. 소스는 달콤하고 정성이 들어간 맛이며, 후추와 비슷한 허브 맛이 느껴진다고 했습니다. 함께 제공된 빵과 양파 소스를 이용해 직접 만들어 먹은 ''미트 버거'' 샌드위치가 정말 맛있다고 극찬하며, 이곳에 다시 방문하고 싶다는 의사를 밝혔습니다. 이날 먹은 양은 총 20,000칼로리에 달했으며, 사장님의 걱정으로 일부는 포장해왔습니다.'),
('나랑가', '서울 마포구 성미산로 71 1층 나랑가', '02-334-6200', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=xg2PrsU0MZ0', 37.5600889, 126.9156738, '서울특별시', '쯔양은 ''인생 초밥''이라는 평을 듣고 서울 마포구 성산동에 위치한 ''나랑가''에 방문했습니다. 총 100접시의 초밥과 우동 한 그릇을 먹었습니다. 초밥의 밥이 부드럽고 간이 잘 되어 있어 입에 넣자마자 녹아내리는 식감을 가장 큰 특징으로 꼽았으며, 이 때문에 모든 초밥이 맛있게 느껴진다고 평가했습니다. 특히 참다랑어 뱃살(도로) 초밥은 기름지지 않고 부드러우며, 장어 초밥은 잡내 없이 역대급으로 맛있다고 극찬하며 9피스를 추가 주문하기도 했습니다. 그 외에도 광어 지느러미, 연어 뱃살, 계란 초밥 등 모든 메뉴가 맛있다고 평가하며 ''인생 초밥집''이라고 결론 내렸습니다. 또한, 사장님이 서비스로 주신 우동, 식혜, 디저트도 맛있게 먹었습니다.'),
('고추장구이', '서울특별시 강동구 상암로 86', '02-473-9291', ARRAY['고기'], 'https://www.youtube.com/watch?v=UOTXMMGvXUk', 37.5479639, 127.1322739, '서울특별시', '쯔양은 고추장구이 6인분, 간장양념구이 6인분, 고추장 삼겹살 2인분, 오징어구이 등을 주문했습니다. 이곳은 가성비가 좋고 양이 푸짐하며, 연탄을 사용해 제대로 된 불맛을 내는 점을 높이 평가했습니다. 고추장구이는 바삭함과 부드러움이 공존하며, 간장구이는 쫄깃하고 바삭한 식감이 특징이라고 언급했습니다. 특히 고추장 삼겹살의 살코기와 비계 비율이 환상적이라고 칭찬했으며, 오징어구이의 부드러움과 불맛도 만족스러워했습니다. 서비스로 나오는 부침개와 얼큰한 된장찌개 등 밑반찬에 대해서도 좋은 평가를 남겼습니다.'),
('테그42 신림점', '서울특별시 관악구 신림로 312', '02-887-6681', ARRAY['패스트푸드'], 'https://www.youtube.com/watch?v=-v5JyOmVirM', 37.4822003, 126.9301574, '서울특별시', '쯔양은 총 10가지의 토스트와 2종류의 피자를 먹고 매우 만족스러운 반응을 보였습니다. 토스트에 대해 전반적으로 빵과 계란이 매우 부드러워 입에서 녹는 수준이며, 특제 소스가 달콤하면서도 물리지 않아 계속 새로운 맛을 느끼게 해준다고 평가했습니다. 특히 ''빅 시그니처''는 푸짐한 양을, ''불고기 토스트''는 실제 불고기 고기가 들어있어 요리 같다고 칭찬했습니다. ''빅 볼케이노''는 매콤한 맛으로 느끼함을 잡아주며 닭가슴살이 퍽퍽하지 않고 촉촉하다고 언급했습니다. 함께 맛본 피자 또한 ''토스트 가게에서 파는 피자''라고 믿기지 않을 정도로 퀄리티가 높다고 평가했습니다. 쯔양은 전체적으로 토스트의 퀄리티가 단순한 간식을 넘어선 하나의 요리 수준이라고 극찬하며, 재료가 신선하고 건강한 느낌을 준다고 요약했습니다. 또한 해당 영상 촬영을 계기로 테그42 본사에서 결식아동에게 토스트 1,000개를 기부했다는 사실도 언급하며 긍정적인 이미지를 더했습니다.'),
('신신옥', '인천 중구 우현로49번길 7', '032-766-0303', ARRAY['한식'], 'https://www.youtube.com/watch?v=4AlE083qq4g', 37.4715554, 126.6279922, '인천광역시', '쯔양은 65년 전통의 우동과 장어튀김 조합을 맛보기 위해 인천 신포국제시장의 ''신신옥''을 방문했습니다. 우동 국물은 짭짤하고 중독성 있는 맛이며, 직접 뽑은 면은 짜장면과 쫄면의 중간 식감으로 매우 쫄깃하고 쉽게 퍼지지 않을 것 같다고 평가했습니다. 특히 장어튀김에서 나온 튀김가루가 우동 위에 올라가는 것이 특징이라고 언급했습니다. 장어튀김은 겉이 매우 바삭하고 속은 부드러워 입에서 녹는 식감이며, 국내산 붕장어를 사용해 뼈가 거의 느껴지지 않는다고 했습니다. 튀김을 우동 국물에 적셔 먹으면 튀김옷이 부드러워지면서 장어의 맛이 더 잘 느껴진다고 덧붙였습니다. 함께 주문한 오징어 데침은 초장보다 참기름 소금장에 찍어 먹는 것이 더 맛있다고 했고, 물만두는 평범하지만 맛있다고 평가했습니다. 김치 맛이 뛰어나 국수와 잘 어울린다고 여러 번 칭찬했습니다. 유튜버는 우동 3그릇과 장어튀김 3접시를 먹어 식당 주인을 놀라게 할 정도로 만족스러운 식사를 했습니다.'),
('김밥천국 건대2호점', '서울특별시 광진구 능동로13길 21 1층', '0507-1404-0318', ARRAY['분식'], 'https://www.youtube.com/watch?v=NrSREOoZrnw', 37.5429918, 127.0707364, '서울특별시', '쯔양은 이곳이 다녀본 ''김밥천국'' 중 최고라고 극찬했습니다. 특히 다른 지점과 달리 10년 경력의 주방장이 직접 개발한 특별 메뉴와 소스에 감탄했습니다. 대표 메뉴인 ''건대 유부말이''는 이곳에서만 맛볼 수 있는 메뉴로, 부드러운 유부와 특제 양념으로 볶은 고기 소의 조화가 훌륭하다고 평가했습니다. ''묵은지 참치김밥''은 주먹만 한 크기와 꽉 찬 속, 묵은지의 깊은 맛이 일품이라고 언급했습니다. 이 외에도 집에서 끓인 것보다 2배는 맛있다던 ''치즈라면'', 전문점 수준의 ''얼큰 손수제비'', 직접 만든 비빔장이 인상적인 ''불고기 비빔밥'' 등 모든 메뉴가 양이 푸짐하고 집밥처럼 맛있다고 종합적으로 평가하며 만족감을 드러냈습니다.'),
('무공돈까스 동탄호수공원점', '경기도 화성시 동탄대로 182 레이크파로스 b104, 105', '031-377-3513', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=E7SlWEc4aJ0', 37.1707362, 127.1072649, '경기도', '쯔양은 무공돈까스에서 다양한 메뉴를 맛보았습니다. 대표 메뉴인 무공돈까스는 크기가 매우 크고 두꺼우며, 속이 치즈, 옥수수, 피망 등으로 꽉 차 있어 부드럽고 소스도 맛있다고 평가했습니다. 채소를 싫어하는 사람도 즐길 수 있을 맛이라고 덧붙였습니다[attached_file:1, ]. 치즈돈까스는 사용된 치즈가 매우 고소하고 풍미가 깊어 ''인생 치즈''라고 극찬하며, 마치 양념된 치즈스틱 같다고 표현했습니다[attached_file:1, ]. 함박스테이크는 부드러운 식감과 풍부한 육즙을 칭찬하며 아이들이 좋아할 메뉴로 추천했습니다[attached_file:1, ]. 사이드 메뉴인 오징어 튀김은 거대한 크기와 부드러운 식감에 감탄했고, 떡볶이는 익숙하면서도 맛있는 맛으로 돈까스와 잘 어울린다고 언급했습니다[attached_file:1, , ]. 전반적으로 모든 메뉴가 맛있다고 평가하며, 총 11접시를 먹고 ''공복이 없다''는 식당 이름에 걸맞게 매우 만족스러운 식사였다고 총평했습니다[attached_file:1, {ts:466, ts:1172-1181}].'),
('을밀대 본점', '서울 마포구 숭문길 24', '02-717-1922', ARRAY['한식'], 'https://www.youtube.com/watch?v=5RR_DTMZhlY', 37.5474881, 126.945522, '서울특별시', '쯔양은 평양냉면을 처음 먹어보는 것이라 걱정했지만, 예상과 달리 아주 맛있게 먹었다고 평가했습니다. 특히 ''걸레 빤 물'' 같다는 선입견과 달리, 국물이 매우 슴슴하고 깔끔해서 오히려 중독성이 강하다고 말했습니다. ''맛있다!''라기보다는 ''응?'' 하면서 계속 먹게 되는 매력이 있다고 표현했으며, 평소 슴슴한 음식을 즐기지 않음에도 입맛에 잘 맞았다고 합니다. 면은 쫄깃한 편이며, 수육은 얇게 썰려 나와 부드럽고 고소했습니다. 비빔냉면은 일반적인 맛과 비슷하지만 면의 식감이 달랐다고 언급했습니다. 가장 인상 깊었던 메뉴 중 하나는 녹두전으로, ''꼭 시켜야 한다''고 강력히 추천하며 포장까지 해갔습니다. 전반적으로 음식의 간이 세지 않아 입안이 깔끔했으며, 이번 방문을 계기로 다른 평양냉면 맛집도 찾아다니고 싶다는 긍정적인 반응을 보였습니다.'),
('유엔가든', '서울 용산구 독서당로20길 7', '02-3785-1113', ARRAY['고기'], 'https://www.youtube.com/watch?v=niKjpsJ3naM', 37.533614, 127.009276, '서울특별시', '쯔양은 대표 메뉴인 ''손차돌'' 20인분과 된장찌개를 주문했습니다. 손으로 직접 썰어내어 두께가 있는 차돌박이는, 지방 부분의 오독오독한 식감과 부드러운 살코기의 조화가 완벽하며 육즙이 풍부하다고 극찬했습니다. 특히 일반 차돌박이보다 더 고소하고 진한 맛이 특징이라고 평가했습니다. 함께 먹은 된장찌개는 집된장으로 끓인 듯한 깊고 구수한 맛이 일품이라며 여러 차례 감탄했고, 따로 포장하고 싶을 정도라고 말했습니다. 고기가 기름지고 풍미가 강해 20인분을 다 먹지는 못했지만, 맛 자체는 매우 훌륭하여 꼭 다시 방문하고 싶은 곳이라고 언급했습니다.'),
('어랑추', '경기도 구리시 동구릉로 145', '031-568-6866', ARRAY['한식'], 'https://www.youtube.com/watch?v=vcxz6LfElKM', 37.6116285, 127.1374902, '경기도', '쯔양은 대표 메뉴인 묵은지 고등어조림과 함께 떡갈비, 메밀전병을 주문했습니다. 먼저 묵은지 김치를 맛보고 ''새콤하면서 생선 맛이 나는 게 맛있다''고 평가했으며, 매우 이상적인 묵은지로 단맛과 신맛의 조화가 완벽하고 부드러워 입에서 녹는다고 극찬했습니다. 고등어는 살이 통통하고 고소하며, 특히 뱃살이 맛있다고 언급했습니다. 뼈를 발라 먹는 수고를 감수할 만큼 맛이 좋다고 했으며, 묵은지와 고등어의 조합이 훌륭하다고 여러 번 강조했습니다. 나중에는 남은 국물에 김과 고등어 살을 넣어 비빔밥을 만들어 먹으며 ''참치김치볶음밥 같은 식감''이라고 표현하는 등 매우 만족스러운 식사를 했습니다. 가족을 위해 포장해 가고 싶다는 말을 남기기도 했습니다.'),
('맥도날드 굽은다리역DT점', '서울 강동구 천호동 42', '070-7017-0623', ARRAY['패스트푸드'], 'https://www.youtube.com/watch?v=kr3gKEdvxCo', 37.5457197, 127.142281, '서울특별시', '쯔양은 맥도날드를 일주일에 한 번은 먹을 정도로 가장 좋아하는 햄버거 가게라고 밝혔습니다. 최애 메뉴는 불고기 버거로, 특유의 쫄깃한 번과 맛있는 소스를 극찬했습니다. 감자튀김은 갓 튀겨 나왔을 때 가장 맛있다고 평가했습니다. 또한, 상하이 치킨 스낵랩은 소스가 맛있어 버거만큼이나 좋아하며 자주 시켜 먹는 메뉴라고 언급했습니다. 이 외에도 맥스파이시 상하이 버거, 슈슈 버거, 신메뉴인 케이준 치즈 맥치킨, 맥치킨 모짜렐라 등 다양한 메뉴를 맛보며 전반적으로 모든 메뉴에 중독성 있는 맛이라며 만족감을 표현했습니다. 이날 쯔양은 총 17개의 버거와 스낵랩, 그리고 여러 사이드 메뉴와 음료를 먹었습니다.'),
('쭈꾸미도사 오목교점', '서울 양천구 오목로 313-3 1층', '0507-1335-2089', ARRAY['한식'], 'https://www.youtube.com/watch?v=GJ0TXbKNk-g', 37.5254135, 126.872361, '서울특별시', '쯔양은 ''쭈꾸미도사''의 여러 메뉴를 맛보았습니다. 메인 메뉴인 ''대창 쭈꾸미''에 대해 소스가 맛있고 쭈꾸미는 살이 통통하며 식감이 훌륭하다고 평가했습니다. 특히 대창이 느끼하지 않고 고소해, 쭈꾸미만 주문하기보다 대창과 함께 먹는 것을 강력히 추천하며 ''올해 최고의 조합''이라고 극찬했습니다. 또한, ''위험한 쭈꾸미''는 매우 맵지만 스트레스가 풀리는 맛있는 매운맛이라고 언급했으며, 삼겹살과 함께 먹으면 맵기가 조절되어 맛있다고 했습니다. 사이드 메뉴인 ''육전''은 입에서 녹을 정도로 부드럽고, ''치즈 폭탄 계란찜''은 옥수수 콘이 들어가 쭈꾸미와 잘 어울린다고 칭찬했습니다. 볶음밥 역시 남은 양념에 볶아 바닥의 누룽지까지 맛있게 먹었습니다. 전반적으로 다양한 곁들임 메뉴와 함께 즐길 수 있는 천호동 스타일의 쭈꾸미 요리에 큰 만족감을 표현했습니다.'),
('진건 감자옹심이', '경기 남양주시 진건읍 진관로501번길 12-1', '031-575-3276', ARRAY['한식'], 'https://www.youtube.com/watch?v=s3NW0nDh15s', 37.6532645, 127.1545327, '경기도', '쯔양은 비 오는 날씨에 감자전이 먹고 싶어 방문했으며, 식당의 요청으로 상호와 위치는 비공개라고 밝혔습니다. 주력 메뉴인 감자전에 대해 "정말 쫀득하고 맛있다"고 평가하며, 감자가 덩어리로 씹히는 식감을 칭찬했습니다. 갈아서 만든 감자전을 선호하는데 이 집이 바로 그런 방식이라 마음에 들어 했습니다. 또 다른 대표 메뉴인 감자옹심이는 쫀득한 식감은 훌륭하지만, 맛이 다소 심심하게 느껴질 수 있다고 평했습니다. 보리밥은 여러 나물과 된장, 고추장, 참기름을 넣어 비빔밥으로 만들어 먹으며 "오랜만에 먹어서 너무 맛있다"고 감탄했습니다. 함께 나온 청국장은 냄새가 강하지 않고 깔끔한 맛이라고 언급했습니다. 전반적으로 "집밥 같은 느낌"의 식사였으며, 왜 항상 손님이 많은지 알 것 같은 맛집이라고 총평했습니다. 맛에 매우 만족하여 감자전과 옹심이국을 추가로 포장하기도 했습니다.'),
('충무연어', '서울특별시 중구 충무로2길 33-1', '+82222748769', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=1m3NVZm5n_A', 37.5624278, 126.9950442, '서울특별시', '쯔양은 2kg의 연어와 햄치즈를 주문했습니다. 연어에 대해 전혀 비린 맛이 없고 매우 부드럽고 맛있다고 극찬했습니다. 특히 기름지고 부드러운 뱃살을 선호했으며, 쫄깃한 꼬리살과의 식감 차이를 설명했습니다. 간장, 와사비, 양파, 케이퍼 등 다양한 조합으로 연어를 즐겼으며, 처음 먹어보는 케이퍼가 연어의 느끼함을 중화시켜준다고 평가했습니다. 함께 주문한 햄치즈 또한 중독성 있고 맛있다고 언급했습니다. 또한, 70대 사장님 혼자 가게를 운영하시기 때문에 손님이 많을 경우 음식이 늦게 나올 수 있다는 정보를 전달했습니다.'),
('한뭉티기', '서울특별시 송파구 올림픽로35길 124 장미A상가 지하1층', '0507-1316-2203', ARRAY['고기'], 'https://www.youtube.com/watch?v=SFpOByAR_GQ', 37.5173527, 127.1007382, '서울특별시', '쯔양은 잠실 장미상가에 위치한 ''한뭉티기''를 방문하여 뭉티기(생고기) 10접시를 주문했습니다. 음식이 나오자, 접시를 뒤집어도 고기가 떨어지지 않을 정도로 신선하다고 감탄했습니다. 그는 뭉티기 본연의 맛을 느끼기 위해 처음에는 아무것도 찍지 않고 먹었고, 신선해서 식감이 매우 쫄깃하고 아삭하기까지 하다고 평가했습니다. 또한, 특제 소스, 주먹밥, 생송이버섯, 그리고 간장과 와사비를 곁들인 초밥 등 다양한 방식으로 뭉티기를 즐겼으며, 특히 달콤한 간장에 찍어 먹는 초밥 조합을 최고로 꼽았습니다. 고기에서 잡내가 전혀 나지 않고 신선함이 돋보인다고 مراراً و تكراراً 언급했으며, 함께 나온 소고기뭇국도 맛있다고 칭찬했습니다. 쯔양은 음식이 정말 맛있을 때만 나온다는 ''진실의 손동작''을 보여주며 10접시를 모두 비웠습니다.'),
('순살만공격 중동유니시티점', '경상남도 창원시 의창구 중동중앙로 47', '070-8287-1486', ARRAY['치킨'], 'https://www.youtube.com/watch?v=JruMgt9YEqM', 35.256626, 128.6249983, '경상남도', '쯔양은 뼈를 발라 먹는 것을 번거로워 평소 순살 치킨을 선호하는데, 이 가게는 순살, 특히 닭다리살만 사용해서 좋다고 언급했습니다. 신메뉴인 ''바네요''(BBQ 치킨 4종)와 대표 메뉴인 ''치파포 V2.0''(치킨 5종과 감자튀김), 그리고 치즈볼을 주문했습니다. ''바네요''의 스모크 칠리 맛은 바베큐 맛이 진하고 고기가 부드러워 맛있다고 평가했고, ''치파포''의 다양한 맛(소이 아이올리, 오리지널 양념, 트러플 크림, 치폴레, 파닭, 블랙 크림)을 모두 맛보며 각각의 소스가 가진 개성이 뚜렷하고 맛있다고 칭찬했습니다. 특히 트러플 크림 맛을 ''고급 레스토랑급''이라며 극찬했고, 밥과 함께 먹는 간장 바베큐 맛도 훌륭하다고 평가했습니다. 바삭한 튀김옷과 촉촉한 닭고기의 식감에 매우 만족하며, 여러 가지 맛을 한 번에 즐길 수 있어 친구나 가족 모임에 안성맞춤이라고 추천했습니다. 최종적으로는 ''치파포''의 치폴레 맛과 소이 아이올리 맛, 그리고 ''바네요''의 크림 트러플 맛을 가장 인상 깊었던 메뉴로 꼽았습니다.'),
('평화족발', '전북 군산시 신금길 18', '063-446-2804', ARRAY['분식'], 'https://www.youtube.com/watch?v=JRdqDre3abw', 35.9831265, 126.720339, '전라북도', '쯔양은 군산 공설시장 내 50년 전통의 분식집 ''평화족발''을 방문하여 매운 잡채, 족발, 김밥, 열무국수, 잡탕 등 다양한 메뉴를 맛보았습니다. 특히 이곳의 명물인 ''매운 잡채''에 대해 짬뽕처럼 보이지만 전골의 깊은 국물 맛과 볶음의 매콤함이 조화를 이룬 이색적인 메뉴라고 평가했습니다. 또한 오이가 들어가지 않은 김밥은 맛이 깔끔하다고 언급했으며, 라면, 만두, 떡 등이 푸짐하게 들어간 ''잡탕''도 인상적인 메뉴로 소개했습니다.'),
('원조짜장우동', '서울특별시 동대문구 장한로 65', '02-2246-1970', ARRAY['중식'], 'https://www.youtube.com/watch?v=XWJTe4a-R3c', 37.5668659, 127.0679259, '서울특별시', '쯔양은 이 식당이 40년 이상 운영된 노포 기사식당이라는 점을 언급하며 여러 메뉴를 주문했습니다. **짜장면밥**은 면과 밥이 함께 나오는 형태로, 짜거나 싱겁지 않은 깊은 맛이 특징이라고 평가했습니다. **기계 짬뽕**은 양이 매우 푸짐하고 국물이 얼큰하고 칼칼하다고 말했습니다. **기계 우동**의 면은 일반적인 기계 우동면과 두꺼운 우동면의 중간 식감이라고 설명했습니다. **잔치국수**는 일반 소면이 아닌 생면을 사용한 점이 독특하다고 언급했습니다. 전반적으로 모든 음식의 양이 많고 맛있어 만족스러운 식사였다고 총평했습니다.'),
('메란명가', '전남 곡성군 곡성읍 곡성로 822', '061-363-9955', ARRAY['한식'], 'https://www.youtube.com/watch?v=ovyce1nfjfA', 35.2780771, 127.2941542, '전라남도', '곡성의 특산물인 토란과 멜론을 사용한 반찬이 인상적이라고 평가했습니다. 특히 흑돼지는 지방이 아삭하고 소스가 맛있다고 언급했으며, 멜론과 와사비를 섞은 소스가 고기와 잘 어울린다고 했습니다. 감자와 고구마를 섞은 듯한 맛의 토란 튀김도 언급했으며, 반찬으로 비빔밥을 만들어 먹으며 양이 푸짐하고 맛있다고 만족감을 표했습니다.'),
('생선나라&단비', '전남 곡성군 곡성읍 중앙로 145', '061-363-9288', ARRAY['한식'], 'https://www.youtube.com/watch?v=ovyce1nfjfA', 35.2827569, 127.2977677, '전라남도', '이곳의 깨비정식은 첫 번째 식당과 달리 간장 베이스 양념이며, 고기의 식감과 지방 비율은 비슷하지만 양념이 완전히 다르다고 설명했습니다. 갑오징어, 쭈꾸미, 새우가 들어간 ''갑쭈새''는 독특한 조합이라고 평가했습니다. 전체적으로 양념이 너무 강하지 않고 ''딱 좋다'', ''완벽하다''고 칭찬하며 음식에 만족했습니다.'),
('곡성본때', '전남 곡성군 곡성읍 군청로 47', '061-362-5585', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=ovyce1nfjfA', 35.2815009, 127.2908998, '전라남도', '마침 국물이 먹고 싶었는데 감자탕이 있어 만족스러워하며, 국물이 매우 진하고 좋다고 평가했습니다. 깨비정식 고기는 1인분에 300g으로 양이 매우 푸짐하고 저렴하다며 놀라워했습니다. 양념은 매콤한 간장 베이스로 이전 식당들과 또 다른 맛이라고 설명했습니다. 감자탕 고기가 입에서 녹을 정도로 부드럽다고 칭찬했으며, 토란이 들어간 돌솥밥도 맛있게 먹었습니다.'),
('수조개전골', '대전 유성구 신성로84번길 20', '042-867-0035', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=2JfAGNXldxw', 36.3901319, 127.3502376, '대전광역시', '쯔양은 가리비가 제철이라 그런지 매우 부드럽고 입에서 녹는 맛이라고 극찬했습니다. 조개 자체의 짭짤한 맛이 강해 간장이나 초장 같은 별도의 소스가 거의 필요 없다고 평가하며, 본연의 맛을 즐기기 위해 소스를 적게 찍어 먹는 것을 선호한다고 언급했습니다. 오랜만에 먹는 조개찜이 정말 맛있다고 여러 번 감탄했으며, 찜기 아래에 깔린 양배추와 콩나물, 그리고 국물과의 조합도 훌륭하다고 말했습니다. 특히 치즈를 추가하여 가리비와 함께 먹는 것을 즐겼습니다.'),
('유키사키', '서울 용산구 후암로57길 51-3 1층', '0507-1367-4748', ARRAY['아시안'], 'https://www.youtube.com/watch?v=hD-rCascWOQ', 37.5512012, 126.9741788, '서울특별시', '쯔양은 5인분 분량의 점보 탄탄면을 20분 안에 먹는 도전 먹방을 진행했습니다. 그녀는 이곳이 도전 성공자가 4명뿐인 어려운 곳이라고 언급했습니다. 음식의 맛에 대해서는 국물이 맛있고 고소하면서도 매콤한 맛이 일품이라고 평가했으며, ''너무 좋아서 멈출 수가 없다''고 감탄했습니다. 면발도 아주 잘 익었고, 부드러운 차슈와 반숙 계란 등의 고명도 훌륭하다고 칭찬했습니다. 특히, 견과류의 고소함과 매콤함이 어우러진 국물을 ''상쾌한 매운맛''이라고 표현하며 눈물을 흘리면서도 계속 먹을 정도로 맛있다고 했습니다. 엄청난 크기의 그릇에 담긴 양과 뜨거움, 그리고 점점 강해지는 매운맛 때문에 힘들어했지만, 결국 46초를 남기고 도전에 성공하여 명예의 전당에 5번째로 이름을 올렸습니다.'),
('골목떡볶이', '서울 송파구 문정로1길 33', '02-3402-3452', ARRAY['분식'], 'https://www.youtube.com/watch?v=DqJ4EqRpA0M', 37.4890663, 127.1234844, '서울특별시', '유튜버는 서울 3대 떡볶이 맛집 중 하나로 알려진 문정동의 골목 떡볶이를 방문했습니다. 이곳의 대표 메뉴인 국물 떡볶이와 순대, 튀김만두를 주문했습니다. 국물은 마치 찌개처럼 깊은 맛이 나며 해장용으로도 좋다고 평가했습니다. 떡은 밀떡으로, 겉은 허물어질 정도로 부드럽지만 속은 쫀득하며 국물이 잘 배어있다고 설명했습니다. 전체적인 맛은 익숙하면서도 매콤달콤하고 감칠맛이 돌아 추억을 불러일으키며, 먹을수록 중독성이 강해진다고 합니다. 맵기는 강하지 않고 깔끔한 편이며, 순대와 만두를 국물에 찍어 먹는 조합을 즐겼습니다. 특히 만두가 맛있어서 추가로 주문하기도 했습니다. 유튜버는 이곳을 아차산의 ''신토불이''와 함께 최고의 떡볶이 맛집 중 하나로 꼽았습니다.'),
('고우가 잠실본점', '서울 송파구 올림픽로32길 22-19 1층', '0507-1422-9280', ARRAY['고기'], 'https://www.youtube.com/watch?v=GPBfFGgLQSs', 37.5135501, 127.1085735, '서울특별시', '쯔양은 양갈비를 12인분 주문해서 먹었습니다. 직원이 직접 구워주어 먹기 편했다고 언급했습니다(4:50). 고기가 레어 상태로 익혀져 나와 매우 부드러운 식감이었고, 양고기 특유의 향이 강하지 않아 좋았다고 평가했습니다(4:43). 특히 뼈에 붙은 살코기 부분이 맛있다고 했으며(6:04), 토마토, 파인애플 등 다양한 가니쉬와 곁들여 먹는 점을 장점으로 꼽았습니다. AI 비서를 통한 예약이 매우 편리했다고도 덧붙였습니다(6:16).'),
('별미곱창 잠실본점', '서울 송파구 올림픽로32길 22 1층', '02-421-9984', ARRAY['고기'], 'https://www.youtube.com/watch?v=GPBfFGgLQSs', 37.5140651, 127.1093412, '서울특별시', '쯔양은 소곱창 4인분, 쫄쫄이살, 사이드 메뉴 등을 주문했습니다. 쫄쫄이살은 쫀득하고 살짝 끈적한 식감이 특징이라고 설명했습니다(13:52). 곱창은 안에 곱이 가득 차 있어 매우 고소하고 맛있다고 극찬했으며(16:01), 특히 구운 대파와 함께 먹는 조합을 추천했습니다(14:42). 크림처럼 부드러운 맛이 난다고도 표현했습니다(14:15). 식사를 마친 후, 부산 여행 중 가장 인상 깊었던 맛집으로 꼽았던 ''연지가양곱창''과 비교하며 이곳의 곱창도 정말 맛있다고 평가했습니다(16:59).'),
('일미간장게장', '서울 동대문구 장한로24길 7', '02-2242-4338', ARRAY['한식'], 'https://www.youtube.com/watch?v=fcWQMtEjwJY', 37.5709072, 127.0715196, '서울특별시', '쯔양은 2년 만에 이 식당을 재방문했으며, 간장게장과 양념게장을 각각 2인분씩(총 16마리) 주문했습니다. 간장게장은 알이 가득 차 있고 전혀 비리지 않으며 매우 맛있다고 평가했습니다[attached_file:1, ts:214, 223]. 양념게장 역시 알이 꽉 차 있으며 약간 매우면서도 아주 맛있다고 언급했습니다[attached_file:1, ts:352, 383]. 특히 게딱지와 몸통의 살, 알, 내장을 모두 발라내 밥, 김, 날치알, 계란 노른자를 넣어 비빔밥을 만들어 먹는 것을 ''천상의 맛''이라고 표현하며 극찬했습니다[attached_file:1, ts:560-681]. 함께 나온 된장찌개도 맛있다고 칭찬했으며, 사장님의 친절함에 대해서도 감사함을 표했습니다[attached_file:1, ts:182, 912].'),
('명랑식당', '서울특별시 서초구 방배중앙로25길 38', '02-591-2252', ARRAY['고기'], 'https://www.youtube.com/watch?v=z7YR9ftkwB0', 37.4940367, 126.983978, '서울특별시', '쯔양은 40년 전통의 방배동 맛집 ''명랑식당''에서 2+ 등급 한우 특수부위를 맛보았습니다. 살치살, 제비추리, 차돌박이 등 다양한 소고기 부위와 항정살, 갈매기살 같은 돼지고기를 주문했습니다. 고기의 신선함과 풍부한 육즙, 부드러운 식감에 대해 ''세상에 이런 맛이 있나''라며 극찬을 아끼지 않았습니다. 특히, 메뉴에 없는 짜파게티를 특별 주문하여 고기와 함께 먹으며 ''환상적인 조합''이라고 평가했습니다. 전반적으로 음식 맛과 품질에 대해 매우 높은 만족감을 표현하며 ''역대급 먹방''을 선보였습니다.'),
('훼드라', '서울 서대문구 연세로5길 32', '02-323-3201', ARRAY['분식'], 'https://www.youtube.com/watch?v=BTkB2PiuKeA', 37.5563652, 126.9353823, '서울특별시', '쯔양은 신촌에 위치한 50년 전통의 매운 라면 맛집 ''훼드라''를 방문했다. 그녀는 이곳의 대표 메뉴인 ''최루탄 해장라면'' 보통맛과 매운맛, 그리고 짜파구리를 주문했다. 먼저 기본 해장라면을 맛본 쯔양은 기분 나쁘지 않게 매우면서 스트레스가 풀리는 맛이라고 평가하며 감탄했다. 함께 주문한 짜파구리는 촉촉하고 약간 매콤하면서 감칠맛이 좋다고 언급했다. 이어서 도전한 매운맛 해장라면은 냄새부터 코를 찌를 정도로 강렬했지만, 기분 좋은 매운맛과 함께 감칠맛이 훨씬 진하고 맛있다고 극찬했다. 쯔양은 전반적으로 음식이 매우면서도 맛있어서 오랜만에 스트레스를 풀며 맛있게 먹었다고 총평하며 만족감을 드러냈다.'),
('안동반점', '서울특별시 성북구 고려대로1길 35-1', '02-923-4448', ARRAY['중식'], 'https://www.youtube.com/watch?v=jo-HOeXozr0', 37.5870582, 127.018948, '서울특별시', '쯔양은 이 식당의 여러 메뉴에 대해 전반적으로 매우 긍정적인 평가를 내렸습니다. ''옛날식 짜장면''은 너무 달지 않고 완벽한 맛이라고 칭찬했으며, 사장님이 추천한 ''짬뽕''은 시원하고 깔끔한 국물 맛이 일품이라고 했습니다. ''탕수육''은 겉은 매우 바삭하고 속은 부드러워 계속 손이 가는 맛이라고 평가했고, 이곳의 시그니처 메뉴인 ''잡채밥''은 볶음밥 위에 양이 푸짐한 잡채가 올라가 있으며, 특히 면발이 매우 쫄깃한 식감이 인상적이라고 언급했습니다. 처음 먹어보는 ''난자완스''는 떡갈비와 비슷한 독특한 식감으로 맛있다고 했으며, ''군만두'' 또한 바삭하고 맛있다고 평가했습니다.'),
('BBQ치킨대학', '경기도 이천시 마장면 서이천로 528번길 191', '031-635-8461', ARRAY['치킨'], 'https://www.youtube.com/watch?v=g7eXVZlbyUQ', 37.2706608, 127.413271, '경기도', '쯔양은 다양한 BBQ 메뉴를 시식했습니다. ''자메이카 통다리 구이''는 거대한 크기와 부드러운 살, 매콤한 바베큐 같은 소스가 특징이라고 평하며 너무 맛있어서 아쉬울 정도라고 말했습니다({ts:245.0}, {ts:606.33}). ''황금올리브치킨''은 특히 ''만체고 치즈 소스''와의 조합을 극찬하며, 시간이 지나도 바삭하고 육즙이 풍부하다고 언급했습니다({ts:281.0}, {ts:446.0}, {ts:727.449}). ''양념 순살''은 달콤해서 누구나 좋아할 맛이라고 설명했습니다({ts:333.0}). 이 외에도 새우살이 가득한 ''새우 스틱''과 초코, 고구마 등 다양한 ''치즈볼''도 맛있게 먹었습니다({ts:364.0}, {ts:378.0}). 쯔양은 이달에만 BBQ 치킨을 세 번째 먹을 정도로 만족감을 표현했습니다({ts:256.38}).'),
('허니돈 의정부점', '경기도 의정부시 평화로536번길 5', '0507-1347-5761', ARRAY['분식'], 'https://www.youtube.com/watch?v=rOVZ4kDCWmw', 37.7398547, 127.0479391, '경기도', '쯔양은 과거에 방문했던 매우 저렴한 분식점 ''허니돈''을 오랜만에 다시 찾아갔습니다. 국수가 1,000원, 탕수육이 1,500원이던 시절을 회상하며, 일부 메뉴 가격이 올랐음에도 여전히 믿을 수 없는 ''가성비''를 자랑한다고 평가했습니다. 탕수육, 떡볶이, 멸치국수, 비빔국수, 야끼만두 등 가게의 모든 메뉴를 주문했습니다. 쯔양은 가격에 비해 양이 푸짐하고 맛도 훌륭하다며 감탄했고, 특히 탕수육은 웬만한 중국집보다 맛있다고 칭찬했습니다. 새콤달콤한 떡볶이와 간단하게 즐기기 좋은 국수 메뉴 모두에 만족감을 표하며, 학생들이나 간단한 식사를 원하는 사람들에게 완벽한 곳이라고 언급했습니다. 전 메뉴를 주문해도 만 원이 채 되지 않는 ''가성비 끝판왕'' 식당으로 강력 추천했습니다.'),
('은주정', '서울 중구 창경궁로8길 32', '02-2265-4669', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=go59i01SGhc', 37.5686832, 126.9997668, '서울특별시', '쯔양은 이곳을 예전부터 와보고 싶었던 ''서울 3대 김치찌개'' 맛집으로 알고 있었습니다. 4인분을 주문했는데, 양이 8인분처럼 매우 푸짐하다고 놀라워했습니다. 국물은 처음엔 맵지만 끝 맛은 감칠맛과 단맛이 돌아 조화롭다고 평가했으며, 너무 시지 않고 밸런스가 아주 좋다고 칭찬했습니다. 특히 비계가 붙은 고기가 아주 많이 들어있어 김치찌개가 아니라 ''고기찌개'' 같다고 만족감을 표했습니다. 이곳의 특징인 상추쌈에 밥과 고기, 김치, 쌈장을 넣어 먹는 방식이 색다른 맛을 준다고 했으며, 김과 함께 먹는 조합이 환상적이라고 극찬했습니다. 마지막에는 남은 국물에 스팸, 계란 프라이를 넣어 비벼 먹으며 맛있게 식사를 마무리했습니다.'),
('에이스분식', '대전 동구 대전로785번길 52', '010-3415-9687', ARRAY['분식'], 'https://www.youtube.com/watch?v=xRyaIyl8quc', 36.3289548, 127.4307328, '대전광역시', '떡볶이는 쫄깃한 밀떡으로 만들어졌으며, 너무 달지 않고 중독성 있는 시장 떡볶이의 맛이라고 평가했습니다. 특히 튀김이 아주 맛있다고 칭찬했으며, 수제로 만든 김말이 튀김은 속이 부드럽고 맛있다고 언급했습니다.'),
('개천식당', '대전 동구 대전로791번길 34', '042-256-5627', ARRAY['한식'], 'https://www.youtube.com/watch?v=xRyaIyl8quc', 36.329571, 127.4314117, '대전광역시', '이북식 만두 전문점으로, 70년의 역사를 가지고 있다고 소개했습니다. 만둣국 국물이 매우 시원하고 깔끔하며 맛있다고 평가했고, 만두는 속이 두부와 고기로 꽉 차 있고 피가 얇다고 칭찬했습니다. 특히 튀김만두가 이 집의 최고 메뉴라고 들었다며, 겉은 부드럽고 속은 꽉 차있어 특별한 맛이 있다고 극찬했습니다. 김치만두와 고기만두 역시 속이 꽉 차 맛있다고 언급하며 총 6그릇을 먹어치웠습니다.'),
('고동경양 문래본점', '서울 영등포구 경인로72길 4 1층', '0507-1398-7124', ARRAY['양식'], 'https://www.youtube.com/watch?v=4K6I8tXP_MM', 37.510646, 126.8921049, '서울특별시', '쯔양은 해당 식당의 전체 메뉴를 먹어보는 ''먹방''을 진행했습니다. 기본 ''고동 함박''은 육즙이 터져 나오는 점을 극찬하며 고기와 소스 모두 훌륭하다고 평가했습니다. 함박고기를 돈까스처럼 튀긴 ''고순카츠''와 바삭한 ''순대튀김''도 맛있다고 언급했습니다. ''깔매함박''은 매콤한 맛을 좋아하는 사람에게 완벽하며 소스가 훌륭하다고 말했습니다. ''월드클래스 함박''은 진한 체다 치즈 맛과 약간의 매콤함이 조화롭다고 평했으며, ''로제 함박''과 ''혜자버거'' 역시 맛있게 먹었습니다. 쯔양은 전반적으로 모든 메뉴의 육즙이 풍부하고 맛이 뛰어나다고 만족감을 표현했으며, 총 1.7~1.8kg의 함박 스테이크를 먹었다고 영상에 기록되었습니다.'),
('나정순할매쭈꾸미', '서울 동대문구 무학로 144', '02-928-0231', ARRAY['한식'], 'https://www.youtube.com/watch?v=Iy80EP6v01s', 37.5770942, 127.0307078, '서울특별시', '쯔양은 이 집의 주꾸미 볶음이 스트레스가 풀리는, 맛있게 매운맛이라고 평가했습니다. 처음에는 약간 달콤하면서도 단맛과 짠맛의 조화가 좋다고 언급했습니다. 특히, 오래 익혀도 주꾸미가 질겨지지 않고 부드러운 식감을 유지하는 점을 칭찬했습니다. 깻잎 뒷면에 켈프 누들과 마늘을 함께 싸 먹는 방법을 추천받았으며, 평소 켈프 누들을 선호하지 않음에도 불구하고 이 조합이 맛있다고 느꼈습니다. 매운맛을 중화시키기 위해 마요네즈를 듬뿍 곁들여 먹는 것을 즐겼습니다. 1인분(350g)의 양이 매우 푸짐하며, 다른 채소 없이 오직 주꾸미와 버섯으로만 구성된 점이 특징이라고 설명했습니다. 마지막에는 볶음밥과 된장찌개를 주문하여 식사를 마무리했으며, 볶음밥 역시 매우 뜨겁고 맛있다고 평가했습니다. 전체적으로 매운맛의 강도는 ''틈새라면''과 비슷하다고 요약했습니다.'),
('옥천옥', '서울 동대문구 하정로 16', '02-2292-8201', ARRAY['한식'], 'https://www.youtube.com/watch?v=-8wi-fVqTwk', 37.5724851, 127.0269985, '서울특별시', '쯔양은 이 집의 주력 메뉴인 도가니 수육을 자신의 ''최애 음식 Top 5'' 안에 든다고 소개하며 방문했습니다. 도가니는 매우 쫄깃하고 부드러우며, 특히 따뜻하게 데워 먹을 때 그 식감이 살아난다고 평가했습니다. 간장 소스나 소금에 찍어 먹는 것을 추천했으며, 설렁탕 국물에 넣어 먹는 것도 별미라고 언급했습니다. 설렁탕 국물은 오랜 시간 푹 고아낸 깊은 맛이 나며, 머리고기가 들어가 특유의 풍미가 있다고 설명했습니다. 함께 맛본 김치와 깍두기도 맛있다고 칭찬했습니다. 호기심에 주문한 ''등골''은 참기름 맛과 부드러운 식감을 가졌지만, 생소한 모양 때문에 호불호가 갈릴 수 있는 메뉴라고 평했습니다. 전반적으로 도가니 수육에 대한 높은 만족감을 표현하며, 마지막에는 남은 국물에 밥을 말아 식사를 마무리했습니다.'),
('시장떡볶이', '서울 강북구 노해로17길 21', '02-903-5809', ARRAY['분식'], 'https://www.youtube.com/watch?v=mA1U63BS-AQ', 37.6403382, 127.02117, '서울특별시', '쯔양은 떡볶이 5인분, 순대, 김밥, 어묵, 만두, 계란 등 다양한 메뉴를 주문했습니다. 떡볶이는 어린 시절 학교 앞에서 먹던 맛을 떠올리게 하는, 고추장 맛이 강하고 달콤하며 중독성 있는 옛날식 떡볶이라고 평가했습니다 . 쌀떡의 쫀득한 식감을 특히 칭찬했으며 , 소스가 매우 맛있다고 언급했습니다 . 만두는 식었음에도 불구하고 바삭함이 유지되어 있었고 , 어묵 국물은 매운맛을 중화시켜주는 최고의 조합이라고 말했습니다 . 81세의 사장님이 48년간 한자리를 지켜온 것에 대한 존경심을 표하며 , 주문한 음식을 모두 먹어치울 만큼 맛에 대해 매우 만족했습니다 .'),
('신사한우곱창', '서울특별시 은평구 갈현로 30 신사동빌딩 1층', '02-3239-2834', ARRAY['고기'], 'https://www.youtube.com/watch?v=nOoAc-IZ8i4', 37.6005673, 126.9104796, '서울특별시', '쯔양은 이곳을 ''숨겨진 맛집''이라고 소개하며, 곱창 19인분과 막창, 대창, 염통, 볶음밥까지 먹었습니다. 곱창은 매우 고소하고 풍미가 깊으며, 속의 곱이 가득 차 촉촉하다고 평가했습니다. 특히 느끼하지 않고 고소한 맛이 일품이라고 칭찬했으며, 함께 나오는 와사비 맛이 나는 부추무침과 김치가 곱창과 잘 어울린다고 언급했습니다. 곱창 기름에 구운 감자와 버섯도 별미로 꼽았으며, 볶음밥은 간장 베이스의 독특한 맛으로 중독성이 강하다고 리뷰했습니다. 너무 맛있어서 원래 계획했던 15인분보다 더 많이 먹게 되었다고 말할 정도로 만족스러운 식사였다고 밝혔습니다.'),
('해심수산', '인천 남동구 소래역로 12 소래포구종합어시장 1층 256호', '0507-1425-7517', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=IUvjIG3Bwqw', 37.3987238, 126.7371877, '인천광역시', '쯔양은 이곳에서 12~15인분에 해당하는 10kg(22파운드)가 넘는 거대한 대방어를 보고 크기에 감탄했습니다. 사장님은 혼자서는 다 못 먹을 것이라고 했지만, 쯔양은 한 마리 전체를 구매하기로 결정했습니다. 이곳은 쯔양이 먹방을 위해 대방어를 직접 구매한 곳입니다.'),
('춘천골닭갈비', '서울 광진구 면목로 105', '02-464-7942', ARRAY['한식'], 'https://www.youtube.com/watch?v=CBhRIsc_14A', 37.5630362, 127.0795482, '서울특별시', '쯔양은 23년 전통의 맛집으로, 서울에서 가장 클 것이라 추정되는 47cm 대형 철판에 나오는 점이 인상적이라고 말했습니다. 대표 메뉴인 낙지닭갈비 10인분을 주문하여 먹방을 진행했습니다. 소스에 대해 해산물 향이 살짝 나면서도 짜지 않고 중독성 강한 맛이라고 극찬했으며, 닭고기는 매우 부드럽고 낙지는 쫄깃해 두 재료의 조화가 훌륭하다고 평가했습니다. 깻잎, 무쌈, 김치 등 다양한 조합으로 즐겼으며, 특히 양념이 졸아들어 걸쭉해졌을 때가 가장 맛있다고 강조했습니다. 전반적으로 음식에 매우 만족하며 말을 잃을 정도로 먹는 데 집중하는 모습을 보였습니다.'),
('혜성칼국수', '서울 동대문구 왕산로 247-1', '02-967-6918', ARRAY['한식'], 'https://www.youtube.com/watch?v=dcxQA9WRuq8', 37.5834282, 127.0489994, '서울특별시', '쯔양은 많은 구독자들이 추천한 1968년에 개업한 청량리의 칼국수 맛집 ''혜성칼국수''에 방문했습니다. 메뉴는 닭칼국수와 멸치칼국수 두 가지입니다. 쯔양은 닭칼국수 3그릇과 멸치칼국수 2그릇을 주문했습니다. 먼저 멸치칼국수는 아침에 직접 뽑은 면이라 쫄깃하고 국물이 매우 깊고 구수하며, 짜지 않으면서도 강한 맛이 특징이라고 평가했습니다. 가게에서 직접 담근 김치는 집에서 만든 것 같은 맛으로 칼국수와 잘 어울린다고 언급했습니다. 닭칼국수는 닭고기 고명이 올라가 있으며, 기본적인 국물 맛은 멸치칼국수와 비슷하지만 닭 맛이 더해져 진하고 맛있다고 했습니다. 특히, 함께 제공되는 다진 마늘 양념을 넣어 먹으면 맛이 완전히 달라지며, 마늘의 강한 맛이 개운함을 더해줘 더 선호한다고 밝혔습니다. 시간이 지나도 면이 불지 않고 탄력이 유지되는 점을 칭찬했으며, 국물 맛이 점점 더 진해지는 것을 즐겼습니다. 개인적으로는 고기가 들어있는 닭칼국수를 조금 더 선호한다고 말했습니다.'),
('굴과찜사랑', '서울 성동구 행당로17길 23', '02-2296-9922', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=rWkqKiqyOIA', 37.5603587, 127.0329177, '서울특별시', '쯔양은 겨울 제철을 맞은 굴을 먹기 위해 식당을 방문하여 굴찜(대자 3개)과 굴전을 주문했습니다. 서비스로 나온 생굴이 비리지 않고 우유처럼 신선하다고 칭찬했으며, 굴전은 크기가 매우 크고 속에 굴이 가득 차 있어 아주 맛있다고 평가했습니다. 산처럼 쌓여 나온 굴찜은 양이 매우 많았지만, 굴이 크고 살이 통통하며 입에서 녹을 정도로 부드럽고 비린 맛이 전혀 없다고 감탄했습니다. 초장, 쌈장 등 어떤 양념과도 잘 어울린다고 언급했습니다. 쯔양은 이날 약 200개의 굴을 먹어치우며 15년 만에 가게 신기록을 세웠고, 물리지 않고 끝까지 맛있게 먹었다며 전반적으로 매우 만족스러운 반응을 보였습니다.'),
('현대실비', '강원특별자치도 태백시 시장북길 9', '033-552-6324', ARRAY['고기'], 'https://www.youtube.com/watch?v=ytgDdVzUUy8', 37.1733565, 128.9921688, '강원특별자치도', '쯔양은 연탄에 구워 먹는 소고기는 처음이라고 기대감을 보이며, 채끝, 치마살, 등심, 갈비살, 안창살, 살치살 등 다양한 부위를 주문했습니다 . 채끝은 연탄향이 배어 향이 좋고 씹는 맛이 있다고 평가했고, 치마살은 기름기가 빠져 담백하며 쫄깃하고 뽀독한 식감과 함께 터져 나오는 육즙을 칭찬했습니다 . 등심은 부위마다 맛이 다른 것을 실감하며 부드럽고 맛있다고 감탄했고, 갈비살은 특유의 강한 육향이 일품이라고 말했습니다 . 여러 부위를 맛본 후 쯔양은 안창살을 1위로 꼽으며 ''대박''이라고 표현했고, 이어서 살치살, 등심, 꽃갈비, 갈비, 치마살, 채끝 순으로 순위를 매겼습니다 . 식사 막바지에는 양념 주물럭과 된장찌개를 맛보았는데, 주물럭은 밥과 함께 먹어야 할 맛이라고 했고, 된장찌개는 갓 담근 된장으로 끓여 아주 진하고 맛있다고 평가했습니다 .'),
('까치둥지', '강원 원주시 치악로 1731', '033-761-8008', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=PWWm9Cy4GiY', 37.3369183, 127.9561459, '강원특별자치도', '쯔양은 이 식당의 알탕을 ''전국 원탑''이 될 수 있을 정도라고 극찬했습니다(6:01). 국물은 매우 시원하고(2:24) 추운 날씨에 몸을 덥혀준다고 평가했습니다(3:12). 알은 속이 꽉 차고 크기가 클 뿐만 아니라, 전혀 퍽퍽하지 않고 매우 부드럽고 촉촉하다고 여러 차례 강조했습니다(3:47, 4:11, 8:25). 특히 다른 해물탕에 들어있는 마른 알과 달리, 한 알 한 알이 살아있는 느낌이라고 묘사했습니다(4:15). 함께 나오는 내장 역시 질기지 않고 부드러워서 놀라워했으며(5:00), 밥과 함께 비벼 먹거나(10:33) 국물에 적셔 먹는 등 다양한 방법으로 알탕을 즐겼습니다. 쯔양은 처음 4인분에 알 2인분을 추가한 뒤, 맛에 감탄하여 4인분을 더 추가하려다가 최종적으로 3인분을 추가했으며, 사장님의 서비스까지 더해 총 10인분 가량의 알을 먹었습니다(1:14, 7:02, 11:48). 국물이 졸아들수록 맛이 더욱 깊어지며, 마지막에 남은 국물에 섞인 알 조각까지 맛있게 먹었습니다(13:07).'),
('고든램지버거 롯데월드몰점', '서울 송파구 올림픽로 300 롯데월드몰 지하 1층', '02-3213-4797', ARRAY['패스트푸드'], 'https://www.youtube.com/watch?v=YuO-WQMznsw', 37.5125701, 127.1025624, '서울특별시', '쯔양은 고든램지버거의 모든 버거 메뉴를 맛보았습니다. 가장 먼저 시그니처 메뉴인 ''헬스키친 버거''를 먹고 스테이크처럼 풍미가 깊고 고소하다고 평가했습니다. 이어서 ''포레스트 버거''의 패티는 특급 한우 같고 라구 소스가 맛있다고 감탄했으며, ''1966 버거''에 대해서는 14만 원이라는 가격이 합당할 만큼 고급스러운 맛이라고 극찬했습니다. 이 버거에는 진짜 트러플이 통째로 들어가 있어 풍미가 뛰어나다고 설명했습니다. 반면, ''베지 버거''는 고기를 좋아하는 자신에게는 맞지 않지만, 채식주의자에게는 좋은 선택이 될 것이라고 언급했습니다. 쯔양은 개인적인 순위로 1위에 ''1966 버거'', 2위에 ''포레스트 버거'', 3위에 ''헬스키친 버거''를 꼽았습니다.'),
('짬뽕갑 본점', '서울특별시 관악구 신림동7길 8', '02-882-2113', ARRAY['중식'], 'https://www.youtube.com/watch?v=JUIQs7ytf5U', 37.4866844, 126.9260534, '서울특별시', '쯔양은 신림동에 위치한 중식당 ''짬뽕갑''을 방문하여 매운맛 9단계의 짬뽕에 도전했습니다. 짬뽕은 0.5단계부터 9단계까지 매운맛을 조절할 수 있는 것이 특징입니다. 쯔양은 9단계 짬뽕, 0.5단계 갑짜장, 0.5단계 갑짬뽕밥, 찹쌀 군만두, 탕수육 등을 주문했습니다. 0.5단계 짜장면은 속을 달래기 좋은 맛있는 단맛이라고 평가했고, 0.5단계 짬뽕은 감칠맛이 좋다고 언급했습니다. 메인 메뉴인 9단계 짬뽕에 대해서는, 처음에는 괜찮았지만 점차 단계적으로 강렬한 매운맛이 올라온다고 설명했습니다. 특히, 이 매운맛은 이전에 경험했던 다른 매운 음식들과는 차원이 다른 역대급 매운맛이라고 강조했습니다. 그럼에도 불구하고 단순히 맵기만 한 것이 아니라 깊은 감칠맛이 살아있어 맛있다고 평가했습니다. 탕수육은 유자 향이 나는 맛있는 탕수육이라고 했고, 짬뽕밥은 진한 사골 국물 맛이 나서 밥과 잘 어울린다고 극찬했습니다. 하지만 결국 9단계 짬뽕의 엄청난 매운맛 때문에 먹방 인생 처음으로 음식을 남기고 도전을 포기했습니다.'),
('해궁회타운', '경상북도 포항시 남구 구룡포읍 일출로 103-4', '054-276-8656', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=G5VVUL5tjIY', 36.0052739, 129.5730591, '경상북도', '쯔양은 과메기에 대해 이전에 먹어봤던 것들은 딱딱하고 말라있던 것에 비해, 이곳의 과메기는 매우 부드럽고 촉촉하며 기름진 맛이 일품이라고 평가했습니다. 특히 비린내가 전혀 나지 않아 놀라워하며, 김, 배추, 쪽파 등 다양한 채소와 곁들여 먹으며 맛을 극찬했습니다. 대게라면에 대해서는 국내산 대게 두 마리가 통째로 들어간 비주얼과 양에 감탄하며, 이렇게 많은 게가 들어간 라면은 처음 본다고 언급했습니다. 포항의 유명한 대게답게 살이 꽉 차 있고 부드러우며, 과메기를 먹은 후 해장하는 느낌으로 먹기에도 아주 좋다고 만족감을 표현했습니다.'),
('상록수', '서울 용산구 청파로51길 4', '0507-1464-9046', ARRAY['고기'], 'https://www.youtube.com/watch?v=9oZUTH09vv8', 37.5457829, 126.970026, '서울특별시', '쯔양은 이 식당의 대표 메뉴인 황지살에 대해 일반 항정살과 달리 불필요한 기름을 제거해 식감이 훨씬 쫀득하고 고소하다고 평가했습니다. 특히 구운 고사리와 함께 먹는 조합을 극찬하며, 바삭한 고사리와 쫄깃한 고기의 식감이 일품이라고 언급했습니다. 후추뽈살은 마블링이 독특하며 입에서 녹을 정도로 부드럽고 아삭한 식감이 특징이라고 설명했습니다. 주사위목살은 비계 부분의 쫀득함과 살코기의 부드러움이 조화롭다고 말했으며, 오도독갈비는 오돌뼈처럼 오독오독 씹히는 독특한 식감이 재미있다고 평가했습니다. 사이드 메뉴인 비빔수제비는 예상과 다른 맛이지만 쫄깃한 식감이 좋다고 했고, 고기찌개는 짜거나 달지 않고 맛있다고 리뷰했습니다.'),
('부산진오뎅', '서울특별시 강동구 동남로75길 13-7', '02-442-2588', ARRAY['분식'], 'https://www.youtube.com/watch?v=uoVQb2OXhzM', 37.5539265, 127.1555298, '서울특별시', '쯔양은 날씨가 추워져서 어묵 국물이 먹고 싶어 방문했습니다. 코로나로 인해 테이블마다 개별 어묵 팟을 제공하는 아이디어가 좋다고 평가했습니다. 이곳의 최고 기록(성인 2명이 50개)을 깨겠다고 선언하며 먹방을 시작했습니다. 기본 어묵, 맛살, 매운 고추, 치즈, 우엉, 쭈꾸미, 잡채, 떡 등 다양한 종류의 어묵을 맛보았으며, 특히 치즈, 잡채, 떡 어묵을 가장 좋아하여 추가 주문하려 했으나 재고를 모두 소진시켰다는 말을 들었습니다. 추가로 주문한 시사모 구이는 알이 꽉 차 있고 고소해서 마요네즈 없이도 맛있다고 평했으며, 번데기탕은 아주 맵다고 언급했습니다. 또한, 직원의 추천으로 주문한 오코노미야키는 해물파전처럼 촉촉하고 해산물이 들어있으며, 매콤한 데리야끼 소스와 가쓰오부시가 올라가 아주 맛있다고 칭찬했습니다. 식사를 마친 후, 몸이 따뜻해졌다며 만족감을 표현했습니다.'),
('그니식당', '충남 천안시 서북구 불당32길 3-10', '0507-1479-4578', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=jEM5_8SsSVE', 36.8085223, 127.1050951, '충청남도', '쯔양은 이 식당의 대표 메뉴인 어복쟁반과 소고기 수육을 먹었습니다. 3대째 이어져 온 손만두가 들어간 어복쟁반의 국물 맛이 매우 깔끔하고 담백하면서도 깊은 맛을 내 계속 먹게 된다고 평가했습니다. 소고기 수육은 매우 부드러워 입에서 녹는 듯한 식감이라고 칭찬했으며, 꽉 찬 만두 속도 맛있다고 언급했습니다. 평소 채소를 즐기지 않음에도 국물에 적신 채소는 맛있게 많이 먹는 모습을 보였습니다. 또한, 육개장 정도의 맵기인 매운 어복쟁반도 맛있게 즐겼습니다.'),
('미소의집', '서울 서초구 신반포로 27-6', '02-537-0547', ARRAY['분식'], 'https://www.youtube.com/watch?v=XhUJ-ChfPQw', 37.5023584, 126.9876922, '서울특별시', '쯔양은 이곳의 시그니처 메뉴인 ''튀김순대''를 맛보고 ''겉은 바삭하고 속은 부드러운'' 식감과 맛이 환상적이라며 극찬했습니다. 찍어 먹는 소스 또한 매우 맛있다고 평가하며 왜 사람들이 이곳을 찾는지 알겠다고 말했습니다. ''즉석떡볶이''는 너무 달지 않고 국물이 잘 배어 맛있으며, 라면과 쫄면 사리를 넣어 먹는 것을 즐겼습니다. ''양념만두''는 자극적이지 않고 바삭하며 맛있다고 평가했고, ''꼬마김밥''은 속이 꽉 차 있고 고소해서 맛있다며 튀김순대와 함께 꼭 먹어봐야 할 메뉴로 추천했습니다. 전반적으로 음식들이 너무 달거나 자극적이지 않아 식사처럼 즐길 수 있었다고 총평하며, 모든 음식을 다 먹고 튀김순대를 먹으러 다시 오겠다고 말하며 리뷰를 마쳤습니다.'),
('한남미수', '서울특별시 용산구 대사관로31길 25-9', '010-7540-4522', ARRAY['한식'], 'https://www.youtube.com/watch?v=-e0ERP2rFkY', 37.5345227, 127.0053974, '서울특별시', '쯔양은 대표 메뉴인 우니(성게알)와 육사시미의 조합에 크게 감탄했습니다. 우니는 비린 맛 없이 매우 달고 고소하며, 2+ 등급 한우를 사용한 육사시미는 향이 좋다고 평가했습니다. 두 메뉴를 함께 먹었을 때 ''고소함이 3배가 되는 폭발적인 맛''이라고 표현하며, 다양한 조합으로 먹는 방법을 보여주었습니다. 함께 주문한 오징어 라면 또한 통오징어가 들어간 비주얼을 칭찬하고, 우니와 육사시미를 곁들여 먹으며 ''믿을 수 없는 맛''이라고 극찬했습니다. 식사 내내 ''이렇게 행복했던 적이 없다''고 말할 정도로 만족했으며, 가게 사장님이 6~7년 동안 이렇게 많이 먹는 손님은 처음 봤다며 서비스를 줄 정도로 대식가로서의 면모를 보였습니다.'),
('이백장돈까스 문정점', '서울 송파구 송파대로20길 4 1층 104호', '0507-1381-3810', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=0-RhVo6P3zI', 37.4855635, 127.1232451, '서울특별시', '쯔양은 이백장돈가스 문정점에서 총 9가지 종류의 돈까스 메뉴 전체를 먹었습니다. 돈까스가 매우 바삭하고 시간이 지나도 그 식감이 유지된다고 칭찬했으며, 특히 고기가 부드럽고 잡내가 없다고 평가했습니다. ''고구마 치즈 돈까스''의 풍부한 치즈와 달콤한 고구마 무스를 극찬하며 최고의 메뉴로 꼽았고, 독특한 맛의 ''민치 돈까스''도 인상 깊었다고 말했습니다. ''악마 매운 돈까스''는 맛있게 맵다고 평가했으며, ''와사비 마요 소스''가 느끼함을 잡아주어 모든 소스를 통틀어 가장 뛰어나다고 언급했습니다.'),
('돈탐라제주냉삼1977 방이점', '서울 송파구 올림픽로32길 19-9', '02-415-8382', ARRAY['고기'], 'https://www.youtube.com/watch?v=HLzgIj9j0hs', 37.5147078, 127.1098317, '서울특별시', '쯔양은 이전에 방문했을 때도 만족스러웠다고 언급하며, 이번에는 냉동 삼겹살 20인분(3.2kg)과 김치찌개, 볶음밥 등을 주문했습니다. 특히 제주 돼지고기 특유의 쫄깃한 비계 식감과 고소한 맛을 칭찬했으며, 일반 삼겹살보다 맛있다고 평가했습니다. 마늘 소스와 파채, 명이나물, 갈치속젓 등 다양한 반찬과의 조합을 즐겼습니다. 김치찌개는 마치 김치찜처럼 국물이 진하고 깊은 맛이 난다며, 김치찌개 전문점보다 낫다고 극찬했습니다. 식사 후에는 계란후라이를 올린 볶음밥으로 마무리했으며, 평소 볶음밥을 즐기지 않음에도 불구하고 맛있게 먹었다고 말했습니다. 편안한 분위기에서 식사할 수 있어서 좋았다고도 덧붙였습니다.'),
('다사리아닭꼬치', '서울 동대문구 전농로 239', '010-3018-7728', ARRAY['치킨'], 'https://www.youtube.com/watch?v=7M6gEUjNrKo', 37.5851217, 127.0521445, '서울특별시', '쯔양은 소금, 간장, 치즈, 양념 등 다양한 맛의 닭꼬치와 닭똥집, 닭껍질 꼬치 등을 주문했습니다. 특히 소금 닭꼬치를 맛본 후, 퍽퍽한 살이 아닌 부드럽고 육즙이 많은 닭다리살을 사용한 점과 간이 적절히 밴 점을 칭찬했습니다. 닭똥집 튀김은 매우 쫄깃하고 맛있다고 평가했으며, 닭껍질 꼬치 또한 크기가 크고 맛있다고 언급했습니다. 반면, 열불 꼬치는 눈물이 날 정도로 매우 맵지만 맛있다고 평가했습니다. 전반적으로 이곳의 꼬치들은 다른 곳에 비해 고기가 많이 붙어있어 양이 푸짐하다고 만족감을 표했습니다. 사장님이 식어가는 꼬치를 다시 데워주는 등 친절한 서비스에 대해서도 언급했습니다.'),
('소문난칼국수', '경기 이천시 관고동 10-2', '031-635-6102', ARRAY['한식'], 'https://www.youtube.com/watch?v=_w9_o7ihRrw', 37.281159, 127.4399193, '경기도', '쯔양은 대표 메뉴인 ''면낙지'' 2개를 주문했습니다. 처음 국물을 맛보고 맛있다고 평가했으며, 소스는 고소하면서도 맵다고 언급했습니다. 면이 완벽하게 익었고, 불지 않기를 바란다고 말할 정도로 면의 식감에 만족감을 표했습니다. 낙지가 매우 부드럽고 맛있다고 여러 차례 감탄했으며, 남은 양념에 밥까지 비벼 먹으며 매우 만족스러운 식사였다고 평가했습니다. 총 10인분이 넘는 양을 먹으며, 맛에 대한 극찬을 아끼지 않았습니다.'),
('개화식당', '경기도 평택시 통복시장로6번길 2', '031-655-2225', ARRAY['중식'], 'https://www.youtube.com/watch?v=gKHd2I0KmgQ', 36.9956103, 127.0852328, '경기도', '쯔양은 옛날 짜장면, 일반 짜장면, 짬뽕, 볶음밥, 깐풍기, 탕수육 등 다양한 메뉴를 주문했습니다. 일반 짜장면은 설탕이 들어가지 않아 단맛이 적고 깊은 맛이 나는 ''오리지널 짜장맛''이라고 평가했습니다. 짬뽕은 고추 맛이 나는 매콤함과 함께 매우 개운하고 독특한 맛이 있다고 언급했으며, 해산물이 풍부한 점을 칭찬했습니다. 탕수육은 튀김옷이 눅눅하지 않고 매우 바삭하며 특별한 맛이 난다고 했습니다. 깐풍기는 익숙하면서도 중독성 있는 맛이라 평했으며, 처음에는 특정 허브(마라) 맛으로 추측했으나 후추가 비결이라는 설명을 듣고 흥미로워했습니다. 볶음밥은 밥알이 살아있는 식감으로 제대로 볶아졌다고 평가하며 맛있다고 했습니다. 전반적으로 모든 음식의 양이 많고 맛있다고 만족했으며, 특히 깐풍기는 식어도 맛있을 것 같다며 남은 음식을 포장해갔습니다.'),
('팔도보쌈', '서울 중구 마른내로2길 32', '02-2266-7573', ARRAY['족발·보쌈'], 'https://www.youtube.com/watch?v=Mc-vgVeAHyc', 37.5632327, 126.9914534, '서울특별시', '쯔양은 충무로에 위치한 30년 이상 된 ''팔도보쌈''에 방문하여 보쌈 12인분과 생굴을 주문했습니다. 그녀는 특히 입에서 녹는 듯한 지방이 있는 부드럽고 육즙 가득한 보쌈 고기를 극찬했습니다. 또한, 달콤하면서도 맛있는 김치에 대해 여러 번 감탄했으며, 무채가 들어있어 식감이 좋다고 평가했습니다. 쯔양은 보쌈, 김치, 굴의 세 가지 조합이 환상적이라고 강조하며, 김치와 고기가 굴의 비린 맛을 완벽하게 잡아준다고 언급했습니다. 함께 나온 미역국도 아주 맛있고 구수하다고 칭찬했습니다. 전반적으로 음식에 매우 만족하며, 주인에게 잘 먹는다는 인정을 받기도 했습니다.'),
('옛날돈까스 본점', '경기 수원시 팔달구 수원천로 316', '0507-1307-8050', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=82M8OUA1hKc', 37.2816092, 127.0185688, '경기도', '쯔양은 숙취 해장을 위해 방문하여 돈까스 3인분과 우동 3인분을 주문했다. 돈까스는 경양식 스타일로, 고기가 매우 부드럽고 소스에서 일반적인 돈까스 소스와 다른 버터 향과 마늘빵 소스 같은 특별한 맛이 난다고 평가했다. 우동은 옛날 기계우동 방식으로 면이 매우 부드럽고 쑥갓이 들어가 있는 점이 특징이라고 언급했으며, 돈까스를 우동 국물에 담가 먹는 것을 즐겼다. 며칠 동안 돈까스를 먹고 싶었다며 맛있게 먹었고, 특히 고기의 부드러움을 여러 번 강조했다.'),
('서두산딤섬', '서울 송파구 올림픽로32길 18 1층 서두산딤섬', '02-418-4545', ARRAY['중식'], 'https://www.youtube.com/watch?v=fENTdaloJYw', 37.5144216, 127.1091432, '서울특별시', '쯔양은 여러 종류의 딤섬을 주문했으며, 특히 육즙이 풍부한 점을 높이 평가했습니다. 샤오롱바오는 터뜨리면 육즙이 나올 정도로 풍부하고 고소하며, 야끼만두는 바삭하면서도 속은 촉촉하다고 언급했습니다. 새우튀김만두는 찐만두의 부드러움과 튀김만두의 바삭함을 동시에 느낄 수 있어 가장 맛있다고 평가했습니다. 복주머니 딤섬은 김치만두와 비슷한 맛이라고 했고, 루비 딤섬과 에메랄드 딤섬은 쫄깃하고 부드러운 피가 특징이라고 설명했습니다. 전반적으로 모든 만두가 맛있어서 우열을 가리기 어렵다고 말했으며, 밀가루 맛이 강하지 않아 더부룩하지 않고 가볍게 느껴진다고 덧붙였습니다. 마지막으로 주문한 볶음밥은 나시고렝과 비슷하며, 스모키한 향과 느끼하지 않고 깔끔한 맛이 특징이라고 리뷰했습니다.'),
('500원양꼬치 중곡점', '서울특별시 광진구 영화사로 54-1', '0507-1327-9959', ARRAY['고기'], 'https://www.youtube.com/watch?v=2FhCVd2qNuo', 37.5553904, 127.0923953, '서울특별시', '쯔양은 500원이라는 저렴한 가격에 감탄하며 다양한 꼬치 메뉴를 주문했습니다. 기본 양꼬치에 대해 ''정말 맛있다'', ''입에서 녹는다''고 표현하며 잡내가 전혀 나지 않는 전설적인 맛이라고 극찬했습니다. 특히 겉은 바삭하고 속은 부드러우며 쫄깃한 식감이 일품이라고 평가했습니다. 양 머릿고기는 쫄깃한 식감이 매력적이며, 양념이 된 매운 양갈비는 ''미쳤다'', ''식감이 장난 아니다''라며 감탄했습니다. 새우 꼬치는 훈연 향이 맛있다고 언급했습니다. 서비스로 받은 꿔바로우는 원래 주문하려던 메뉴였다며, 식초 향이 강했지만 막상 먹어보니 과하게 시지 않고 새콤달콤하며 바삭한 식감이 훌륭하여 이 식당의 ''필수 주문 메뉴'' 중 하나라고 강력히 추천했습니다. 전반적으로 양념 맛이 훌륭해 다른 요리도 맛있을 것이라고 확신하며 매우 만족스러운 식사를 했습니다.'),
('수조개전골', '대전광역시 유성구 신성로 80', '042-933-0900', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=H9mug1r0UcY', 36.3902051, 127.3493251, '대전광역시', '쯔양은 7인분 특대 조개찜 세트에 2인분을 추가하여 주문했다. 식전 계란 후라이부터 독특하다고 칭찬했으며, 메인 메뉴인 조개찜에 대해서는 극찬을 아끼지 않았다. 국물은 해장에 완벽하며 술과 함께 마셔도 취하지 않을 것 같고, 끓일수록 더 진하고 맛있어진다고 평가했다. 키조개, 가리비, 전복, 오징어 등 다양한 해산물의 신선함과 맛을 즐겼으며, 특히 부드러운 가리비와 쫄깃한 키조개를 인상 깊게 평가했다. 98.7% 자연산 치즈 퐁듀에 조개를 찍어 먹는 조합이 훌륭하다고 언급했으며, 식사 후반에는 칼국수 사리를 추가하여 진한 국물과 함께 즐겼다. 전반적으로 육류와 조개를 먹을 때 가장 큰 행복을 느낀다고 말하며, 매우 만족스러운 식사였음을 표현했다.'),
('희망휴게실식당', '대전광역시 대덕구 석봉북로 22', '042-931-1060', ARRAY['분식'], 'https://www.youtube.com/watch?v=HRqiND6h_BE', 36.4492419, 127.4250887, '대전광역시', '쯔양은 이곳을 ''오래된 작은 식당''으로 소개하며, 할머니가 해주시던 맛이 나는 추억의 장소라고 평가했다. 떡볶이는 달달한 옛날 떡볶이 맛이며, 특히 얇은 밀떡을 사용해 식감이 좋다고 언급했다. 라면은 정말 맛있게 끓여졌고 국물 색깔도 훌륭하다며 최근 먹은 라면 중 최고라고 극찬했으며, 한 그릇을 다 먹고 추가로 한 그릇을 더 주문했다. 비빔국수 또한 할머니가 해주시던 것처럼 새콤달콤하고 고추장 맛이 살짝 나는 맛이라고 평가했다. 저렴한 가격에도 불구하고 모든 메뉴의 양이 매우 푸짐하다는 점을 여러 번 강조하며, 정겹고 맛있는 식사였다고 만족감을 표현했다.'),
('맷돌칼국수', '인천 중구 신포로 32-16', '032-762-5930', ARRAY['분식'], 'https://www.youtube.com/watch?v=8hWQnvVvLHQ', 37.4715146, 126.6257293, '인천광역시', '쯔양은 40년 전통의 이 식당을 방문하여 다양한 메뉴를 맛보았습니다. 대표 메뉴인 튀김칼국수는 이 지역 명물인 닭강정 튀김 부스러기를 고명으로 사용하며, 국물이 약간 매우면서도 고소하고 바삭한 식감이 일품이라고 평가했습니다. 떡볶이는 친숙한 시장 떡볶이 맛으로 맵다고 언급했으며, 칼제비에 들어간 수제비는 할머니가 만들어주신 맛과 같다며 만족감을 표했습니다. 특히 김치볶음밥은 일반적인 볶음밥과 달리 리조또 같은 독특한 식감을 가졌으며 아주 맛있다고 극찬했습니다. 쫄면은 새콤달콤한 소스를, 쫄우동은 부드러운 면발을 특징으로 꼽았습니다. 전반적으로 여러 메뉴를 함께 먹으니 매운맛이 강하게 느껴진다고 소감을 밝혔습니다.'),
('일산고기집 육삼식당 풍동본점', '경기도 고양시 일산동구 백마로 507 1층', '031-903-6392', ARRAY['고기'], 'https://www.youtube.com/watch?v=Ja4GZqzjJ3U', 37.6633161, 126.8041583, '경기도', '쯔양은 식당의 거대한 1미터 철판과 장작을 사용하는 방식에 큰 감탄을 표했습니다. 먼저 오리고기를 맛본 후 전혀 질기지 않고 매우 부드럽고 맛있다며 칭찬했으며, 특히 부추와 함께 먹는 조합을 추천했습니다. 이어서 두꺼운 삼겹살을 맛보고는 소금만 찍어 먹어도 매우 고소하고 맛이 뛰어나다고 평가했습니다. 또한, 구운 김치와 치즈를 곁들여 먹는 것을 ''고소 파티''라고 표현하며 큰 만족감을 드러냈습니다. 식사 마무리로 철판에 볶아 먹는 볶음밥 역시 맛있다고 언급하며, 전체적으로 음식에 매우 만족하여 과식할 정도라고 말했습니다.'),
('대성식품', '서울 중구 을지로30길 51', '02-2279-1340', ARRAY['한식'], 'https://www.youtube.com/watch?v=-1OU4tkFJns', 37.5648309, 126.9991312, '서울특별시', '쯔양은 이곳을 ''향수를 불러일으키는 곳''이라고 소개하며 대표 메뉴인 짜파게티, 제육볶음, 번데기탕, 햄부침, 찐만두 등 다양한 메뉴를 주문했습니다. 짜파게티는 소스가 넉넉해 면이 불지 않고 맛있으며, 계란 노른자를 터뜨려 먹는 것이 별미라고 평가했습니다. 햄 부침은 스팸과 맛과 식감이 유사하지만 전혀 짜지 않다는 점을 특징으로 꼽았습니다. 제육볶음은 김치와 함께 조리되어 맛있고 술안주로 완벽하다고 언급했으며, 다른 모든 메뉴가 술을 부르는 맛이라고 칭찬했습니다. 특히 짜파게티와 만두, 햄의 조합이 훌륭하다고 강조하며 전반적으로 모든 음식이 서로 잘 어울리고 맛있다고 종합적인 호평을 남겼습니다.'),
('돼지집', '경기 광명시 기아로 56', '02-805-9407', ARRAY['한식'], 'https://www.youtube.com/watch?v=GepbPDhL1X4', 37.4359651, 126.8858708, '경기도', '쯔양은 이곳을 ''전국 1등 김치찌개집''이자 나만 알고 싶은 단골집이라고 소개했습니다. 코미디언 권재관의 소개로 처음 방문한 후 팬이 되어 울릉도에 다녀오자마자 다시 찾을 정도로 그리워했다고 합니다. 음식이 빨리 나오는 점을 장점으로 꼽았으며, 두루치기에 양파가 많이 들어가 끓일수록 국물이 우러나오는 것이 맛의 비결이라고 분석했습니다. 평소 양파를 즐겨 먹지 않음에도 이곳의 양파는 전부 먹을 만큼 맛있다고 극찬했습니다. 맛이 예전보다 더 좋아졌다며 감탄했고, 돌솥밥 자체도 매우 맛있다고 평가했습니다. 두루치기를 밥에 얹거나 김에 싸 먹는 등 다양한 방법을 추천했으며, 남은 국물에 라면 사리를 넣어 완벽한 김치라면으로 마무리했습니다. 평소 찌개류를 남기는 편이지만 이 음식은 남길 수 없었다고 말하며 5인분과 돌솥밥 5개를 모두 비웠습니다.'),
('한신포차 서현점', '경기도 성남시 분당구 서현로210번길 1 2층', '031-707-0410', ARRAY['야식'], 'https://www.youtube.com/watch?v=XySE2tuCoaQ', 37.3864612, 127.1259383, '경기도', '쯔양은 평소 ''한신포차''의 뼈 있는 닭발을 좋아했지만, 뼈를 발라 먹는 것이 번거로워 무뼈닭발이 출시되기를 오랫동안 기다렸다고 밝혔습니다. 20년 만에 출시된 신메뉴 ''한신 무뼈닭발''을 먹어보고는 ''미쳤다''고 감탄하며, 식감이 매우 쫄깃하고 기존 뼈 있는 닭발에 뒤지지 않는 맛이라고 극찬했습니다. 오히려 콜라겐이 더 많은 느낌이라고 덧붙였습니다. 이 외에도 튤립닭발, 옛날통닭, 해물볶음, 소고기육전, 치즈계란말이 등 다양한 메뉴를 주문했습니다. 특히 매운 닭발과 함께 먹는 두툼한 소고기육전의 조합이 환상적이라고 평가했습니다. 닭발 국물은 걸쭉하고 진한 콜라겐 맛이 일품이며, 주먹밥과 함께 먹는 것을 추천했습니다. 옛날통닭은 얇은 튀김옷이 탕수육 같고 매우 육즙이 풍부하다고 설명했습니다. 또한, 제주도 감귤 농가를 돕기 위해 백종원 대표의 솔루션으로 만들어진 ''감귤 소주''가 매운 닭발과 잘 어울리고 깔끔한 맛을 낸다고 소개했습니다.'),
('우진이네', '경상북도 울릉군 서면 태하길 174', '054-791-5351', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=QWtvZ6NfNJ8', 37.5117493, 130.7998301, '울릉도', '쯔양은 해당 식당의 메뉴 조합이 매우 독특하다고 언급하며 먹방을 시작했습니다. 오징어회는 소스 없이 그냥 먹어도 될 정도로 매우 달다고 평가했으며, 오징어 다리는 질기지 않고 부드럽다고 칭찬했습니다. 통으로 쪄낸 오징어찜은 내장이 전혀 쓰지 않고 달콤하며 맛있다고 여러 번 강조했습니다. 컵라면과 오징어를 함께 먹는 조합을 즐겼고, 나중에는 오징어 내장을 라면에 넣어 먹기도 했습니다. 함께 주문한 뿔소라는 아삭함과 부드러움을 동시에 느낄 수 있는 식감이 좋다고 했고, 양념치킨은 옛날식 소스 맛이 나며 시간이 지나도 바삭함이 유지된다고 평가했습니다. 호박 식혜는 인공적이지 않은 단맛으로 아주 맛있다고 만족감을 표했습니다. 마지막으로 맛본 오징어 내장은 비주얼과 달리 고소하고 맛이 매우 강렬하다고 설명했습니다. 전반적으로 만족스러운 식사였다고 마무리했지만, 양이 많아 턱이 조금 아프다고 덧붙였습니다.'),
('울릉도어부', '경북 울릉군 울릉읍 도동길 59', '054-791-8899', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=R-NjhsmMy9U', 37.4827856, 130.9078199, '울릉도', '쯔양은 한사랑 산악회 멤버들과 함께 초밥 200개 먹기 대결을 진행했습니다. 영상의 주요 내용은 맛 평가보다는 대결 상황과 재미에 초점이 맞춰져 있습니다. 준비된 초밥은 광어, 참치 등 다양했으며, 쯔양은 많은 양의 초밥을 빠른 속도로 먹으며 즐거운 분위기를 연출했습니다. 특히 장어초밥에 매콤한 스파이스가 들어간 점을 언급하며 맛에 대한 짧은 평가를 남기기도 했습니다. 전반적으로 맛있는 음식과 함께 즐거운 시간을 보냈다는 긍정적인 반응을 보였습니다.'),
('황소식당', '경상북도 울릉군 울릉읍 울릉순환로 212-6', '054-791-8444', ARRAY['분식'], 'https://www.youtube.com/watch?v=geLAUrLYPWY', 37.4924789, 130.9099736, '울릉도', '쯔양은 이곳을 ''울릉도판 김밥천국''이라고 칭하며 다양한 분식 메뉴를 즐겼습니다. 특히 울릉도 특산물인 부지깽이와 명이나물이 들어간 김밥에 대해, 특유의 향이 살아있어 맛있다고 평가했습니다. 떡볶이는 떡이 매우 부드럽고 말랑말랑하며, 너무 달지 않고 적당히 짭짤한 맛에 카레 향이 살짝 나는 점이 인상적이라고 언급했습니다. 또한, 생물 오징어로 만든 튀김은 식감이 쫄깃하고 맛있으며, 치즈돈까스도 부드럽고 촉촉하다고 칭찬했습니다. 해산물 위주의 식사를 하던 중 분식이 먹고 싶었던 쯔양은 전반적으로 모든 메뉴에 크게 만족하며 맛있게 식사했습니다.'),
('삼정본가식당', '경상북도 울릉군 울릉읍 울릉순환로 212-8', '054-791-2905', ARRAY['한식'], 'https://www.youtube.com/watch?v=vHVVjeq_H9A', 37.4926077, 130.9099234, '울릉도', '쯔양은 따개비밥, 따개비 칼국수, 홍합밥, 오징어 내장탕, 오삼불고기 등 다양한 메뉴를 주문하여 먹었다. 따개비밥은 전복처럼 쫄깃하고 고소하며, 간장을 넣어 비벼 먹으면 익숙하면서도 맛있는 맛이라고 평가했다. 따개비 칼국수는 국물이 매우 진하고 깊으며, 면발이 넓고 훌륭하다고 언급했다. 오징어 내장탕은 아주 시원한 맛이며, 내장이 오징어 살보다 더 부드럽다고 했다. 오삼불고기는 달콤하면서도 적당히 매콤한 양념이 맛있고, 밥과 탕과 함께 먹는 조합을 극찬했다. 마지막으로 홍합밥은 비린 맛 없이 깔끔한 맛이라고 평가했다.'),
('독도반점', '경상북도 울릉군 울릉읍 울릉순환로 211-3', '054-791-3323', ARRAY['중식'], 'https://www.youtube.com/watch?v=Xvf7fTt9MFA', 37.4920109, 130.9099416, '울릉도', '쯔양은 여러 메뉴를 주문하며 각 음식에 대한 긍정적인 평가를 남겼습니다. ''해물쟁반짜장''은 매콤하면서 불맛이 나고 소스와 면이 훌륭하다고 평가했습니다. ''전복 해물 짬뽕''의 국물은 진하면서도 자극적이지 않고 깔끔하고 개운한 맛이라고 했으며, 울릉도 오징어가 들어가 부드럽다고 언급했습니다. ''새우 탕수육''은 일반적인 바삭함과 달리 매우 부드러운 식감이 특징이라고 말했습니다. ''해물 우동''은 울릉도산 홍합이 크고 맛있으며 국물이 시원하고 깔끔하다고 칭찬했습니다. 특히 ''중화비빔밥''에 대해서는 ''미쳤다'', ''불맛이 장난 아니다''라며 극찬했고, 보이는 그대로의 맛있는 맛이라며 경상도 지역 중국집에 방문하면 꼭 먹어보라고 강력하게 추천했습니다.'),
('상록식육식당', '경상북도 울릉군 서면 남양4길 25', '054-791-7706', ARRAY['고기'], 'https://www.youtube.com/watch?v=w6bl16AWWJo', 37.467446, 130.8377235, '울릉도', '쯔양은 울릉도 토종 소인 ''칡소''를 먹기 위해 상록식육식당을 방문하여 구이 30인분과 육회를 주문했습니다. 구이용 고기는 부위별로 다양한 식감을 즐길 수 있으며, 특히 ''항정살''처럼 쫄깃한 식감과 풍부한 육즙, 그리고 잡내 없이 깔끔하고 고소한 맛이 일품이라고 평가했습니다. 또한, 등급이 높은 부위뿐만 아니라 일반 부위도 질기지 않고 훌륭한 식감을 가졌다고 칭찬했습니다. 함께 주문한 육회는 냉동이 아닌 신선한 생고기를 사용해 ''젤리''처럼 부드럽고 쫀득한 식감이 특징이며, 달콤한 양념과 어우러져 매우 맛있다고 극찬했습니다.'),
('삼정본가식당', '경북 울릉군 울릉읍 울릉순환로 212-8', '054-791-5870', ARRAY['한식'], 'https://www.youtube.com/watch?v=VBLqlTpBbB0', 37.4926077, 130.9099234, '울릉도', ''),
('상록식당', '경북 울릉군 서면 남양4길 25', '054-791-7706', ARRAY['고기'], 'https://www.youtube.com/watch?v=VBLqlTpBbB0', 37.467446, 130.8377235, '울릉도', ''),
('명진맛집', '전남 목포시 옥암로54번길 8', '0507-1338-6288', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=qezd7DRa8XM', 34.804609, 126.4297866, '전라남도', '쯔양은 대표 메뉴인 소고기 낙지 탕탕이에 대해 한우 소고기와 신선한 목포 낙지의 조합이 훌륭하다고 극찬했습니다. 특히 탕탕이를 먹고 난 후 볶아주는 볶음밥은 ''지금까지 먹어본 볶음밥 중 왕''이라며 최고의 맛이라고 평가했습니다. 함께 나오는 미역국, 무한리필 게장 등 기본 반찬에도 만족감을 표하며 ''인생 맛집''이라고 부를 정도로 전반적인 식사에 대해 매우 긍정적인 반응을 보였습니다.'),
('진갈비', '전북 군산시 구영1길 108-7', '063-446-7707', ARRAY['고기'], 'https://www.youtube.com/watch?v=PUWwFTzh-zc', 35.9894143, 126.7090492, '전라북도', '쯔양은 30년 전통의 군산 떡갈비 맛집 ''진갈비''를 방문했다. 이곳의 떡갈비는 넓고 평평한 모양에 마늘이 올라간 독특한 비주얼을 가졌다. 숯불에 구워내 진한 불맛과 풍부한 육즙이 특징이며, 쯔양은 고기가 매우 부드럽고 연하다고 평가했다. 특히 수제로 다진 한우 갈빗살과 차돌박이를 사용해 고기 품질이 뛰어나고, 너무 달지 않아 물리지 않는 맛이라고 칭찬했다. 함께 나온 곰탕은 후추 맛이 강한 진한 국물로 집에서 끓인 듯한 맛이라고 언급했다. 쯔양은 갓김치, 백김치 등 다양한 밑반찬과 떡갈비를 곁들여 먹었으며, 그중에서도 톡 쏘는 갓김치와의 조합을 최고로 꼽았다. 밥 위에 떡갈비를 얹어 먹거나 떡갈비 사이에 밥을 넣어 ''갈비 버거''를 만들어 먹는 등 다양한 방법으로 10인분을 즐겼으며, 식어도 맛있다고 감탄했다. 전국에서 찾아올 만큼 잊을 수 없는 맛이라고 최종 평가를 내렸다.'),
('태화원', '인천 중구 차이나타운로59번길 10', '032-766-7688', ARRAY['중식'], 'https://www.youtube.com/watch?v=F7X1tougqpk', 37.4740217, 126.6185615, '인천광역시', '유니짜장면은 처음 먹어보는데, 소스가 진하고 채소와 고기가 잘게 다져져 있어 면과 잘 어우러져 정말 맛있다고 평가했습니다. 탕수육은 꿔바로우 형태로 나오며 맛있다고 언급했고, 멘보샤는 기대 이상으로 맛있다며 겉은 얇고 속은 부드러운 새우살로 가득 차 있다고 감탄했습니다. 깐쇼새우는 양이 푸짐하고 촉촉하며, 삼선짬뽕은 전복, 주꾸미 등 해산물이 풍부하고 국물에서 훈제 향이 나면서 맵지만 맛있다고 했습니다. 해물볶음밥도 짜장 소스와 잘 어울린다고 평가하며 전반적으로 음식에 높은 만족도를 보였습니다.'),
('잔잔한식탁', '인천 강화군 강화읍 동문안길 16', '0507-1355-7942', ARRAY['한식'], 'https://www.youtube.com/watch?v=F7X1tougqpk', 37.747074, 126.4864191, '인천광역시', '쑥쑥막걸리녹두전은 매우 두툼함에도 밀가루 맛이 전혀 나지 않고 식감이 바삭하며 맛있다고 극찬했습니다. 쑥 향이 강하지 않고 은은하게 남아 좋다고 평가했습니다. 함께 마신 막걸리는 일반 막걸리와 달리 품질이 좋고 맛이 깔끔하며, 쌀 맛이 진하고 탄산이 적어 목 넘김이 부드럽다고 설명했습니다. 녹두전 맛에 크게 감탄하여 집에서 먹기 위해 6인분을 추가로 포장해 갔습니다.'),
('애플하우스', '서울특별시 서초구 반포동 978 L동 205호', '02-595-1629', ARRAY['분식'], 'https://www.youtube.com/watch?v=wnaaDzQZo1o', 37.5017887, 126.9901312, '서울특별시', '쯔양은 ''애플하우스''가 즉석 떡볶이와 특히 무침만두로 매우 유명한 곳이라고 소개했습니다. 즉석 떡볶이는 어린 시절 먹던 추억의 맛으로, 약간의 짜장 소스가 섞인 맛이 훌륭하다고 평가했으며, 라면 사리가 최고라고 언급했습니다. 떡은 밀가루 떡임에도 매우 쫄깃하다고 했습니다. 가장 큰 기대를 모았던 무침만두는 ''오늘의 MVP''로 꼽을 만큼 극찬했습니다. 양념치킨 소스 같으면서도 옛날 탕수육 소스 맛이 나는 독특한 소스가 핵심이며, 튀김이 눅눅하지 않고 칩처럼 바삭해서 밀가루 맛이 거의 나지 않는다고 상세히 묘사했습니다. 순대볶음은 달고 짠 맛이 특징이며, 술안주로 좋겠다고 평가했습니다. 전반적으로 어린 시절을 떠올리게 하는 맛이라며, 평소 튀김만두를 즐기지 않음에도 불구하고 이곳의 만두는 정말 맛있게 먹었다고 만족감을 표현했습니다.'),
('일미정', '인천 중구 신포로23번길 5', '032-772-9595', ARRAY['한식'], 'https://www.youtube.com/watch?v=RiQrl1R2EFE', 37.4709671, 126.6243634, '인천광역시', '쯔양은 최근 불고기에 빠져서 일부러 찾아온 30년 전통의 맛집이라고 소개했습니다. 불고기 8인분을 주문했으며, 달콤하고 짭짤한 맛의 조화가 좋은, 본인이 좋아하는 맛있는 불고기라고 평가했습니다. 특히 밥과 함께 먹는 것을 추천하며, 식당에서 직접 먹는 것이 배달시켜 먹는 것보다 훨씬 맛있다고 강조했습니다. 함께 나온 된장찌개도 맛있다고 언급했습니다. 이후 사장님이 서비스로 주신 육개장 또한 국물이 진하고 양념이 잘 배어있어 맛있다고 칭찬했으며, 불고기와 육개장의 조합이 최고라고 말하며 만족스러운 식사를 마쳤습니다.'),
('두찜 한양대점', '서울특별시 성동구 살곶이길 346-1', '02-2295-9959', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=aFYx-qcWaYw', 37.5563181, 127.0410302, '서울특별시', '쯔양은 소개팅 컨셉으로 ''두찜''의 네 가지 메뉴(불마왕불닭, 트러플크림찜닭, 묵은지찜닭, 로제찜닭)와 다양한 사이드 메뉴를 먹었습니다. ''트러플크림찜닭''을 가장 극찬하며, 진한 트러플 향과 처음 맛보는 크림소스의 조화가 훌륭하고 가장 맛있다고 평가했습니다. ''불마왕불닭''은 맛있게 매운 중독적인 맛이지만 본인에게는 너무 매웠다고 하며, 매운 음식을 좋아하는 사람들에게 추천했습니다. ''묵은지찜닭''은 김치찜과 찜닭을 동시에 먹는 느낌이라 좋다고 했고, ''로제찜닭''은 크림소스가 맛있으며 매장에서 직접 먹으니 더 맛있다고 언급했습니다. 또한 닭고기가 모두 부드러운 닭다리살인 점을 장점으로 꼽았습니다.'),
('초당비스트로', '강원 강릉시 초당순두부길 19', '0507-1466-0914', ARRAY['양식'], 'https://www.youtube.com/watch?v=58GslGnZcS4', 37.7878908, 128.9104834, '강원특별자치도', '쯔양은 스테이크 6종(안심, 채끝, 부채살, 갈비살, 토마호크, 티본)을 모두 맛보았습니다. 특히 안심 스테이크에 대해 ''완벽하게 구워져 입에서 녹는다''고 극찬하며 그날의 최고 메뉴로 꼽았습니다. 토마호크의 새우살 부위 역시 부드러운 식감을 칭찬했으며, 부채살과 척플랩테일은 풍부한 육즙과 쫄깃한 식감이 일품이라고 평가했습니다. 또한, 서비스로 제공된 짬뽕 파스타는 해산물이 가득하고 스테이크와 잘 어울려 해장용으로도 완벽하다고 만족감을 표했습니다. 전반적으로 모든 음식이 매우 맛있었지만 양이 부족해 더 먹고 싶다는 아쉬움을 남겼습니다.'),
('틈새라면 명동본점', '서울특별시 중구 명동10길 19-10', '02-756-5477', ARRAY['분식'], 'https://www.youtube.com/watch?v=_EZZ89fBBU0', 37.5630373, 126.98598, '서울특별시', '쯔양은 이곳의 매운맛을 ''스트레스가 풀리는 매운맛''이라고 평가하며, ''빨계떡'', ''계떡'', ''부대떡'', ''스팸주먹밥'' 등 다양한 메뉴를 주문했습니다. ''계떡''은 짬뽕 맛이 살짝 느껴지는 기분 좋은 매운맛이라고 설명했고, 대표 메뉴인 ''빨계떡''에 대해서는 눈물이 날 정도로 맵지만 맛있어서 스트레스가 해소되는 느낌이라고 극찬했습니다. 특히 가장 매운맛의 ''빨계떡''은 100% 눈물이 나는 맛이라고 표현하면서도, 고춧가루가 아주 곱게 갈려있어 식감이 좋다고 언급했습니다. 함께 먹은 스팸주먹밥도 아주 맛있다고 평가했으며, 매운맛을 중화시키기 위해 냉라면을 추가로 주문하기도 했습니다. 전반적으로 매운 음식이 당겨 방문했는데, 스트레스가 완전히 풀릴 정도로 만족스러운 식사였다고 총평했습니다.'),
('치킨플러스 여의도점', '서울특별시 영등포구 여의대방로 379 제일빌딩 1층 115호', '02-782-0515', ARRAY['치킨'], 'https://www.youtube.com/watch?v=-Tf_SWz5f9k', 37.5191451, 126.9309372, '서울특별시', '쯔양은 치킨플러스의 여러 메뉴를 맛보았습니다. 메인 메뉴인 ''치플 백립''에 대해서는 돼지갈비와 비슷한 모양이지만 맛은 닭고기라고 평했습니다. 특히 뼈와 살이 쉽게 분리되어 먹기 편하고, 기름기가 적고 풍미가 깊어 질리지 않는다고 언급했습니다. 총 112조각을 먹을 정도로 만족도가 높았습니다. 함께 나온 ''핫초킹 소스''의 윙과 드럼펫은 스트레스가 풀리는 매운맛이라고 표현했으며, 매운맛이 서서히 올라온다고 덧붙였습니다. 추가로 맛본 ''로제 닭볶이''는 이전에 먹어본 치킨플러스의 떡볶이처럼 여전히 훌륭한 맛이라고 칭찬했습니다. 순살 닭고기, 당면, 감자튀김 같은 감자 슬라이스가 들어있어 마치 ''로제 닭 스튜'' 같다고 평가하며 맛있게 먹었습니다.'),
('대동순대', '대전광역시 중구 서문로43번길 70', '042-584-2928', ARRAY['한식'], 'https://www.youtube.com/watch?v=Ygwp9LZf1CU', 36.3139101, 127.4049844, '대전광역시', '쯔양은 난생 처음 먹어보는 막창순대에 대해 겉은 쫄깃하고 속은 부드러우면서도 일반적인 순대 맛이 난다고 평가하며, 매우 흥미로운 맛이라고 극찬했습니다. 세 접시도 거뜬히 먹을 수 있겠다고 말할 정도로 만족감을 표현했습니다. 함께 주문한 모듬순대도 속이 꽉 차 있어 맛있다고 언급했지만, 막창순대가 훨씬 더 맛있다고 강조했습니다. 순대국밥 역시 맛있게 먹었으며, 사장님이 국물을 리필해주자 새로 받은 것처럼 기뻐하며 식사를 이어갔습니다. 쯔양은 막창순대와 얇은 순대를 청양고추와 함께 먹으면 기름진 맛을 잡아주어 더욱 맛있게 즐길 수 있다고 설명했습니다. 전반적으로 음식에 매우 만족했으며, 다음에 꼭 다시 방문하고 싶다는 말로 리뷰를 마쳤습니다.'),
('금단양만', '전북 고창군 심원면 검당길 51-10', '063-563-5125', ARRAY['한식'], 'https://www.youtube.com/watch?v=eeifh5Jq198', 35.5365499, 126.5542402, '전라북도', '쯔양은 영상에서 장어 10마리를 먹는 것으로 맛을 표현했습니다. 평소 맛없는 음식은 많이 먹지 못한다고 알려진 만큼, 많은 양의 장어를 먹었다는 사실 자체가 맛에 대한 긍정적인 평가로 해석됩니다. 또한, 영상 후반부에는 후식으로 고창 멜론을 먹으며 "한입 먹자마자 단맛이 팡팡 터지는 게 정말 꿀맛"이라고 언급하며 달콤함에 대해 극찬했습니다.'),
('신정식당', '충남 아산시 시민로409번길 18', '041-545-7500', ARRAY['한식'], 'https://www.youtube.com/watch?v=TxVJhLAo7j0', 36.785876, 126.9999534, '충청남도', '쯔양은 메뉴판의 모든 메뉴(온면, 우동, 비빔냉면, 물밀면, 닭수육, 만두)를 주문했습니다. 닭육수에 대해 기름기 없이 매우 맑고 깨끗한 맛이라고 평가했습니다. 온면은 쫄면 같은 식감에 국물이 닭 자체의 맛이며, 자극적이지 않고 중독성 있는 맛이라고 언급했습니다. 물밀면은 평양냉면과 비슷할 것 같다며, 국물 맛이 풍부하고 중독성이 강하다고 했습니다. 특히 비빔냉면은 ''정말 맛있다''고 감탄하며, 새콤달콤한 맛이 쫄면과 비슷하고 아이들도 좋아할 맛이라고 평가했습니다. 닭수육은 부드러운 식감을 칭찬했으며, 만두도 맛있다고 언급했습니다. 최종적으로 65년 전통을 이어온 비결이 납득되는 맛이라며, 소고기 육수가 아닌 닭육수로 밀면을 만든다는 점과 밀가루면과 닭육수의 조합이 매우 독특하고 훌륭했다고 총평했습니다.'),
('쿄우노식당', '충청남도 당진시 당진중앙2로 163-58', '041-354-1712', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=H8a1fQojZj0', 36.8961506, 126.6329432, '충청남도', '쯔양은 이곳을 ''진짜 맛집''이라고 칭하며 매우 만족했습니다. 특히 다시마로 숙성시킨 연어의 두툼한 두께와 쫄깃한 식감에 감탄하며, 비린 맛이 전혀 없고 맛있다고 평가했습니다. 총 2.5kg에 달하는 연어 사시미 12인분과 돈코츠 라멘, 연어덮밥을 주문했습니다. 돈코츠 라멘은 국물이 매우 진하고 차슈가 두껍다고 칭찬했으며, 연어덮밥에도 연어가 푸짐하게 들어있다고 언급했습니다. 쯔양은 두꺼운 연어의 식감을 즐기며 행복해했고, 양과 맛 모두에서 높은 만족도를 보였습니다.'),
('경원참숯', '강원도 횡성군 우천면 전재로 435-20', '0507-1312-0413', ARRAY['고기'], 'https://www.youtube.com/watch?v=mEAjm54Jxvc', 37.4262932, 128.1103161, NULL, '쯔양은 1200도 숯가마에서 ''쟌슨빌'' 소세지와 삼겹살, 부대찌개를 먹는 경험을 했습니다. 이 영상은 유료 광고를 포함하고 있습니다. 숯가마의 엄청난 화력 덕분에 소세지가 3초 만에 익는 것을 신기해하며, 겉은 터질 듯이 익고 속은 육즙이 가득한 점을 긍정적으로 평가했습니다. 특히 치즈가 들어간 소세지를 좋아했습니다. 가져온 부대찌개에 소세지를 넣어 먹으며 고급스러운 맛이라고 표현했습니다. 다만, 숯가마에서 조리 시 기름기가 너무 많이 빠지는 점은 아쉬워하며, 전자레인지에 조리하는 것도 맛있다고 언급했습니다. 전반적으로 숯가마에서 직접 음식을 구워 먹는 특별한 경험과 맛에 대해 만족감을 표현하며 촬영을 마무리했습니다.'),
('소풍가는날', '경기도 수원시 장안구 수성로261번길 25', '031-252-7339', ARRAY['분식'], 'https://www.youtube.com/watch?v=ccl49P78geg', 37.2908993, 127.0001894, '경기도', '쯔양은 25년 전 가격인 1,000원(포장 현금가)에 김밥을 파는 것에 매우 놀라워했습니다. 매장에서 식사하여 1,500원인 원조김밥은 가격이 저렴함에도 불구하고 계란, 시금치, 우엉, 당근, 햄, 단무지 등 속재료가 가득 차 있어 가성비가 훌륭하다고 평가했습니다. 함께 주문한 치즈라면은 고소한 체다치즈 맛이 일품이라고 했으며, 쫄면은 새콤달콤하고, 돈까스는 소스가 맛있다고 언급했습니다. 2,500원인 참치김밥 또한 참치가 넉넉하게 들어있다고 칭찬했습니다. 전체적으로 요즘 보기 드문 저렴한 가격에 푸짐하고 맛있는 식사를 할 수 있는 곳이라며 만족스러운 식사였다고 총평했습니다.'),
('고곱창', '서울 강남구 논현로150길 38', '02-549-7521', ARRAY['고기'], 'https://www.youtube.com/watch?v=EjzwNy4UwJo', 37.5197963, 127.0316685, '서울특별시', '쯔양은 이 식당에서 곱창, 대창, 막창, 차돌박이, 특양, 볶음밥 등 총 21인분을 먹었습니다. 특히 통으로 구운 염통을 그날의 ''MVP''로 꼽으며, 레어로 살짝 익혔을 때 사각거리는 식감과 함께 입에서 녹는 맛이 스테이크 같다고 극찬했습니다. 곱창은 잡내가 전혀 없고 고소하며, 너무 부드럽지도 질기지도 않은 완벽한 식감이라고 평가했습니다. 평소 즐겨 먹지 않는 대창도 이 집에서는 기름지기보다 고소한 맛이 강하고 겉이 바삭해 맛있다고 감탄했습니다. 또한, 함께 나온 특제 소스가 먹어본 곱창 소스 중 최고라고 여러 번 강조하며, 전반적으로 모든 메뉴에 높은 만족감을 표현했습니다.'),
('꿀꿀이연탄구이', '충청북도 청주시 서원구 사직대로164번길 30', '043-274-8995', ARRAY['고기'], 'https://www.youtube.com/watch?v=QVVX9adc1fM', 36.6338044, 127.4653372, '충청북도', '쯔양은 이전에 방송 촬영으로 방문했던 이곳을 ''인생 맛집''으로 기억하고 재방문했다. 삼겹살 5인분과 목살 5인분, 총 10인분을 주문했다. 연탄불에 구워 불향이 가득하면서도 육즙이 살아있는 고기 맛을 극찬했다. 특히 껍질이 붙어있는 삼겹살은 지방과 껍질의 쫀득한 식감이 일품이며, 목살은 풍미가 매우 풍부하다고 평가했다. 고기의 지방이 느끼하지 않고 고소하며 바삭한 맛있는 종류라고 언급했다. 식사 막바지에는 라면을 추가로 주문해 남은 고기를 차슈처럼 올려 먹으며 만족감을 표했다. 만두 40개를 먹고 온 상태임에도 불구하고 매우 만족스러운 식사였다고 총평했다.'),
('코끼리만두', '충북 청주시 상당구 남사로 133-5', '043-255-9842', ARRAY['한식'], 'https://www.youtube.com/watch?v=zMmOvMdfvS0', 36.6324473, 127.4898575, '충청북도', '쯔양은 고추만두국, 맑은 떡만두국 등 세 종류의 만두국과 찐만두(김치, 고기)를 주문했습니다. 대표 메뉴인 고추만두국에 대해 고추장 칼국수와 비슷하지만 훨씬 시원하고 해장에 좋은 맛이라고 평가했습니다. 만두소에 다진 염장 고추가 들어가 맛이 매우 풍부하고 끝 맛이 칼칼하다고 언급했습니다. 맑은 떡만두국은 전형적이고 맛있는 떡만두국이라 평했으며, 만두피의 쫄깃함과 부드러운 만두소가 인상적이라고 말했습니다. 한 그릇에 만두가 10개나 들어가는 푸짐한 양에 감탄했으며, 단무지와 함께 먹으면 식감이 달라져 더 맛있다고 덧붙였습니다. 식당에 탄산음료가 없는 점이 특이하다고 언급했습니다.'),
('김종구참치박사', '서울특별시 동작구 동작대로 25-1', '02-523-9261', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=nmnwrWov8QU', 37.4787391, 126.9809994, '서울특별시', '가장 비싼 무한리필 코스를 주문하여 다양한 부위의 참치회를 맛보았습니다. 이전에는 보지 못했던 부위들이 많아 신기해했으며, 특히 오도로, 머릿살, 뽈살, 턱살 등의 맛과 식감에 감탄했습니다. 붉은 살은 육회 같다고 평가했으며, 함께 나온 성게알(우니)은 그냥 먹어도, 참치와 함께 먹어도 쓴맛 없이 고소하여 극찬했습니다. 기름진 부위 외에 붉은 살 부위도 맛있다며 입맛이 변하고 있다고 언급했고, 참치와 함께 제공된 콘치즈, 구이, 조림, 튀김, 알밥 등 다양한 곁들임 메뉴도 맛있게 먹었습니다. 앞으로 참치는 이 집으로 와야겠다고 말할 정도로 전반적으로 매우 만족스러운 식사였습니다.'),
('진아네떡볶이', '서울특별시 중구 퇴계로56길 52', '02-2275-8078', ARRAY['분식'], 'https://www.youtube.com/watch?v=koQmU0V3AbU', 37.5615744, 127.0055137, '서울특별시', '쯔양은 이곳이 25년 만에 처음으로 촬영하는 곳이라 매우 영광이라고 말하며 식사를 시작했습니다. 떡볶이의 쌀떡이 매우 쫀득하고 통통하며, 달콤한 고추장 맛이 진해 실패할 수 없는 맛이라고 평가했습니다. 어릴 때 먹던 추억의 맛과 비슷하다고도 덧붙였습니다. 어묵 또한 두툼해서 마음에 들어 했고, 튀김과 김밥, 라면까지 주문하여 떡볶이 국물과 함께 즐겼습니다. 특히 김밥은 참기름 때문에 고소해 보이며, 기본적인 재료로도 맛이 좋다고 칭찬했습니다. 전반적으로 음식의 맛과 양, 그리고 분위기에 크게 만족하며 먹방을 마무리했습니다.'),
('송주불냉면 안양본점', '경기 안양시 만안구 안양로257번길 14', '031-468-9298', ARRAY['한식'], 'https://www.youtube.com/watch?v=nd4-Jis9szM', 37.3954643, 126.923031, '경기도', '쯔양은 안양에 위치한 송주불냉면을 방문하여 매운 냉면 먹방에 도전했습니다. 1단계부터 3단계까지의 불냉면과 돈까스, 튀김만두를 주문했습니다. 1단계는 신라면보다 맵지만 기분 좋게 매운맛이라고 평가했습니다. 2단계는 엽기떡볶이 수준의 매운맛으로, 먹고 3~5초 후에 매운맛이 올라오며 불닭볶음면보다 훨씬 맵다고 했습니다. 가장 매운 3단계는 불닭볶음면보다 더 매운 수준으로, 먹는 도중 포기할 생각까지 했지만 결국 다 먹는 데 성공했습니다. 달콤하면서도 매우 고통스러운 매운맛이라고 묘사하며, 매웠지만 견딜 만했다고 소감을 밝혔습니다.'),
('신형제횟집', '경상남도 통영시 사량면 상도일주로 1580-6', '055-643-3876', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=Z0UN-2qZoZo', 34.8452594, 128.219421, '경상남도', '쯔양은 이곳의 모든 해산물이 매우 신선하다고 극찬했습니다. 특히 사장님이 직접 잡은 자연산 참돔 회를 ''오늘의 베스트'' 요리로 꼽으며, 매우 부드럽고 고소하며 맛있다고 평가했습니다. 또한 뿔소라는 전복보다 맛있다고 했고, 멍게는 쓴맛이 전혀 없이 완벽한 맛이라고 감탄했습니다. 전복, 해삼 등 다른 해산물도 식감과 맛이 훌륭하다고 언급했습니다. 서비스로 받은 해물라면에는 문어 한 마리가 통째로 들어가는 등 푸짐함에 놀라며 아주 맛있게 먹었습니다.'),
('용천가든', '충남 천안시 서북구 입장면 성진로 637', '041-585-8959', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=wF3eisdCcBA', 36.9126683, 127.2016048, '충청남도', '쯔양은 이곳의 김치찌개를 ''인공적인 맛이 아닌 엄마가 해주는 맛'', ''할머니가 해주신 맛''이라고 표현하며 맛을 극찬했습니다. 특히 6인분에 1.8kg에 달하는 엄청난 고기 양에 놀라며, ''고기찌개''라고 불러야 할 정도라고 감탄했습니다. 김치는 1.5년 묵은지와 2.5년 묵은지를 섞어 사용하는데, 쯔양은 신맛이 강하다고 느껴 설탕을 추가해서 먹었습니다. 양이 매우 푸짐하여 6인분이 12인분처럼 느껴진다고 말했으며, 남은 국물에 밥을 비벼 먹으며 식사를 마무리했습니다. 어른들도 좋아할 만한 맛이라고 언급했습니다.'),
('팔팔낙지', '서울 동작구 만양로18길 11 1층', '0507-1445-8316', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=rEzxA0cx9QI', 37.5132037, 126.9450597, '서울특별시', '영상에서 쯔양은 ''대왕 낙곱새''라는 거대한 사이즈의 메뉴를 주문합니다. 압도적인 양에 놀라면서도, 낙지, 곱창, 새우의 조합이 훌륭하고 매콤달콤한 양념이 맛있다고 평가합니다. 함께 나온 주먹밥과 계란찜을 곁들여 먹고, 메인 메뉴를 다 먹은 뒤 남은 양념에 밥까지 볶아 먹으며 만족스러운 ''먹방''을 선보입니다. 영상 내내 음식의 푸짐한 양과 맛에 대해 긍정적인 반응을 보입니다.'),
('청해조개구이.영미네맛집', '충청남도 당진시 신평면 삽교천3길 20', '041-362-8889', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=JSZznsO7t9o', 36.890323, 126.8228589, '충청남도', '쯔양은 당진에 방문하여 조개구이가 먹고 싶어 식당을 찾았습니다. 이곳의 조개구이는 계절과 상관없이 맛있으며, 특히 더운 날씨에 땀을 흘리며 먹는 것이 좋다고 평가했습니다. 그는 살아있는 신선한 가리비를 포함한 다양한 조개를 맛보았으며, 조개가 매우 부드럽고 입에서 녹는다고 표현했습니다. 또한, 치즈와 함께 먹는 것을 추천했으며, 너무 익히면 질겨질 수 있다고 조언했습니다. 쯔양은 서비스로 받은 맛조개가 매우 달고 맛있다고 칭찬했으며, 조개 자체의 간이 완벽해 별도의 소스가 필요 없다고 말했습니다. 사이드 메뉴인 김치전과 떡볶이 소스에 당면을 넣은 것도 맛있게 먹었습니다. 마지막으로 주문한 칼국수는 양이 매우 푸짐하고, 진하고 고소한 국물 맛이 일품이라고 극찬했습니다. 특히 칼국수 안에 맛조개가 들어가 국물 맛이 더욱 좋았다고 언급했습니다.'),
('중앙스넥', '경기 안성시 시장길 63', '031-671-8757', ARRAY['분식'], 'https://www.youtube.com/watch?v=y-csSkw5IbQ', 37.0063607, 127.2714095, '경기도', '쯔양은 이곳의 쫄면이 40년 전통을 가진 만큼 다른 곳과 차별화된 특별한 맛이라고 평가했습니다. 일반적인 새콤달콤한 맛보다는 고추장의 진한 맛과 매콤함이 강하게 느껴지며, 면발이 매우 쫄깃하다고 언급했습니다(transcript , , ). 함께 주문한 함박스테이크는 ''옛날 수제 햄버거'' 같은 맛이 난다고 표현했으며, 소스가 맛있고 고기가 두툼하여 만족감을 표했습니다(transcript , ). 기본으로 제공되는 육수 또한 맛있다고 덧붙였습니다.'),
('두손진곰탕', '경기 김포시 운곡로 4', '031-981-1868', ARRAY['한식'], 'https://www.youtube.com/watch?v=xOIdJ4N5CTw', 37.6505036, 126.6582136, '경기도', '쯔양은 2년 전 방송 촬영 때 방문했던 곳으로, 수육이 매우 맛있었던 기억에 재방문했다고 밝혔습니다. 그는 수육 중(中)자 3판과 곰탕을 주문했습니다. 수육은 국물을 부어 먹으면 고기가 마르지 않고 촉촉하고 부드러움을 유지할 수 있다고 설명했습니다. 고기는 매우 부드러워 입에서 녹는 수준이며, 특히 기름진 부위와 쫀득한 식감의 힘줄(도가니)을 좋아한다고 언급했습니다. 소의 혀(우설) 같은 특수부위도 맛이 좋다고 평가했습니다. 곰탕 국물에 대해서는 매우 진하고 고소하며, 수육보다 더 맛있다고 극찬했습니다. 함께 나온 깍두기 김치도 맛있다고 여러 번 칭찬했습니다.'),
('진미집 본점', '전북 전주시 완산구 노송여울2길 106', '063-254-0460', ARRAY['고기'], 'https://www.youtube.com/watch?v=TTlZQxQz0H4', 35.8268529, 127.1424162, '전라북도', '쯔양은 돼지불고기와 김밥을 상추에 함께 싸 먹는 방식이 매우 독특하고 매력적이라고 평가했습니다. 그는 간이 되어 있는 김밥과 짭짤한 연탄 불고기가 어우러져 맛의 조화가 완벽하다고 말했습니다. 특히, 45년 전통을 이어온 2대째 운영되는 식당으로, 현대적인 맛과는 다른 옛날 추억의 맛과 깊은 내공이 느껴진다고 감탄했습니다. 또한, 김밥을 고추장에 찍어 먹으면 비빔밥 같은 느낌이 나고, 참기름에 찍어 먹어도 고소함이 더해져 맛있다고 덧붙였습니다.'),
('바다꽃게장', '충청남도 태안군 태안읍 능샘1길 45', '041-674-5197', ARRAY['한식'], 'https://www.youtube.com/watch?v=F7sPLM-ThnA', 36.7546316, 126.2939545, '충청남도', '쯔양은 간장게장과 양념게장을 주문하여 먹었습니다. 간장게장에 대해 짜지 않고 고소하며 감칠맛이 풍부하다고 평가했으며, 양념게장은 고소하면서도 약간 매콤한 맛이 특징이라고 설명했습니다. 두 게장 모두 알이 꽉 차 있고 너무 맛있어서 맛을 표현하기 어렵다고 감탄했습니다. 함께 제공된 탕은 게장의 맛을 중화시켜준다고 언급했습니다. 특히 게딱지에 밥, 김, 날달걀, 참기름을 넣어 비벼 먹는 것을 ''눈물이 나는 맛'', ''참기름을 넣으면 두 배 더 맛있다''고 극찬하며 ''이 직업을 선택하길 잘했다는 생각이 드는 맛''이라고 전반적으로 매우 만족스러운 식사였다고 총평했습니다.'),
('이차돌 홍대점', '서울특별시 마포구 잔다리로6길 36', '02-336-3888', ARRAY['고기'], 'https://www.youtube.com/watch?v=twNrW673xWM', 37.5522554, 126.9212072, '서울특별시', '쯔양은 점심과 저녁에 걸쳐 이차돌의 다양한 메뉴를 맛보았습니다. 점심에는 소불고기 스튜, 비빔밥, 막국수 등을 바게트 빵과 함께 먹으며 특히 불고기와 바게트의 조합, 매콤한 국수와 달콤한 불고기의 조화를 칭찬했습니다. 저녁에는 주력 메뉴인 차돌박이 10인분을 시작으로 된장찌개, 초밥, 쫄면을 함께 즐겼습니다. 차돌박이는 빨리 익어서 좋고, 고소한 맛이 일품이라고 평가했으며, 특히 와사비를 올린 초밥과 함께 먹는 것을 최고의 조합으로 꼽았습니다. 이후 신메뉴인 차돌과 특양 구이(차돌양)와 해산물 모둠을 추가로 주문하여, 가리비, 낙지, 새우 등과 함께 다양한 조합으로 맛보며 특히 새우와의 조합이 가장 고소하고 맛있다고 언급했습니다. 전반적으로 매우 저렴하고 합리적인 가격에 다양한 음식을 즐길 수 있어 만족스럽다는 평을 남겼습니다.'),
('스떼이끄300 신촌직영점', '서울 서대문구 명물1길 28', '02-3394-5378', ARRAY['고기'], 'https://www.youtube.com/watch?v=MJnLz9-rPrU', 37.5586391, 126.9374359, '서울특별시', '쯔양은 1.5kg 스테이크 도전 먹방을 진행했습니다. 스테이크가 ''버터처럼 썰릴'' 정도로 매우 부드럽고, 육즙이 풍부하며 고소해서 입에서 녹는다고 평가했습니다. 특히 미디엄 레어로 익힌 스테이크와 와사비의 조합이 훌륭하다고 언급했습니다. 채소는 싫어했지만, 도전 성공을 위해 빠르게 먹었습니다[attached_file_1]. 도전에 성공한 후, 추가로 ''척플랩(진갈비살)'' 400g을 주문하여 먹었으며, 이 부위는 쫄깃하고 양념이 잘 배어 맛있다고 칭찬했습니다.'),
('금암소바', '전북 전주시 덕진구 기린대로 400-75', '063-278-0945', ARRAY['한식'], 'https://www.youtube.com/watch?v=1O5vTQR8EO8', 35.8385078, 127.1332251, '전라북도', '쯔양은 45년 전통의 여름철 맛집으로 ''금암소바''를 소개하며, 모든 메뉴(메밀소바, 비빔소바, 콩국수, 물냉면, 비빔냉면)를 주문했습니다. 메밀소바는 면이 매우 쫄깃하고, 일반적인 가쓰오부시 육수와 달리 멸치 맛이 강한 한국적인 맛이라고 평가했습니다. 비빔소바는 짜지 않고 맛있는 소스가 특징이며, 육수가 독특하다고 언급했습니다. 비빔냉면은 처음에는 달콤하지만 뒤늦게 매운맛이 올라온다고 했습니다. 콩국수는 주로 소금과 먹지만 설탕과 함께 먹어보니 놀랍게도 잘 어울렸으며, 콩국물이 매우 진하고 맛있다고 감탄했습니다. 전반적으로 이곳의 음식은 평범하지 않고 매우 특별하며, 처음 맛보는 건강하고 고소한 맛이라고 요약하며 새로운 경험이었다고 극찬했습니다.'),
('망원동즉석우동 본점', '서울 마포구 동교로 83', '02-336-1330', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=_vOic_3U_YM', 37.5542453, 126.9111372, '서울특별시', '쯔양은 이 식당의 돈까스와 우동을 모두 맛보았습니다. 돈까스는 얼굴보다 큰 왕돈까스로, 매우 얇지만 바삭하고 소스가 특히 맛있다고 평가했습니다. 소스가 너무 맛있어서 집에 가져가고 싶을 정도라고 언급하며, 고기 자체도 훌륭하지만 소스가 맛의 핵심이라고 강조했습니다. 어묵우동은 길거리 우동 스타일로 해장에 좋다고 평했으며, 즉석우동은 국물이 전통적인 맛에 약간 맵다고 했습니다. 두 우동 모두 양이 일반 식당의 두 배 정도로 매우 푸짐하다고 언급했습니다. 쯔양은 돈까스에 대한 만족감이 매우 높아, 이 식당 방문을 계기로 며칠 연속 돈까스를 먹을 정도였다고 밝혔습니다.'),
('떡보라 본점', '충청북도 청주시 청원구 율량로189번길 7', '043-263-3850', ARRAY['분식'], 'https://www.youtube.com/watch?v=pZtl70DR8Cs', 36.6657975, 127.4993392, '충청북도', '쯔양은 떡볶이가 먹고 싶어 청주에 있는 이 가게를 방문했습니다. 가래떡 떡볶이 소스에 대해 "실패할 수 없는 소스"라며, 달고 매우면서도 어린 시절 먹던 맛처럼 톡 쏘는 맛이 난다고 평가했습니다. 고추장 대신 고춧가루를 사용한 것 같다고 추측했는데, 가게에서 실제로 그렇다고 확인해주었습니다. 쌀로 만든 떡을 선호하는데, 이곳의 길고 쫄깃한 가래떡을 특히 좋아했습니다. 처음 20줄을 주문하고 나중에 10줄을 더 먹을 정도로 만족했으며, 갓 나온 떡이 따끈하고 쫄깃해서 맛있다고 언급했습니다. 튀김, 순대, 어묵 등 다양한 메뉴를 함께 즐겼고, 특히 새우튀김이 다른 곳보다 훨씬 크다고 감탄했습니다. 가격이 매우 저렴하다고 생각했으며, 며칠 동안 먹고 싶었던 떡볶이를 아주 만족스럽게 먹었고, 맛있어서 포장 주문까지 했다고 밝혔습니다.'),
('파스타입니다 청라점', '인천 서구 청라에메랄드로163번길 10', '032-563-3852', ARRAY['양식'], 'https://www.youtube.com/watch?v=Z-4vMHNvH0E', 37.5399111, 126.6554495, '인천광역시', '유튜버 쯔양은 배달 앱 파스타 랭킹 1위인 ''파스타입니다''의 인기 메뉴 먹방을 진행했습니다. 스테이크 크림 파스타, 쉬림프 로제 파스타, 트러플 크림 파스타, 바질 페스토 파스타 등 4종의 파스타와 쉬림프 로제 리조또, 트러플 크림 리조또 등 2종의 리조또, 그리고 감바스, 해쉬브라운, 치킨 너겟 등 다양한 사이드 메뉴를 주문했습니다. 쯔양은 특히 스테이크 크림 파스타의 부드러운 스테이크와 꾸덕하고 매콤한 크림 소스의 조화를 칭찬했으며, 쉬림프 로제 파스타는 통통한 새우가 넉넉히 들어있어 맛있다고 평가했습니다. 트러플 크림 파스타와 리조또에서는 깊은 트러플 향을 느낄 수 있었다고 언급했습니다. 전반적으로 배달 음식임에도 불구하고 높은 퀄리티의 맛과 다양한 메뉴에 크게 만족하며 대식가답게 모든 음식을 맛있게 먹어치우며 인기를 실감했습니다.'),
('송림식당', '대구광역시 동구 동부로 13-1 구두수선대10', '053-421-9233', ARRAY['고기'], 'https://www.youtube.com/watch?v=QJvAURjJPqU', 35.8741723, 128.6141678, '대구광역시', '쯔양은 대구의 명물인 (mungtigi)를 먹기 위해 방문했습니다. 일요일에 방문하여 당일 도축한 신선한 (mungtigi) 대신 숙성된 소고기를 먹었지만, 매우 부드럽고 맛있다고 평가했습니다(2:39). 특히, 접시를 뒤집어도 떨어지지 않을 정도로 고기가 찰지다고 언급하며 신선함에 감탄했습니다(4:22). 또한, 다진 마늘과 부추 등이 들어간 특제 소스가 아주 맛있다고 극찬했으며(4:37), 깍둑썰기와 얇게 썬 두 가지 형태의 고기를 모두 맛보고 각각의 식감 차이를 즐겼습니다(4:52). 기본 반찬으로 나오는 간과 (cheonyeop)을 좋아한다고 밝혔고(2:14), 함께 주문한 (doenjang-jjigae)와 (tangguk)도 국물이 진하고 훌륭하다고 평가했습니다(11:26, 10:10). 나중에 추가로 주문한 (yukhoe)도 달콤하고 맛이 환상적이라고 언급했습니다(13:08). 일요일에 방문한 탓에 진정한 (mungtigi)를 맛보지 못해 아쉬워하며, 평일에 꼭 다시 오고 싶다는 말을 남겼습니다(6:47).'),
('1500회전초밥 용전점', '대전광역시 동구 동서대로1695번길 43 1층', '0507-1433-1422', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=CQpxJhN16pM', 36.3513661, 127.4366971, '대전광역시', '쯔양은 모든 접시가 1,300원이라는 저렴한 가격에 감탄하며 방문했습니다. 간장새우, 연어, 떡갈비, 스테이크 타르타르, 전복, 연어 뱃살, 문어, 성게알, 참치 뱃살, 우삼겹, 광어, 장어 등 다양한 초밥을 맛보았습니다. 특히 가격 대비 고기 품질이 훌륭하다며 참치 뱃살과 우삼겹 초밥에 감탄했고, 구운 연어, 떡갈비, 성게알, 광어 지느러미 초밥을 맛있게 먹었습니다. 식사 중 남은 음식을 기부한다는 사실을 알고 깊은 감명을 받았으며, 이로 인해 음식이 더욱 맛있게 느껴진다고 말했습니다. 최종적으로 초밥 112접시, 우동, 닭꼬치 등을 먹고, 매우 합리적인 가격과 음식을 기부하는 식당의 선행에 큰 만족감을 표현하며 식사를 마쳤습니다.'),
('구공탄막창 형님본점', '대구 서구 서대구로 120', '053-573-9282', ARRAY['고기'], 'https://www.youtube.com/watch?v=cSGhMZka22c', 35.8687021, 128.5556889, '대구광역시', '쯔양은 이 식당을 이제껏 방문한 막창집 중 최고라고 평가했습니다. 대표적인 특징으로 막창 특유의 잡내가 거의 나지 않는다는 점을 꼽으며, ''겉은 바삭하고 속은 촉촉하다''고 맛을 표현했습니다. 또한, 초벌구이가 되어 나와 바로 먹을 수 있다는 점을 장점으로 언급했습니다. 함께 주문한 된장찌개도 고기가 들어있지 않음에도 매우 맛있다고 칭찬했습니다. 종합적으로, 쯔양은 이곳을 자신이 가본 곳 중 가장 냄새가 적고 맛있는, ''최애 막창집 1위''라고 극찬했습니다.'),
('인천분식', '경상북도 구미시 장천면 강동로 175', '054-471-5316', ARRAY['분식'], 'https://www.youtube.com/watch?v=1uWeJMamJDM', 36.1251831, 128.4947078, '경상북도', '쯔양은 이곳에서의 식사를 ''정겨운 한 끼''였다고 평가했습니다. 직접 끓인 라면은 분식집에서 먹어 더 맛있는 것 같다고 평했으며, 라볶이는 면발이 불지 않고 쫄깃한 것이 ''연륜''이 느껴진다고 말했습니다. 특히 김밥은 참기름 맛이 고소해 할머니가 해주시던 맛과 비슷하고 밥도 맛있다고 칭찬했습니다. 80세가 넘으신 사장님의 따뜻한 인심과 정을 느낄 수 있는 곳이었다고 요약했습니다.'),
('정원분식', '서울 동작구 사당로28길 5 1층', '0507-1429-0425', ARRAY['분식'], 'https://www.youtube.com/watch?v=-wr8xH31c8M', 37.4841451, 126.9797374, '서울특별시', '쯔양은 ''정원분식''이 자신이 운영하는 식당이기 때문에 맛에 대한 직접적인 평가는 하지 않았습니다. 하지만, 손님 입장에서 음식을 즐기는 팁을 공유했습니다. 예를 들어, 가장 인기 있는 메뉴는 짬뽕 떡볶이라고 소개했고, 몬테크리스토 샌드위치는 짬뽕 국물에 찍어 먹거나 마스카포네 치즈를 곁들이면 더 맛있다고 설명했습니다. 영상 후반부에는 짬뽕 떡볶이, 부대 떡볶이, 몬테크리스토 샌드위치, 순대볶음, 연어장 덮밥, 어묵탕 등 챌린지 메뉴 전체를 남김없이 먹으며 모든 음식을 즐기는 모습을 보여주었습니다.'),
('부안수산', '서울 동작구 노들로 674 노량진수산물도매시장', '02-821-2309', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=MpMfSdOgiMg', 37.5148237, 126.9379759, '서울특별시', ''),
('광암막국수', '강원 횡성군 우천면 경강로 2887', '033-342-2693', ARRAY['한식'], 'https://www.youtube.com/watch?v=rqwXDBojRpY', 37.4879396, 128.0724884, '강원특별자치도', '쯔양은 물막국수를 먹고 ''지금까지 먹어본 막국수 중 가장 맛있다''고 극찬했습니다. 100% 순메밀로 만든 면이 얇아 양념이 잘 배고, 쉽게 끊어지지만 먹을수록 더 맛있어진다고 평가했습니다. 수육은 갓 삶아 나와 매우 신선하고, 기름지고 쫄깃하며 고소한 맛이 환상적이라고 표현하며 김치와 함께 먹는 것을 추천했습니다. 비빔막국수는 물막국수보다 더 취향에 맞으며, 달콤새콤한 양념의 명태회가 맛있다고 언급했습니다. 처음 접해본 간장막국수는 고소한 맛이 특징이며, 녹두전은 매우 바삭하고 담백하지만 고소해서 중독성 있는 맛이라고 리뷰했습니다.'),
('녹두빈대떡', '서울 영등포구 영신로 28', '02-2636-0073', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=7FSLE13ONM0', 37.5139559, 126.9085467, '서울특별시', '쯔양은 닭볶음탕, 동그랑땡, 골뱅이무침을 주문했습니다. 닭볶음탕은 18호 닭을 사용하여 양이 매우 푸짐하며 3~4인분으로 보인다고 언급했습니다. 국물은 너무 맵거나 달지 않으면서 집에서 끓여주는 듯한 깊은 감칠맛이 난다고 평가했습니다. 닭고기는 크고 신선하며 살이 통통하고 쫄깃하다고 칭찬했습니다. 함께 들어있는 통감자도 크기가 매우 크고 맛있다고 언급했습니다. 동그랑땡 역시 크기가 크고 고기 완자가 꽉 차 있어 씹는 맛이 좋다고 평가했으며, 골뱅이무침도 맛있게 먹었습니다. 전체적으로 푸짐한 양과 맛에 만족하며 노포 감성이 느껴지는 맛집이라고 평가했습니다.'),
('입이 즐거운 그만두 본점', '충북 청주시 청원구 사뜸로 105', '043-241-6005', ARRAY['분식'], 'https://www.youtube.com/watch?v=PmXO5xXxhPU', 36.6704525, 127.4774119, '충청북도', '쯔양은 극강의 매운맛으로 유명한 청주의 ''미친만두''에 도전했습니다. 가게에는 ''19세 미만 판매 금지'' 경고가 붙어 있을 정도로 강력한 메뉴입니다. 쯔양은 먼저 안 매운 만두와 매운 만두를 맛보며, 속이 꽉 차고 맛있다고 평가했습니다. 이어서 도전한 미친만두는 한 입 먹자마자 극심한 고통을 호소하며 말을 잇지 못했습니다. 땀을 비 오듯 쏟고 우유를 계속 마시면서도, 매운맛의 근본은 맛있지만 일반인은 절대 도전해서는 안 될, 응급실에 갈 수도 있는 수준의 통증이라고 설명했습니다. 웬만한 매운맛에 단련된 쯔양조차 매우 힘들어하는 모습을 보이며 역대급 매운맛이라고 평가했습니다.'),
('백만불식품', '서울 중구 충무로7길 10', '02-2275-3957', ARRAY['한식'], 'https://www.youtube.com/watch?v=M8whof-__nY', 37.5657632, 126.9921972, '서울특별시', '쯔양은 처음 방문하는 가맥집 스타일에 기대를 보였습니다. LA갈비가 품절되어 아쉬워하며 보쌈, 돼지갈비, 오겹살, 고추장찌개를 주문했습니다. 오겹살은 껍질이 있어 매우 쫄깃하고, 보쌈은 부드럽기보다는 쫄깃한 식감이라고 평했습니다. 돼지갈비는 이날 먹은 것 중 최고로 꼽으며, 가맥집에서 파는 고기라고는 믿기지 않을 정도로 부드럽고 맛있다고 감탄했습니다. 고추장찌개는 국물이 매우 진하고 고기가 입에서 녹을 정도로 부드럽다고 칭찬했습니다. 추가로 주문한 번데기탕은 국물 맛이 깊고 칼칼해서 좋다고 했으며, 스팸, 짜파게티, 라면도 주문했습니다. 특히 짜파게티와 라면은 집에서 끓이는 것과 달리 왜 이렇게 맛있는지 모르겠다며 극찬했습니다. 전반적으로 안주가 될 만한 맛있는 음식이 많아 술이 생각나는 곳이라고 평가했습니다.'),
('경주천년한우', '경북 경주시 외동읍 산업로 3005-10', '054-746-9700', ARRAY['고기'], 'https://www.youtube.com/watch?v=C1osQlfEwfo', 35.7746922, 129.3000778, '경상북도', '쯔양은 총 15가지의 다양한 한우 부위를 맛보며, 이렇게 많은 종류의 소고기는 처음 먹어본다고 감탄했습니다. 특히 가장 좋아하는 부위로 ''살치살''을 꼽으며, 입안에서 녹는 듯한 부드러운 식감과 풍부한 육즙을 극찬했습니다. 또한, 평소 기대하지 않았던 ''부채살''의 높은 품질에 놀라워했고, ''꽃살''은 ''천상의 맛''이라고 표현했습니다. 처음 구워 먹어본 ''아롱사태''의 쫄깃하고 독특한 식감에도 큰 만족감을 드러냈습니다. 된장찌개 또한 색깔만 봐도 맛있는 것을 알겠다며 좋아했습니다. 전반적으로 고기의 풍미가 매우 깊고, 부드러우면서도 육즙이 풍부하다고 평가했으며, 경주를 방문하는 사람들에게 이곳을 강력히 추천하며 영상을 마무리했습니다.'),
('장꼬방묵은김치찌개전문', '서울 서초구 효령로 364 장꼬방', '02-522-0035', ARRAY['한식'], 'https://www.youtube.com/watch?v=psDMjJWOZlg', 37.4868994, 127.0236804, '서울특별시', '쯔양은 30초 만에 완성되는 대형 철판 계란말이로 유명한 곳으로 알고 방문했으나, 실제로는 김치찌개 전문점이라고 언급했습니다. 그녀는 계란말이 6판, 김치찌개 1인분, 돼지 숯불구이 1인분을 주문했습니다. 계란말이는 계란 7-8개가 들어가며 예상보다 두 배나 큰 크기에 놀랐다고 합니다. 맛에 대해서는 계란의 깊고 진한 맛이 느껴지며, 완전히 익혀서 말아내 부드러운 ''지단'' 같다고 평가했습니다. 김치찌개에는 고기가 들어있었고, 돼지구이는 매우 맛있다고 언급하며 쌈이나 숭늉과 함께 즐겼습니다. 또한, 어묵볶음을 포함한 밑반찬들이 맛있고 무한리필이라는 점을 장점으로 꼽았습니다. 양이 너무 많아 주문한 계란말이 6판 중 5판(계란 40개)을 먹고 1판은 포장했습니다.'),
('호산나의정부부대찌개', '서울 서대문구 충정로4길 8', '02-313-1678', ARRAY['한식'], 'https://www.youtube.com/watch?v=D-ibX5vxe6M', 37.5610232, 126.9638785, '서울특별시', '쯔양은 이 집이 부대찌개 전문점이지만 돈까스로도 매우 유명하다고 언급했다. 돈까스는 과일 맛이 나는 새콤달콤한 수제 소스가 특징이며, 먹을수록 더 맛있어지는 맛이라고 극찬했다. 부대찌개는 다른 곳과 달리 기름지지 않고 마늘 향이 강하며 칼칼하고 시원한 국물 맛이 일품이라고 평가했다. 함께 주문한 계란말이는 달콤하고 맛있으며, 돈까스 소스에 찍어 먹는 조합도 좋다고 말했다. 쯔양은 부대찌개 국물에 라면 사리를 두 번이나 추가해 먹을 정도로 만족감을 보였으며, CJ 스팸이 들어가 국물 맛이 더욱 좋다고 덧붙였다.'),
('장다리곱창', '서울 중구 다산로 140', '02-2236-8276', ARRAY['고기'], 'https://www.youtube.com/watch?v=ZdUZHgnBIe0', 37.5562084, 127.0116756, '서울특별시', '쯔양은 이 식당의 음식에 대해 전반적으로 매우 만족스러운 평가를 내렸습니다. 특히 곱창은 속이 꽉 차 있고 고소하며, 바삭하게 구웠을 때 느끼하지 않고 맛있다고 언급했습니다. 소 혀(우설)에 대해서는 ''눈이 번쩍 뜨이는 맛''이라며 극찬했고, 개인적으로 가장 맛있는 부위로 꼽았습니다. 또한, 특양은 부드럽고 쫄깃하며, 염통은 고무 같을 것이라는 예상과 달리 전혀 그렇지 않고 맛있다고 평가했습니다. 대창은 이미 양념이 되어 있어 그냥 먹어도 맛있다고 했으며, 식사를 통해 아팠던 몸이 회복되는 느낌을 받았다고 말하며 만족감을 표현했습니다.'),
('풍년식당', '충청북도 충주시 동량면 조동2길 88 1층', '043-851-0181', ARRAY['중식'], 'https://www.youtube.com/watch?v=wfKSmMuTnQo', 37.0287456, 127.9690214, '충청북도', '쯔양은 이곳의 모든 메뉴(짜장면, 짬뽕, 우동, 탕수육)를 주문했습니다. 대표 메뉴인 **짬뽕**은 너구리 라면 맛과 매우 비슷하며 국물이 중독성 있고 면이 굵은 것이 특징이라고 평가했습니다. **탕수육**은 매우 부드럽고 쫄깃하며 맛있다고 언급했고, **우동**은 예상외로 아주 맛있다며 감탄했습니다. 감자가 들어간 **짜장면** 역시 소스가 맛있고 면의 식감이 좋다고 긍정적으로 평가했습니다. 43년 전통의 노포 식당으로, 두 어르신이 운영해 음식이 나오는 데 시간이 다소 걸릴 수 있다고 덧붙였습니다.'),
('대전막장집', '대전광역시 중구 선화서로 48-1 1층', '0507-1345-0324', ARRAY['야식'], 'https://www.youtube.com/watch?v=tFFtj7P3_fk', 36.3280875, 127.4181176, '대전광역시', '쯔양은 해물라면, 꼬마김밥, 돌문어, 참소라를 주문했습니다. 메인 메뉴인 꼬마김밥을 초장에 찍어 먹는 조합이 독특하지만 아주 잘 어울린다고 평가했으며, 김밥의 단단한 식감과 깻잎의 아삭함에 만족감을 표했습니다. 새우, 게, 가리비가 들어간 해물라면은 해산물 맛이 진하고 얼큰해서 맛있다고 언급했습니다. 통으로 삶아진 돌문어는 매우 부드럽고, 특히 머리와 내장 부분이 다리보다 더 연하고 맛있다고 극찬했습니다. 제철인 참소라는 독특한 풍미와 훌륭한 식감을 칭찬하며 추천에 대한 고마움을 표시했습니다.'),
('산쪼메 이수점', '서울특별시 동작구 사당로 300', '070-4110-1534', ARRAY['아시안'], 'https://www.youtube.com/watch?v=qvKoOD71VvY', 37.4843925, 126.9805811, '서울특별시', '쯔양은 점보라멘을 먹으며 ''라멘은 너무 맛있다'', ''정말 맛있다'', ''국물이 매우 고소하고 진하다''고 평가했습니다. 4인분 양의 많은 양임에도 불구하고 ''2만원이라는 가격이 아깝지 않다''고 언급했으며, 숙주나물이 많아 양이 많게 느껴진다고 말했습니다. 식사 도중에도 ''여전히 맛있다''고 감탄했으며, 20분 안에 먹기 도전에 성공한 후에도 ''정말 맛있게 먹었다''고 만족감을 표현했습니다.'),
('제천명물빨간오뎅', '충북 제천시 의병대로18길 2', '010-3570-0601', ARRAY['분식'], 'https://www.youtube.com/watch?v=4svzZO8Yi3o', 37.1355411, 128.2119487, '충청북도', '쯔양은 가게의 빨간어묵 한 솥을 통째로 구매했다. 어묵은 얇은 두 겹으로 된 한입 크기이며 양념이 잘 배어있다고 평가했다. 맛은 떡볶이 소스와 매우 흡사하지만 예상보다 더 맵다고 설명했다. 1,000원에 3개라는 가격이 매우 저렴하다고 언급했다. 총 76개의 어묵을 먹어 가게에서 2위 기록을 세웠으며, 술을 마시지 않은 사람 중에서는 1위라고 했다. 매운 어묵과 슬러시의 조합이 아주 좋다고 말했으며, 쫄깃한 쌀떡과 어묵 국물도 함께 즐겼다. 저렴한 가격 덕분에 술안주로 즐기기에도 완벽한 장소라고 결론지었다.'),
('이봉원의 봉짬뽕', '충남 천안시 서북구 성정두정로 70', '041-551-0026', ARRAY['중식'], 'https://www.youtube.com/watch?v=7RPGcG-AnCw', 36.8319425, 127.1421844, '충청남도', '쯔양은 이봉원이 제시한 ''준비된 7가지 음식을 모두 먹으면 평생 무료 식사권 제공'' 도전에 응했습니다. 도전 메뉴는 탕수육, 깐쇼새우, 프리미엄 짬뽕, 짜장면, 벚꽃새우볶음밥, 잡채, 군만두였습니다. 쯔양은 자신감을 보이며 식사를 시작했고, 결국 모든 음식을 다 먹어 도전에 성공하며 이봉원으로부터 ''평생 무료 식사권'' 인증서를 받았습니다.'),
('이수생삼겹살 이수역점', '서울 동작구 동작대로23길 23', '0507-1378-1976', ARRAY['고기'], 'https://www.youtube.com/watch?v=iy0EquYjNuc', 37.4840968, 126.9804152, '서울특별시', '쯔양은 이 식당을 과거에 포장해 먹었을 때 매우 맛있었던 기억이 있어 재방문했다고 밝혔습니다. 얇은 삼겹살로 시작해 차돌박이, 항정살, 목살 등 다양한 부위를 맛보았습니다. 특히 차돌박이는 지방 부분이 쫄깃하고 얇은 삼겹살보다 맛있다고 평가했으며, 항정살의 독특한 식감을 좋아한다고 말했습니다. 평소 즐기지 않는 목살도 이 집에서는 맛있다고 언급하며, 삼겹살과 목살을 최고의 메뉴로 꼽았습니다. 쯔양은 이곳의 고기로는 5kg도 먹을 수 있을 정도로 맛있다고 극찬했으며, 사장님이 김치를 계속 리필해주는 등 서비스에도 만족감을 표현했습니다.'),
('영주랜떡', '경상북도 영주시 중앙로83번길 26-2', '010-4999-6975', ARRAY['분식'], 'https://www.youtube.com/watch?v=_mwL-KkeYxk', 36.8237257, 128.6236918, '경상북도', '쯔양은 이곳의 떡볶이가 매우 맵지만 중독성 있는 맛이라고 평가했습니다. 특히, 다른 곳에서는 맛본 적 없는 독특한 소스와 쫄깃한 가래떡의 조화가 인상적이라고 언급했습니다. 튀김(김말이, 만두)은 바삭하지 않고 빵과 같은 독특한 식감을 가졌다고 설명했습니다. 어묵은 쫄깃하고 맛있으며, 어묵 국물 또한 맵고 뜨겁지만 맛있다고 평가했습니다. 전반적으로 매우 유명한 이유를 알 것 같은 맛집이라고 극찬하며, 엄청난 양의 떡볶이와 튀김, 어묵 등을 먹고도 추가로 포장해갔습니다.'),
('선창횟집', '충남 태안군 남면 마검포길 427-5', '041-674-3989', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=MjXw08tatIc', 36.6199459, 126.2869508, '충청남도', '쯔양은 봄철을 맞아 꽃게와 주꾸미를 먹기 위해 식당을 방문했습니다. 먼저 봄 암꽃게찜 3kg을 주문하여, 꽉 찬 알과 내장을 극찬하며 ''갑각류 중 맛으로 최고''라고 평가했습니다. 특히 살이 매우 달고 풍미가 깊다고 거듭 감탄했습니다. 이어서 주문한 주꾸미 샤부샤부는 거대한 크기에 놀라움을 표했으며, 살짝 데친 다리는 매우 부드럽고 쫄깃하다고 묘사했습니다. 또한, 머리 부분에 가득 찬 알과 내장을 별미로 꼽으며, 샤부샤부 국물 또한 맛이 일품이라고 칭찬했습니다. 쯔양은 바다 앞에서 즐기는 신선한 해산물이라 더욱 맛있다며, 봄에는 꼭 태안에 와서 꽃게와 주꾸미를 먹어보라고 강력히 추천했습니다.'),
('석곡식당', '전남 곡성군 석곡면 석곡로 60', '061-362-3133', ARRAY['고기'], 'https://www.youtube.com/watch?v=hryirOKFk38', 35.1324288, 127.2538612, '전라남도', '120년 전통의 4대째 내려오는 식당으로, 양념 석쇠구이와 간장 석쇠구이를 모두 맛보았다. 양이 푸짐하고 비계와 육즙이 풍부해 보인다고 평가했다. 양념구이는 맵지 않고 달달한 편이며, 비계의 식감은 아삭하고 맛있다고 언급했다. 간장구이는 훈연 향이 좋다고 말했다. 흰 쌀밥과 매우 잘 어울린다고 덧붙였다.'),
('돌실숯불회관', '전남 곡성군 석곡면 석곡로 52-1', '061-363-1457', ARRAY['고기'], 'https://www.youtube.com/watch?v=hryirOKFk38', 35.1316541, 127.2536967, '전라남도', '두 번째로 방문한 식당으로, 사장이 직접 양봉한 꿀을 고추장 양념에 사용하는 것이 특징이다. 고기가 두툼하여 식감이 좋을 것이라 예상했고, 맛을 본 후 첫 번째 식당과 완전히 다른 맛이라고 평가했다. 꿀이 들어가 단맛이 진하고 풍부하며, 고기는 매우 두껍고 부드러우면서도 비계의 쫄깃한 식감이 입안을 가득 채운다고 말했다. 겉은 바삭하고 속은 쫄깃한 식감이 일품이며, 꿀맛이 강하게 느껴지는 것이 특징이라고 요약했다.'),
('석곡돼지한마리', '전남 곡성군 석곡면 석곡2길 13', '061-362-3077', ARRAY['고기'], 'https://www.youtube.com/watch?v=hryirOKFk38', 35.1302175, 127.2548982, '전라남도', '세 번째로 방문한 식당으로, 3인분을 주문했다. 고기 두께나 양념 맛이 너무 과하지 않은 ''평균적인 맛''이라고 표현했지만, 맛있다고 평가했다. 흑돼지 특유의 부드러운 육질과 쫄깃한 비계 식감이 특징이라고 언급하며, 일반 돼지고기와는 식감이 확연히 다르다고 강조했다. 창밖으로 보이는 강과 산의 경치가 좋다는 점도 언급했다.'),
('우리식당', '전남 곡성군 석곡면 석곡로 30', '061-363-5617', ARRAY['고기'], 'https://www.youtube.com/watch?v=hryirOKFk38', 35.1296596, 127.2535956, '전라남도', '네 번째 마지막 식당으로, 이미 11인분을 먹어 배가 부른 상태였음에도 맛있다고 감탄했다. 훈연 향이 입안 가득 퍼지는 것이 특징이며, 양념 맛도 좋지만 고기 본연의 맛을 잘 살렸다고 평가했다. 특히 고기가 매우 부드럽고 쫄깃하다고 말했다. 함께 나온 돌솥밥이 정말 맛있다고 여러 번 칭찬했으며, 무쌈이나 다른 채소쌈과도 잘 어울린다고 언급했다. 식사를 마친 후, 4번째 식당임에도 불구하고 정말 맛있게 먹었다고 소감을 밝혔다.'),
('등대경양식', '인천광역시 중구 제물량로 190', '032-773-3473', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=tKrnOGzewVI', 37.4708285, 126.6231165, '인천광역시', '쯔양은 이 식당이 1968년에 개업하여 50년이 넘는 전통을 가졌으며, 하루에 25그릇만 한정 판매하는 특별한 곳이라고 소개했습니다. 소스는 8시간 동안 직접 만들며, 묽고 신맛이 나는 옛날 스타일이라고 설명했습니다. 돈까스는 소스에 푹 적셔져 나와 튀김옷이 매우 부드러운 것이 특징이며, 어릴 적 먹었던 추억의 맛이 생각난다고 여러 번 언급했습니다. 고기는 두툼하지만 질기지 않고, 기름지지 않아 깔끔한 맛이라고 평가하며, 양도 푸짐하다고 덧붙였습니다. 쯔양은 총 5접시를 먹으며 맛에 대한 높은 만족감을 표현했습니다.'),
('라멘81번옥 신촌점', '서울 서대문구 신촌역로 16 대현동 효자가이아오피스텔 1층 104호', '02-313-2232', ARRAY['아시안'], 'https://www.youtube.com/watch?v=j3k6vNtyARs', 37.558073, 126.9431952, '서울특별시', '쯔양은 이전에 방문했을 때 맛있었던 기억으로 재방문하여 점보라멘(쇼유라멘 4인분)에 도전함. 라멘이 아주 맛있어 보이고 냄새도 좋다고 평가했으며, 첫 입을 먹고 ''맛있다''고 감탄함. 특히 간장 베이스의 차슈(돼지고기)가 아주 맛있다고 칭찬했으며, 부드러운 반숙 계란도 언급함. 일부러 도전 시간에 실패하여 식사 비용을 지불했는데, 이는 이전에 무료로 먹은 것에 대한 미안함 때문이었다고 밝힘. 점보라멘을 다 먹고도 배가 차지 않아 가라아게와 멘보샤를 추가로 주문했으며, 가라아게가 ''매우 바삭하다''고 평가함.'),
('호수집', '서울 중구 청파로 443', '02-392-0695', ARRAY['한식'], 'https://www.youtube.com/watch?v=hjYYEklZsgM', 37.5590591, 126.9684823, '서울특별시', '쯔양은 이 식당의 대표 메뉴인 닭꼬치에 뼈가 있는 점이 독특하다고 언급했으며, 고기가 매우 부드럽고 육즙이 풍부하다고 평가했습니다. 소스는 너무 달거나 맵지 않은 특별한 맛이라고 칭찬했습니다. 또한 닭볶음탕은 국물이 진하고 깻잎 향이 강하며, 안에 들어있는 닭고기와 감자도 매우 부드럽고 맛있다고 말했습니다. 함께 주문한 오삼불고기는 특제 소스와 불맛이 잘 어우러져 술안주로 제격이라고 평가했으며, 전반적으로 인공적인 맛이 느껴지지 않는 집밥 같은 맛이라고 요약했습니다. 특히 같이 나온 파김치가 아주 맛있다고 극찬했습니다.'),
('장미맨숀 이수점', '서울 동작구 동작대로23길 15', '0507-1382-0314', ARRAY['한식'], 'https://www.youtube.com/watch?v=Ypc1A5p1BQ0', 37.4841048, 126.9809108, '서울특별시', '쯔양은 인기 술집인 ''장미맨숀'' 이수점을 방문하여 가게의 모든 라면 메뉴를 주문했습니다. 가장 먼저 ''짜파구리''를 먹으며 식당에서 먹는 라면이 집에서 끓여 먹는 것과 맛이 다르다며 만족감을 표했습니다. 특히 계란 프라이와 함께 먹는 것을 즐겼습니다. 이어서 먹은 ''해물짜장라면''에 대해서는 짜파구리보다 개인적으로 더 맛있다고 평가했으며, ''불닭짜파게티''는 매우 맵다며 먹는 내내 힘들어하는 모습을 보였습니다. ''해물라면''은 새우와 바지락 등 해산물과 채소가 많이 들어있고 칼칼한 맛이 특징이라고 언급했습니다. 매운맛을 중화시키기 위해 먹은 ''우동''은 국물 맛을 칭찬하며 아주 맛있다고 평가했습니다. 전반적으로 다양한 라면 메뉴를 즐겼으며, 다음에는 곱도리탕이나 파스타 같은 다른 메뉴도 술과 함께 먹어보고 싶다는 의사를 밝혔습니다.'),
('김밥천국 방배점', '서울특별시 서초구 동광로 70 (방배동)', '02-535-8545', ARRAY['분식'], 'https://www.youtube.com/watch?v=48tVCdhcerE', 37.4925977, 126.9902869, '서울특별시', '쯔양은 총 9가지 메뉴를 주문했다. 처음에는 계란말이김밥, 참치김밥, 참치찌개, 치즈라면, 고구마돈까스, 떡볶이, 우동, 쫄면 8개 메뉴를 주문했다. 특히 ''참치찌개''를 ''말 그대로 최고''이며 ''왕관을 차지했다''고 극찬했다. ''치즈라면''은 매우 크리미하고, 이런 분식집의 라면이 화력이 강해서 가장 맛있다고 평가했다. ''참치김밥''과 ''고구마 돈까스''도 맛있다고 언급했다. 이후 배가 덜 차서 사장님이 직접 개발한 메뉴인 ''짜파게티 떡볶이''를 추가로 주문했으며, 일반 떡볶이보다 맛있다고 평가했다. 오랜만에 제대로 된 식사를 해서 매우 기쁘고, 더 많은 메뉴를 먹어보지 못해 아쉬워했다.'),
('가막새', '서울특별시 서대문구 연세로7안길 54', '02-326-2227', ARRAY['한식'], 'https://www.youtube.com/watch?v=vx9VnkSs7QM', 37.558632, 126.9340208, '서울특별시', '주문한 전 모두 맛있다고 평가했습니다. 특히 감자전을 아주 좋아하며 정말 맛있다고 했고, 부추로 보이는 전은 채소를 좋아하지 않음에도 불구하고 밥이 생각날 정도로 맛있다고 극찬했습니다.'),
('푼푼찌개집 신촌점', '서울특별시 서대문구 연세로11길 27', '02-322-0308', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=vx9VnkSs7QM', 37.5588708, 126.9353112, '서울특별시', '찌개 국물이 신맛, 단맛, 짠맛의 조화가 완벽하며 아주 맛있다고 평가했습니다. 특히 묵은지가 훌륭하다고 언급했으며, 남은 국물에 라면 사리를 넣어 먹으며 김치찌개 라면 같다며 만족감을 표했습니다.'),
('평화족발', '전북 군산시 신금길 18 군산공설시장 1층 1074호', '063-446-2804', ARRAY['분식'], 'https://www.youtube.com/watch?v=L79gwuMulig', 35.9831265, 126.720339, '전라북도', '쯔양은 50년 전통의 시장 분식집인 이곳에서 매운잡채, 족발, 김밥, 열무국수 등 다양한 메뉴를 주문했습니다. 특히 라면, 만두, 떡, 계란, 당면 등 푸짐한 재료가 들어간 ''잡탕'' 메뉴가 인상 깊었으며, 계속된 주문에 사장님이 만류하는 장면으로 화제가 되기도 했습니다.'),
('솔밭식당', '서울특별시 은평구 갈현로 62', '02-388-5937', ARRAY['고기'], 'https://www.youtube.com/watch?v=RkMdigpgVF0', 37.6033392, 126.9105331, '서울특별시', '쯔양은 ''솔밭식당''이 방송 전부터 자주 가던 단골 맛집이라고 소개했습니다. 이날 먹은 돼지고기 특수부위에 대해 연신 "진짜 맛있다"고 감탄했습니다. 특히 ''하얀살''은 항정살과 특양을 섞은 듯한 독특한 식감이라고 평했으며, ''볼살''은 부드러우면서도 쫄깃하다고 말했습니다. ''꼬리살''에 대해서는 소꼬리처럼 진하고 쫀득한 맛이 일품이라고 극찬했습니다. 전반적으로 모든 부위가 매우 맛있다고 평가하며 식당에 대한 높은 만족감을 드러냈습니다.'),
('한양화로 삼성동본점', '서울 강남구 봉은사로 632 1층', '02-563-8592', ARRAY['고기'], 'https://www.youtube.com/watch?v=B3PH-TLulNk', 37.5147392, 127.0645427, '서울특별시', '쯔양은 영상에서 여러 부위의 소고기(치마살, 등심, 갈비살, 살치살, 안심) 3kg를 먹었습니다. 처음 맛본 치마살에 대해 ''살치살보다 맛있다''며 감탄했고, 레어 또는 미디엄 레어로 익혀 먹는 것을 선호했습니다. 각 부위마다 고유의 향과 식감이 다르다고 평가했으며, 특히 갈비살의 독특한 향과 부드러운 식감을 칭찬했습니다. 처음에는 즐겨 먹지 않는다고 했던 등심도 전혀 질기지 않다고 말했습니다. 안심은 씹는 맛이 있는 부드러움, 살치살과 다른 부위들은 입에서 녹는 부드러움이라고 식감을 비교했습니다. 전체적으로 고기의 품질과 맛에 매우 만족하며, 마지막에는 고양이에게도 나눠주는 모습을 보였습니다.'),
('풍미당', '충북 옥천군 옥천읍 중앙로 23-1', '043-732-1827', ARRAY['분식'], 'https://www.youtube.com/watch?v=zLXawaUk8R4', 36.2997124, 127.5677535, '충청북도', '쯔양은 이곳의 대표 메뉴인 ''물쫄면''을 비롯해 비빔쫄면, 수제비, 김밥 등 전 메뉴를 주문했습니다. 그는 물쫄면이 차가울 것이라는 예상과 달리 따뜻한 국물 형태로 나와 놀라워했으며, 쫄면의 쫄깃한 면발을 특히 마음에 들어 했습니다. 국물 맛에 대해서는 잔치국수와 어묵 국물을 섞은 듯한 느낌이라고 묘사했습니다. 영상의 설명란을 통해 "사람마다 입맛 차이가 있다 보니 저한테는 오 괜찮네 정도였어요. 어마어마하게 맛있진 않았어요. 수제비는 정말 맛있었습니다!"라고 솔직한 평가를 남겼습니다. 또한, 어른들이 더 좋아할 만한 맛이라고 덧붙였습니다.'),
('돈불식당', '인천 남동구 문화서로28번길 25-2 1층', '032-435-1999', ARRAY['고기'], 'https://www.youtube.com/watch?v=m3FE0WmS8xU', 37.4476698, 126.6977652, '인천광역시', '쯔양은 석쇠오징어와 소불고기를 처음에는 따로 맛본 후, 두 가지를 섞어서 먹는 것이 더 맛있다는 것을 발견하고 감탄했습니다. 특히 연탄구이의 ''불맛''이 대단하다고 여러 번 언급하며 오징어의 부드러운 식감을 칭찬했습니다. 쯔양은 소불고기와 오징어구이 각각의 맛도 훌륭하지만, 이 둘을 섞어 먹었을 때 맛이 2배가 아닌 10배가 되는 엄청난 시너지를 낸다고 극찬했습니다.'),
('한양식당', '경남 통영시 욕지면 서촌윗길 183-3', '055-642-5146', ARRAY['중식'], 'https://www.youtube.com/watch?v=meXc2Z83Mn4', 34.6354253, 128.2636452, '욕지도', ''),
('김밥천국 건대2호점', '서울특별시 광진구 능동로13길 21', '02-499-0308', ARRAY['분식'], 'https://www.youtube.com/watch?v=rCvknQgxzb8', 37.5429918, 127.0707364, '서울특별시', '쯔양은 주문한 모든 메뉴가 매우 맛있다고 평가하며 전반적으로 극찬했습니다 . 특히 ''고구마 치즈 돈까스''는 입에서 녹을 정도로 부드럽고 최고라고 언급했으며 , ''쫄면''과 함께 먹는 조합이 환상적이라고 했습니다 . ''라제비''는 공장 수제비가 아닌 직접 뜬 수제비의 식감과 집에서는 흉내 낼 수 없는 특유의 라면 국물 맛이 좋다고 평가했습니다 . 참치김밥은 크기가 크고 떡볶이 소스나 참치김치찌개와 잘 어울린다고 말했습니다. 전체적으로 ''미친듯이 맛있다''고 표현하며 방문한 식당에 대해 높은 만족감을 드러냈습니다 .'),
('구복만두', '서울특별시 용산구 두텁바위로 7', '02-797-8656', ARRAY['중식'], 'https://www.youtube.com/watch?v=GGQrROGsuuw', 37.5454116, 126.9729879, '서울특별시', '쯔양은 숙대입구에 위치한 200년 전통의 만두 맛집 ''구복만두''를 방문하여 총 12판, 72개의 만두를 먹었습니다. 주문한 메뉴는 구복 전통만두, 통새우만두, 김치만두, 샤오롱바오 네 종류입니다. 그녀는 특히 ''구복 전통만두''의 아래는 바삭하고 위는 촉촉한 ''겉바속촉'' 식감을 극찬했으며, ''샤오롱바오''의 풍부한 육즙이 정말 맛있다고 평가했습니다. ''통새우만두''는 크기가 크고 속이 꽉 차 있으며, 편의점 만두와는 비교할 수 없는 맛이라고 언급했습니다. 개인적인 취향으로 새우만두와 샤오롱바오를 꼽으며 추가 주문까지 했고, 전반적으로 모든 만두가 맛있어 만족스러운 식사였다고 총평했습니다.'),
('마루돈까스', '서울 마포구 양화로6길 17', '02-333-8235', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=OON0kwUgOlw', 37.5492645, 126.9151841, '서울특별시', '쯔양은 치즈 돈까스 20개와 크림수프를 배달시켜 먹었습니다. 그녀는 크림수프의 농도가 완벽하고 아주 맛있다고 평가했습니다. 돈까스는 고기가 매우 부드럽고 맛있으며, 치즈가 환상적이라고 극찬했습니다. 특히 카레 소스가 아주 맛있다고 여러 번 언급했습니다. 다만, 배달 후 에어프라이어에 데워 먹어서 튀김옷의 바삭함이 덜한 점을 아쉬워하며, 매장에서 바로 먹는 것이 더 맛있을 것이라고 말했습니다. 또한 안심 돈까스가 등심보다 더 부드럽다고 덧붙였습니다.'),
('Shake Shack Madison Square Park', '23rd Street and Madison Ave, New York, NY 10010, USA', '+1 212-889-6600', ARRAY['패스트푸드'], 'https://www.youtube.com/watch?v=Y3-Rai9eJDg', 40.740872, -73.987963, '미국', '쯔양은 뉴욕 맨해튼의 매디슨 스퀘어 파크에 위치한 쉑쉑버거 1호점을 방문하여 다양한 메뉴를 맛보았습니다. 대표 메뉴인 ''쉑 버거''는 크기는 작지만 수제 패티처럼 육즙이 풍부하고 빵이 쫄깃해서 맛있다고 평가했습니다. 감자튀김은 바삭하고 신선하며, 초콜릿 밀크셰이크에 찍어 먹는 ''단짠단짠'' 조합을 즐겼습니다. 반면 ''스모크 쉑 버거''는 베이컨이 너무 짜서 추천하지 않았고, 토핑을 직접 추가해야 하는지 몰랐던 ''햄버거''는 소스가 없어 퍽퍽하고 건조했다고 말했습니다. 이 외에도 거대한 버섯 패티가 인상적인 ''슈룸 버거'', 바삭함이 오래가는 ''치킨 버거'', 그리고 ''쉑 스택 버거''도 맛있게 먹었습니다. 전반적으로 음식이 맛있었지만 양은 부족하게 느꼈다고 언급했습니다.'),
('미남참치 신림점', '서울 관악구 남부순환로 1589', '02-875-7538', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=CKVFCysYo8E', 37.4842412, 126.9271943, '서울특별시', '쯔양은 이곳을 ''최애 참치집''이자 단골 가게라고 소개하며, 방송 때문이 아니라 정말 먹고 싶어서 방문했다고 밝혔습니다. 무한리필 VIP 코스와 특초밥을 주문했으며, 제공되는 참치의 품질에 대해 ''전설적이다'', ''천상의 맛이다''라며 극찬을 아끼지 않았습니다. 특히 참치의 특수부위와 놀라운 마블링에 감탄했고, 여러 번 리필을 요청했습니다. 쯔양은 식당에서 제공하는 해동 및 숙성 방식 덕분에 참치가 더욱 맛있다고 언급했으며, 참치 외에도 장어, 가오리, 메로구이, 콘치즈, 튀김, 탕 등 함께 나오는 모든 음식이 맛있다고 평가했습니다.'),
('화덕고깃간 신촌점', '서울 서대문구 연세로7안길 1', '0507-1335-5392', ARRAY['고기'], 'https://www.youtube.com/watch?v=TiSia0lpZgI', 37.5577901, 126.9362027, '서울특별시', '쯔양은 이곳의 고기가 아궁이에서 초벌되어 나오는 점을 특징으로 꼽으며, 일반적인 삼겹살과는 다른 ''훈연향''이 느껴진다고 평가했습니다. 주문한 메뉴는 오겹살, 항정살, 가브리살, 그리고 4가지 맛의 꼬치였습니다. 고기가 두꺼워 오래 익혀야 하지만 아주 맛있다고 언급했으며, 소시지는 크고 겉이 바삭하다고 했습니다. 개인적인 순위로는 항정살, 오겹살, 가브리살 순으로 맛있다고 밝혔는데, 가브리살은 지방이 적어 상대적으로 선호도가 낮다고 설명했습니다. 함께 나온 뼈도 갈비처럼 맛있다며 만족감을 표현했습니다.'),
('육촌동', '서울 중구 신당동 141-5', '02-2234-8592', ARRAY['고기'], 'https://www.youtube.com/watch?v=WyxpcnXGoTs', 37.5647859, 127.0201258, '서울특별시', '쯔양은 이 식당의 특수부위 모듬을 주문하여 맛보았습니다. ''하얀살''에 대해서는 매우 고소하며(0:244) 항정살보다 더 단단한 식감이 좋다고 평가했고(0:265), 기름기가 적다고 언급했습니다(0:623). ''뽈살''은 닭똥집 같은 식감에 매우 쫄깃하다고 했으며(0:225), ''꼬리살''은 매우 부드러우면서도(0:367) 쫄깃하고 기름진 맛이 특징이라고 설명했습니다(0:501, 0:532). 함께 나온 된장찌개는 할머니가 끓여준 것처럼 진하고 맛이 깊다고 칭찬했습니다(0:491). 전반적으로 모든 부위가 맛있고 식감이 다양해서 좋았으며(0:433, 0:459), 특히 기름지고 쫄깃한 부위를 좋아하는 사람들에게 강력히 추천했습니다(0:902).'),
('명가돈까스', '경기 안양시 만안구 장내로139번길 30', '0507-1377-9407', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=dYcD3nJCjCs', 37.3990568, 126.9223123, '경기도', '쯔양은 이 식당에서 명가(기본), 매운맛, 왕돈까스, 고구마, 이탈리안 돈까스와 쫄면을 주문했습니다 . 기본 돈까스는 매우 전형적인 스타일로 소스가 맛있고 고기가 부드러워 학생들이 좋아할 맛이라고 평가했습니다 . 매운 돈까스는 색과 달리 상당히 맵다고 느꼈지만, 소스를 덜어내니 먹을 만하다고 했습니다 . 여러 돈까스 중 치즈와 고구마가 함께 들어간 돈까스를 최고로 꼽았으며 , 왕돈까스는 기본 돈까스와 크기만 다르다고 언급했습니다 . 쫄면은 달콤하고 매콤한 맛의 균형이 좋다고 평가했습니다 . 전반적으로 현대적인 돈까스보다 이런 전통적인 스타일을 선호하며, 소스가 맛있어서 다양한 종류를 먹어도 질리지 않는다고 말했습니다 . 최종적으로 매우 맛있는 전통 돈까스였다고 만족감을 표했습니다 .'),
('철원막국수', '강원도 철원군 갈말읍 명성로158번길 13', '033-452-2589', ARRAY['한식'], 'https://www.youtube.com/watch?v=bC711I-IPck', 38.145997, 127.3087916, NULL, '쯔양은 물막국수, 비빔막국수, 수육, 녹두빈대떡, 찐만두 등 전 메뉴를 주문했습니다. 물막국수는 일반적인 냉면과 달리 메밀을 삶은 면수를 육수로 사용해 구수한 메밀 향이 나는 것이 특징이며, 자극적이지 않고 중독성 있는 맛이라고 평가했습니다. 비빔막국수는 양념 소스가 달콤하고 새콤해서 맛있다고 했으며, 강한 맛을 선호하는 사람에게 추천했습니다. 개인적으로는 비빔막국수를 더 선호한다고 밝혔습니다. 수육은 족발처럼 생겼으며 아주 맛있다고 감탄했습니다. 메밀로 만든 면은 메밀 함량이 적당하여 쉽게 끊어지지 않으면서도 쫄깃하고 독특한 식감이 일품이라고 칭찬했습니다. 반면 찐만두는 평범한 손만두 맛이라고 평가했습니다. 전반적으로 다른 막국수 식당과는 다른 특별한 경험이었으며, 젊은 세대보다는 어르신들이 더 좋아할 맛이라고 덧붙였습니다.'),
('모두랑', '서울 광진구 자양로28길 24', '02-457-1178', ARRAY['분식'], 'https://www.youtube.com/watch?v=NmmIwEi-Ogg', 37.5420735, 127.0855309, '서울특별시', '쯔양은 이 집의 즉석 떡볶이를 먹어본 것 중 최고라고 평가했으며, 전통적인 맛이 학창 시절의 추억을 떠올리게 한다고 말했습니다. 떡볶이 국물은 달콤하고 매콤하며 전형적인 맛이라고 언급했고, 일반 떡이 치즈 떡보다 더 부드럽고 쫄깃해서 맛있다고 했습니다. 특히 볶음밥은 다른 곳보다 더 고소하고 맛있다며, 옥수수와 깨가 아낌없이 들어가 ''밥 반, 옥수수 반''이라고 표현할 정도로 재료가 풍성하다고 극찬했습니다. 볶음밥은 꼭 먹어야 할 필수 메뉴라고 강조했습니다.'),
('줘마양다리구이 본점', '서울특별시 영등포구 도림천로11길 13', '010-6797-6088', ARRAY['고기'], 'https://www.youtube.com/watch?v=Qe5w3eSHhUE', 37.4915758, 126.8972481, '서울특별시', '쯔양은 2.2kg 대왕 양다리 구이를 처음 먹어보며, 직접 잘라 먹는 것이 힘들고 인내심이 필요하다고 언급했습니다(4:01, 9:32). 하지만 맛에 대해서는 잡내가 없고 쫄깃하며(3:38), 지방보다 살코기를 즐기는 사람에게 추천한다고 평가했고, 특히 매콤한 향신료 가루와 잘 어울린다고 덧붙였습니다(11:28). 함께 먹은 꿔바로우는 매우 바삭하고 달콤하다며 만족감을 표했습니다(2:11). 추가로 주문한 1.6kg의 양갈비에 대해서는 양다리보다 육즙이 풍부하고 정말 맛있다며 극찬했으며(14:58), 서비스로 나온 찐만두도 육즙이 터져 나온다며 맛있게 먹었습니다(12:24).'),
('꾸이꾸이 돼지촌 쭈꾸미 본점', '서울 강서구 초원로 77', '02-2662-3450', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=R88YwEzAqls', 37.5676812, 126.8141435, '서울특별시', '과거 다른 방송 촬영으로 방문했다가 그리워서 다시 찾아온 두 번째 방문이라고 밝혔습니다 . 대표 메뉴인 ''부추쭈꾸미''에 대해 부추가 매우 고소하고 지난번보다 더 맛있어졌다고 평가했으며, 삼겹살, 주꾸미, 부추의 조합을 ''최고의 조합''이라고 극찬했습니다 . 살아있는 주꾸미를 사용해 머릿속 내장과 알이 특히 고소하고 맛있다고 감탄했습니다 . 추가한 국수 사리도 맛있지만, 특히 볶음밥은 국수와 비교할 수 없을 정도로 훌륭하다고 평가하며 식사를 마무리했습니다 . 전반적으로 매우 훌륭한 식사 경험이었다고 만족감을 표했습니다 .'),
('홍가네영양센타', '경기 안양시 만안구 장내로 148', '031-443-2924', ARRAY['찜·탕'], 'https://www.youtube.com/watch?v=AV1GLZOoctA', 37.3979591, 126.9239521, '경기도', '쯔양은 닭매운탕, 전기구이 통닭, 닭죽, 볶음밥을 먹었습니다. 애피타이저로 나온 닭죽은 간이 되어 있어 맛있고 인삼이 들어간 정석적인 맛이라고 평가했습니다. 전기구이 통닭은 껍질이 아주 바삭하고 속살은 촉촉하며, 전통적인 방식으로 구워져 맛있다고 했습니다. 메인 메뉴인 닭매운탕은 닭볶음탕과 매운탕을 섞은 듯한 맛의 국물이 일품이라고 표현했으며, 압력솥에 조리한 듯 닭고기가 뼈에서 그냥 발라질 정도로 부드러워 입에서 녹는다고 극찬했습니다. 특히 닭가슴살조차 매우 부드럽다고 여러 번 강조했습니다. 닭고기가 너무 부드러워 국물에도 살이 다 녹아들어 있다고 언급했습니다. 함께 들어있는 감자도 매우 부드럽다고 칭찬했으며, 남은 국물에 볶은 밥까지 맛있게 먹었습니다.'),
('장다리곱창 약수본점', '서울 중구 동호로7길 13-6', '02-2234-2220', ARRAY['고기'], 'https://www.youtube.com/watch?v=JUtNGH1R3Gs', 37.5530618, 127.0113167, '서울특별시', '쯔양은 27년 전통의 곱창집이라며 기대감을 나타냈습니다. 음식이 나오자 곱창에 곱이 가득 차 있다며 감탄했고, 먼저 맛본 특양의 쫄깃한 식감을 칭찬했습니다. 메인 메뉴인 소곱창은 ''진짜 진리''라고 표현하며, 시간이 지날수록 더 부드러워지는 것 같다며 만족감을 보였습니다. 대창과 막창 등 다른 부위도 맛있게 먹었으며, 식사 중간중간 계속해서 음식을 추가 주문했습니다. 마지막으로 볶음밥을 먹으며, 특히 누룽지 부분이 맛있다며 극찬하면서 식사를 마무리했습니다.'),
('호호분식', '서울 도봉구 도봉로121길 32', '02-900-1377', ARRAY['분식'], 'https://www.youtube.com/watch?v=JZU3p0Gmsio', 37.6524485, 127.0348202, '서울특별시', '쯔양은 어릴 적 살던 동네의 추억이 담긴 분식집이라고 소개하며, 원조 치즈밥을 먹기 위해 방문했다. 그는 원조 치즈밥, 피자 떡볶이, 치즈 떡볶이, 쫄면, 튀김만두, 탕수육, 양념치킨 등 다양한 메뉴를 주문했다. 음식 맛에 대해, 떡볶이는 매우 달고 쫄깃해 옛날 생각이 나는 맛이라고 평했으며, 개인적으로는 피자 떡볶이를 더 선호한다고 밝혔다. 탕수육과 양념치킨 소스 역시 추억의 맛이라고 언급했다. 전반적으로 ''경이로운 맛''이라기보다는 초등학생, 중학생 시절을 떠올리게 하는 추억의 맛이라는 점을 강조했다. 다만, 쫄면이 예상외로 맵게 느껴졌다고 덧붙였다.'),
('지린성', '전북 군산시 미원로 93', '063-467-2906', ARRAY['중식'], 'https://www.youtube.com/watch?v=Pr0I7zpL3dQ', 35.9796826, 126.7146138, '전라북도', '이곳의 시그니처 메뉴인 고추짜장은 혀를 마비시킬 정도의 강력한 매운맛을 자랑한다고 평가했습니다. 일반 짜장면과 달리 다진 고추가 듬뿍 들어가 있어, 매운 음식을 좋아하는 사람들에게는 도전해볼 만한 메뉴라고 언급했습니다. 짬뽕 역시 다른 곳에 비해 훨씬 맵고 자극적이며, 먹는 내내 땀을 흘릴 정도의 강력한 매운맛이 특징이라고 요약했습니다.'),
('Wolfgang''s Steakhouse Times Square', '250 W 41st St, New York, NY 10036', '+1 212-921-3720', ARRAY['고기'], 'https://www.youtube.com/watch?v=JXGKeq14Lbk', 40.7560539, -73.9898529, NULL, '쯔양은 이곳을 뉴욕 3대 스테이크 맛집 중 하나로 소개하며 포터하우스, 립아이, 양갈비 스테이크를 주문했습니다. 포터하우스 스테이크의 안심 부위는 매우 부드럽고 맛있다고 평가했고, 등심 부위는 안심보다 질기지만 씹는 맛이 좋다고 언급했습니다. 립아이 스테이크는 버터처럼 부드럽게 잘리며 갈비찜과 비슷한 맛이 난다고 표현했습니다. 다양한 스테이크 중 양갈비가 가장 맛있다며 ''1순위''로 꼽았으며, 함께 제공된 새콤달콤한 소스 역시 훌륭하다고 칭찬했습니다. 다만, 미국 현지 식당이라 간이 다소 짜게 느껴진다고 덧붙였습니다.'),
('해녀촌식당', '경남 통영시 욕지면 서촌아랫길 112', '055-644-0277', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=HnBsYS5Y_T0', 34.6345647, 128.264681, '욕지도', '쯔양은 이곳을 두 번째 방문했으며, 특히 이전에 먹었던 전복죽이 맛있어서 계속 생각났다고 언급했습니다. 그는 주문한 모든 메뉴에 대해 전반적으로 극찬했습니다. 성게알(우니)은 매우 신선하고 맛있으며 전혀 쓰지 않다고 평가했고, 성게알 비빔밥을 멍게 비빔밥보다 훨씬 선호한다고 말했습니다. 전복죽은 가장 좋아하는 메뉴로 꼽았으며, 식어도 맛있고 전복 건더기가 매우 크다고 칭찬했습니다. 제철인 뿔소라는 부드럽고 훌륭하다고 했으며, 특히 전복 내장이 맛있다고 감탄했습니다. 마지막으로 먹은 자연산 전복 라면에 성게알을 넣어 먹으며, 국물 맛이 완전히 달라지고 완벽한 바다의 맛이라고 표현했습니다. 이곳을 ''해산물 애호가들을 위한 완벽한 장소''라고 요약했습니다.'),
('호수곱창', '경기 고양시 일산동구 무궁화로 32-12 라르시티', '031-902-3973', ARRAY['고기'], 'https://www.youtube.com/watch?v=HrlUZv2s8l4', 37.6620916, 126.7680142, '경기도', '쯔양은 이 식당의 거의 모든 메뉴를 맛보고 전반적으로 극찬했다. 특히 마늘과 함께 구워 먹는 ''특양(마늘 벌양)''의 독특하고 아삭한 식감에 놀라며, 평생 먹어본 곱창 중에 가장 맛있다고 평가했다. 일반 양은 부드러운 식감이 특징이며, 특양과는 또 다른 매력이 있다고 언급했다. 소곱창 역시 ''특''과 ''일반'' 두 종류를 비교하며, 기름진 고소함이 가득한 특곱창이 더 인상적이었다고 말했다. 막창은 다른 곳보다 훨씬 부드럽고 맛있다고 했으며, 염통 또한 부드럽고 쫄깃한 식감이 일품이라고 칭찬했다. 차돌박이, 볶음밥, 된장술밥, 국수 등 사이드 메뉴까지 모두 섭렵하며 맛에 감탄했다. 특히 고기 기름에 구워진 감자와 잘 익은 마늘, 볶음밥의 누룽지를 별미로 꼽았다. 전체적으로 신선한 재료와 다양한 부위의 독특한 식감, 그리고 마늘과의 조화를 이 식당의 가장 큰 특징으로 요약했다.'),
('평화족발', '전북 군산시 신금길 18-1', '063-446-2804', ARRAY['분식'], 'https://www.youtube.com/watch?v=8AR6YsJ3SC4', 35.9831265, 126.720339, '전라북도', '군산 공설시장 근처에 위치한 50년 전통의 맛집으로, 쯔양은 이곳에서 매운 잡채, 족발, 김밥 등 다양한 메뉴를 즐겼습니다. 특히 라면, 만두, 떡, 계란, 당면 등 푸짐한 재료가 들어간 ''잡탕'' 메뉴가 인상적이었으며, 사장님과의 유쾌한 소통이 영상에 담기기도 했습니다.'),
('지린성', '전북 군산시 미원로 87', '0507-1369-2905', ARRAY['중식'], 'https://www.youtube.com/watch?v=8AR6YsJ3SC4', 35.9796712, 126.7139533, '전라북도', '매운 고추짜장과 고추짬뽕으로 유명한 중식당입니다. 쯔양은 군산 3대 짬뽕 맛집 중 한 곳으로 이곳을 방문하여 강렬한 매운맛이 특징인 메뉴들을 맛보았습니다. 매운맛을 즐기는 사람들에게 특히 인기가 많으며, 땀을 흘리면서도 계속 먹게 되는 중독성 있는 맛으로 평가받고 있습니다.'),
('법주사', '충북 보은군 속리산면 법주사로 405', '043-544-5656', ARRAY['한식'], 'https://www.youtube.com/watch?v=A5qOkDOnMAg', 36.5413087, 127.83307, '충청북도', '쯔양은 정성스럽고 예쁘게 차려진 사찰 음식에 감탄하지만, 평소 채소를 즐겨 먹지 않아 힘들어하는 모습을 보입니다. 특히 시래기와 호박전 등 다양한 나물 반찬을 맛보며 ''태어나서 야채를 제일 많이 먹는 날''이라고 언급합니다. 채식에 익숙하지 않아 식사량이 평소보다 현저히 줄었으며, 식사 중에도 고기에 대한 그리움을 표현합니다. 템플스테이를 통해 고기와 채소의 소중함을 모두 느꼈다고 소감을 밝혔으며, 결국 템플스테이를 떠나 고기를 먹는 것으로 영상은 마무리됩니다.'),
('스시로 안양점', '경기 안양시 만안구 만안로 244 엔터식스 7층', '0507-1391-6347', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=1kVddWboA0A', 37.4014281, 126.9230623, '경기도', '의료 검진 때문에 18시간 공복 상태로 방문하여 배가 매우 고픈 상태였다. 다양한 종류의 초밥이 있고, 특히 광어 지느러미와 마블링이 좋은 참치 뱃살이 맛있다고 언급했다. 간장새우, 연어 뱃살, 장어, 너비아니, 육회, 묵은지, 항정살, 버터 구이 꼬막 등 다양한 메뉴를 맛보았다. 밥 양이 조금 더 적었으면 좋겠다고 했지만, 생선 크기가 커서 비율은 맞는 것 같다고 평가했다. 특히 매콤한 양념 새우가 가장 맛있다고 극찬하며 계속 먹을 수 있을 것 같다고 말했다. 중간에 디저트로 딸기 아이스크림을 먹기도 했으며, 최종적으로 총 75접시를 먹고 만족스러운 식사를 마쳤다.'),
('짬뽕이야기', '서울 성북구 동소문로20다길 30 1층', '02-3298-8282', ARRAY['중식'], 'https://www.youtube.com/watch?v=a42wwS86JTc', 37.5920362, 127.0183008, '서울특별시', '쯔양은 차돌해물짬뽕에 대해 ''불맛이 미쳤다''고 감탄하며 국물이 매우 진하고 맛있다고 평가했습니다. 일반 짬뽕보다 훨씬 맛있다고 언급했으며, 면보다는 국물에 밥을 말아 먹는 것을 더 선호한다고 말했습니다. 찹쌀탕수육 또한 맛있게 먹는 모습을 보였습니다. 짬뽕은 3인분짜리 3개를 주문했으며, 양이 2.5인분에서 3인분 정도 되는 것 같다고 언급했습니다.'),
('대물림전복낙지볶음', '경기 안양시 동안구 귀인로190번길 70-9', '031-382-3525', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=-H-mhUeu_qk', 37.381856, 126.9619136, '경기도', '쯔양은 버터로 구운 전복 50마리와 매콤한 주꾸미 볶음 2인분을 주문했습니다. 특히 버터구이 전복에 대해 ''미쳤다'', ''버터 풍미가 대박이다''라며 극찬했고, 지난 방문 이후 계속 생각났던 맛이라고 언급했습니다. 전복과 주꾸미를 함께 먹는 조합을 ''환상적인 맛''이라고 표현했으며, 주꾸미보다 전복이 더 맛있다고 평가했습니다. 또한, 버터로 구운 전복 내장도 ''진짜 대박''이라고 칭찬했습니다. 사용된 주꾸미는 냉동이 아닌 살아있는 생물이라 신선하다고 말했고, 볶음 양념은 맵지 않고 독특한 맛이 일품이라고 했습니다. 남은 음식으로는 전복을 듬뿍 넣은 볶음밥을 만들어 먹으며 만족감을 표했습니다.'),
('전원분식', '경남 통영시 욕지면 서촌아랫길 130', '010-9240-3740', ARRAY['분식'], 'https://www.youtube.com/watch?v=jzIDWJV1pjE', 34.6348792, 128.2636462, '욕지도', '떡볶이는 할머니가 집에서 만들어주는 것 같은 맛으로, 달콤하고 중독성이 강하며 위에 뿌려진 참깨가 맛을 더한다고 평가했습니다. 떡은 밀떡일 것이라고 추측했습니다. 김밥은 식초로 간을 한 초밥 밥처럼 촉촉해서 먹기 편하고, 소스는 달콤하고 새콤하여 최고의 김밥이라고 극찬했습니다. 우동은 포장마차에서 파는 맛과 비슷하다고 했고, 콩국수는 국물이 매우 맛있어서 아껴 먹고 싶다고 언급했습니다. 가게에서 직접 만든 김치 또한 훌륭하다고 칭찬했습니다.'),
('욕지도할매바리스타', '경남 통영시 욕지면 욕지일주로 155', '055-645-8121', ARRAY['카페·디저트'], 'https://www.youtube.com/watch?v=jzIDWJV1pjE', 34.6351371, 128.2696237, '욕지도', '아이스 아메리카노, 딸기 스무디, 고구마 라떼를 주문했습니다. 이곳은 노인 일자리 창출을 위해 어르신들이 직접 운영하는 카페라는 점을 긍정적으로 언급했습니다. 가게에서 서비스로 제공된 디저트는 욕지도산 유기농 고구마로 만들었다는 설명을 들으며 맛있게 먹었습니다. 음료의 맛에 대한 구체적인 평가보다는 어르신들이 운영하는 카페의 따뜻한 분위기와 좋은 취지에 대해 긍정적으로 반응했습니다.'),
('해녀촌식당', '경남 통영시 욕지면 서촌아랫길 112', '0507-1305-0277', ARRAY['분식'], 'https://www.youtube.com/watch?v=8bk4qd4h2mM', 34.6345647, 128.264681, '욕지도', '쯔양은 네 번의 방문 시도 끝에 식당에 들어갈 수 있었습니다. 처음에는 라면 5개와 김밥 2줄을 주문했으나, 버너가 3개밖에 없어 사장님이 먼저 라면 3개를 끓여주셨습니다. 메뉴판에는 ''콩나물 신라면''이라 적혀있었지만, 사장님은 맵다며 대신 ''안성탕면''을 끓여주셨고 쯔양은 맛있다고 평가했습니다. 이후 남은 라면 2개는 신라면으로 제공되었으며, 이 또한 맛있게 먹었습니다. 김밥은 크기가 크고 맛이 좋으며, 라면 국물에 찍어 먹으면 더욱 맛있다고 언급했습니다. 또한, 라면 국물에 날달걀을 풀어 먹는 것을 좋아하며, 공깃밥까지 추가해 남은 국물과 함께 먹었습니다. 전반적으로 모든 음식을 맛있게 먹었으며, 특히 푸짐한 양에 만족감을 표현했습니다.'),
('풍어횟집', '강원 고성군 죽왕면 심층수길 40-12', '033-632-8582', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=q2EPGy1ZOZ0', 38.327207, 128.5290995, '강원특별자치도', '쯔양은 3kg짜리 통문어와 양이 푸짐한 물회를 주문했습니다. 물회에 들어간 회가 가리비처럼 부드럽고 양이 매우 많다며 칭찬했고, 더운 여름에 먹기 완벽한 메뉴라고 평가했습니다. 특히 국수가 물회와 잘 어울린다고 언급했습니다. 통문어는 일반 문어임에도 불구하고 전혀 질기지 않고 매우 부드럽게 잘 삶겼다며 놀라워했습니다. 처음에는 그냥 먹어도 맛있다고 했고, 참기름에 찍어 먹는 것이 해산물 본연의 맛을 해치지 않아 초장보다 더 좋다고 말했습니다. 마늘 쌈장과 함께 먹어도 맛있다고 덧붙였습니다. 문어 머리 부분이 다리보다 훨씬 맛있다고 평가했으며, 식은 후에도 부드러움을 유지하는 점을 신기해했습니다. 전반적으로 바닷가에 위치해 해산물이 매우 신선하고, 특히 문어가 부드럽고 맛있었다고 극찬하며 만족스러운 식사였음을 표현했습니다.'),
('진미떡볶이', '서울 중구 다산로36길 36', '02-2252-5889', ARRAY['분식'], 'https://www.youtube.com/watch?v=_8p0m5ohxLI', 37.5619214, 127.0169233, '서울특별시', '면사리를 먼저 먹고, 한국인에게는 흔한 음식이지만 외국인에게는 그렇지 않을 수 있다는 점이 멋지다고 생각했으며, 떡과 어묵, 그리고 반으로 가른 계란을 국물과 함께 즐겼습니다.'),
('곱스떡스 강남본점', '서울특별시 강남구 강남대로102길 20', '02-554-2888', ARRAY['분식'], 'https://www.youtube.com/watch?v=a9yR7a6NNMs', 37.5022539, 127.0273335, '서울특별시', '쯔양은 곱창떡볶이가 상상하지 못한 조합이지만 매우 잘 어울리고 맛있다고 평가했습니다. 특히 잡내가 없고 깔끔한 맛의 곱창을 장점으로 꼽았으며, 통으로 제공되어 곱이 빠져나가지 않는 점을 칭찬했습니다. 강한 불맛과 독특한 소스 맛이 일반 떡볶이와는 다른 특별한 경험을 제공한다고 언급했습니다. 쯔양은 맛에 매우 만족하여 사리를 12번이나 추가 주문했으며, 함께 먹은 어묵탕, 콘도그, 볶음밥도 훌륭했다고 평가하며, 특히 볶음밥을 필수 메뉴로 추천했습니다.'),
('T.G.I.프라이데이스 롯데영등포점', '서울특별시 영등포구 경인로 846 영등포민자역사 3층', '02-2632-2083', ARRAY['양식'], 'https://www.youtube.com/watch?v=TMESU7zMhso', 37.515668, 126.907666, '서울특별시', '출시 전인 ''바이킹 스테이크''를 최초로 시식하기 위해 방문하여 3kg을 주문했습니다. 이와 함께 바이킹 크림 파스타, 토마토 파스타, 모든 종류의 에이드도 함께 주문했습니다. 스테이크 갈빗대가 매우 크다며 놀라워했고, 칼을 쓰지 않고 통째로 먹으며 맛있다고 감탄했습니다. 쪄서 나온 갈비는 매우 부드럽고 연하다고 평가했습니다. 두 종류의 파스타 역시 고기와 함께 먹을 때 훨씬 맛이 좋다고 언급했습니다. 스테이크 굽기는 웰던에 가까웠으며, 쫄깃한 식감이 좋다고 말했습니다. 특히 기름진 부위의 고소한 맛을 좋아했으며, 식어가는 고기를 직원들이 계속 데워주는 서비스에 만족감을 표했습니다. 전반적으로 한 종류의 스테이크를 많은 양으로 즐길 수 있었던 멋진 경험이었다고 총평했습니다.'),
('도산분식 도산공원점', '서울 강남구 도산대로49길 10-6 젤로빌딩', '02-514-5060', ARRAY['분식'], 'https://www.youtube.com/watch?v=ot9FvjMwLbk', 37.5237202, 127.0379299, '서울특별시', '쯔양은 이곳이 ''인터넷에서 엄청 핫한 곳''이라며 기대를 보였고, 음식을 맛본 후에는 ''왜 유명한지 알겠다''며 만족감을 드러냈습니다. 그녀는 함께한 유도부 선수들과 떡볶이, 육회김밥, 돈까스 샌드, 마라 라면 등 다양한 메뉴를 주문해 먹으며 ''오늘 음식이 정말 맛있었다'', ''다 부쉈다''고 말하며 전반적으로 매우 긍정적인 평가를 내렸습니다.'),
('이레수산', '충청남도 홍성군 서부면 남당항로213번길 12', '041-631-2750', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=DZTe3nfHfI4', 36.5397437, 126.4709574, '충청남도', '쯔양은 충남 홍성 남당항에 위치한 ''이레수산''에서 제철 새조개 샤부샤부 ''먹방''을 진행했습니다. 1kg에 75,000원인 새조개를 약 200마리나 먹어치워 식당 사장님을 놀라게 할 만큼 엄청난 양을 주문했습니다. 쯔양은 무, 배추, 파, 바지락으로 맛을 낸 시원한 육수에 새조개를 살짝 데쳐 야들야들하고 부드러운 식감을 즐겼습니다. 새조개 본연의 맛을 느끼기 위해 초장보다는 간장에 찍어 먹는 것을 추천했으며, 함께 제공된 신선한 생굴, 가리비찜, 해삼, 멍게 등 푸짐하고 퀄리티 높은 밑반찬에도 만족감을 표했습니다. 영상 내내 맛있게 먹는 모습을 보이며 새조개의 신선함과 뛰어난 맛을 극찬했습니다.'),
('동해러시아대게마을', '강원특별자치도 동해시 추암택지길 2', '033-522-4774', ARRAY['돈까스·회'], 'https://www.youtube.com/watch?v=Jf6CmGR4b9k', 37.477915, 129.1562801, '강원특별자치도', '쯔양은 5kg짜리 대왕 킹크랩, 2kg짜리 킹크랩과 스노우 크랩(대게)을 먹었습니다. 킹크랩에 대해 ''여태 먹어본 킹크랩 중에 제일 맛있다''고 평가하며, 짜지 않고 단맛이 돌며 간이 완벽하다고 극찬했습니다. 킹크랩의 식감은 쫄깃하고, 스노우 크랩은 매우 부드럽다고 비교했습니다. 특히 스노우 크랩의 내장과 살을 함께 먹는 것을 즐겼으며, 맛 자체는 스노우 크랩이 더 취향에 맞다고 언급했습니다. 러시아에서 수입된 크랩의 신선한 보관 상태를 칭찬했으며, 함께 나온 새우튀김과 양념 새우장도 맛있게 먹었습니다. 마지막으로 스노우 크랩 내장으로 볶음밥을 먹는 것이 전통이라며 만족감을 표현했습니다.'),
('현풍닭칼국수 본점', '대구 달성군 현풍읍 현풍중앙로 50', '053-611-8880', ARRAY['한식'], 'https://www.youtube.com/watch?v=JPCHnKMMaNs', 35.6940033, 128.4457884, '대구광역시', '쯔양은 5.5kg 대왕 칼국수를 20분 안에 먹는 도전에 참여했습니다. 그녀는 음식이 매우 뜨거워서 시간 안에 다 먹지 못하고 도전에 실패했습니다. 쯔양은 양이 많아서가 아니라 뜨거움 때문에 실패했다고 밝혔습니다. 도전 전 김치가 맛있다고 언급했으며, 도전 실패 후에도 음식이 식으니 더 맛있다며 맛있게 식사를 마쳤습니다.');
